def _bridge_console_env_aliases() -> None:
    for key, value in list(os.environ.items()):
        if key.startswith(CANONICAL_CONSOLE_ENV_PREFIX):
            suffix = key.removeprefix(CANONICAL_CONSOLE_ENV_PREFIX)
            os.environ.setdefault(f"{LEGACY_CONSOLE_ENV_PREFIX}{suffix}", value)
        elif key.startswith(LEGACY_CONSOLE_ENV_PREFIX):
            suffix = key.removeprefix(LEGACY_CONSOLE_ENV_PREFIX)
            os.environ.setdefault(f"{CANONICAL_CONSOLE_ENV_PREFIX}{suffix}", value)


_bridge_console_env_aliases()


