def normalize_queue_interlace_mode(value: Any) -> str:
    clean = str(value or "").strip().lower().replace("_", "-")
    aliases = {
        "": "queue",
        "ack": "interrupt",
        "cli": "interrupt",
        "default": "queue",
        "inline": "interrupt",
        "inject": "interrupt",
        "injected": "interrupt",
        "interject": "interrupt",
        "interrupt": "interrupt",
        "interrupted": "interrupt",
        "serial": "queue",
        "wait": "queue",
        "waiting": "queue",
        "observe": "queue",
        "observe-only": "queue",
    }
    normalized = aliases.get(clean, clean)
    return normalized if normalized in {"interrupt", "queue"} else "queue"


