def _codex_model_version(value: Any) -> tuple[int, int] | None:
    clean = str(value or "").strip().lower()
    if clean.startswith("openai."):
        clean = clean.removeprefix("openai.")
    match = re.search(r"\bgpt-(\d+)(?:\.(\d+))?", clean)
    if not match:
        return None
    return int(match.group(1)), int(match.group(2) or 0)


def codex_model_below_floor(value: Any) -> bool:
    version = _codex_model_version(value)
    floor = _codex_model_version(CODEX_MODEL_FLOOR)
    if version is None or floor is None:
        return False
    return version < floor


def _codex_model_aliases(value: Any) -> set[str]:
    clean = str(value or "").strip()
    if not clean:
        return set()
    aliases = {clean}
    if clean.startswith("openai."):
        aliases.add(clean.removeprefix("openai."))
    elif clean.startswith("gpt-"):
        aliases.add(f"openai.{clean}")
    return aliases


def codex_model_switchable_below_floor(value: Any) -> bool:
    aliases = _codex_model_aliases(value)
    if not aliases:
        return False
    raw = os.environ.get(
        "NORMAN_CODEX_SWITCHABLE_MODELS", CODEX_SWITCHABLE_MODEL_DEFAULTS
    )
    for item in raw.split(","):
        if aliases & _codex_model_aliases(item):
            return True
    return False


def normalize_codex_model_name(
    value: Any,
    *,
    fallback: Any = "",
    allow_blank: bool = False,
    allow_switchable: bool = False,
) -> str:
    clean = str(value or "").strip()
    if not clean:
        return "" if allow_blank else str(fallback or CODEX_MODEL_FLOOR).strip()
    if codex_model_below_floor(clean):
        if (
            CODEX_ALLOW_BELOW_FLOOR_SWITCHABLE
            and allow_switchable
            and codex_model_switchable_below_floor(clean)
        ):
            return clean
        return str(fallback or CODEX_MODEL_FLOOR).strip() or CODEX_MODEL_FLOOR
    return clean


def _dedupe_models(values: Iterable[str]) -> list[str]:
    seen: set[str] = set()
    models: list[str] = []
    for value in values:
        clean = str(value or "").strip()
        if not clean or clean in seen:
            continue
        seen.add(clean)
        models.append(clean)
    return models


