def _node_version_key(path: Path) -> tuple[int, int, int, str]:
    match = re.search(r"(?:^|[/-])(?:node-)?v(\d+)\.(\d+)\.(\d+)", str(path))
    if not match:
        return (0, 0, 0, str(path))
    return (*(int(part) for part in match.groups()), str(path))


def _node_bin_dir(path: Path) -> Path:
    return path if path.name == "bin" else path / "bin"


def _append_node_bin_dir(items: list[Path], path: Path) -> None:
    candidate = _node_bin_dir(path.expanduser())
    if not (candidate / "node").exists():
        return
    if candidate not in items:
        items.append(candidate)


def _glob_node_roots(root: Path, pattern: str) -> list[Path]:
    try:
        return list(root.glob(pattern))
    except OSError:
        return []


def resolve_node_bin_dirs() -> list[Path]:
    items: list[Path] = []
    for raw_path in os.environ.get("NORMAN_CODEX_NODE_PATHS", "").split(os.pathsep):
        if raw_path.strip():
            _append_node_bin_dir(items, Path(raw_path.strip()))
    configured_dir = os.environ.get("NORMAN_CODEX_NODE_DIR", "").strip()
    if configured_dir:
        _append_node_bin_dir(items, Path(configured_dir))
    configured_bin = os.environ.get("NORMAN_CODEX_NODE_BIN", "").strip()
    if configured_bin:
        _append_node_bin_dir(items, Path(configured_bin).parent)

    search_roots = (
        (Path("/opt"), "node-v*"),
        (Path("/home/operator/.nvm/versions/node"), "v*"),
        (Path("/home/kristopher/.nvm/versions/node"), "v*"),
        (Path("/root/.nvm/versions/node"), "v*"),
    )
    for root, pattern in search_roots:
        for child in sorted(
            _glob_node_roots(root, pattern), key=_node_version_key, reverse=True
        ):
            _append_node_bin_dir(items, child / "bin")
    return items


def configure_node_path(node_bin_dirs: list[Path]) -> None:
    merged: list[str] = []
    for value in [
        *(str(path) for path in node_bin_dirs),
        *os.environ.get("PATH", "").split(os.pathsep),
    ]:
        if value and value not in merged:
            merged.append(value)
    if merged:
        os.environ["PATH"] = os.pathsep.join(merged)


NODE_BIN_DIRS = resolve_node_bin_dirs()
configure_node_path(NODE_BIN_DIRS)


def resolve_codex_bin() -> str:
    configured = os.environ.get("NORMAN_CODEX_BIN", "").strip()
    candidates = [
        configured,
        *(str(path / "codex") for path in NODE_BIN_DIRS),
        "/usr/local/bin/codex",
        "codex",
    ]
    for candidate in candidates:
        if not candidate:
            continue
        if os.path.isabs(candidate):
            if os.path.exists(candidate) and os.access(candidate, os.X_OK):
                return candidate
            continue
        resolved = shutil.which(candidate)
        if resolved:
            return resolved
    return configured or "codex"


CODEX_BIN = resolve_codex_bin()


def resolve_codex_profile_config_flag() -> str:
    configured = os.environ.get("NORMAN_CODEX_PROFILE_CONFIG_FLAG", "").strip()
    if configured:
        return configured
    try:
        completed = subprocess.run(
            [CODEX_BIN, "exec", "--help"],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=2,
            check=False,
        )
    except (OSError, subprocess.TimeoutExpired):
        return "--profile"
    help_text = f"{completed.stdout}\n{completed.stderr}"
    has_profile = "--profile" in help_text
    has_profile_v2 = "--profile-v2" in help_text
    if has_profile and has_profile_v2:
        try:
            version = subprocess.run(
                [CODEX_BIN, "--version"],
                text=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                timeout=2,
                check=False,
            )
        except (OSError, subprocess.TimeoutExpired):
            return "--profile-v2"
        match = re.search(r"(\d+)\.(\d+)\.(\d+)", f"{version.stdout} {version.stderr}")
        if match and tuple(int(part) for part in match.groups()) < (0, 134, 0):
            return "--profile-v2"
        return "--profile"
    if has_profile:
        return "--profile"
    if has_profile_v2:
        return "--profile-v2"
    return "--profile"


