RESPONSE_SPEED_TO_REASONING = {
    "fast": "low",
    "balanced": "medium",
    "careful": "xhigh",
}
EMERGENCY_XFAST_ALIASES = {"fast", "xfast", "x-fast", "extra-fast", "low", "minimal"}
RESPONSE_DETAIL_LABELS = {
    1: "Simple",
    2: "Lean",
    3: "Balanced",
    4: "Detailed",
    5: "Deep",
}
RESPONSE_DETAIL_INSTRUCTIONS = {
    1: "Use the minimum words needed. Prefer one short paragraph or a very short list. Skip background unless it is essential.",
    2: "Stay concise and practical. Keep explanation lean and avoid extra context unless it clearly helps.",
    3: "Use balanced depth. Cover the main answer, the key rationale, and the next useful detail.",
    4: "Go a layer deeper. Explain the reasoning, tradeoffs, and relevant context while staying organized.",
    5: "Be thorough. Include the important context, tradeoffs, and next steps, but stay concrete and readable.",
}


def reasoning_effort_to_speed(value: str | None) -> str:
    clean = str(value or "").strip().lower()
    if clean in EMERGENCY_XFAST_ALIASES:
        return "fast" if EMERGENCY_XFAST_ENABLED else "balanced"
    if clean in {"medium", "med"}:
        return "balanced"
    return "careful"


def normalize_response_speed(value: Any) -> str:
    clean = str(value or "").strip().lower().replace("_", "-").replace(" ", "-")
    if clean in EMERGENCY_XFAST_ALIASES:
        return "fast" if EMERGENCY_XFAST_ENABLED else "balanced"
    if clean in {"fast", "quick", "brief", "low", "cheap"}:
        return "fast"
    if clean in {"balanced", "medium", "med", "std", "standard"}:
        return "balanced"
    if clean in {"careful", "deep", "high", "xhigh", "x-high"}:
        return "careful"
    return reasoning_effort_to_speed(REASONING_EFFORT)


def normalize_response_detail(value: Any) -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return 3
    if parsed < 1:
        return 1
    if parsed > 5:
        return 5
    return parsed


DEFAULT_RESPONSE_SPEED = normalize_response_speed(
    os.environ.get(
        "NORMAN_CODEX_RESPONSE_SPEED", reasoning_effort_to_speed(REASONING_EFFORT)
    )
)
DEFAULT_RESPONSE_DETAIL = normalize_response_detail(
    os.environ.get("NORMAN_CODEX_RESPONSE_DETAIL", "3")
)
AUTO_CONTINUE_MIN_RESPONSE_SPEED = normalize_response_speed(
    os.environ.get("NORMAN_CODEX_AUTO_CONTINUE_MIN_RESPONSE_SPEED", "careful")
)
AUTO_CONTINUE_MIN_RESPONSE_DETAIL = normalize_response_detail(
    os.environ.get("NORMAN_CODEX_AUTO_CONTINUE_MIN_RESPONSE_DETAIL", "4")
)


def response_speed_rank(speed: Any) -> int:
    return {"fast": 0, "balanced": 1, "careful": 2}.get(
        normalize_response_speed(speed), 1
    )


def auto_continue_reasoning_controls(speed: Any, detail: Any) -> tuple[str, int]:
    normalized_speed = normalize_response_speed(speed)
    if response_speed_rank(normalized_speed) < response_speed_rank(
        AUTO_CONTINUE_MIN_RESPONSE_SPEED
    ):
        normalized_speed = AUTO_CONTINUE_MIN_RESPONSE_SPEED
    normalized_detail = max(
        normalize_response_detail(detail), AUTO_CONTINUE_MIN_RESPONSE_DETAIL
    )
    return normalized_speed, normalized_detail


