def normalize_service_tier(value: Any) -> str:
    clean = str(value or "").strip().lower().replace("_", "-").replace(" ", "-")
    clean = SERVICE_TIER_ALIASES.get(clean, clean)
    if not clean:
        return "auto" if "auto" in SERVICE_TIER_OPTIONS else "default"
    if clean in SERVICE_TIER_OPTIONS:
        return clean
    if clean in {"flex", "priority"} and "default" in SERVICE_TIER_OPTIONS:
        return "default"
    return "auto" if "auto" in SERVICE_TIER_OPTIONS else "default"


DEFAULT_SERVICE_TIER = normalize_service_tier(
    os.environ.get(
        "NORMAN_CODEX_SERVICE_TIER",
        os.environ.get("OPENAI_SERVICE_TIER", "auto"),
    )
)


def service_tier_execution_tier(value: Any) -> str:
    tier = normalize_service_tier(value)
    if tier != "auto":
        return tier
    if CODEX_STANDARD_PROFILE_V2:
        return "default"
    if CODEX_DIRECT_TIERS_ENABLED and "flex" in SERVICE_TIER_OPTIONS:
        return "flex"
    if "default" in SERVICE_TIER_OPTIONS:
        return "default"
    return tier


def service_tier_options_payload() -> list[dict[str, str]]:
    return [
        {
            "key": key,
            "label": str(option["label"]),
            "short_label": str(option["short_label"]),
            "risk": str(option["risk"]),
            "hint": str(option["hint"]),
        }
        for key, option in SERVICE_TIER_OPTIONS.items()
    ]


def service_tier_label(value: Any) -> str:
    tier = normalize_service_tier(value)
    return str(SERVICE_TIER_OPTIONS[tier]["label"])


def service_tier_config_args(value: Any) -> list[str]:
    tier = service_tier_execution_tier(value)
    if tier == "auto":
        return []
    if codex_profile_v2_for_service_tier(tier):
        return []
    codex_tier = (
        "default" if tier in {"bedrock-failover", "bedrock-failover-2"} else tier
    )
    return ["-c", f'service_tier="{codex_tier}"']


def codex_profile_v2_for_service_tier(value: Any) -> str:
    tier = service_tier_execution_tier(value)
    if tier in {"auto", "default"}:
        return CODEX_STANDARD_PROFILE_V2
    if tier == "bedrock-failover":
        return CODEX_BEDROCK_FAILOVER_PROFILE_V2
    if tier == "bedrock-failover-2":
        return CODEX_BEDROCK_FAILOVER2_PROFILE_V2
    if tier == "flex":
        return CODEX_FLEX_PROFILE_V2
    if tier == "priority":
        return CODEX_PRIORITY_PROFILE_V2
    return ""


def codex_bedrock_model_name(value: Any) -> str:
    model = normalize_codex_model_name(value, fallback=MODEL, allow_switchable=True)
    if model.startswith("gpt-"):
        return f"openai.{model}"
    return model


def codex_direct_model_name(value: Any) -> str:
    model = normalize_codex_model_name(value, fallback=MODEL, allow_switchable=True)
    if model.startswith("openai.gpt-"):
        return model.removeprefix("openai.")
    return model


def _codex_configured_model_for_service_tier(tier: str) -> str:
    tier = service_tier_execution_tier(tier)
    if tier in {"auto", "default"}:
        return CODEX_STANDARD_MODEL
    if tier == "bedrock-failover":
        return CODEX_BEDROCK_FAILOVER_MODEL
    if tier == "bedrock-failover-2":
        return CODEX_BEDROCK_FAILOVER2_MODEL
    if tier == "flex":
        return CODEX_FLEX_MODEL
    if tier == "priority":
        return CODEX_PRIORITY_MODEL
    return ""


def codex_model_for_service_tier(value: Any, model: Any = "") -> str:
    tier = service_tier_execution_tier(value)
    requested_model = str(model or "").strip()
    default_model = normalize_runtime_model("codex")
    normalized_model = normalize_runtime_model("codex", requested_model)
    configured_model = _codex_configured_model_for_service_tier(tier)
    if codex_profile_v2_for_service_tier(tier):
        if not requested_model or normalized_model == default_model:
            return codex_bedrock_model_name(configured_model or normalized_model)
        return codex_bedrock_model_name(normalized_model)
    if tier == "flex" and (not requested_model or normalized_model == default_model):
        return codex_direct_model_name(CODEX_FLEX_MODEL)
    if tier == "priority" and (
        not requested_model or normalized_model == default_model
    ):
        return codex_direct_model_name(CODEX_PRIORITY_MODEL)
    return codex_direct_model_name(normalized_model)


def codex_thread_scope_key(value: Any, model: Any = "") -> str:
    tier = service_tier_execution_tier(value)
    resolved_model = codex_model_for_service_tier(tier, model)
    profile = codex_profile_v2_for_service_tier(tier)
    if profile:
        return f"profile-v2:{profile}:model:{resolved_model}"
    return f"direct:model:{resolved_model}"


def codex_profile_v2_config_args(value: Any) -> list[str]:
    profile = codex_profile_v2_for_service_tier(value)
    if not profile:
        return []
    return [CODEX_PROFILE_CONFIG_FLAG, profile]


def codex_aws_profile_for_service_tier(value: Any) -> str:
    tier = service_tier_execution_tier(value)
    if tier == "bedrock-failover":
        return CODEX_BEDROCK_FAILOVER_AWS_PROFILE
    if tier == "bedrock-failover-2":
        return CODEX_BEDROCK_FAILOVER2_AWS_PROFILE
    if tier in {"auto", "default"}:
        return CODEX_STANDARD_AWS_PROFILE
    return ""


def codex_aws_region_for_service_tier(value: Any) -> str:
    tier = service_tier_execution_tier(value)
    if tier == "bedrock-failover":
        return CODEX_BEDROCK_FAILOVER_AWS_REGION
    if tier == "bedrock-failover-2":
        return CODEX_BEDROCK_FAILOVER2_AWS_REGION
    if tier in {"auto", "default"}:
        return CODEX_STANDARD_AWS_REGION
    return ""


def apply_codex_provider_environment(env: dict[str, str], value: Any) -> None:
    tier = service_tier_execution_tier(value)
    profile = codex_profile_v2_for_service_tier(tier)
    if not profile:
        return
    aws_profile = codex_aws_profile_for_service_tier(tier)
    aws_region = codex_aws_region_for_service_tier(tier)
    if aws_profile:
        env["AWS_PROFILE"] = aws_profile
    if aws_region:
        env["AWS_REGION"] = aws_region


def _bounded_prompt_timeout(seconds: int) -> int:
    return max(
        WEB_PROMPT_MIN_TIMEOUT_SECONDS,
        min(WEB_PROMPT_MAX_TIMEOUT_SECONDS, max(0, int(seconds or 0))),
    )


