def normalize_job_budget(value: Any) -> str:
    clean = str(value or "").strip().lower().replace("_", "-")
    clean = JOB_BUDGET_ALIASES.get(clean, clean)
    if clean in JOB_BUDGET_PRESETS:
        return clean
    return "normal"


