def prompt_has_any_marker(prompt: str, markers: tuple[str, ...]) -> bool:
    lower = prompt_core_request(prompt).lower()
    return any(marker in lower for marker in markers)


def prompt_is_quick_status_request(prompt: str) -> bool:
    lower = prompt_core_request(prompt).lower().strip()
    if prompt_has_any_marker(lower, AUTO_TURN_CONTROL_QUICK_MARKERS):
        return True
    return lower.startswith(
        (
            "are we ",
            "did it ",
            "did that ",
            "did you ",
            "is it ",
            "is that ",
            "is this ",
            "was it ",
            "was that ",
        )
    )


def prompt_is_literal_response_request(prompt: Any) -> bool:
    lower = prompt_core_request(str(prompt or "")).lower().strip()
    if not lower:
        return False
    if any(marker in lower for marker in AUTO_TURN_CONTROL_LITERAL_RESPONSE_MARKERS):
        return True
    if "canary" in lower and any(
        token in lower for token in ("reply", "respond", "return", "say", "output")
    ):
        return True
    return lower.startswith(("canary only", "smoke test only"))


def prompt_duration_budget_for_seconds(seconds: int) -> str:
    target = max(0, int(seconds or 0))
    if target <= 60:
        return "1m"
    if target <= 2 * 60:
        return "2m"
    if target <= 5 * 60:
        return "5m"
    if target <= 10 * 60:
        return "10m"
    if target <= 15 * 60:
        return "15m"
    if target <= 20 * 60:
        return "20m"
    if target <= 30 * 60:
        return "30m"
    if target <= 45 * 60:
        return "45m"
    if target <= 60 * 60:
        return "60m"
    if target <= 90 * 60:
        return "90m"
    if target <= 2 * 60 * 60:
        return "deep"
    if target <= 4 * 60 * 60:
        return "high-impact"
    return "overnight"


def prompt_duration_match_is_time_target(core: str, match: re.Match[str]) -> bool:
    before = core[max(0, match.start() - 56) : match.start()]
    surface = match.group(0)
    if AUTO_TURN_CONTROL_REPORTED_DURATION_RE.search(before):
        return False
    return bool(AUTO_TURN_CONTROL_TARGET_DURATION_RE.search(f"{before} {surface}"))


def prompt_has_long_run_approval(prompt: str) -> bool:
    lower = prompt_core_request(prompt).lower()
    return any(marker in lower for marker in AUTO_TURN_CONTROL_LONG_APPROVAL_MARKERS)


def prompt_has_explicit_effort_or_time(prompt: str, time_hint: dict[str, Any]) -> bool:
    core = prompt_core_request(prompt)
    if prompt_has_any_marker(core, AUTO_TURN_CONTROL_EXPLICIT_MARKERS):
        return True
    requested_budget = normalize_job_budget(time_hint.get("requested_job_budget"))
    if requested_budget in {"20m", "30m", "45m", "60m"}:
        return True
    lower = core.lower()
    return any(
        token in lower
        for token in (
            "deep reasoning",
            "extended thought",
            "extra time",
            "spend time",
            "think harder",
            "think longer",
        )
    )


def prompt_time_budget_hint(prompt: str) -> dict[str, Any]:
    core = prompt_core_request(prompt)
    lower = core.lower()
    if not lower:
        return {}

    requested_budget = ""
    requested_seconds = 0
    source = ""
    if "all night" in lower or "overnight" in lower or "work all night" in lower:
        requested_budget = "overnight"
        requested_seconds = job_budget_timeout_seconds(requested_budget)
        source = "overnight language"
    elif "all day" in lower:
        requested_budget = "overnight"
        requested_seconds = job_budget_timeout_seconds(requested_budget)
        source = "all-day language"
    else:
        minute_matches = [
            match
            for match in AUTO_TURN_CONTROL_MINUTE_RE.finditer(core)
            if prompt_duration_match_is_time_target(core, match)
        ]
        hour_matches = [
            match
            for match in AUTO_TURN_CONTROL_HOUR_RE.finditer(core)
            if prompt_duration_match_is_time_target(core, match)
        ]
        if minute_matches:
            minutes = max(1, _coerce_int(minute_matches[-1].group(1)))
            requested_seconds = minutes * 60
            requested_budget = prompt_duration_budget_for_seconds(requested_seconds)
            source = f"{minutes} minute text"
        elif hour_matches:
            hours = max(1, _coerce_int(hour_matches[-1].group(1)))
            requested_seconds = hours * 60 * 60
            requested_budget = prompt_duration_budget_for_seconds(requested_seconds)
            source = f"{hours} hour text"
        elif any(marker in lower for marker in AUTO_TURN_CONTROL_QUICK_TIME_MARKERS):
            requested_budget = "5m"
            requested_seconds = job_budget_timeout_seconds(requested_budget)
            source = "quick-response language"
        elif "take your time" in lower:
            requested_budget = "60m"
            requested_seconds = job_budget_timeout_seconds(requested_budget)
            source = "take-your-time language"

    if not requested_budget:
        return {}
    requested_budget = normalize_job_budget(requested_budget)
    requested_seconds = requested_seconds or job_budget_timeout_seconds(
        requested_budget
    )
    approval_required = requested_budget in {"deep", "high-impact", "overnight"}
    approval_granted = prompt_has_long_run_approval(core)
    return {
        "requested_job_budget": requested_budget,
        "requested_seconds": requested_seconds,
        "requested_label": job_budget_label(requested_budget),
        "source": source,
        "approval_required": bool(approval_required),
        "approval_granted": bool(approval_granted),
    }


def turn_control_steering_chips(
    workload: str, time_hint: dict[str, Any], approval_pending: bool
) -> list[str]:
    if approval_pending:
        return ["Estimate first", "Ask approval", "No long run yet"]
    if workload == "literal_response":
        return ["Answer exactly", "No tools", "Stop"]
    if workload == "status":
        return ["Answer now", "One check", "No broad audit"]
    if workload == "quick_decision":
        return ["Decide", "Blocker if needed", "No drift"]
    if workload in {"implementation", "approval_boundary"}:
        return ["Small slice", "Focused tests", "Checkpoint before impact"]
    if workload == "long_work" or normalize_job_budget(
        time_hint.get("requested_job_budget")
    ) in {"deep", "high-impact", "overnight"}:
        return ["Cost watch", "Checkpoint", "Narrow scope"]
    return ["Stay scoped", "Return evidence", "Escalate if broad"]


def classify_prompt_workload(
    prompt: str, attachments: list[dict[str, Any]] | None = None
) -> str:
    core = prompt_core_request(prompt)
    lower = core.lower()
    attachment_count = len(normalize_attachments(attachments or []))
    time_hint = prompt_time_budget_hint(core)
    if prompt_has_explicit_effort_or_time(core, time_hint):
        return "explicit"
    if time_hint.get("approval_required") and not time_hint.get("approval_granted"):
        return "long_run_approval"
    if normalize_job_budget(time_hint.get("requested_job_budget")) in {
        "deep",
        "high-impact",
        "overnight",
    }:
        return "long_work"
    if prompt_has_any_marker(core, AUTO_TURN_CONTROL_LONG_MARKERS):
        return "long_work"
    if prompt_is_literal_response_request(core):
        return "literal_response"
    if prompt_is_quick_status_request(core):
        return "status"
    if route_receipt_requires_operator_approval(core):
        return "approval_boundary"
    if prompt_has_any_marker(core, AUTO_TURN_CONTROL_IMPLEMENT_MARKERS):
        return "implementation"
    if prompt_has_any_marker(core, AUTO_TURN_CONTROL_VERIFY_MARKERS):
        return "verification"
    requested_action = route_receipt_requested_action(core)
    if requested_action == "status":
        return "status"
    if requested_action in {"proceed_or_next", "undo_or_back"}:
        return "quick_decision"
    if any(token in lower for token in ("explain", "why", "how should", "how do")):
        return "analysis"
    if attachment_count:
        return "verification"
    return "standard"


def turn_control_operator_intent_class(prompt: Any) -> str:
    clean = prompt_core_request(str(prompt or ""))
    lower = clean.lower()
    requested_action = route_receipt_requested_action(clean)
    if prompt_is_literal_response_request(clean):
        return "literal_response"
    if route_receipt_requires_operator_approval(clean):
        if any(token in lower for token in ("undo", "rollback", "revert", "reopen")):
            return "undo_gate"
        if any(token in lower for token in ("deploy", "restart", "systemctl", "caddy")):
            return "deploy_gate"
        return "approval_gate"
    if requested_action == "status":
        return "status"
    if requested_action == "proceed_or_next":
        if "continue" in lower or "resume" in lower:
            return "continue"
        if (
            "what next" in lower
            or "what's next" in lower
            or "whats next" in lower
            or "wahts next" in lower
        ):
            return "what_next"
        return "proceed"
    if requested_action == "undo_or_back":
        return "undo_gate"
    if any(token in lower for token in ("debug", "why did", "what failed", "failure")):
        return "debug"
    if any(token in lower for token in AUTO_TURN_CONTROL_IMPLEMENT_MARKERS):
        return "bounded_edit"
    if requested_action == "benchmark_or_optimizer":
        return "benchmark"
    return "operator_prompt"


def turn_control_mutation_risk(prompt: Any, *extra_text: Any) -> str:
    text = "\n".join([str(prompt or ""), *(str(item or "") for item in extra_text)])
    if prompt_is_literal_response_request(text):
        return "none"
    if prompt_is_route_status_diagnostic(text):
        return "none"
    lower = f" {prompt_core_request(text).lower()} "
    secret_marker = re.search(
        r"\b(?:credential|credentials|purse|secret|secrets|token)\b"
        r"|\b(?:api|access|refresh|client|signing|webhook|private|ssh)\s+keys?\b",
        lower,
    )
    billing_marker = re.search(r"\bbilling\b", lower)
    billing_status_label = re.search(
        r"\bbilling\s*=\s*"
        r"(?:healthy|unhealthy|ok|down|up|timeout|timed[- ]?out|"
        r"degraded|failed|failing|offline|online)\b",
        lower,
    )
    if secret_marker or (billing_marker and not billing_status_label):
        return "billing_secret"
    if any(
        token in lower
        for token in (
            " aws",
            " bedrock",
            " caddy",
            " cloud",
            " deploy",
            " dns",
            " production",
            " restart",
            " systemctl",
            " webrestart",
        )
    ):
        return "deploy_restart"
    if any(
        token in lower
        for token in (
            " ack ",
            " apply ",
            " bbs ",
            " block ",
            " close ",
            " done ",
            " firewall",
            " reopen",
            " revert",
            " rollback",
            " vendor",
        )
    ):
        return "external_write"
    if any(
        token in lower
        for token in (
            " add ",
            " apply_patch",
            " change ",
            " commit",
            " edit ",
            " file",
            " fix ",
            " patch",
            " write ",
        )
    ):
        return "local_file"
    return "none"


def turn_control_authority_class(
    prompt: Any,
    *,
    selected_model_tier: str = "",
    mutation_risk: str = "",
    requested_action: str = "",
) -> str:
    if route_receipt_requires_operator_approval(prompt):
        return "approval_required"
    if "5_5" in str(selected_model_tier or ""):
        return "final_authority"
    risk = str(mutation_risk or "none")
    if risk in {"deploy_restart", "external_write", "billing_secret"}:
        return "approval_required"
    if risk == "local_file":
        return "draft"
    if requested_action == "benchmark_or_optimizer":
        return "dry_run"
    return "read_only"


def build_turn_control_envelope(
    *,
    prompt: str,
    attachments: list[dict[str, Any]] | None = None,
    turn_control: dict[str, Any] | None = None,
    runtime: str = "",
    model: str = "",
    service_tier: str = "",
    job_budget: str = "",
    speed: str = "",
    detail: int = 0,
    optimization_mode: str = "",
    requested_model: str = "",
    requested_service_tier: str = "",
) -> dict[str, Any]:
    normalized_runtime = normalize_runtime(runtime)
    normalized_model = normalize_runtime_model(normalized_runtime, model)
    normalized_tier = normalize_service_tier(service_tier)
    requested = normalize_runtime_model(
        normalized_runtime, requested_model or normalized_model
    )
    requested_tier = normalize_service_tier(requested_service_tier or normalized_tier)
    normalized_attachments = normalize_attachments(attachments or [])
    requested_action = route_receipt_requested_action(prompt)
    selected_model_tier = route_receipt_model_tier(normalized_model, normalized_tier)
    mutation_risk = turn_control_mutation_risk(prompt)
    intent_class = turn_control_operator_intent_class(prompt)
    authority_class = turn_control_authority_class(
        prompt,
        selected_model_tier=selected_model_tier,
        mutation_risk=mutation_risk,
        requested_action=requested_action,
    )
    control = dict(turn_control or {})
    max_decisions = max(
        1,
        _coerce_int(control.get("decision_budget_max"))
        or (3 if intent_class == "status" else 6),
    )
    max_retries = 0 if intent_class == "status" else 1
    allowed_actions = ["read_state", "inspect_local_evidence"]
    blocked_actions: list[str] = []
    if authority_class in {"approval_required", "final_authority"}:
        blocked_actions.extend(["external_write_without_approval", "deploy_restart"])
    if mutation_risk == "none":
        allowed_actions.append("answer_from_current_state")
    elif mutation_risk == "local_file":
        allowed_actions.extend(["draft_patch", "run_focused_tests"])
        blocked_actions.append("external_write")
    return {
        "schema": TURN_CONTROL_ENVELOPE_SCHEMA,
        "route_policy_version": ROUTE_RECEIPT_POLICY_VERSION,
        "prompt_id": route_receipt_prompt_id(prompt),
        "operator_request": summarize_text(prompt_core_request(prompt), 360),
        "owner_tui": ROUTE_RECEIPT_OWNER_TUI,
        "requested_action": requested_action,
        "operator_intent_class": intent_class,
        "authority_class": authority_class,
        "mutation_risk": mutation_risk,
        "requested_model": requested,
        "effective_model": normalized_model,
        "requested_service_tier": requested_tier,
        "effective_service_tier": normalized_tier,
        "runtime": normalized_runtime,
        "reasoning_effort": response_reasoning_effort(speed),
        "workload": str(control.get("workload") or classify_prompt_workload(prompt)),
        "allowed_actions": allowed_actions,
        "blocked_actions": blocked_actions,
        "budget": {
            "max_wall_seconds": job_budget_timeout_seconds(job_budget),
            "max_model_calls": 1,
            "max_retries": max_retries,
            "max_decisions": max_decisions,
        },
        "checkpoint_rule": (
            "write route receipt after classification, after tool use, and before final answer"
        ),
        "stop_condition": "validator passes or explicit blocker is found",
        "attachment_count": len(normalized_attachments),
        "steering_chips": [
            str(item).strip()
            for item in control.get("steering_chips") or []
            if str(item).strip()
        ][:4],
    }


