def turn_control_recommendation(
    prompt: str,
    attachments: list[dict[str, Any]] | None = None,
    *,
    speed: Any = "",
    detail: Any = 0,
    job_budget: Any = "",
    optimization_mode: Any = "",
) -> dict[str, Any]:
    normalized_speed = normalize_response_speed(speed)
    normalized_detail = normalize_response_detail(detail)
    normalized_budget = normalize_job_budget(job_budget)
    normalized_mode = normalize_optimization_mode(optimization_mode)
    workload = classify_prompt_workload(prompt, attachments)
    profile = AUTO_TURN_CONTROL_PROFILES[workload]
    time_hint = prompt_time_budget_hint(prompt)
    hinted_budget = normalize_job_budget(time_hint.get("requested_job_budget"))
    time_approval_pending = bool(
        time_hint.get("approval_required") and not time_hint.get("approval_granted")
    )
    auto_enabled = normalized_mode == "auto"
    explicit = workload == "explicit"
    recommended_speed = (
        normalize_response_speed(profile["speed"])
        if profile.get("speed")
        else normalized_speed
    )
    recommended_detail = (
        normalize_response_detail(profile["detail"])
        if _coerce_int(profile.get("detail"))
        else normalized_detail
    )
    recommended_budget = (
        normalize_job_budget(profile["job_budget"])
        if profile.get("job_budget")
        else normalized_budget
    )
    if hinted_budget != "normal" or time_hint:
        recommended_budget = (
            normalize_job_budget(profile["job_budget"])
            if time_approval_pending
            else hinted_budget
        )
    apply_recommendation = auto_enabled and not explicit
    effective_speed = recommended_speed if apply_recommendation else normalized_speed
    effective_detail = recommended_detail if apply_recommendation else normalized_detail
    effective_budget = (
        recommended_budget
        if auto_enabled and (apply_recommendation or time_hint)
        else normalized_budget
    )
    if (
        auto_enabled
        and apply_recommendation
        and not time_hint
        and workload in {"standard", "analysis", "verification"}
    ):
        effective_budget = normalized_budget
    decision_min = _coerce_int(profile.get("decision_budget_min"))
    decision_max = _coerce_int(profile.get("decision_budget_max"))
    if decision_max <= 0:
        target_seconds = job_budget_timeout_seconds(effective_budget)
        decision_min = 2 if target_seconds <= 10 * 60 else 6
        decision_max = 4 if target_seconds <= 10 * 60 else 12
    steering_chips = turn_control_steering_chips(
        workload, time_hint, time_approval_pending
    )
    return {
        "schema": AUTO_TURN_CONTROL_SCHEMA,
        "workload": workload,
        "optimization_mode": normalized_mode,
        "auto_applied": bool(apply_recommendation),
        "explicit_depth_or_time": bool(explicit),
        "selected_speed": normalized_speed,
        "selected_detail": normalized_detail,
        "selected_job_budget": normalized_budget,
        "recommended_speed": recommended_speed,
        "recommended_detail": recommended_detail,
        "recommended_job_budget": recommended_budget,
        "effective_speed": effective_speed,
        "effective_detail": effective_detail,
        "effective_job_budget": effective_budget,
        "effective_reasoning_effort": response_reasoning_effort(effective_speed),
        "text_time_hint": time_hint,
        "requested_job_budget": hinted_budget if time_hint else "",
        "requested_time_label": str(time_hint.get("requested_label") or ""),
        "time_approval_required": bool(time_approval_pending),
        "time_approval_granted": bool(time_hint.get("approval_granted")),
        "decision_budget_min": decision_min,
        "decision_budget_max": max(decision_min, decision_max),
        "decisions_per_hour": _coerce_int(profile.get("decisions_per_hour")),
        "steering_chips": steering_chips,
        "summary": str(profile.get("summary") or ""),
    }


def preserve_turn_controls_for_relay(
    recommendation: dict[str, Any],
    *,
    speed: Any,
    detail: Any,
    job_budget: Any,
) -> dict[str, Any]:
    preserved = dict(recommendation or {})
    effective_speed = normalize_response_speed(speed)
    effective_detail = normalize_response_detail(detail)
    effective_budget = normalize_job_budget(job_budget)
    preserved.update(
        {
            "auto_applied": False,
            "relay_callback_preserved": True,
            "effective_speed": effective_speed,
            "effective_detail": effective_detail,
            "effective_job_budget": effective_budget,
            "effective_reasoning_effort": response_reasoning_effort(effective_speed),
        }
    )
    return preserved


def turn_control_prompt_guidance(recommendation: dict[str, Any]) -> str:
    if not isinstance(recommendation, dict):
        return ""
    workload = str(recommendation.get("workload") or "standard")
    summary = str(recommendation.get("summary") or "").strip()
    decision_min = _coerce_int(recommendation.get("decision_budget_min"))
    decision_max = _coerce_int(recommendation.get("decision_budget_max"))
    decisions_per_hour = _coerce_int(recommendation.get("decisions_per_hour"))
    parts = [
        "- Auto scope classifier: "
        f"{workload}; {summary or 'Use selected controls and keep scope explicit.'}"
    ]
    if recommendation.get("auto_applied"):
        parts.append(
            "- Auto-applied controls: "
            f"reasoning={response_speed_label(recommendation.get('effective_speed'))}/"
            f"{recommendation.get('effective_reasoning_effort')}, "
            f"reply={response_detail_label(recommendation.get('effective_detail'))}, "
            f"time={job_budget_label(recommendation.get('effective_job_budget'))}."
        )
    time_hint = recommendation.get("text_time_hint")
    if isinstance(time_hint, dict) and time_hint:
        requested_label = str(time_hint.get("requested_label") or "").strip()
        source = str(time_hint.get("source") or "prompt text").strip()
        parts.append(
            "- Text time target detected: "
            f"{requested_label or job_budget_label(recommendation.get('requested_job_budget'))} from {source}; "
            f"effective target is {job_budget_label(recommendation.get('effective_job_budget'))}."
        )
    if recommendation.get("time_approval_required"):
        parts.append(
            "- Long-run approval gate: do not start the requested hours-long run "
            "in this turn. Give a compact estimate/runbook, name the cost/risk, "
            "and ask for explicit approval before committing the long window."
        )
    elif recommendation.get("explicit_depth_or_time"):
        parts.append(
            "- Explicit depth/time request detected: preserve the selected settings, "
            "but still checkpoint at the timing boundary."
        )
    elif recommendation.get("relay_callback_preserved"):
        parts.append(
            "- Relay callback detected: preserve the upstream routed settings; do not "
            "rewrite reasoning, reply depth, or budget from the prompt text."
        )
    if decision_min or decision_max:
        parts.append(
            "- Decision budget: "
            f"aim for {decision_min}-{max(decision_min, decision_max)} material "
            "planning/tool/escalation decisions this turn"
            + (
                f" (about {decisions_per_hour}/hour at this scope)."
                if decisions_per_hour
                else "."
            )
        )
    chips = [
        str(item).strip()
        for item in recommendation.get("steering_chips") or []
        if str(item).strip()
    ]
    if chips:
        parts.append(
            "- Visible steering hints: "
            + ", ".join(chips[:4])
            + ". Treat these as soft operator affordances, not new requirements."
        )
    parts.append(
        "- Escalation rule: if a quick/status turn discovers implementation, "
        "deployment, broad debugging, or approval-boundary work, return a checkpoint "
        "or explicitly expand the scope instead of silently spending xhigh."
    )
    return "\n".join(parts)


def optimization_mode_options_payload() -> list[dict[str, str]]:
    return [
        {
            "key": key,
            "label": str(option["label"]),
            "short_label": str(option["short_label"]),
            "risk": str(option["risk"]),
            "hint": str(option["hint"]),
        }
        for key, option in OPTIMIZATION_MODE_OPTIONS.items()
    ]


def optimization_mode_label(value: Any) -> str:
    mode = normalize_optimization_mode(value)
    return str(OPTIMIZATION_MODE_OPTIONS[mode]["label"])


def optimization_mode_prompt_guidance(value: Any) -> str:
    mode = normalize_optimization_mode(value)
    if mode == "raw":
        return (
            "Raw benchmark mode. Keep approval, safety, and timebox guardrails, "
            "but do not rely on optional context-pack, cache-saving, or hybrid "
            "shortcut optimizations unless the operator asks for them explicitly."
        )
    return (
        "Auto optimizer mode. Use the cheapest reliable path: Bedrock profile if "
        "configured, otherwise Flex when available; reuse cached/local evidence, "
        "compact large context before model calls, and spend paid/tool work only "
        "after cheap checks identify the smallest useful slice."
    )


def job_budget_timeout_seconds(value: Any) -> int:
    return int(JOB_BUDGET_PRESETS[normalize_job_budget(value)]["seconds"])


def bedrock_converse_tool_call_budget(
    job_budget: Any = "", timeout_seconds: Any = None
) -> int:
    if BEDROCK_CONVERSE_MAX_TOOL_CALLS > 0:
        return min(
            BEDROCK_CONVERSE_MAX_TOOL_CALLS,
            BEDROCK_CONVERSE_MAX_TOOL_CALLS_CEILING,
        )
    normalized_budget = normalize_job_budget(job_budget)
    target_seconds = job_budget_timeout_seconds(normalized_budget)
    effective_seconds = target_seconds
    if effective_seconds <= 2 * 60:
        budget = 8
    elif effective_seconds <= 5 * 60:
        budget = 12
    elif effective_seconds <= 10 * 60:
        budget = 18
    elif effective_seconds <= 20 * 60:
        budget = 32
    elif effective_seconds <= 30 * 60:
        budget = 48
    elif effective_seconds <= 60 * 60:
        budget = 64
    elif effective_seconds <= 90 * 60:
        budget = 80
    elif effective_seconds <= 2 * 60 * 60:
        budget = 96
    else:
        budget = 128
    return max(1, min(budget, BEDROCK_CONVERSE_MAX_TOOL_CALLS_CEILING))


def job_budget_guardrail_overage_seconds(target_seconds: int) -> int:
    target = max(0, int(target_seconds or 0))
    if target <= 2 * 60:
        return 60
    if target <= 10 * 60:
        return 5 * 60
    if target <= 30 * 60:
        return 10 * 60
    if target <= 60 * 60:
        return 20 * 60
    if target <= 2 * 60 * 60:
        return 30 * 60
    return 60 * 60


def job_budget_guardrail_seconds(value: Any) -> int:
    target = job_budget_timeout_seconds(value)
    return _bounded_prompt_timeout(
        target + job_budget_guardrail_overage_seconds(target)
    )


def normalize_job_timeout_seconds(value: Any, budget: Any = "") -> int:
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        parsed = 0
    if parsed > 0:
        if budget:
            target = job_budget_timeout_seconds(budget)
            if parsed <= target:
                return job_budget_guardrail_seconds(budget)
        return _bounded_prompt_timeout(parsed)
    return job_budget_guardrail_seconds(budget or DEFAULT_JOB_BUDGET)


def local_llm_foreground_timeout_seconds(
    timeout_seconds: int | None,
    job_budget: Any = "",
) -> int:
    normalized_budget = normalize_job_budget(job_budget)
    target = job_budget_timeout_seconds(normalized_budget)
    guardrail = normalize_job_timeout_seconds(timeout_seconds, normalized_budget)
    cap = LOCAL_LLM_FOREGROUND_TIMEOUT_SECONDS
    if target <= 2 * 60:
        cap = min(cap, LOCAL_LLM_SHORT_TIMEOUT_SECONDS)
    elif target <= 5 * 60:
        cap = min(cap, max(LOCAL_LLM_SHORT_TIMEOUT_SECONDS, 180))
    return max(5, min(LOCAL_LLM_CALL_TIMEOUT_SECONDS, guardrail, cap))


def local_llm_num_ctx_for_budget(job_budget: Any = "") -> int:
    target = job_budget_timeout_seconds(normalize_job_budget(job_budget))
    if target <= 2 * 60:
        return max(512, min(LOCAL_LLM_NUM_CTX, LOCAL_LLM_SHORT_NUM_CTX))
    if target <= 5 * 60:
        return max(512, min(LOCAL_LLM_NUM_CTX, max(LOCAL_LLM_SHORT_NUM_CTX, 8192)))
    return max(512, LOCAL_LLM_NUM_CTX)


def local_llm_max_output_tokens_for_budget(job_budget: Any = "") -> int:
    target = job_budget_timeout_seconds(normalize_job_budget(job_budget))
    if target <= 2 * 60:
        return max(
            64, min(LOCAL_LLM_MAX_OUTPUT_TOKENS, LOCAL_LLM_QUICK_MAX_OUTPUT_TOKENS)
        )
    if target <= 5 * 60:
        return max(
            128, min(LOCAL_LLM_MAX_OUTPUT_TOKENS, LOCAL_LLM_SHORT_MAX_OUTPUT_TOKENS)
        )
    return max(128, LOCAL_LLM_MAX_OUTPUT_TOKENS)


def job_budget_label(value: Any) -> str:
    return str(JOB_BUDGET_PRESETS[normalize_job_budget(value)]["label"])


def job_budget_mode(value: Any) -> str:
    preset = JOB_BUDGET_PRESETS[normalize_job_budget(value)]
    return str(preset.get("mode") or "work-window")


def job_budget_mode_guidance(value: Any) -> str:
    mode = job_budget_mode(value)
    if mode == "quick-reply":
        return (
            "Quick reply/checkpoint. Do not start long polling loops or broad research; "
            "answer with current evidence, one fast check, or a clear blocker."
        )
    if mode == "quick-slice":
        return (
            "Quick slice. Complete one concrete pass and return; park deeper follow-up "
            "work instead of stretching the turn."
        )
    if mode == "focused-slice":
        return (
            "Focused slice. Inspect the smallest useful context, do the requested work, "
            "and verify the highest-risk point."
        )
    if mode == "focused-work":
        return (
            "Focused work window. Use the extra time for implementation, comparison, "
            "or verification, but avoid unrelated branches."
        )
    if mode in {"work-window", "normal-work", "deep-work"}:
        return (
            "Work window. Do not stop at the first plausible answer if useful tests, "
            "edge cases, benchmarks, or cost accounting remain; if truly done early, "
            "state why more work would be low-value or unsafe."
        )
    if mode == "high-impact":
        return (
            "High-impact work window. Spend the time on evidence, reversible planning, "
            "and guardrails; stop before destructive or externally visible actions."
        )
    if mode == "overnight":
        return (
            "Long unattended window. Keep checkpointing, avoid runaway polling, and "
            "stop at approval boundaries or when the remaining work becomes low-value."
        )
    return "Use the selected time target as a scope contract."


def prompt_duration_label(seconds: int) -> str:
    total = max(0, int(seconds or 0))
    if total >= 3600 and total % 3600 == 0:
        hours = total // 3600
        return f"{hours} hour" if hours == 1 else f"{hours} hours"
    if total >= 60 and total % 60 == 0:
        minutes = total // 60
        return f"{minutes} minute" if minutes == 1 else f"{minutes} minutes"
    return f"{total} second" if total == 1 else f"{total} seconds"


def time_target_wrap_up_window_seconds(target_seconds: int) -> int:
    target = max(0, int(target_seconds or 0))
    if target <= 0:
        return 0
    if target <= 2 * 60:
        window = 15
    elif target <= 5 * 60:
        window = 45
    elif target <= 15 * 60:
        window = 2 * 60
    elif target <= 30 * 60:
        window = 5 * 60
    elif target <= 60 * 60:
        window = 10 * 60
    elif target <= 2 * 60 * 60:
        window = 15 * 60
    else:
        window = 30 * 60
    return max(5, min(window, max(5, target // 2)))


def time_target_stop_new_work_after_seconds(target_seconds: int) -> int:
    target = max(0, int(target_seconds or 0))
    if target <= 0:
        return 0
    wrap_window = time_target_wrap_up_window_seconds(target)
    stop_window = min(target, max(wrap_window * 2, target // 4))
    return max(0, target - stop_window)


def time_target_plan(
    job_budget: Any,
    timeout_seconds: Any = None,
    *,
    started_at: int = 0,
    now: int = 0,
    pending: bool = False,
) -> dict[str, Any]:
    normalized_budget = normalize_job_budget(job_budget)
    target_seconds = job_budget_timeout_seconds(normalized_budget)
    guardrail_seconds = normalize_job_timeout_seconds(
        timeout_seconds, normalized_budget
    )
    wrap_window_seconds = time_target_wrap_up_window_seconds(target_seconds)
    wrap_up_after_seconds = max(0, target_seconds - wrap_window_seconds)
    stop_new_work_after_seconds = time_target_stop_new_work_after_seconds(
        target_seconds
    )
    observed_now = _coerce_int(now) or now_ts()
    started = _coerce_int(started_at)
    elapsed_seconds = max(0, observed_now - started) if started > 0 else 0
    target_remaining_seconds = max(0, target_seconds - elapsed_seconds)
    guardrail_remaining_seconds = max(0, guardrail_seconds - elapsed_seconds)
    progress_percent = (
        min(100, int((elapsed_seconds / max(target_seconds, 1)) * 100))
        if pending or elapsed_seconds > 0
        else 0
    )

    if not pending and elapsed_seconds <= 0:
        phase = "idle"
        phase_label = "Window"
    elif elapsed_seconds >= guardrail_seconds:
        phase = "expired"
        phase_label = "Expired"
    elif elapsed_seconds >= target_seconds:
        phase = "over_target"
        phase_label = "Over target"
    elif elapsed_seconds >= wrap_up_after_seconds:
        phase = "wrap_up"
        phase_label = "Wrap up"
    elif elapsed_seconds >= stop_new_work_after_seconds:
        phase = "narrow"
        phase_label = "Narrow"
    else:
        phase = "work"
        phase_label = "Work"

    if phase in {"over_target", "expired"}:
        value = f"{format_duration_label(guardrail_remaining_seconds)} guardrail"
        meta = f"{phase_label} · target passed"
        next_action = "Return a concise checkpoint or final answer now."
    elif pending or elapsed_seconds > 0:
        value = f"{format_duration_label(target_remaining_seconds)} target"
        meta = f"{phase_label} · guardrail {format_duration_label(guardrail_remaining_seconds)}"
        if phase == "wrap_up":
            next_action = "Stop broad work and write the result or resume checkpoint."
        elif phase == "narrow":
            next_action = "Stop opening new branches; finish the highest-value path."
        else:
            next_action = "Keep work scoped to the selected target."
    else:
        value = format_duration_label(target_seconds)
        meta = f"guardrail {format_duration_label(guardrail_seconds)}"
        next_action = "Use the budget as a scope contract before starting."

    title = (
        f"Time target {job_budget_label(normalized_budget)} · "
        f"target {format_duration_label(target_seconds)} · "
        f"stop new work at {format_duration_label(stop_new_work_after_seconds)} elapsed · "
        f"wrap up at {format_duration_label(wrap_up_after_seconds)} elapsed · "
        f"hard guardrail {format_duration_label(guardrail_seconds)} · "
        f"phase {phase_label} · {next_action}"
    )
    return {
        "schema": "norman.tui.time_target.v1",
        "job_budget": normalized_budget,
        "label": job_budget_label(normalized_budget),
        "target_seconds": target_seconds,
        "guardrail_seconds": guardrail_seconds,
        "guardrail_overage_seconds": max(0, guardrail_seconds - target_seconds),
        "stop_new_work_after_seconds": stop_new_work_after_seconds,
        "stop_new_work_remaining_seconds": max(
            0, stop_new_work_after_seconds - elapsed_seconds
        ),
        "wrap_up_after_seconds": wrap_up_after_seconds,
        "wrap_up_window_seconds": wrap_window_seconds,
        "wrap_up_remaining_seconds": max(0, wrap_up_after_seconds - elapsed_seconds),
        "elapsed_seconds": elapsed_seconds,
        "target_remaining_seconds": target_remaining_seconds,
        "guardrail_remaining_seconds": guardrail_remaining_seconds,
        "progress_percent": progress_percent,
        "phase": phase,
        "phase_label": phase_label,
        "value": value,
        "meta": meta,
        "next_action": next_action,
        "title": title,
        "pending": bool(pending),
        "hidden": not bool(pending),
    }


def timing_target_plan_guidance(job_budget: Any, timeout_seconds: Any = None) -> str:
    plan = time_target_plan(job_budget, timeout_seconds)
    return (
        "- Time plan: work backwards from the target. "
        f"Stop opening new branches by {format_duration_label(plan['stop_new_work_after_seconds'])} elapsed; "
        f"start wrap-up by {format_duration_label(plan['wrap_up_after_seconds'])} elapsed; "
        f"target close-up is {format_duration_label(plan['target_seconds'])}; "
        f"hard guardrail is {format_duration_label(plan['guardrail_seconds'])}."
    )


DEADLINE_WARNING_REMAINING_SECONDS = (15 * 60, 5 * 60, 60)


def deadline_warning_checkpoints(
    target_seconds: int, guardrail_seconds: int
) -> list[dict[str, Any]]:
    target = max(0, int(target_seconds or 0))
    guardrail = max(0, int(guardrail_seconds or 0))
    if guardrail <= 0:
        return []
    checkpoints_by_remaining: dict[int, dict[str, Any]] = {}

    def add_checkpoint(remaining_seconds: int, kind: str) -> None:
        remaining = max(0, int(remaining_seconds or 0))
        elapsed = guardrail - remaining
        if remaining <= 0 or elapsed <= 0:
            return
        existing = checkpoints_by_remaining.get(remaining)
        if existing:
            kinds = set(str(existing.get("kind") or "").split("+"))
            kinds.add(kind)
            existing["kind"] = "+".join(sorted(item for item in kinds if item))
            return
        checkpoints_by_remaining[remaining] = {
            "kind": kind,
            "elapsed_seconds": elapsed,
            "remaining_seconds": remaining,
            "guardrail_seconds": guardrail,
            "target_seconds": target,
        }

    for remaining in DEADLINE_WARNING_REMAINING_SECONDS:
        add_checkpoint(remaining, "remaining")
    if target > 0 and target < guardrail:
        add_checkpoint(guardrail - target, "target")
    return sorted(
        checkpoints_by_remaining.values(),
        key=lambda item: int(item.get("elapsed_seconds") or 0),
    )


def deadline_warning_prompt_guidance(
    target_seconds: int, guardrail_seconds: int
) -> str:
    checkpoints = deadline_warning_checkpoints(target_seconds, guardrail_seconds)
    warning_labels = []
    for item in checkpoints:
        kind = str(item.get("kind") or "")
        remaining = _coerce_int(item.get("remaining_seconds"))
        if "target" in kind:
            warning_labels.append(
                f"target mark ({prompt_duration_label(remaining)} before guardrail)"
            )
        elif remaining > 0:
            warning_labels.append(
                f"{prompt_duration_label(remaining)} before guardrail"
            )
    if not warning_labels:
        return (
            "treat the stated target as the close-up point and finish or checkpoint "
            "before the hard guardrail."
        )
    return (
        "expect close-up warnings at "
        + ", ".join(warning_labels)
        + "; use them to finish, summarize current state, or leave a precise resume checkpoint."
    )


def deadline_warning_status_message(
    warning: dict[str, Any], *, agent_name: str = ""
) -> str:
    remaining = _coerce_int(warning.get("remaining_seconds"))
    elapsed = _coerce_int(warning.get("elapsed_seconds"))
    kind = str(warning.get("kind") or "")
    remaining_label = prompt_duration_label(remaining)
    elapsed_label = prompt_duration_label(elapsed)
    name = str(agent_name or AGENT_NAME or "This TUI").strip()
    if "target" in kind:
        return (
            f"Time target reached after {elapsed_label}. {name} should close up, "
            f"checkpoint, or finish; hard guardrail in {remaining_label}."
        )
    if remaining <= 60:
        return (
            f"Final time warning: hard guardrail in {remaining_label}. {name} "
            "should stop broad work and return a concise checkpoint now."
        )
    return (
        f"Time warning: hard guardrail in {remaining_label}. {name} should close "
        "up, checkpoint, or finish before timeout."
    )


def timing_target_prompt_guidance(job_budget: Any, timeout_seconds: Any = None) -> str:
    normalized_budget = normalize_job_budget(job_budget)
    target_seconds = job_budget_timeout_seconds(normalized_budget)
    normalized_timeout = normalize_job_timeout_seconds(
        timeout_seconds, normalized_budget
    )
    target_label = job_budget_label(normalized_budget)
    target_duration_label = prompt_duration_label(target_seconds)
    guardrail_duration_label = prompt_duration_label(normalized_timeout)
    mode_guidance = job_budget_mode_guidance(normalized_budget)
    lines = [
        "Also honor the operator timing target for this turn.",
        f"- Time target: {target_label} ({target_duration_label}).",
        f"- Local guardrail: this TUI may terminate the turn after {guardrail_duration_label}.",
        f"- Time contract: {mode_guidance}",
        timing_target_plan_guidance(normalized_budget, normalized_timeout),
        "- Use that as scope control: for short targets, return the fastest useful result or next concrete slice; for longer targets, keep doing valuable work until the target, the work is genuinely done, or an approval/blocker boundary appears.",
        "- Time awareness: if the task looks likely to exceed the target, produce a concise checkpoint with elapsed/remaining work and the next concrete resume step instead of running blindly into the guardrail.",
        "- At the stop-new-work mark, narrow scope: finish the current branch, verify the highest-value result, and park lower-value work for a follow-up.",
        "- At the wrap-up mark, return the final result if ready; otherwise return a compact checkpoint with done/remaining/risks/next action.",
        f"- Close-up warnings: {deadline_warning_prompt_guidance(target_seconds, normalized_timeout)}",
        "- Early finish rule: if a long target is selected and the main task appears done early, use remaining useful time for tests, replay, edge cases, cost accounting, or documentation. Do not idle-poll just to fill time; finish early only with evidence that more work would be wasteful, unsafe, or out of scope.",
    ]
    if normalized_timeout >= 60 * 60:
        lines.extend(
            [
                "- Long-run mode: do not stop at the first plausible answer; keep researching, testing, and narrowing the answer until the target is genuinely handled or the guardrail is close.",
                "- Cost notice: long runs can be materially expensive. Stay efficient, avoid repeating setup, and leave concise checkpoints so progress is auditable.",
                "- Approval boundary: before any final destructive, irreversible, externally visible, or high-impact action, stop at the approval point and state exactly what would be done next.",
            ]
        )
    elif normalized_timeout >= 30 * 60:
        lines.extend(
            [
                "- Extended mode: use the extra time for verification or a second evidence pass, not for broad unrelated exploration.",
                "- Cost notice: this is a longer-than-normal turn. Keep the work focused and summarize concrete progress.",
            ]
        )
    return "\n".join(lines)


def job_budget_options_payload() -> list[dict[str, Any]]:
    payload = []
    for key, preset in JOB_BUDGET_PRESETS.items():
        target_seconds = int(preset["seconds"])
        payload.append(
            {
                "key": key,
                "label": str(preset["label"]),
                "seconds": target_seconds,
                "target_seconds": target_seconds,
                "guardrail_seconds": job_budget_guardrail_seconds(key),
                "stop_new_work_after_seconds": time_target_stop_new_work_after_seconds(
                    target_seconds
                ),
                "wrap_up_after_seconds": max(
                    0,
                    target_seconds - time_target_wrap_up_window_seconds(target_seconds),
                ),
                "mode": str(preset.get("mode") or job_budget_mode(key)),
                "hint": str(preset["hint"]),
            }
        )
    return payload


def normalize_runtime(value: Any) -> str:
    clean = str(value or "").strip().lower().replace("_", "-").replace(" ", "-")
    clean = RUNTIME_ALIASES.get(clean, clean)
    if clean in RUNTIME_REGISTRY:
        return clean
    return DEFAULT_RUNTIME


def runtime_key_known(value: Any) -> bool:
    clean = str(value or "").strip().lower().replace("_", "-").replace(" ", "-")
    clean = RUNTIME_ALIASES.get(clean, clean)
    return clean in RUNTIME_REGISTRY


def runtime_can_execute(runtime: Any) -> bool:
    entry = RUNTIME_REGISTRY.get(normalize_runtime(runtime), {})
    return bool(entry.get("can_execute"))


def normalize_runtime_model(runtime: Any, model: Any = "") -> str:
    normalized_runtime = normalize_runtime(runtime)
    clean_model = str(model or "").strip()
    if clean_model:
        if normalized_runtime == "codex":
            return normalize_codex_model_name(
                clean_model, fallback=MODEL, allow_switchable=True
            )
        return clean_model
    entry = RUNTIME_REGISTRY.get(normalized_runtime, {})
    default_model = str(entry.get("default_model") or MODEL).strip() or MODEL
    if normalized_runtime == "codex":
        return normalize_codex_model_name(
            default_model, fallback=MODEL, allow_switchable=True
        )
    return default_model


def runtime_label(runtime: Any, model: Any = "") -> str:
    normalized_runtime = normalize_runtime(runtime)
    entry = RUNTIME_REGISTRY.get(normalized_runtime, {})
    label = str(entry.get("label") or normalized_runtime).strip() or normalized_runtime
    return f"{label} · {normalize_runtime_model(normalized_runtime, model)}"


def runtime_registry_payload() -> list[dict[str, Any]]:
    payload: list[dict[str, Any]] = []
    for key, entry in RUNTIME_REGISTRY.items():
        runtime = normalize_runtime(key)
        item = dict(entry)
        item["key"] = runtime
        item["default_model"] = normalize_runtime_model(runtime)
        item["models"] = [
            str(model).strip() for model in item.get("models", []) if str(model).strip()
        ]
        item["can_execute"] = runtime_can_execute(runtime)
        payload.append(item)
    return payload


