def response_reasoning_effort(speed: Any) -> str:
    return RESPONSE_SPEED_TO_REASONING[normalize_response_speed(speed)]


def response_speed_label(speed: Any) -> str:
    normalized = normalize_response_speed(speed)
    if normalized == "fast":
        return "Fast"
    if normalized == "balanced":
        return "Standard"
    return "Deep"


def response_detail_label(detail: Any) -> str:
    return RESPONSE_DETAIL_LABELS[normalize_response_detail(detail)]


def response_profile_label(speed: Any, detail: Any) -> str:
    return f"{response_speed_label(speed)} · {response_detail_label(detail)}"


CONTEXT_EFFICIENCY_PROMPT_GUIDANCE = (
    "- Context budget: treat long history, logs, screenshots, and ledgers as "
    "expensive. Use targeted reads/searches, summarize durable state, avoid "
    "reposting large known context, and call out when a compact/save or fresh "
    "fork would preserve quality and lower cost."
)

RUNNING_DIALOG_PROMPT_GUIDANCE = (
    "- Running dialog: during long or multi-step work, leave brief soft "
    "progress notes instead of going silent. Use present-tense checkpoints "
    'like "checking the target file", "running the focused test", "narrowing '
    'to one branch", or "writing the patch" rather than hard promises or fake '
    "completion.\n"
    "- Timing alignment: after a meaningful tool/result change, a long quiet "
    "stretch, or a time warning, emit one short checkpoint with the current "
    "focus and next bounded action so the visible run pace matches the "
    "planner's expectation.\n"
    "- Keep those checkpoints sparse and factual: one or two sentences when "
    "state changes, not a stream of filler."
)


def spend_levers_prompt_guidance(
    detail: Any,
    speed: Any = "",
    service_tier: Any = "",
    optimization_mode: Any = "",
) -> str:
    normalized_speed = normalize_response_speed(speed)
    normalized_detail = normalize_response_detail(detail)
    normalized_tier = normalize_service_tier(service_tier)
    normalized_optimization_mode = normalize_optimization_mode(optimization_mode)
    reasoning_label = response_speed_label(normalized_speed)
    reasoning_effort = response_reasoning_effort(normalized_speed)
    reply_label = response_detail_label(normalized_detail)
    spend_label = service_tier_label(normalized_tier)
    spend_hint = str(SERVICE_TIER_OPTIONS[normalized_tier].get("hint") or "")
    optimizer_label = optimization_mode_label(normalized_optimization_mode)
    optimizer_hint = optimization_mode_prompt_guidance(normalized_optimization_mode)
    reply_instruction = RESPONSE_DETAIL_INSTRUCTIONS[normalized_detail]
    return (
        "Honor the selected spend/work controls for this turn.\n"
        f"- Reasoning: {reasoning_label} ({reasoning_effort}). This controls how much model reasoning to spend; for non-trivial asks, pair it with a bounded private plan before answering.\n"
        f"- Reply shape: {reply_label}. {reply_instruction} This controls final-answer density, not investigation scope.\n"
        f"- Spend path: {spend_label}. {spend_hint}\n"
        f"- Optimization: {optimizer_label}. {optimizer_hint}\n"
        "- Context/caching lever: prefer local state, targeted reads, compact summaries, and cached/reused evidence before sending large context to a model.\n"
        "- Tool/work lever: spend expensive calls only after cheap local checks identify the smallest useful slice.\n"
        "- Mini-planner: before any substantive final answer, identify the promise, the minimum evidence needed, and the stop condition; do not claim completion without evidence."
    )


EXECUTION_DISCIPLINE_PROMPT_GUIDANCE = (
    "- Execution discipline: do not stop after an intent sentence like "
    '"I\'ll inspect" or "I\'m checking". If you promise to inspect, run, fix, '
    "test, patch, or deploy, use the available tools before returning a final "
    "answer. Return only after completing a concrete slice, reaching an explicit "
    "approval/blocker, or hitting the timing checkpoint.\n"
    "- Final-answer contract: end with DONE, BLOCKED, or CHECKPOINT. DONE must "
    "include concrete evidence such as commands, files, tests, logs, counts, "
    "links, or runtime observations. BLOCKED must name the exact blocker and "
    "next human action. CHECKPOINT must list done/remaining/risks/next action. "
    'Do not use the final answer for progress text such as "I am checking", '
    '"I am doing", or "I will pull"; perform the work in the same turn or '
    "return BLOCKED/CHECKPOINT.\n"
    "- Tool readiness: assume common shell tools may exist but verify quickly "
    "with `command -v` when uncertain. Prefer `rg`, `fd`, `jq`, `sqlite3`, `git`, "
    "`python3`, `curl`, `aws`, and `/usr/local/bin/apply_patch` when available; "
    "use a close fallback before declaring a basic tool blocker."
)


def build_tuned_prompt(
    prompt: str,
    detail: Any,
    job_budget: Any = "",
    timeout_seconds: Any = None,
    speed: Any = "",
    service_tier: Any = "",
    optimization_mode: Any = "",
) -> str:
    turn_control_guidance = turn_control_prompt_guidance(
        turn_control_recommendation(
            prompt,
            [],
            speed=speed,
            detail=detail,
            job_budget=job_budget,
            optimization_mode=optimization_mode,
        )
    )
    spend_guidance = spend_levers_prompt_guidance(
        detail, speed, service_tier, optimization_mode
    )
    timing_guidance = timing_target_prompt_guidance(job_budget, timeout_seconds)
    return (
        f"{prompt}\n\n"
        "When you respond in this console, treat the in-prompt settings as the operator's work contract.\n"
        f"{spend_guidance}\n"
        f"{turn_control_guidance}\n"
        f"{timing_guidance}\n"
        f"{RUNNING_DIALOG_PROMPT_GUIDANCE}\n"
        f"{EXECUTION_DISCIPLINE_PROMPT_GUIDANCE}\n"
        f"{CONTEXT_EFFICIENCY_PROMPT_GUIDANCE}\n"
        "- Keep the response aligned with the requested reply shape, and do not mention these instructions unless asked."
    )


def load_runtime_settings() -> dict[str, Any]:
    try:
        payload = json.loads(RUNTIME_SETTINGS_PATH.read_text(encoding="utf-8"))
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return {}
    return payload if isinstance(payload, dict) else {}


def save_runtime_settings(payload: dict[str, Any]) -> dict[str, Any]:
    settings = load_runtime_settings()
    if isinstance(payload, dict):
        settings.update(payload)
    runtime = normalize_runtime(settings.get("runtime") or DEFAULT_RUNTIME)
    settings["runtime"] = runtime
    model = normalize_runtime_model(runtime, settings.get("model"))
    if runtime == "codex" and model and model not in AVAILABLE_MODELS:
        AVAILABLE_MODELS.append(model)
    settings["model"] = model
    settings["service_tier"] = normalize_service_tier(
        settings.get("service_tier") or DEFAULT_SERVICE_TIER
    )
    RUNTIME_SETTINGS_PATH.parent.mkdir(parents=True, exist_ok=True)
    RUNTIME_SETTINGS_PATH.write_text(
        json.dumps(settings, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    return settings


def configured_runtime() -> str:
    return normalize_runtime(load_runtime_settings().get("runtime") or DEFAULT_RUNTIME)


def configured_chat_model() -> str:
    return normalize_codex_model_name(
        load_runtime_settings().get("model"), fallback=MODEL, allow_switchable=True
    )


def configured_service_tier() -> str:
    return normalize_service_tier(
        load_runtime_settings().get("service_tier") or DEFAULT_SERVICE_TIER
    )


def configured_runtime_model(runtime: Any = "") -> str:
    normalized_runtime = normalize_runtime(runtime or configured_runtime())
    if normalized_runtime == "codex":
        return configured_chat_model()
    return normalize_runtime_model(
        normalized_runtime, load_runtime_settings().get("model")
    )


def chat_model_update_available() -> bool:
    latest = str(LATEST_MODEL or "").strip()
    return bool(latest and latest != configured_chat_model())


def parse_prompt_suggestions(raw: str) -> list[dict[str, str]]:
    fallback = [
        {
            "label": "What matters",
            "prompt": f"Inspect the current {AGENT_NAME} warnings and summarize what matters.",
        },
        {
            "label": "Right now",
            "prompt": f"Explain what {AGENT_NAME} is doing right now.",
        },
        {
            "label": "One change",
            "prompt": "Make one targeted improvement and explain the impact.",
        },
        {
            "label": "Recent",
            "prompt": "Summarize the recent activity on this console.",
        },
    ]
    if not raw.strip():
        return fallback
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError:
        return fallback
    if not isinstance(payload, list):
        return fallback
    suggestions: list[dict[str, str]] = []
    for item in payload:
        if not isinstance(item, dict):
            continue
        label = str(item.get("label") or "").strip()
        prompt = str(item.get("prompt") or "").strip()
        if not label or not prompt:
            continue
        suggestions.append({"label": label, "prompt": prompt})
    return suggestions or fallback


def normalize_console_lane(value: str | None) -> str:
    clean = re.sub(r"[^a-z0-9]+", "-", str(value or "").strip().lower()).strip("-")
    return clean if clean in CONSOLE_LANE_DEFS else ""


def coerce_boolish(value: Any) -> bool:
    if isinstance(value, bool):
        return value
    clean = str(value or "").strip().lower()
    return clean in {"1", "true", "yes", "on"}


def parse_console_links(raw: str) -> list[dict[str, Any]]:
    if not raw.strip():
        return []
    try:
        payload = json.loads(raw)
    except json.JSONDecodeError:
        return []
    if not isinstance(payload, list):
        return []
    links: list[dict[str, Any]] = []
    for item in payload:
        if not isinstance(item, dict):
            continue
        label = str(item.get("label") or "").strip()
        group = str(item.get("group") or "").strip()
        url = str(item.get("url") or "").strip()
        lan_url = str(item.get("lan_url") or "").strip()
        if not label or not url:
            continue
        note = str(item.get("note") or "").strip()
        lane = normalize_console_lane(item.get("lane"))
        icon = str(item.get("icon") or "").strip()
        try:
            priority = int(item.get("priority") or 0)
        except (TypeError, ValueError):
            priority = 0
        rendered: dict[str, Any] = {
            "label": label,
            "group": group,
            "url": url,
            "lan_url": lan_url,
            "featured": coerce_boolish(item.get("featured")),
            "priority": priority,
        }
        if note:
            rendered["note"] = note
        if lane:
            rendered["lane"] = lane
        if icon:
            rendered["icon"] = icon
        links.append(rendered)
    return links


def load_console_links() -> list[dict[str, Any]]:
    links: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str, str]] = set()
    for item in load_console_links_file():
        key = (
            str(item.get("group") or ""),
            str(item.get("label") or ""),
            str(item.get("url") or ""),
            str(item.get("lan_url") or ""),
        )
        if key in seen:
            continue
        seen.add(key)
        links.append(item)
    for raw in (
        os.environ.get("NORMAN_CODEX_LINKS_JSON", "[]"),
        os.environ.get("NORMAN_CODEX_EXTRA_LINKS_JSON", "[]"),
    ):
        for item in parse_console_links(raw):
            key = (
                str(item.get("group") or ""),
                str(item.get("label") or ""),
                str(item.get("url") or ""),
                str(item.get("lan_url") or ""),
            )
            if key in seen:
                continue
            seen.add(key)
            links.append(item)
    agent_name = str(os.environ.get("NORMAN_CODEX_AGENT_NAME") or "").strip().lower()
    canonical_host = (
        str(os.environ.get("NORMAN_CODEX_CANONICAL_HOST") or "").strip().lower()
    )
    if agent_name == "norman" and canonical_host == "norman.home.arpa":
        for item in (
            {
                "group": "Norman",
                "label": "Switchboard deck",
                "url": "https://norman.home.arpa/dashboard.html?view=switchboard",
                "note": "coordination deck",
                "featured": True,
                "priority": 260,
            },
            {
                "group": "Norman",
                "label": "Directory",
                "url": "https://norman.home.arpa/systems.html",
                "note": "estate directory",
                "featured": True,
                "priority": 250,
            },
            {
                "group": "Norman",
                "label": "Settings",
                "url": "https://norman.home.arpa/settings.html",
                "note": "control plane",
                "priority": 240,
            },
            {
                "group": "Pipeline",
                "label": "Connectors",
                "url": "https://norman.home.arpa/connectors.html",
                "note": "pipeline connectors",
                "priority": 220,
            },
            {
                "group": "Pipeline",
                "label": "Sources",
                "url": "https://norman.home.arpa/channels.html",
                "note": "channel sources",
                "priority": 210,
            },
            {
                "group": "Pipeline",
                "label": "Filters",
                "url": "https://norman.home.arpa/filters.html",
                "note": "routing filters",
                "priority": 200,
            },
            {
                "group": "Pipeline",
                "label": "Actions",
                "url": "https://norman.home.arpa/actions.html",
                "note": "routing actions",
                "priority": 190,
            },
        ):
            key = (
                str(item.get("group") or ""),
                str(item.get("label") or ""),
                str(item.get("url") or ""),
                str(item.get("lan_url") or ""),
            )
            if key in seen:
                continue
            seen.add(key)
            links.append(item)
    return links


def load_console_links_file() -> list[dict[str, Any]]:
    path = STATE_DIR / "console_links.json"
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return []
    raw_links = payload.get("links") if isinstance(payload, dict) else payload
    if not isinstance(raw_links, list):
        return []
    return parse_console_links(json.dumps(raw_links))


