def canonical_origin_components() -> tuple[str, str]:
    if not CANONICAL_HOST:
        return ("http", "")
    if canonical_host_uses_direct_http(CANONICAL_HOST):
        return ("http", f"{CANONICAL_HOST}:{PORT}")
    return ("https", CANONICAL_HOST)


