def profile_mode(profile_name: str) -> str:
    profile = UI_PROFILES[normalize_profile_name(profile_name)]
    mode = str(profile.get("mode") or "dark").strip().lower()
    return mode if mode in PROFILE_MODE_ORDER else PROFILE_MODE_ORDER[0]


def profile_family(profile_name: str) -> str:
    profile = UI_PROFILES[normalize_profile_name(profile_name)]
    return str(profile.get("family") or normalize_profile_name(profile_name))


def profiles_for_mode(mode: str) -> list[tuple[str, dict[str, Any]]]:
    clean_mode = mode if mode in PROFILE_MODE_ORDER else PROFILE_MODE_ORDER[0]
    return [
        (slug, data)
        for slug, data in UI_PROFILES.items()
        if profile_mode(slug) == clean_mode
    ]


def profile_for_mode(profile_name: str, target_mode: str) -> str:
    target = target_mode if target_mode in PROFILE_MODE_ORDER else PROFILE_MODE_ORDER[0]
    normalized = normalize_profile_name(profile_name)
    if profile_mode(normalized) == target:
        return normalized
    family = profile_family(normalized)
    for slug in UI_PROFILES:
        if profile_mode(slug) == target and profile_family(slug) == family:
            return slug
    for slug in UI_PROFILES:
        if profile_mode(slug) == target:
            return slug
    return normalized


def profile_vars_css(profile_name: str) -> str:
    profile = UI_PROFILES[normalize_profile_name(profile_name)]
    return "\n".join(
        f"      --{key}: {value};" for key, value in profile["vars"].items()
    )


ROUTE_MODE_ORDER = ("auto", "lan", "host", "tail")


def normalize_route_mode(value: str | None) -> str:
    candidate = (value or "").strip().lower()
    if candidate in ROUTE_MODE_ORDER:
        return candidate
    return ROUTE_MODE_ORDER[0]


def build_console_href(
    *, token: str, profile: str, route: str = "", prefix: str = ""
) -> str:
    query: dict[str, str] = {}
    if token:
        query["token"] = token
    if profile:
        query["profile"] = profile
    route_mode = normalize_route_mode(route)
    if route_mode != "auto":
        query["route"] = route_mode
    root_path = prefixed_path("/", prefix)
    if not query:
        return root_path
    return f"{root_path}?{urlencode(query)}"


def build_file_href(
    *,
    token: str,
    path: str,
    profile: str = "",
    route: str = "",
    prefix: str = "",
    raw: bool = False,
    download: bool = False,
) -> str:
    clean_path, fragment = split_file_target(path)
    query: dict[str, str] = {"path": clean_path or path}
    if token:
        query["token"] = token
    if profile:
        query["profile"] = profile
    route_mode = normalize_route_mode(route)
    if route_mode != "auto":
        query["route"] = route_mode
    if raw:
        query["raw"] = "1"
    if download:
        query["download"] = "1"
    href = f"{prefixed_path('/api/file', prefix)}?{urlencode(query)}"
    return f"{href}{fragment}" if fragment else href


def client_prefers_tailnet(client_ip: str = "") -> bool:
    return client_ip_matches(client_ip, TAILNET_CLIENT_NETWORKS)


def host_prefers_lan(request_host: str = "", client_ip: str = "") -> bool:
    if client_prefers_tailnet(client_ip):
        return False
    return host_access_mode(request_host) in {"loopback", "private_ip", "lan_dns"}


def effective_route_mode(
    request_host: str = "", route_mode: str = "auto", client_ip: str = ""
) -> str:
    normalized = normalize_route_mode(route_mode)
    if normalized == "lan":
        return "lan"
    if normalized == "host":
        return "host"
    if normalized == "tail":
        return "tail"
    if client_prefers_tailnet(client_ip):
        return "tail"
    return "lan" if host_prefers_lan(request_host, client_ip) else "host"


def append_route_preference(url: str, route_mode: str) -> str:
    normalized = normalize_route_mode(route_mode)
    if normalized == "auto":
        return url
    parsed = urlparse(url)
    query = parse_qs(parsed.query, keep_blank_values=True)
    query["route"] = [normalized]
    encoded = urlencode(query, doseq=True)
    return parsed._replace(query=encoded).geturl()


def build_norman_prime_href(
    request_host: str = "", route_mode: str = "auto", client_ip: str = ""
) -> str:
    current_host = normalize_host_alias(request_host)
    effective_mode = effective_route_mode(request_host, route_mode, client_ip)
    if current_host and current_host in NORMAN_HOME_ALIASES:
        target_host = current_host
    elif host_access_mode(current_host) == "private_ip":
        target_host = "192.168.2.241"
    elif host_access_mode(current_host) == "tailnet":
        target_host = "norman.tail94915.ts.net"
    elif host_access_mode(current_host) == "lan_dns":
        target_host = "norman.home.arpa"
    else:
        target_host = (
            "norman.home.arpa" if effective_mode == "lan" else "norman.tail94915.ts.net"
        )
    if host_access_mode(target_host) in {"loopback", "private_ip"}:
        return f"http://{target_host}:8000/"
    return f"https://{target_host}/"


def build_norman_directory_href(
    request_host: str = "", route_mode: str = "auto", client_ip: str = ""
) -> str:
    return f"{build_norman_prime_href(request_host, route_mode, client_ip)}systems.html"


def render_console_link_url(
    link: dict[str, Any],
    *,
    token: str,
    profile: str,
    request_host: str = "",
    route_mode: str = "auto",
    client_ip: str = "",
) -> str:
    requested_mode = normalize_route_mode(route_mode)
    effective_mode = effective_route_mode(request_host, requested_mode, client_ip)
    request_mode = host_access_mode(request_host)
    has_tail = bool(str(link.get("tail_url") or "").strip())
    remote_from_lan_only = request_mode in {"public_dns", "public_ip"} and has_tail
    if (effective_mode == "tail" or remote_from_lan_only) and has_tail:
        raw_url = str(link.get("tail_url") or "").strip()
    elif effective_mode == "lan" and link.get("lan_url") and not remote_from_lan_only:
        raw_url = str(link.get("lan_url") or "").strip()
    else:
        raw_url = str(link.get("url") or "").strip()
    rendered = (
        raw_url.replace("{token}", quote(token, safe=""))
        .replace("{profile}", quote(profile, safe=""))
        .strip()
    )
    rendered = append_route_preference(rendered, route_mode)
    current_host = normalize_host_alias(request_host)
    if not current_host:
        return rendered
    parsed = urlparse(rendered)
    target_host = normalize_host_alias(parsed.netloc or parsed.hostname or "")
    if not target_host or target_host not in LOCAL_HOST_ALIASES:
        return rendered
    target_port = parsed.port or (443 if parsed.scheme == "https" else 80)
    if target_port != PORT:
        return rendered
    port = f":{parsed.port}" if parsed.port else ""
    rewritten = parsed._replace(netloc=f"{current_host}{port}")
    return rewritten.geturl()


def console_link_anchor_attrs(url: str) -> str:
    scheme = urlparse(str(url or "").strip()).scheme.lower()
    if scheme in {"", "http", "https"}:
        return ' target="_blank" rel="noreferrer"'
    return ""


def console_lane_for_link(link: dict[str, Any]) -> str:
    explicit_lane = normalize_console_lane(link.get("lane"))
    if explicit_lane:
        return explicit_lane
    label = re.sub(r"[^a-z0-9]+", " ", str(link.get("label") or "").lower()).strip()
    if any(hint in label for hint in CONSOLE_EXPLORE_HINTS):
        return "explore"
    tone_group = semantic_console_group(
        link.get("tone_group") or link.get("group_slug") or link.get("group")
    )
    if tone_group in {"norman", "personal"}:
        return "make"
    if tone_group == "shared":
        return "review"
    if tone_group in {"work", "private"}:
        return "operate"
    return "make"


def console_note_for_link(link: dict[str, Any], lane: str) -> str:
    note = str(link.get("note") or "").strip()
    if note:
        return note
    label_slug = normalize_console_group_slug(link.get("label"))
    if label_slug in {"workspace", "workbench"}:
        return "Repo root, notes, and local files."
    if label_slug == "bridge-state":
        return "Bridge logs, state snapshots, and live status."
    tone_group = semantic_console_group(
        link.get("tone_group") or link.get("group_slug") or link.get("group")
    )
    return CONSOLE_GROUP_NOTES.get(
        tone_group, CONSOLE_LANE_DEFS.get(lane, {}).get("description", "")
    )


def console_focus_score(
    link: dict[str, Any], current_agent_candidates: set[str] | None = None
) -> int:
    candidates = current_agent_candidates or set()
    label_slug = normalize_console_group_slug(link.get("label"))
    tone_group = semantic_console_group(
        link.get("tone_group") or link.get("group_slug") or link.get("group")
    )
    lane = console_lane_for_link(link)
    score = int(link.get("priority") or 0)
    score += {"make": 240, "explore": 220, "review": 140, "operate": 80}.get(lane, 0)
    score += {
        "norman": 80,
        "personal": 60,
        "shared": 32,
        "private": 18,
        "work": 0,
        "agents": 10,
    }.get(tone_group, 0)
    if link.get("featured"):
        score += 280
    if str(link.get("source") or "") == "local":
        score += 120
    if label_slug and label_slug in candidates:
        score += 140
    if lane == "operate" and not link.get("featured"):
        score -= 20
    return score


def build_console_focus_lanes(
    links: list[dict[str, Any]], current_agent_candidates: set[str] | None = None
) -> list[dict[str, Any]]:
    candidates = current_agent_candidates or set()
    grouped: dict[str, dict[str, Any]] = {
        slug: {"slug": slug, **data, "items": []}
        for slug, data in CONSOLE_LANE_DEFS.items()
    }
    for link in links:
        lane = console_lane_for_link(link)
        tone_group = semantic_console_group(
            link.get("tone_group") or link.get("group_slug") or link.get("group")
        )
        item = dict(link)
        item["lane"] = lane
        item["tone_group"] = tone_group or "agents"
        item["note"] = console_note_for_link(item, lane)
        item["icon"] = str(
            item.get("icon") or icon_for_label(str(item.get("label") or ""))
        )
        item["score"] = console_focus_score(item, candidates)
        grouped.setdefault(
            lane,
            {
                "slug": lane,
                "label": lane.title(),
                "description": "",
                "eyebrow": "",
                "items": [],
            },
        )["items"].append(item)
    lane_limits = {"make": 3, "explore": 2, "review": 2, "operate": 2}
    ordered: list[dict[str, Any]] = []
    for lane in CONSOLE_LANE_DEFS:
        bucket = grouped.get(lane)
        if not bucket:
            continue
        items = sorted(
            bucket["items"],
            key=lambda item: (
                -int(item.get("score") or 0),
                str(item.get("label") or ""),
            ),
        )[: lane_limits.get(lane, 2)]
        if not items:
            continue
        ordered.append({**bucket, "items": items})
    return ordered


def build_relay_targets(
    *,
    token: str,
    profile: str,
    request_host: str = "",
    route_mode: str = "auto",
    client_ip: str = "",
) -> list[dict[str, str]]:
    current_host = normalize_host_alias(request_host)
    targets: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for link in CONSOLE_LINKS:
        rendered = render_console_link_url(
            link,
            token=token,
            profile=profile,
            request_host=request_host,
            route_mode=route_mode,
            client_ip=client_ip,
        )
        parsed = urlparse(rendered)
        if parsed.scheme not in {"http", "https"} or not parsed.netloc:
            continue
        if (parsed.path or "/") not in {"", "/"}:
            continue
        query = parse_qs(parsed.query)
        target_token = (query.get("token") or [""])[0].strip()
        if not target_token:
            continue
        target_host = normalize_host_alias(parsed.hostname or "")
        if (
            current_host
            and target_host == current_host
            and (parsed.port or 80) == PORT
            and target_token == token
        ):
            continue
        api_url = parsed._replace(path="/api/ask", query="", fragment="").geturl()
        key = (link["label"], api_url)
        if key in seen:
            continue
        seen.add(key)
        targets.append(
            {
                "label": link["label"],
                "url": rendered,
                "api_url": api_url,
                "token": target_token,
                "host": parsed.netloc,
            }
        )
    return targets


def build_handoff_message(source_prompt: str, source_response: str) -> str:
    prompt = source_prompt.strip() or "[no original prompt recorded]"
    response = source_response.strip() or "[no assistant response recorded]"
    return (
        f"You are receiving a handoff from {AGENT_NAME}.\n\n"
        "Continue this operator task in your own workspace and tools. "
        "Reuse the context below, but re-check anything environment-specific.\n\n"
        "Original operator prompt:\n"
        f"{prompt}\n\n"
        f"Response from {AGENT_NAME} so far:\n"
        f"{response}\n\n"
        "Take the next best action. If anything important is missing, say exactly "
        "what you need."
    )


def relay_eta_label(queue_position: int, pending: bool) -> str:
    if pending and queue_position <= 0:
        return "running now"
    if queue_position <= 0:
        return "ETA unknown"
    minutes = max(5, min(120, queue_position * 10))
    return f"rough ETA {minutes} min"


def build_relay_acknowledgement(
    target_label: str, downstream: dict[str, Any] | None
) -> dict[str, Any]:
    payload = downstream if isinstance(downstream, dict) else {}
    snapshot = (
        payload.get("snapshot") if isinstance(payload.get("snapshot"), dict) else {}
    )
    queue_depth = _coerce_int(snapshot.get("queue_depth"))
    pending = bool(snapshot.get("pending"))
    queue_position = queue_depth if queue_depth > 0 else 0
    model_alive = bool(
        snapshot.get("model_process_alive") or snapshot.get("web_worker_alive")
    )

    if queue_position > 0:
        state = "queued"
        label = "Queued"
        detail = f"{target_label} picked it up; queued at position {queue_position}."
    elif pending:
        state = "running"
        label = "Picked up"
        detail = f"{target_label} picked it up and is working now."
    else:
        state = "picked-up"
        label = "Picked up"
        detail = f"{target_label} accepted the handoff."

    return {
        "state": state,
        "label": label,
        "target": target_label,
        "picked_up": True,
        "pending": pending,
        "queue_depth": queue_depth,
        "queue_position": queue_position,
        "model_alive": model_alive,
        "eta_label": relay_eta_label(queue_position, pending),
        "detail": detail,
    }


def now_ts() -> int:
    return int(time.time())


def run(
    cmd: list[str], *, input_text: str | None = None, check: bool = False
) -> subprocess.CompletedProcess[str]:
    kwargs: dict[str, Any] = {}
    if input_text is None:
        kwargs["stdin"] = subprocess.DEVNULL
    else:
        kwargs["input"] = input_text
    return subprocess.run(
        cmd,
        text=True,
        capture_output=True,
        check=check,
        **kwargs,
    )


def tmux_cmd(*args: str) -> list[str]:
    return ["tmux", "-L", TMUX_SOCKET, *args]


def ensure_state_dir() -> None:
    STATE_DIR.mkdir(parents=True, exist_ok=True)


def _state_db_id(kind: str, payload: dict[str, Any]) -> str:
    material = json.dumps(
        {
            "kind": kind,
            "thread_id": payload.get("thread_id"),
            "started_at": payload.get("started_at"),
            "finished_at": payload.get("finished_at"),
            "prompt": str(payload.get("prompt") or "")[:512],
            "response": str(payload.get("response") or "")[:512],
            "error": str(payload.get("error") or payload.get("error_text") or "")[:512],
            "total_tokens": payload.get("total_tokens"),
        },
        sort_keys=True,
        default=str,
    )
    return hashlib.sha256(material.encode("utf-8")).hexdigest()


def _state_db_connect() -> sqlite3.Connection | None:
    if not STATE_DB_ENABLED:
        return None
    ensure_state_dir()
    try:
        conn = sqlite3.connect(str(STATE_DB_PATH), timeout=2)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS meta (
                key TEXT PRIMARY KEY,
                value TEXT NOT NULL,
                updated_at INTEGER NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS turns (
                id TEXT PRIMARY KEY,
                thread_id TEXT,
                started_at INTEGER,
                finished_at INTEGER,
                runtime TEXT,
                model TEXT,
                speed TEXT,
                detail INTEGER,
                service_tier TEXT,
                job_budget TEXT,
                timeout_seconds INTEGER,
                prompt_chars INTEGER NOT NULL DEFAULT 0,
                response_chars INTEGER NOT NULL DEFAULT 0,
                error_chars INTEGER NOT NULL DEFAULT 0,
                prompt_preview TEXT,
                response_preview TEXT,
                error_preview TEXT,
                attachment_count INTEGER NOT NULL DEFAULT 0,
                usage_total_tokens INTEGER NOT NULL DEFAULT 0,
                provider_surface TEXT,
                route_class TEXT,
                route_label TEXT,
                route_charge_basis TEXT,
                charge_ledger_kind TEXT,
                success INTEGER NOT NULL DEFAULT 1,
                payload_json TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS usage_events (
                id TEXT PRIMARY KEY,
                thread_id TEXT,
                started_at INTEGER,
                finished_at INTEGER,
                runtime TEXT,
                model TEXT,
                speed TEXT,
                detail INTEGER,
                service_tier TEXT,
                provider_label TEXT,
                provider_surface TEXT,
                profile_v2 TEXT,
                aws_profile TEXT,
                aws_region TEXT,
                route_class TEXT,
                route_label TEXT,
                route_charge_basis TEXT,
                success INTEGER NOT NULL DEFAULT 0,
                input_tokens INTEGER NOT NULL DEFAULT 0,
                cached_input_tokens INTEGER NOT NULL DEFAULT 0,
                output_tokens INTEGER NOT NULL DEFAULT 0,
                reasoning_output_tokens INTEGER NOT NULL DEFAULT 0,
                total_tokens INTEGER NOT NULL DEFAULT 0,
                usage_meter_mode TEXT,
                billing_owner TEXT,
                billing_project TEXT,
                billing_scope TEXT,
                billing_unit TEXT,
                charge_ledger_kind TEXT,
                charge_display_unit TEXT,
                charge_status TEXT,
                provider_yield_kind TEXT,
                provider_yield_reasons TEXT,
                provider_error_kind TEXT,
                provider_request_ids TEXT,
                provider_trace_ids TEXT,
                codex_returncode INTEGER NOT NULL DEFAULT 0,
                zero_token_provider_failure INTEGER NOT NULL DEFAULT 0,
                payload_json TEXT NOT NULL
            )
            """
        )
        _state_db_ensure_column(conn, "usage_events", "charge_ledger_kind", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "charge_display_unit", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "charge_status", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_label", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_surface", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "profile_v2", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "aws_profile", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "aws_region", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "route_class", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "route_label", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "route_charge_basis", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_yield_kind", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_yield_reasons", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_error_kind", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_request_ids", "TEXT")
        _state_db_ensure_column(conn, "usage_events", "provider_trace_ids", "TEXT")
        _state_db_ensure_column(
            conn,
            "usage_events",
            "codex_returncode",
            "INTEGER NOT NULL DEFAULT 0",
        )
        _state_db_ensure_column(
            conn,
            "usage_events",
            "zero_token_provider_failure",
            "INTEGER NOT NULL DEFAULT 0",
        )
        _state_db_ensure_column(conn, "turns", "provider_surface", "TEXT")
        _state_db_ensure_column(conn, "turns", "route_class", "TEXT")
        _state_db_ensure_column(conn, "turns", "route_label", "TEXT")
        _state_db_ensure_column(conn, "turns", "route_charge_basis", "TEXT")
        _state_db_ensure_column(conn, "turns", "charge_ledger_kind", "TEXT")
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS context_cards (
                id TEXT PRIMARY KEY,
                created_at INTEGER NOT NULL,
                scope TEXT,
                summary TEXT,
                payload_json TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS audit_events (
                id TEXT PRIMARY KEY,
                event_at INTEGER NOT NULL,
                event_type TEXT,
                severity TEXT,
                actor_type TEXT,
                thread_id TEXT,
                summary TEXT,
                detail TEXT,
                payload_json TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS human_interventions (
                id TEXT PRIMARY KEY,
                fingerprint TEXT NOT NULL,
                kind TEXT NOT NULL,
                severity TEXT NOT NULL,
                status TEXT NOT NULL,
                question TEXT NOT NULL,
                detail TEXT,
                options_json TEXT NOT NULL,
                evidence_json TEXT NOT NULL,
                source_actor TEXT,
                target_actor TEXT,
                thread_id TEXT,
                created_at INTEGER NOT NULL,
                updated_at INTEGER NOT NULL,
                closed_at INTEGER NOT NULL DEFAULT 0,
                payload_json TEXT NOT NULL
            )
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_turns_thread_started
            ON turns(thread_id, started_at)
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_usage_thread_started
            ON usage_events(thread_id, started_at)
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_audit_events_type_at
            ON audit_events(event_type, event_at)
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_human_interventions_status
            ON human_interventions(status, severity, updated_at)
            """
        )
        conn.execute(
            """
            CREATE INDEX IF NOT EXISTS idx_human_interventions_fingerprint
            ON human_interventions(fingerprint, status)
            """
        )
        conn.execute(
            "INSERT OR REPLACE INTO meta(key, value, updated_at) VALUES (?, ?, ?)",
            ("schema", "norman.tui-state.v1", now_ts()),
        )
        conn.commit()
        return conn
    except sqlite3.Error:
        try:
            conn.close()  # type: ignore[name-defined]
        except Exception:
            pass
        return None


def _state_db_ensure_column(
    conn: sqlite3.Connection, table: str, column: str, definition: str
) -> None:
    try:
        rows = conn.execute(f"PRAGMA table_info({table})").fetchall()
        existing = {str(row[1]) for row in rows}
        if column not in existing:
            conn.execute(f"ALTER TABLE {table} ADD COLUMN {column} {definition}")
    except sqlite3.Error:
        pass


def _state_db_json(payload: dict[str, Any]) -> str:
    return json.dumps(payload, sort_keys=True, default=str)


def mirror_history_entry_to_state_db(entry: dict[str, Any]) -> None:
    if not STATE_DB_ENABLED or not isinstance(entry, dict):
        return
    conn = _state_db_connect()
    if conn is None:
        return
    try:
        raw_usage = entry.get("usage") if isinstance(entry.get("usage"), dict) else {}
        usage = normalize_usage_entry(
            {
                **raw_usage,
                "runtime": entry.get("runtime"),
                "model": entry.get("model"),
                "service_tier": entry.get("service_tier"),
            }
        )
        usage_success = usage.get("success") if "success" in usage else None
        attachments = normalize_attachments(entry.get("attachments"))
        prompt = str(entry.get("prompt") or "")
        response = str(entry.get("response") or "")
        error_text = str(entry.get("error") or "")
        conn.execute(
            """
            INSERT OR REPLACE INTO turns(
                id, thread_id, started_at, finished_at, runtime, model, speed, detail,
                service_tier, job_budget, timeout_seconds, prompt_chars,
                response_chars, error_chars, prompt_preview, response_preview,
                error_preview, attachment_count, usage_total_tokens, provider_surface,
                route_class, route_label, route_charge_basis, charge_ledger_kind, success,
                payload_json
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                _state_db_id("turn", entry),
                str(entry.get("thread_id") or ""),
                _coerce_int(entry.get("started_at")),
                _coerce_int(entry.get("finished_at")),
                str(entry.get("runtime") or ""),
                str(entry.get("model") or ""),
                str(entry.get("speed") or ""),
                _coerce_int(entry.get("detail")),
                str(entry.get("service_tier") or ""),
                str(entry.get("job_budget") or ""),
                _coerce_int(entry.get("timeout_seconds")),
                len(prompt),
                len(response),
                len(error_text),
                summarize_text(prompt, 220),
                summarize_text(response, 220),
                summarize_text(error_text, 220),
                len(attachments),
                _coerce_int(usage.get("total_tokens")),
                str(usage.get("provider_surface") or ""),
                str(usage.get("route_class") or ""),
                str(usage.get("route_label") or ""),
                str(usage.get("route_charge_basis") or ""),
                str(usage.get("charge_ledger_kind") or ""),
                0 if error_text or usage_success is False else 1,
                _state_db_json(entry),
            ),
        )
        conn.commit()
    except sqlite3.Error:
        pass
    finally:
        conn.close()


