def mirror_audit_event_to_state_db(entry: dict[str, Any]) -> None:
    if not STATE_DB_ENABLED or not isinstance(entry, dict):
        return
    conn = _state_db_connect()
    if conn is None:
        return
    event_at = _coerce_int(entry.get("event_at"))
    event_id = hashlib.sha256(
        json.dumps(
            {
                "event_at": event_at,
                "event_type": entry.get("event_type"),
                "thread_id": entry.get("thread_id"),
                "summary": entry.get("summary"),
                "detail": entry.get("detail"),
            },
            sort_keys=True,
            default=str,
        ).encode("utf-8", errors="replace")
    ).hexdigest()
    try:
        conn.execute(
            """
            INSERT OR REPLACE INTO audit_events(
                id, event_at, event_type, severity, actor_type, thread_id,
                summary, detail, payload_json
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                event_id,
                event_at,
                str(entry.get("event_type") or ""),
                str(entry.get("severity") or ""),
                str(entry.get("actor_type") or ""),
                str(entry.get("thread_id") or ""),
                summarize_text(str(entry.get("summary") or ""), 500),
                summarize_text(str(entry.get("detail") or ""), 800),
                _state_db_json(entry),
            ),
        )
        conn.commit()
    except sqlite3.Error:
        pass
    finally:
        conn.close()


def truncate_block(text: str, limit: int = MAX_BLOCK_CHARS) -> str:
    value = (text or "").strip()
    if not value:
        return ""
    if len(value) <= limit:
        return value
    tail = value[-limit:]
    omitted = len(value) - len(tail)
    return f"[truncated {omitted} earlier characters]\n{tail}"


def summarize_text(text: str, limit: int = 180) -> str:
    value = " ".join((text or "").split())
    if len(value) <= limit:
        return value
    return f"{value[: limit - 1]}…"


HUMAN_INTERVENTION_OPEN_STATUSES = {"open", "acknowledged"}
HUMAN_INTERVENTION_ALL_STATUSES = {
    "open",
    "acknowledged",
    "answered",
    "closed",
    "canceled",
}
HUMAN_INTERVENTION_SEVERITIES = {"ask_now", "batch_review", "quiet_log"}


def normalize_human_intervention(value: Any) -> dict[str, Any]:
    payload = value if isinstance(value, dict) else {}
    options = payload.get("options")
    if not isinstance(options, list):
        try:
            options = json.loads(str(payload.get("options_json") or "[]"))
        except json.JSONDecodeError:
            options = []
    clean_options = [
        summarize_text(str(item), 120) for item in options if str(item or "").strip()
    ][:6]
    evidence = payload.get("evidence")
    if not isinstance(evidence, dict):
        try:
            evidence = json.loads(str(payload.get("evidence_json") or "{}"))
        except json.JSONDecodeError:
            evidence = {}
    kind = str(payload.get("kind") or "operator_decision").strip().lower()
    kind = re.sub(r"[^a-z0-9_.:-]+", "_", kind).strip("_") or "operator_decision"
    raw_severity = str(payload.get("severity") or "batch_review").strip().lower()
    severity_aliases = {
        "ask": "ask_now",
        "urgent": "ask_now",
        "blocker": "ask_now",
        "now": "ask_now",
        "review": "batch_review",
        "batch": "batch_review",
        "log": "quiet_log",
        "quiet": "quiet_log",
    }
    severity = severity_aliases.get(raw_severity, raw_severity)
    if severity not in HUMAN_INTERVENTION_SEVERITIES:
        severity = "batch_review"
    status = str(payload.get("status") or "open").strip().lower()
    if status not in HUMAN_INTERVENTION_ALL_STATUSES:
        status = "open"
    question = summarize_text(str(payload.get("question") or "").strip(), 240)
    detail = summarize_text(str(payload.get("detail") or "").strip(), 700)
    source_actor = summarize_text(str(payload.get("source_actor") or AGENT_NAME), 80)
    target_actor = summarize_text(str(payload.get("target_actor") or ""), 80)
    thread_id = summarize_text(str(payload.get("thread_id") or ""), 120)
    fingerprint = str(payload.get("fingerprint") or "").strip()
    if not fingerprint:
        material = json.dumps(
            {
                "kind": kind,
                "source_actor": source_actor,
                "target_actor": target_actor,
                "thread_id": thread_id,
                "question": question,
                "evidence": evidence,
            },
            sort_keys=True,
            default=str,
        )
        fingerprint = hashlib.sha256(material.encode("utf-8")).hexdigest()[:32]
    item_id = str(payload.get("id") or "").strip()
    if not item_id:
        item_id = f"hi_{hashlib.sha256(fingerprint.encode('utf-8')).hexdigest()[:16]}"
    created_at = _coerce_int(payload.get("created_at")) or now_ts()
    updated_at = _coerce_int(payload.get("updated_at")) or created_at
    closed_at = _coerce_int(payload.get("closed_at"))
    return {
        "id": item_id,
        "fingerprint": fingerprint,
        "kind": kind,
        "severity": severity,
        "status": status,
        "question": question or "Operator input is needed before this can continue.",
        "detail": detail,
        "options": clean_options,
        "evidence": evidence,
        "source_actor": source_actor,
        "target_actor": target_actor,
        "thread_id": thread_id,
        "created_at": created_at,
        "updated_at": updated_at,
        "closed_at": closed_at,
    }


def upsert_human_intervention(value: dict[str, Any]) -> dict[str, Any]:
    item = normalize_human_intervention(value)
    conn = _state_db_connect()
    created = False
    if conn is None:
        return item
    try:
        row = conn.execute(
            """
            SELECT payload_json
            FROM human_interventions
            WHERE fingerprint = ?
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (item["fingerprint"],),
        ).fetchone()
        if row:
            try:
                existing = normalize_human_intervention(json.loads(row["payload_json"]))
            except json.JSONDecodeError:
                existing = {}
            if existing:
                existing_status = str(existing.get("status") or "").strip().lower()
                existing_closed_at = _coerce_int(existing.get("closed_at")) or 0
                existing_updated_at = _coerce_int(existing.get("updated_at")) or 0
                recently_closed_at = existing_closed_at or existing_updated_at
                if (
                    existing_status not in HUMAN_INTERVENTION_OPEN_STATUSES
                    and recently_closed_at
                    and now_ts() - recently_closed_at
                    <= HUMAN_INTERVENTION_SUPPRESS_SECONDS
                ):
                    return existing
                if existing_status in HUMAN_INTERVENTION_OPEN_STATUSES:
                    item["id"] = existing.get("id") or item["id"]
                    item["created_at"] = (
                        existing.get("created_at") or item["created_at"]
                    )
                    item["status"] = existing.get("status") or item["status"]
                else:
                    created = True
        else:
            created = True
        item["updated_at"] = now_ts()
        options_json = json.dumps(item["options"], sort_keys=True, default=str)
        evidence_json = json.dumps(item["evidence"], sort_keys=True, default=str)
        conn.execute(
            """
            INSERT OR REPLACE INTO human_interventions(
                id, fingerprint, kind, severity, status, question, detail,
                options_json, evidence_json, source_actor, target_actor, thread_id,
                created_at, updated_at, closed_at, payload_json
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                item["id"],
                item["fingerprint"],
                item["kind"],
                item["severity"],
                item["status"],
                item["question"],
                item["detail"],
                options_json,
                evidence_json,
                item["source_actor"],
                item["target_actor"],
                item["thread_id"],
                item["created_at"],
                item["updated_at"],
                item["closed_at"],
                _state_db_json(item),
            ),
        )
        conn.commit()
    except sqlite3.Error:
        return item
    finally:
        conn.close()
    if created:
        append_audit_event(
            event_type="human_intervention.raised",
            summary=item["question"],
            detail=item["detail"],
            severity="warn" if item["severity"] == "ask_now" else "info",
            actor_type="system",
            thread_id=item["thread_id"],
            payload={
                "intervention_id": item["id"],
                "kind": item["kind"],
                "severity": item["severity"],
                "source_actor": item["source_actor"],
                "target_actor": item["target_actor"],
                "fingerprint": item["fingerprint"],
            },
        )
    return item


def update_human_intervention_status(
    intervention_id: str,
    action: str,
    *,
    note: str = "",
    actor_ip: str = "",
) -> dict[str, Any]:
    clean_id = str(intervention_id or "").strip()
    if not clean_id:
        raise ValueError("intervention id is required")
    clean_action = str(action or "").strip().lower().replace("-", "_")
    action_status = {
        "ack": "acknowledged",
        "acknowledge": "acknowledged",
        "acknowledged": "acknowledged",
        "defer": "acknowledged",
        "deferred": "acknowledged",
        "complete": "answered",
        "completed": "answered",
        "done": "answered",
        "answer": "answered",
        "answered": "answered",
        "approve": "answered",
        "approved": "answered",
        "access_done": "answered",
        "retry": "answered",
        "retry_abandoned": "answered",
        "close": "closed",
        "closed": "closed",
        "cancel": "canceled",
        "canceled": "canceled",
        "not_actionable": "canceled",
        "not-actionable": "canceled",
    }
    next_status = action_status.get(clean_action)
    if not next_status:
        raise ValueError("unsupported human intervention action")
    conn = _state_db_connect()
    if conn is None:
        raise RuntimeError("state db is unavailable")
    try:
        row = conn.execute(
            """
            SELECT payload_json
            FROM human_interventions
            WHERE id = ? OR fingerprint = ?
            ORDER BY updated_at DESC
            LIMIT 1
            """,
            (clean_id, clean_id),
        ).fetchone()
        if not row:
            raise ValueError("human intervention not found")
        try:
            item = normalize_human_intervention(json.loads(row["payload_json"]))
        except json.JSONDecodeError as exc:
            raise ValueError("human intervention payload is corrupt") from exc
        now = now_ts()
        item["status"] = next_status
        item["updated_at"] = now
        if next_status not in HUMAN_INTERVENTION_OPEN_STATUSES:
            item["closed_at"] = now
        evidence = item.get("evidence")
        if not isinstance(evidence, dict):
            evidence = {}
        evidence["operator_action"] = clean_action
        evidence["operator_note"] = summarize_text(note, 240)
        evidence["operator_action_at"] = now
        item["evidence"] = evidence
        evidence_json = json.dumps(item["evidence"], sort_keys=True, default=str)
        conn.execute(
            """
            UPDATE human_interventions
            SET status = ?, updated_at = ?, closed_at = ?, evidence_json = ?,
                payload_json = ?
            WHERE id = ?
            """,
            (
                item["status"],
                item["updated_at"],
                item["closed_at"] or 0,
                evidence_json,
                _state_db_json(item),
                item["id"],
            ),
        )
        conn.commit()
    except sqlite3.Error as exc:
        raise RuntimeError("could not update human intervention") from exc
    finally:
        conn.close()
    append_audit_event(
        event_type="human_intervention.actioned",
        summary=f"Operator marked intervention {clean_action}.",
        detail=summarize_text(item.get("question") or "", 220),
        severity="info" if next_status == "acknowledged" else "warn",
        actor_type="operator",
        actor_ip=actor_ip,
        thread_id=str(item.get("thread_id") or ""),
        payload={
            "intervention_id": item["id"],
            "fingerprint": item["fingerprint"],
            "kind": item["kind"],
            "action": clean_action,
            "status": item["status"],
        },
    )
    return item


def _looks_like_instructional_human_gate_preview(text: str) -> bool:
    lower_text = str(text or "").lower()
    instructional_markers = (
        "for the screenshot:",
        "click access done",
        "click `access done`",
        "if you can't deal",
        "if you can\u2019t deal",
        "mark this as not actionable",
        "i staged tui improvements",
    )
    return any(marker in lower_text for marker in instructional_markers)


def load_human_interventions(
    *,
    limit: int = MAX_HUMAN_INTERVENTION_ITEMS,
    statuses: set[str] | tuple[str, ...] | list[str] = tuple(
        HUMAN_INTERVENTION_OPEN_STATUSES
    ),
) -> list[dict[str, Any]]:
    wanted = [
        str(status).strip().lower()
        for status in statuses
        if str(status or "").strip().lower() in HUMAN_INTERVENTION_ALL_STATUSES
    ]
    if not wanted:
        wanted = ["open", "acknowledged"]
    conn = _state_db_connect()
    if conn is None:
        return []
    placeholders = ",".join("?" for _ in wanted)
    try:
        rows = conn.execute(
            f"""
            SELECT payload_json
            FROM human_interventions
            WHERE status IN ({placeholders})
            ORDER BY
                CASE severity
                    WHEN 'ask_now' THEN 0
                    WHEN 'batch_review' THEN 1
                    ELSE 2
                END,
                updated_at DESC
            LIMIT ?
            """,
            (*wanted, max(1, int(limit or MAX_HUMAN_INTERVENTION_ITEMS))),
        ).fetchall()
    except sqlite3.Error:
        return []
    finally:
        conn.close()
    items: list[dict[str, Any]] = []
    for row in rows:
        try:
            item = normalize_human_intervention(json.loads(row["payload_json"]))
        except (json.JSONDecodeError, KeyError, TypeError):
            continue
        if item.get("kind") == "auth_or_human_gate":
            evidence = item.get("evidence")
            preview = ""
            if isinstance(evidence, dict):
                preview = str(evidence.get("text_preview") or "")
            if not item.get(
                "thread_id"
            ) or _looks_like_instructional_human_gate_preview(preview):
                continue
        items.append(item)
    return items


def _snapshot_text_for_human_intervention(snapshot: dict[str, Any]) -> str:
    chunks = [
        str(snapshot.get("status_message") or ""),
        str(snapshot.get("last_error") or ""),
        str(snapshot.get("last_response") or ""),
        str(snapshot.get("last_action_detail") or ""),
    ]
    history = snapshot.get("history")
    if isinstance(history, list):
        for entry in history[-6:]:
            if isinstance(entry, dict):
                chunks.extend(
                    [
                        str(entry.get("prompt") or ""),
                        str(entry.get("response") or ""),
                        str(entry.get("error") or ""),
                    ]
                )
    return "\n".join(chunk for chunk in chunks if chunk.strip())


def _snapshot_active_text_for_human_gate(snapshot: dict[str, Any]) -> str:
    chunks = [
        str(snapshot.get("status_message") or ""),
        str(snapshot.get("last_error") or ""),
        str(snapshot.get("last_action_detail") or ""),
    ]
    return "\n".join(chunk for chunk in chunks if chunk.strip())


def detect_human_interventions(snapshot: dict[str, Any]) -> list[dict[str, Any]]:
    text = _snapshot_text_for_human_intervention(snapshot)
    lower_text = text.lower()
    detected: list[dict[str, Any]] = []
    thread_match = re.search(r"\bth_[A-Za-z0-9_.:-]+", text)
    thread_id = (
        str(thread_match.group(0))
        if thread_match
        else str(snapshot.get("thread_id") or "")
    )
    if "actor_not_allowed_for_target" in lower_text:
        target_actor = ""
        for candidate in (
            "eyebat",
            "glimpser",
            "netops",
            "infra",
            "norman",
            "subprime",
        ):
            if candidate in lower_text:
                target_actor = candidate
                break
        detected.append(
            upsert_human_intervention(
                {
                    "kind": "bbs_permission_block",
                    "severity": "ask_now",
                    "fingerprint": ":".join(
                        [
                            "bbs_permission_block",
                            str(AGENT_NAME or SESSION),
                            target_actor,
                            thread_id,
                        ]
                    ),
                    "question": (
                        "BBS routing is blocked by actor permissions. Should Norman/Subprime "
                        "adjust the route, ask the target bot to pick it up, or leave it blocked?"
                    ),
                    "detail": (
                        "Detected actor_not_allowed_for_target. The bot can see the handoff "
                        "need, but current BBS permissions do not allow the requested target."
                    ),
                    "options": [
                        "Grant or adjust the BBS route",
                        "Ask the target bot to pick up the thread",
                        "Leave blocked and record why",
                    ],
                    "evidence": {
                        "blocker_code": "actor_not_allowed_for_target",
                        "thread_id": thread_id,
                        "text_preview": summarize_text(text, 500),
                    },
                    "source_actor": AGENT_NAME,
                    "target_actor": target_actor,
                    "thread_id": thread_id,
                }
            )
        )
    human_gate_text = _snapshot_active_text_for_human_gate(snapshot)
    lower_human_gate_text = human_gate_text.lower()
    abandoned_after_restart = (
        "web prompt was abandoned after restart" in lower_human_gate_text
        or (
            "no running model process was found" in lower_human_gate_text
            and "restart" in lower_human_gate_text
        )
    )
    if thread_id and abandoned_after_restart:
        detected.append(
            upsert_human_intervention(
                {
                    "kind": "stale_web_prompt_after_restart",
                    "severity": "ask_now",
                    "fingerprint": ":".join(
                        [
                            "stale_web_prompt_after_restart",
                            str(AGENT_NAME or SESSION),
                            thread_id,
                        ]
                    ),
                    "question": (
                        "A web prompt was parked after restart. Should this TUI review, "
                        "draft, retry, or close the stale blocker?"
                    ),
                    "detail": (
                        "The worker/model process is no longer running. This is restart "
                        "recovery state, not automatically a provider, sign-in, or captcha failure."
                    ),
                    "options": [
                        "Review the parked prompt details",
                        "Draft a cleanup note without sending",
                        "Retry the abandoned prompt as a new model turn",
                        "Defer and keep the blocker visible",
                        "Mark this as not actionable",
                    ],
                    "evidence": {
                        "thread_id": thread_id,
                        "text_preview": summarize_text(human_gate_text, 500),
                    },
                    "source_actor": AGENT_NAME,
                    "thread_id": thread_id,
                }
            )
        )
        return detected
    human_gate_terms = (
        "captcha",
        "verification required",
        "device code",
        "sign-in required",
        "sign in required",
        "needs reauth",
        "requires reauth",
        "browser sign-in",
    )
    if thread_id and any(term in lower_human_gate_text for term in human_gate_terms):
        detected.append(
            upsert_human_intervention(
                {
                    "kind": "auth_or_human_gate",
                    "severity": "ask_now",
                    "fingerprint": ":".join(
                        [
                            "auth_or_human_gate",
                            str(AGENT_NAME or SESSION),
                            thread_id,
                        ]
                    ),
                    "question": (
                        "A human gate appears to be blocking progress. Can you complete "
                        "the sign-in, captcha, or verification step for this TUI?"
                    ),
                    "detail": "Detected auth/captcha/verification language in the active TUI state.",
                    "options": [
                        "Complete the human gate now",
                        "Defer and keep the blocker visible",
                        "Mark this as not actionable",
                    ],
                    "evidence": {
                        "thread_id": thread_id,
                        "text_preview": summarize_text(human_gate_text, 500),
                    },
                    "source_actor": AGENT_NAME,
                    "thread_id": thread_id,
                }
            )
        )
    return detected


