def _coerce_int(value: Any) -> int:
    try:
        return int(value or 0)
    except (TypeError, ValueError):
        return 0


def _coerce_float(value: Any) -> float:
    try:
        return float(value or 0)
    except (TypeError, ValueError):
        return 0.0


def host_pressure_guard_snapshot(snapshot_at: int | None = None) -> dict[str, Any]:
    if not HOST_PRESSURE_GUARD_ENABLED:
        return {"enabled": False, "stale": True}
    payload = read_json(HOST_PRESSURE_GUARD_PATH, {})
    if not isinstance(payload, dict) or not payload:
        return {"enabled": True, "stale": True, "missing": True}
    observed_at = snapshot_at if snapshot_at is not None else now_ts()
    checked_at = _coerce_int(payload.get("checked_at_epoch"))
    stale = (
        checked_at <= 0 or observed_at - checked_at > HOST_PRESSURE_GUARD_STALE_SECONDS
    )
    guard = dict(payload)
    guard["enabled"] = True
    guard["stale"] = stale
    guard["path"] = str(HOST_PRESSURE_GUARD_PATH)
    return guard


def host_pressure_guard_blocks_new_work(guard: dict[str, Any]) -> bool:
    if not guard or guard.get("stale") or guard.get("enabled") is False:
        return False
    admission = guard.get("admission")
    if not isinstance(admission, dict):
        return False
    return str(admission.get("action") or "").strip() == "block_new_work"


def host_pressure_guard_defers_heavy_work(guard: dict[str, Any]) -> bool:
    if not guard or guard.get("stale") or guard.get("enabled") is False:
        return False
    admission = guard.get("admission")
    if not isinstance(admission, dict):
        return False
    return str(admission.get("action") or "").strip() == "defer_heavy_work"


def host_pressure_guard_work_is_heavy(
    turn_control: dict[str, Any], *, speed: str, job_budget: str
) -> bool:
    workload = str(turn_control.get("workload") or "").strip()
    if workload == "status":
        return False
    if response_reasoning_effort(speed) == "xhigh":
        return True
    if job_budget_timeout_seconds(job_budget) > 15 * 60:
        return True
    return workload in {
        "implementation",
        "approval_boundary",
        "long_run_approval",
    }


def host_pressure_guard_message(guard: dict[str, Any]) -> str:
    admission = guard.get("admission") if isinstance(guard, dict) else {}
    reason = (
        str(admission.get("reason") or "").strip()
        if isinstance(admission, dict)
        else ""
    )
    target = str(guard.get("target") or "this host").strip()
    if reason:
        return f"Host pressure guard is blocking new work on {target}: {reason}."
    return f"Host pressure guard is blocking new work on {target}."


def _parse_env_file(path: Path) -> dict[str, str]:
    values: dict[str, str] = {}
    try:
        lines = path.expanduser().read_text(encoding="utf-8").splitlines()
    except OSError:
        return values
    for raw_line in lines:
        line = raw_line.strip()
        if not line or line.startswith("#") or "=" not in line:
            continue
        key, value = line.split("=", 1)
        values[key.strip()] = value.strip().strip("\"'")
    return values


def bbs_summary_token() -> str:
    token = (
        os.environ.get("NORMAN_CODEX_BBS_TOKEN")
        or os.environ.get("NORMAN_CODEX_BBS_TOKEN")
        or os.environ.get("SWITCHBOARD_TOKEN")
        or ""
    ).strip()
    if token:
        return token
    if BBS_SUMMARY_TOKEN_FILE:
        try:
            return (
                Path(BBS_SUMMARY_TOKEN_FILE)
                .expanduser()
                .read_text(encoding="utf-8")
                .strip()
            )
        except OSError:
            return ""
    if BBS_SUMMARY_ENV_FILE:
        env = _parse_env_file(Path(BBS_SUMMARY_ENV_FILE))
        token = str(env.get("SWITCHBOARD_TOKEN") or "").strip()
        if token:
            return token
        token_file = str(env.get("SWITCHBOARD_TOKEN_FILE") or "").strip()
        if token_file:
            try:
                return Path(token_file).expanduser().read_text(encoding="utf-8").strip()
            except OSError:
                return ""
    return ""


def default_bbs_janitor_summary(
    *,
    state: str = "unavailable",
    summary: str = "BBS janitor unavailable",
    detail: str = "",
    enabled: bool | None = None,
) -> dict[str, Any]:
    return {
        "schema": "norman.tui.bbs-janitor-summary.v1",
        "enabled": (BBS_JANITOR_SUMMARY_ENABLED if enabled is None else bool(enabled)),
        "state": state,
        "summary": summary,
        "detail": detail,
        "generated_at": now_ts(),
        "open_thread_count": 0,
        "action_count": 0,
        "safe_count": 0,
        "review_count": 0,
        "live_actor_count": 0,
        "recently_closed_count": 0,
        "recent_done_count": 0,
        "recent_blocked_count": 0,
        "recently_closed": [],
        "actions": [],
    }


def _load_bbs_janitor_module() -> Any | None:
    global BBS_JANITOR_MODULE, BBS_JANITOR_MODULE_MISSING
    if BBS_JANITOR_MODULE is not None:
        return BBS_JANITOR_MODULE
    if BBS_JANITOR_MODULE_MISSING:
        return None
    candidates = [
        WEB_SCRIPT_PATH.with_name("bbs_janitor.py"),
        WEB_SCRIPT_PATH.parent.parent / "bbs_janitor.py",
    ]
    for path in candidates:
        try:
            if not path.exists():
                continue
            spec = importlib.util.spec_from_file_location("bbs_janitor", path)
            if not spec or not spec.loader:
                continue
            module = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(module)
            BBS_JANITOR_MODULE = module
            return module
        except Exception:
            continue
    BBS_JANITOR_MODULE_MISSING = True
    return None


def _bbs_janitor_action_summary(action: dict[str, Any]) -> dict[str, Any]:
    return {
        "action": str(action.get("action") or "").strip(),
        "safety": str(action.get("safety") or "").strip(),
        "thread_id": str(action.get("thread_id") or "").strip(),
        "title": summarize_text(str(action.get("title") or ""), 96),
        "owner": str(action.get("owner") or "").strip(),
        "target_owner": str(action.get("target_owner") or "").strip(),
        "status": str(action.get("status") or "").strip(),
        "priority": str(action.get("priority") or "").strip(),
        "reason": summarize_text(str(action.get("reason") or ""), 180),
        "age_days": action.get("age_days"),
    }


def _bbs_terminal_thread_timestamp(thread: dict[str, Any]) -> int:
    loop = thread.get("loop") if isinstance(thread.get("loop"), dict) else {}
    for value in (
        loop.get("closed_at"),
        thread.get("updated_at"),
        thread.get("last_message_at"),
        thread.get("created_at"),
    ):
        parsed = _parse_bbs_timestamp(value)
        if parsed:
            return parsed
    return 0


def _bbs_recent_terminal_tone(status: str) -> str:
    clean = status.strip().lower()
    if clean == "blocked":
        return "review"
    return "safe"


def _bbs_recent_terminal_loop_label(status: str) -> str:
    clean = status.strip().lower()
    if clean in {"done", "closed"}:
        return "Loop closed"
    if clean == "blocked":
        return "Loop blocked"
    if clean == "canceled":
        return "Loop canceled"
    return "Loop terminal"


def _bbs_recent_terminal_summary(
    thread: dict[str, Any], *, observed_at: int
) -> dict[str, Any] | None:
    status = str(thread.get("status") or "").strip().lower()
    if status not in BBS_TERMINAL_STATUSES:
        return None
    closed_at = _bbs_terminal_thread_timestamp(thread)
    if not closed_at:
        return None
    closed_age_seconds = max(0, observed_at - closed_at)
    if closed_age_seconds > BBS_RECENT_TERMINAL_WINDOW_SECONDS:
        return None
    title = str(thread.get("title") or thread.get("thread_id") or "").strip()
    thread_id = str(thread.get("thread_id") or "").strip()
    owner = str(thread.get("owner") or "").strip()
    priority = str(thread.get("priority") or "").strip()
    status_label = status.replace("_", " ")
    loop_label = _bbs_recent_terminal_loop_label(status)
    activity = (
        f"{loop_label} recently"
        if not closed_age_seconds
        else f"{loop_label} {closed_age_seconds}s ago"
    )
    return {
        "thread_id": thread_id,
        "title": title,
        "owner": owner,
        "priority": priority,
        "status": status,
        "status_label": status_label,
        "loop_state": "blocked" if status == "blocked" else "closed",
        "loop_label": loop_label,
        "tone": _bbs_recent_terminal_tone(status),
        "closed_at": closed_at,
        "closed_age_seconds": closed_age_seconds,
        "activity": activity,
    }


def summarize_bbs_janitor_payload(
    threads_payload: dict[str, Any],
    bots_payload: dict[str, Any],
) -> dict[str, Any]:
    if not BBS_JANITOR_SUMMARY_ENABLED:
        return default_bbs_janitor_summary(
            state="disabled",
            summary="BBS janitor disabled",
            enabled=False,
        )
    janitor = _load_bbs_janitor_module()
    if janitor is None:
        return default_bbs_janitor_summary(
            state="unavailable",
            summary="BBS janitor helper missing",
            detail="bbs_janitor.py is not deployed beside this console.",
        )
    if not threads_payload.get("ok"):
        return default_bbs_janitor_summary(
            state="error",
            summary="BBS janitor cannot read threads",
            detail=str(
                threads_payload.get("error") or threads_payload.get("status") or ""
            ),
        )
    if not bots_payload.get("ok"):
        return default_bbs_janitor_summary(
            state="error",
            summary="BBS janitor cannot read bot directory",
            detail=str(bots_payload.get("error") or bots_payload.get("status") or ""),
        )
    threads = [
        thread
        for thread in threads_payload.get("threads") or []
        if isinstance(thread, dict)
    ]
    observed_at = now_ts()
    live_actors = janitor.live_actors_from_bots(bots_payload)
    owner_aliases = dict(getattr(janitor, "DEFAULT_OWNER_ALIASES", {}) or {})
    actions = janitor.classify_threads(
        threads,
        live_actors=live_actors,
        owner_aliases=owner_aliases,
        stale_days=BBS_JANITOR_STALE_DAYS,
    )
    recent_terminal_items = [
        item
        for item in (
            _bbs_recent_terminal_summary(thread, observed_at=observed_at)
            for thread in threads
        )
        if item is not None
    ]
    recent_terminal_items.sort(
        key=lambda item: (
            -_coerce_int(item.get("closed_at")),
            str(item.get("thread_id") or ""),
        )
    )
    recent_done_count = sum(
        1
        for item in recent_terminal_items
        if str(item.get("status") or "") in {"done", "closed", "canceled"}
    )
    recent_blocked_count = sum(
        1
        for item in recent_terminal_items
        if str(item.get("status") or "") == "blocked"
    )
    safe_count = sum(1 for item in actions if item.get("safety") == "safe")
    review_count = sum(1 for item in actions if item.get("safety") != "safe")
    open_thread_count = len(janitor._open_threads(threads))
    if review_count:
        state = "review"
        summary = (
            "1 BBS review needed"
            if review_count == 1
            else f"{review_count} BBS reviews needed"
        )
    elif safe_count:
        state = "safe"
        summary = (
            "1 safe BBS cleanup"
            if safe_count == 1
            else f"{safe_count} safe BBS cleanups"
        )
    else:
        state = "clear"
        summary = "BBS janitor clear"
    detail_parts = [
        f"{open_thread_count} open",
        f"{safe_count} safe",
        f"{review_count} review",
        f"{len(live_actors)} live actors",
    ]
    if recent_done_count:
        detail_parts.append(f"{recent_done_count} done recent")
    if recent_blocked_count:
        detail_parts.append(f"{recent_blocked_count} blocked recent")
    return {
        "schema": "norman.tui.bbs-janitor-summary.v1",
        "enabled": True,
        "state": state,
        "summary": summary,
        "detail": " · ".join(detail_parts),
        "generated_at": observed_at,
        "open_thread_count": open_thread_count,
        "action_count": len(actions),
        "safe_count": safe_count,
        "review_count": review_count,
        "live_actor_count": len(live_actors),
        "recently_closed_count": len(recent_terminal_items),
        "recent_done_count": recent_done_count,
        "recent_blocked_count": recent_blocked_count,
        "recently_closed": recent_terminal_items[:BBS_RECENT_TERMINAL_MAX_ITEMS],
        "actions": [
            _bbs_janitor_action_summary(action)
            for action in actions[:BBS_JANITOR_MAX_ACTIONS]
        ],
    }


