def bbs_request_json(
    path: str,
    *,
    token: str,
    method: str = "GET",
    payload: dict[str, Any] | None = None,
    timeout_seconds: float | None = None,
) -> dict[str, Any]:
    url = f"{BBS_SUMMARY_URL.rstrip('/')}/{path.lstrip('/')}"
    data = None
    headers = {
        "Accept": "application/json",
        "Authorization": f"Bearer {token}",
    }
    if payload is not None:
        data = json.dumps(payload, separators=(",", ":")).encode("utf-8")
        headers["Content-Type"] = "application/json"
    req = urllib_request.Request(
        url,
        data=data,
        headers=headers,
        method=method.upper(),
    )
    timeout = (
        BBS_SUMMARY_TIMEOUT_SECONDS if timeout_seconds is None else timeout_seconds
    )
    with urllib_request.urlopen(req, timeout=timeout) as response:
        raw = response.read().decode("utf-8", errors="replace")
    payload = json.loads(raw or "{}")
    return payload if isinstance(payload, dict) else {}


def bbs_proxy_error(detail: str, *, state: str = "unavailable") -> dict[str, Any]:
    return {
        "ok": False,
        "state": state,
        "error": detail,
        "source_url": BBS_SUMMARY_URL,
    }


def load_bbs_thread_payload(thread_id: str) -> dict[str, Any]:
    clean = str(thread_id or "").strip()
    if not clean or not clean.startswith("th_"):
        return bbs_proxy_error("missing or invalid BBS thread id", state="bad_request")
    if not BBS_SUMMARY_ENABLED or not BBS_SUMMARY_URL:
        return bbs_proxy_error("BBS summary URL is not configured")
    token = bbs_summary_token()
    if not token:
        return bbs_proxy_error("BBS token is not configured")
    try:
        payload = bbs_request_json(f"/api/v1/threads/{quote(clean)}", token=token)
    except Exception as exc:
        return bbs_proxy_error(f"BBS thread fetch failed: {exc}")
    if isinstance(payload, dict):
        payload.setdefault("source_url", BBS_SUMMARY_URL)
        payload.setdefault(
            "board_url", f"{BBS_SUMMARY_URL.rstrip('/')}/threads/{quote(clean)}"
        )
        return payload
    return bbs_proxy_error("BBS thread response was not JSON")


def load_bbs_search_payload(query: str) -> dict[str, Any]:
    clean = str(query or "").strip()
    if not clean:
        return bbs_proxy_error("missing BBS search query", state="bad_request")
    if not BBS_SUMMARY_ENABLED or not BBS_SUMMARY_URL:
        return bbs_proxy_error("BBS summary URL is not configured")
    token = bbs_summary_token()
    if not token:
        return bbs_proxy_error("BBS token is not configured")
    try:
        if clean.startswith("msg_"):
            events_payload = bbs_request_json("/api/v1/events?limit=1000", token=token)
            events = (
                events_payload.get("events")
                if isinstance(events_payload.get("events"), list)
                else []
            )
            matches = [
                item
                for item in events
                if isinstance(item, dict)
                and isinstance(item.get("message"), dict)
                and str((item.get("message") or {}).get("message_id") or "") == clean
            ]
            return {
                "ok": True,
                "q": clean,
                "count": len(matches),
                "results": matches,
                "source": "events",
                "source_url": BBS_SUMMARY_URL,
            }
        payload = bbs_request_json(
            f"/api/v1/search?{urlencode({'q': clean, 'limit': '50'})}",
            token=token,
        )
    except Exception as exc:
        return bbs_proxy_error(f"BBS search failed: {exc}")
    if isinstance(payload, dict):
        payload.setdefault("source_url", BBS_SUMMARY_URL)
        return payload
    return bbs_proxy_error("BBS search response was not JSON")


def publish_bbs_heartbeat(token: str) -> dict[str, Any]:
    if not BBS_SUMMARY_ACTOR:
        return {}
    return bbs_request_json(
        f"/api/v1/actors/{quote(BBS_SUMMARY_ACTOR)}/heartbeat",
        token=token,
        method="POST",
        timeout_seconds=min(3.0, BBS_SUMMARY_TIMEOUT_SECONDS),
        payload={
            "actor": BBS_SUMMARY_ACTOR,
            "agent": AGENT_NAME,
            "host": HOST_NAME,
            "session": SESSION,
            "model": MODEL,
            "service_tier": DEFAULT_SERVICE_TIER,
            "ui_version": UI_VERSION,
            "port": PORT,
        },
    )


def _parse_bbs_timestamp(value: Any) -> int:
    text = str(value or "").strip()
    if not text:
        return 0
    try:
        return int(datetime.fromisoformat(text.replace("Z", "+00:00")).timestamp())
    except (TypeError, ValueError, OSError):
        return 0


def _bbs_actor_label(actor: str) -> str:
    clean = str(actor or "").strip()
    return clean or "owner"


def _bbs_thread_activity(
    *,
    owner: str,
    loop_state: str,
    loop_label: str,
    owner_heartbeat: str,
    owner_heartbeat_age_seconds: int,
    picked_up_by: str,
    eta: str,
) -> str:
    owner_label = _bbs_actor_label(owner)
    state = loop_state.strip().lower()
    if state == "waiting_pickup":
        base = f"Owner {owner_label} needs pickup ACK; no fork or done yet"
        if owner_heartbeat_age_seconds:
            return f"{base}; owner heartbeat " f"{owner_heartbeat_age_seconds}s"
        return base
    if state == "picked_up":
        pickup = _bbs_actor_label(picked_up_by or owner)
        eta_text = f"; ETA {eta}" if eta else ""
        return f"ACKed by {pickup}; waiting for DONE{eta_text}"
    if state == "owner_offline":
        return f"{owner_label} heartbeat missing"
    if state == "owner_stale":
        return f"{owner_label} heartbeat stale"
    if state == "closed":
        return "Thread closed"
    if loop_label:
        return loop_label
    if owner_heartbeat:
        return f"{owner_label} heartbeat {owner_heartbeat}"
    return f"Open with {owner_label}"


def _bbs_thread_lifecycle(loop_state: str, status: str) -> tuple[str, str, str]:
    state = loop_state.strip().lower()
    clean_status = status.strip().lower()
    if clean_status in {"closed", "done"} or state == "closed":
        return "done", "done", "No action needed."
    if clean_status == "blocked":
        return (
            "blocked",
            "blocked",
            "Thread is blocked. Keep the reason current, then unblock, fork, or close done.",
        )
    if state == "waiting_pickup":
        return (
            "needs_ack",
            "needs owner pickup",
            "Owner TUI should ACK only if picking up; otherwise fork, mark BLOCKED, or close DONE.",
        )
    if state == "picked_up":
        return (
            "working_needs_done",
            "working",
            "Owner has acknowledged. Expect a done/blocked update or child fork.",
        )
    if state == "owner_offline":
        return (
            "owner_unreachable",
            "owner offline",
            "Owner heartbeat is missing. Reassign or restore the owner TUI.",
        )
    if state == "owner_stale":
        return (
            "owner_stale",
            "owner stale",
            "Owner heartbeat is stale. Confirm the target TUI is alive.",
        )
    return "open", "open", "Thread is open; confirm owner and next action."


def _bbs_thread_is_terminal(item: dict[str, Any]) -> bool:
    lifecycle = str(item.get("lifecycle") or "").strip().lower()
    status = str(item.get("status") or "").strip().lower()
    loop_state = str(item.get("loop_state") or "").strip().lower()
    return (
        lifecycle in BBS_TERMINAL_LIFECYCLES
        or status in BBS_TERMINAL_STATUSES
        or loop_state == "closed"
    )


def _bbs_janitor_action_is_terminal(action: dict[str, Any]) -> bool:
    status = str(action.get("status") or "").strip().lower()
    lifecycle = str(action.get("lifecycle") or "").strip().lower()
    loop_state = str(action.get("loop_state") or "").strip().lower()
    return (
        status in BBS_TERMINAL_STATUSES
        or lifecycle in BBS_TERMINAL_LIFECYCLES
        or loop_state == "closed"
    )


def _bbs_lifecycle_command_hints(
    *,
    thread_id: str,
    owner: str = "",
    title: str = "",
    ack_enabled: bool = True,
    blocked_reason: str = "",
) -> dict[str, str]:
    clean_thread_id = str(thread_id or "").strip()
    actor = str(BBS_SUMMARY_ACTOR or owner or AGENT_SLUG).strip()
    clean_owner = str(owner or actor or "owner").strip()
    clean_title = str(title or clean_thread_id or "BBS handoff").strip()
    if not clean_thread_id:
        return {
            "ack_command": "",
            "ack_command_label": "",
            "ack_command_kind": "",
            "ack_command_note": "",
            "done_command": "",
            "blocked_command": "",
            "fork_command_hint": "",
        }
    actor_arg = f" --actor {shlex.quote(actor)}" if actor else ""
    is_takeover = bool(actor and clean_owner and actor != clean_owner)
    if is_takeover:
        ack_note = f"Picked up by {actor}; taking over from owner {clean_owner}."
        ack_label = "TAKEOVER ACK"
        ack_kind = "takeover_ack"
        ack_explainer = (
            f"Runs as {actor}; use only if this console is taking ownership from "
            f"{clean_owner}."
        )
    else:
        ack_note = "Picked up; working now."
        ack_label = "ACK"
        ack_kind = "owner_ack"
        ack_explainer = "Use only when the owner is picking up the task."
    if not ack_enabled:
        ack_note = ""
        ack_label = "ACK disabled"
        ack_kind = "ack_disabled"
        ack_explainer = "ACK is disabled until the creator adds body/evidence."
    thread_arg = shlex.quote(clean_thread_id)
    owner_arg = shlex.quote(clean_owner)
    child_title = shlex.quote(f"{clean_title} child task")
    clean_blocked_reason = (
        str(blocked_reason or "").strip()
        or "Blocked: describe the blocker and owner needed."
    )
    return {
        "ack_command": ""
        if not ack_enabled
        else (
            f"python3 scripts/bbs_task_lifecycle.py ack{actor_arg} {thread_arg} "
            f'--eta "15m" --note {shlex.quote(ack_note)}'
        ),
        "ack_command_label": ack_label,
        "ack_command_kind": ack_kind,
        "ack_command_note": ack_explainer,
        "done_command": (
            f"python3 scripts/bbs_task_lifecycle.py done{actor_arg} {thread_arg} "
            '--reason "Completed and posted result."'
        ),
        "blocked_command": (
            f"python3 scripts/bbs_task_lifecycle.py blocked{actor_arg} {thread_arg} "
            f"--reason {shlex.quote(clean_blocked_reason)}"
        ),
        "fork_command_hint": (
            f"python3 scripts/bbs_task_lifecycle.py fork{actor_arg} {thread_arg} "
            f"--title {child_title} --owner {owner_arg} "
            '--summary "Finite child task with expected done condition." '
            "--site <site> --system <system> --topic <topic> --lane <lane>"
        ),
    }


def _bbs_thread_tone(priority: str, loop_state: str, lifecycle: str) -> str:
    priority = priority.strip().lower()
    state = loop_state.strip().lower()
    clean_lifecycle = lifecycle.strip().lower()
    if priority == "urgent":
        return "alert"
    if clean_lifecycle in {"blocked", "missing_context"}:
        return "review"
    if clean_lifecycle == "needs_ack" or state == "waiting_pickup":
        return "ack"
    if clean_lifecycle == "working_needs_done" or state == "picked_up":
        return "working"
    if clean_lifecycle == "owner_unreachable" or state == "owner_offline":
        return "offline"
    if clean_lifecycle == "owner_stale" or state == "owner_stale":
        return "stale"
    if priority == "high":
        return "watch"
    return "neutral"


def _bbs_handoff_context_sources(
    thread: dict[str, Any],
    *,
    message_count: int,
    message_count_present: bool,
) -> list[str]:
    sources: list[str] = []
    if message_count > 0:
        sources.append("messages")
    for key in ("summary", "body"):
        if str(thread.get(key) or "").strip():
            sources.append(key)
    evidence = thread.get("evidence")
    if (
        isinstance(evidence, (dict, list))
        and evidence
        or not isinstance(evidence, (dict, list))
        and str(evidence or "").strip()
    ):
        sources.append("evidence")
    if (
        not sources
        and not message_count_present
        and str(thread.get("last_message_at") or "").strip()
    ):
        sources.append("last_message")
    return sources


def _bbs_thread_summary(thread: dict[str, Any], *, observed_at: int) -> dict[str, Any]:
    loop = thread.get("loop") if isinstance(thread.get("loop"), dict) else {}
    last_message_at = _parse_bbs_timestamp(thread.get("last_message_at"))
    age_seconds = max(0, observed_at - last_message_at) if last_message_at else 0
    priority = str(thread.get("priority") or "").strip()
    owner = str(thread.get("owner") or "").strip()
    loop_state = str(loop.get("state") or "").strip()
    loop_label = str(loop.get("label") or "").strip()
    owner_heartbeat = str(loop.get("owner_heartbeat") or "").strip()
    owner_heartbeat_age_seconds = _coerce_int(loop.get("owner_heartbeat_age_seconds"))
    picked_up_by = str(loop.get("picked_up_by") or "").strip()
    eta = str(loop.get("eta") or "").strip()
    lifecycle, lifecycle_label, next_action = _bbs_thread_lifecycle(
        loop_state,
        str(thread.get("status") or ""),
    )
    thread_id = str(thread.get("thread_id") or "").strip()
    title = str(thread.get("title") or "").strip()
    message_count_present = "message_count" in thread
    message_count = _coerce_int(thread.get("message_count"))
    handoff_context_sources = _bbs_handoff_context_sources(
        thread,
        message_count=message_count,
        message_count_present=message_count_present,
    )
    has_handoff_context = bool(handoff_context_sources)
    missing_handoff_context = (
        loop_state.strip().lower() == "waiting_pickup" and not has_handoff_context
    )
    handoff_contract_state = "missing_context" if missing_handoff_context else "ready"
    handoff_contract_label = (
        "missing context" if missing_handoff_context else "context present"
    )
    handoff_contract_note = (
        "Creator should add body/evidence before owner ACKs."
        if missing_handoff_context
        else ""
    )
    if missing_handoff_context:
        lifecycle = "missing_context"
        lifecycle_label = "missing context"
        next_action = (
            "Creator should add body/evidence before owner ACKs; if context cannot "
            "be recovered, mark BLOCKED with the missing-context reason."
        )
        activity = (
            "Missing BBS context; creator must add body/evidence before owner ACKs"
        )
    else:
        activity = _bbs_thread_activity(
            owner=owner,
            loop_state=loop_state,
            loop_label=loop_label,
            owner_heartbeat=owner_heartbeat,
            owner_heartbeat_age_seconds=owner_heartbeat_age_seconds,
            picked_up_by=picked_up_by,
            eta=eta,
        )
    command_hints = _bbs_lifecycle_command_hints(
        thread_id=thread_id,
        owner=owner,
        title=title,
        ack_enabled=not missing_handoff_context,
        blocked_reason=(
            BBS_MISSING_CONTEXT_BLOCKED_REASON if missing_handoff_context else ""
        ),
    )
    return {
        "thread_id": thread_id,
        "title": title,
        "thread_console_url": _build_bbs_ref_href(thread_id) if thread_id else "",
        "thread_board_url": (
            f"{BBS_SUMMARY_URL.rstrip('/')}/threads/{quote(thread_id)}"
            if BBS_SUMMARY_URL and thread_id
            else ""
        ),
        "priority": priority,
        "status": str(thread.get("status") or "").strip(),
        "owner": owner,
        "loop_state": loop_state,
        "loop_label": loop_label,
        "lifecycle": lifecycle,
        "lifecycle_label": lifecycle_label,
        "next_action": next_action,
        "owner_heartbeat": owner_heartbeat,
        "owner_heartbeat_age_seconds": owner_heartbeat_age_seconds,
        "picked_up_by": picked_up_by,
        "picked_up_at": str(loop.get("picked_up_at") or "").strip(),
        "eta": eta,
        "message_count": message_count,
        "has_handoff_context": has_handoff_context,
        "handoff_context_sources": handoff_context_sources,
        "handoff_contract_state": handoff_contract_state,
        "handoff_contract_label": handoff_contract_label,
        "handoff_contract_note": handoff_contract_note,
        "activity": activity,
        "tone": _bbs_thread_tone(priority, loop_state, lifecycle),
        "last_message_at": str(thread.get("last_message_at") or "").strip(),
        "age_seconds": age_seconds,
        **command_hints,
    }


def _bbs_handoff_summary(
    thread_summaries: list[dict[str, Any]],
    janitor: dict[str, Any] | None = None,
) -> dict[str, Any]:
    janitor = janitor if isinstance(janitor, dict) else {}
    actions = janitor.get("actions") if isinstance(janitor.get("actions"), list) else []
    clean_actions = [action for action in actions if isinstance(action, dict)]
    needs_ack = [
        item
        for item in thread_summaries
        if str(item.get("lifecycle") or "") == "needs_ack"
    ]
    working = [
        item
        for item in thread_summaries
        if str(item.get("lifecycle") or "") == "working_needs_done"
    ]
    missing_context = [
        item
        for item in thread_summaries
        if str(item.get("lifecycle") or "") == "missing_context"
    ]
    owner_attention = [
        item
        for item in thread_summaries
        if str(item.get("lifecycle") or "") in {"owner_unreachable", "owner_stale"}
    ]
    terminal_thread_ids = {
        str(item.get("thread_id") or "").strip()
        for item in thread_summaries
        if str(item.get("thread_id") or "").strip() and _bbs_thread_is_terminal(item)
    }
    review_actions = [
        action
        for action in clean_actions
        if str(action.get("safety") or "").strip().lower() != "safe"
        and str(action.get("thread_id") or "").strip() not in terminal_thread_ids
        and not _bbs_janitor_action_is_terminal(action)
    ]
    unacked_actions = [
        action
        for action in review_actions
        if str(action.get("action") or "") == "unacked_handoff"
        and str(action.get("thread_id") or "").strip() not in terminal_thread_ids
    ]
    needs_ack_ids = {
        str(item.get("thread_id") or "").strip()
        for item in [*needs_ack, *unacked_actions]
        if str(item.get("thread_id") or "").strip()
    }
    needs_ack_total = len(needs_ack_ids) or len(needs_ack) + len(unacked_actions)
    focus: dict[str, Any] = {}
    if owner_attention:
        state = "owner_attention"
        focus = owner_attention[0]
        focus_lifecycle = str(focus.get("lifecycle") or "").strip()
        tone = "offline" if focus_lifecycle == "owner_unreachable" else "stale"
        summary = f"{len(owner_attention)} BBS owner attention"
        next_action = str(focus.get("next_action") or "Restore or reassign the owner.")
    elif missing_context:
        state = "review"
        focus = missing_context[0]
        tone = "review"
        summary = f"{len(missing_context)} BBS handoff missing context"
        next_action = str(
            focus.get("next_action")
            or "Creator should add body/evidence before owner ACKs."
        )
    elif unacked_actions:
        state = "needs_ack"
        focus = unacked_actions[0]
        tone = "ack"
        summary = f"{len(unacked_actions)} unacked BBS handoff"
        owner_label = _bbs_actor_label(str(focus.get("owner") or "owner"))
        next_action = (
            f"Owner TUI {owner_label!r} should ACK only if picking up. "
            "Otherwise a coordinator should fork, reassign, mark BLOCKED, or close DONE."
        )
    elif needs_ack:
        state = "needs_ack"
        focus = needs_ack[0]
        tone = "ack"
        summary = f"{len(needs_ack)} BBS handoff needs ACK"
        next_action = str(focus.get("next_action") or "Owner should ack pickup.")
    elif working:
        state = "working"
        focus = working[0]
        tone = "working"
        summary = f"{len(working)} BBS handoff working"
        next_action = str(
            focus.get("next_action") or "Owner should post done/blocked when complete."
        )
    elif review_actions:
        state = "review"
        focus = review_actions[0]
        tone = "review"
        summary = f"{len(review_actions)} BBS review needed"
        next_action = str(focus.get("reason") or "Review BBS queue hygiene.")
    else:
        state = "clear"
        tone = "ok"
        summary = "BBS handoffs clear"
        next_action = "No BBS handoff action needed."

    title = str(focus.get("title") or focus.get("thread_id") or "").strip()
    owner = str(focus.get("owner") or "").strip()
    reason = str(focus.get("reason") or focus.get("activity") or "").strip()
    thread_id = str(focus.get("thread_id") or "").strip()
    focus_missing_context = (
        str(focus.get("lifecycle") or "").strip().lower() == "missing_context"
        or str(focus.get("handoff_contract_state") or "").strip().lower()
        == "missing_context"
    )
    command_hints = _bbs_lifecycle_command_hints(
        thread_id=thread_id,
        owner=owner,
        title=title,
        ack_enabled=not focus_missing_context,
        blocked_reason=BBS_MISSING_CONTEXT_BLOCKED_REASON
        if focus_missing_context
        else "",
    )
    detail_parts = []
    if title:
        detail_parts.append(title)
    if owner:
        detail_parts.append(f"owner {owner}")
    if reason:
        detail_parts.append(reason)
    return {
        "state": state,
        "tone": tone,
        "summary": summary,
        "detail": " · ".join(detail_parts),
        "next_action": next_action,
        "ack_semantics": "manual_pickup_ack",
        "needs_ack": needs_ack_total,
        "working": len(working),
        "missing_context": len(missing_context),
        "owner_attention": len(owner_attention),
        "review": len(review_actions),
        "thread_id": thread_id,
        "owner": owner,
        "age_seconds": _coerce_int(focus.get("age_seconds")),
        **command_hints,
    }


def summarize_bbs_payload(payload: dict[str, Any]) -> dict[str, Any]:
    observed_at = now_ts()
    bot = payload.get("bot") if isinstance(payload.get("bot"), dict) else {}
    threads = payload.get("inbox") if isinstance(payload.get("inbox"), list) else []
    thread_summaries = [
        _bbs_thread_summary(thread, observed_at=observed_at)
        for thread in threads
        if isinstance(thread, dict)
    ]
    actionable_thread_summaries = [
        item for item in thread_summaries if not _bbs_thread_is_terminal(item)
    ]
    top_threads = thread_summaries[:BBS_SUMMARY_MAX_THREADS]
    inbox_count = _coerce_int(payload.get("inbox_count")) or len(threads)
    urgent_count = sum(
        1
        for thread in threads
        if isinstance(thread, dict)
        and str(thread.get("priority") or "").strip().lower() == "urgent"
    )
    high_count = sum(
        1
        for thread in threads
        if isinstance(thread, dict)
        and str(thread.get("priority") or "").strip().lower() == "high"
    )
    actionable_urgent_count = sum(
        1
        for item in actionable_thread_summaries
        if str(item.get("priority") or "").strip().lower() == "urgent"
    )
    actionable_high_count = sum(
        1
        for item in actionable_thread_summaries
        if str(item.get("priority") or "").strip().lower() == "high"
    )
    waiting_pickup_count = sum(
        1
        for item in thread_summaries
        if str(item.get("loop_state") or "").strip().lower() == "waiting_pickup"
    )
    missing_context_count = sum(
        1
        for item in thread_summaries
        if str(item.get("lifecycle") or "").strip().lower() == "missing_context"
    )
    picked_up_count = sum(
        1
        for item in thread_summaries
        if str(item.get("loop_state") or "").strip().lower() == "picked_up"
    )
    owner_offline_count = sum(
        1
        for item in thread_summaries
        if str(item.get("loop_state") or "").strip().lower() == "owner_offline"
    )
    owner_stale_count = sum(
        1
        for item in thread_summaries
        if str(item.get("loop_state") or "").strip().lower() == "owner_stale"
    )
    stale_count = sum(
        1
        for item in thread_summaries
        if (
            str(item.get("loop_state") or "").strip().lower() == "waiting_pickup"
            and _coerce_int(item.get("age_seconds")) >= BBS_SUMMARY_STALE_SECONDS
        )
    )
    heartbeat_ok = bool(bot.get("heartbeat_ok"))
    heartbeat_age_seconds = _coerce_int(bot.get("heartbeat_age_seconds"))
    if urgent_count or stale_count or owner_offline_count:
        state = "alert"
    elif (
        inbox_count
        or high_count
        or waiting_pickup_count
        or missing_context_count
        or owner_stale_count
    ):
        state = "watch"
    elif heartbeat_ok:
        state = "ok"
    else:
        state = "unknown"
    if urgent_count:
        tone = "alert"
    elif owner_offline_count:
        tone = "offline"
    elif stale_count or owner_stale_count:
        tone = "stale"
    elif missing_context_count:
        tone = "review"
    elif waiting_pickup_count:
        tone = "ack"
    elif picked_up_count:
        tone = "working"
    elif high_count or inbox_count:
        tone = "watch"
    elif heartbeat_ok:
        tone = "ok"
    else:
        tone = "unknown"
    if urgent_count:
        summary = f"{urgent_count} urgent BBS thread{'s' if urgent_count != 1 else ''}"
    elif owner_offline_count:
        summary = (
            "1 BBS owner offline"
            if owner_offline_count == 1
            else f"{owner_offline_count} BBS owners offline"
        )
    elif stale_count:
        summary = f"{stale_count} stale BBS pickup{'s' if stale_count != 1 else ''}"
    elif owner_stale_count:
        summary = (
            "1 BBS owner stale"
            if owner_stale_count == 1
            else f"{owner_stale_count} BBS owners stale"
        )
    elif missing_context_count:
        summary = (
            f"{missing_context_count} BBS handoff missing context"
            f"{'s' if missing_context_count != 1 else ''}"
        )
    elif waiting_pickup_count:
        summary = (
            f"{waiting_pickup_count} BBS pickup waiting"
            f"{'s' if waiting_pickup_count != 1 else ''}"
        )
    elif picked_up_count:
        summary = (
            f"{picked_up_count} BBS handoff active"
            f"{'s' if picked_up_count != 1 else ''}"
        )
    elif inbox_count:
        summary = f"{inbox_count} open BBS thread{'s' if inbox_count != 1 else ''}"
    elif heartbeat_ok:
        summary = "BBS clear"
    else:
        summary = "BBS reachable"
    if top_threads:
        activity = str(top_threads[0].get("activity") or "").strip()
    elif heartbeat_ok:
        activity = f"Watcher polling; heartbeat {heartbeat_age_seconds}s"
    else:
        activity = "BBS reachable; watcher heartbeat unknown"
    return {
        "schema": "norman.tui.bbs-summary.v1",
        "enabled": True,
        "configured": True,
        "state": state,
        "tone": tone,
        "actor": str(payload.get("actor") or BBS_SUMMARY_ACTOR).strip(),
        "summary": summary,
        "detail": (
            f"heartbeat {heartbeat_age_seconds}s"
            if heartbeat_age_seconds
            else "heartbeat unknown"
        ),
        "activity": activity,
        "generated_at": observed_at,
        "heartbeat_ok": heartbeat_ok,
        "heartbeat_age_seconds": heartbeat_age_seconds,
        "counts": {
            "inbox": inbox_count,
            "urgent": urgent_count,
            "high": high_count,
            "actionable_urgent": actionable_urgent_count,
            "actionable_high": actionable_high_count,
            "waiting_pickup": waiting_pickup_count,
            "picked_up": picked_up_count,
            "missing_context": missing_context_count,
            "owner_offline": owner_offline_count,
            "owner_stale": owner_stale_count,
            "stale": stale_count,
        },
        "handoff": _bbs_handoff_summary(thread_summaries),
        "top_threads": top_threads,
        "janitor": default_bbs_janitor_summary(
            state="unavailable",
            summary="BBS janitor not sampled",
        ),
        "source_url": BBS_SUMMARY_URL,
    }


def load_bbs_janitor_summary(token: str) -> dict[str, Any]:
    if not BBS_JANITOR_SUMMARY_ENABLED:
        return default_bbs_janitor_summary(
            state="disabled",
            summary="BBS janitor disabled",
            enabled=False,
        )
    try:
        threads_payload = bbs_request_json("/api/v1/threads", token=token)
        bots_payload = bbs_request_json("/api/v1/bots", token=token)
        return summarize_bbs_janitor_payload(threads_payload, bots_payload)
    except (OSError, urllib_error.URLError, json.JSONDecodeError) as exc:
        return default_bbs_janitor_summary(
            state="error",
            summary="BBS janitor unavailable",
            detail=f"{type(exc).__name__}: {exc}",
        )


def merge_bbs_janitor_summary(
    summary: dict[str, Any],
    janitor: dict[str, Any],
) -> dict[str, Any]:
    merged = dict(summary)
    merged["janitor"] = janitor
    thread_summaries = (
        merged.get("top_threads") if isinstance(merged.get("top_threads"), list) else []
    )
    merged["handoff"] = _bbs_handoff_summary(
        [item for item in thread_summaries if isinstance(item, dict)],
        janitor,
    )
    review_count = _coerce_int(janitor.get("review_count"))
    safe_count = _coerce_int(janitor.get("safe_count"))
    recent_terminal_count = _coerce_int(janitor.get("recently_closed_count"))
    state = str(merged.get("state") or "").strip().lower()
    if (review_count > 0 or safe_count > 0) and state not in {"alert", "error"}:
        merged["state"] = "watch"
    counts = merged.get("counts") if isinstance(merged.get("counts"), dict) else {}
    has_visible_bbs_work = any(
        _coerce_int(counts.get(key))
        for key in (
            "urgent",
            "high",
            "waiting_pickup",
            "picked_up",
            "owner_offline",
            "owner_stale",
            "stale",
        )
    )
    if not has_visible_bbs_work and (review_count > 0 or safe_count > 0):
        merged["summary"] = str(janitor.get("summary") or merged.get("summary") or "")
    actions = janitor.get("actions") if isinstance(janitor.get("actions"), list) else []
    first_action = actions[0] if actions and isinstance(actions[0], dict) else {}
    reason = str(first_action.get("reason") or "").strip()
    action = str(first_action.get("action") or "").strip().replace("_", " ")
    if reason and not has_visible_bbs_work and (review_count > 0 or safe_count > 0):
        merged["activity"] = f"Janitor {action}: {reason}" if action else reason
    recent_items = (
        janitor.get("recently_closed")
        if isinstance(janitor.get("recently_closed"), list)
        else []
    )
    first_recent = (
        recent_items[0] if recent_items and isinstance(recent_items[0], dict) else {}
    )
    if recent_terminal_count > 0 and not has_visible_bbs_work:
        recent_status = str(
            first_recent.get("status_label") or first_recent.get("status") or "closed"
        ).strip()
        recent_loop = str(first_recent.get("loop_label") or "Loop closed").strip()
        recent_title = str(
            first_recent.get("title") or first_recent.get("thread_id") or ""
        ).strip()
        recent_age_seconds = _coerce_int(first_recent.get("closed_age_seconds"))
        recent_parts = [recent_loop, recent_status]
        if recent_title:
            recent_parts.append(recent_title)
        if recent_age_seconds:
            recent_parts.append(f"{recent_age_seconds}s ago")
        merged["activity"] = f"Recent BBS loop: {' · '.join(recent_parts)}"
    if review_count <= 0 and safe_count <= 0 and recent_terminal_count <= 0:
        return merged
    return merged


def load_bbs_summary() -> dict[str, Any]:
    if not BBS_SUMMARY_ENABLED:
        return default_bbs_summary(
            state="disabled",
            summary="BBS summary disabled",
            enabled=False,
        )
    if not BBS_SUMMARY_URL:
        return default_bbs_summary(
            state="unconfigured",
            summary="BBS summary unconfigured",
            detail="Set NORMAN_CODEX_BBS_URL and a BBS actor token.",
        )
    token = bbs_summary_token()
    if not token:
        return default_bbs_summary(
            state="unconfigured",
            summary="BBS token unavailable",
            detail="Set NORMAN_CODEX_BBS_TOKEN, SWITCHBOARD_TOKEN, or a token file.",
        )
    try:
        try:
            publish_bbs_heartbeat(token)
        except (OSError, urllib_error.URLError, TimeoutError, json.JSONDecodeError):
            pass
        summary = summarize_bbs_payload(bbs_request_json("/api/v1/me", token=token))
        return merge_bbs_janitor_summary(summary, load_bbs_janitor_summary(token))
    except (OSError, urllib_error.URLError, json.JSONDecodeError) as exc:
        return default_bbs_summary(
            state="error",
            summary="BBS status unavailable",
            detail=f"{type(exc).__name__}: {exc}",
        )


def current_bbs_summary(*, force: bool = False) -> dict[str, Any]:
    now = now_ts()
    with BBS_SUMMARY_LOCK:
        cached = BBS_SUMMARY_CACHE.get("payload")
        expires_at = _coerce_int(BBS_SUMMARY_CACHE.get("expires_at"))
        if not force and isinstance(cached, dict) and expires_at > now:
            return dict(cached)
    payload = load_bbs_summary()
    with BBS_SUMMARY_LOCK:
        BBS_SUMMARY_CACHE["payload"] = dict(payload)
        BBS_SUMMARY_CACHE["expires_at"] = now + BBS_SUMMARY_CACHE_SECONDS
    return payload


def _bbs_transition_next_action(item: dict[str, Any]) -> str:
    status = str(item.get("status") or "").strip().lower()
    if status in {"done", "closed"}:
        return "Loop is closed. No action needed unless the operator asks; use the linked trace if context is needed."
    if status == "blocked":
        return "Loop is not cleanly closed: blocker remains active. Inspect the linked trace before unblocking, forking, or asking operations."
    if status == "canceled":
        return "Loop was canceled/superseded. Avoid reopening unless the operator explicitly asks."
    return "Inspect the linked trace before taking a BBS lifecycle action."


def bbs_transition_prompt_context(summary: dict[str, Any] | None = None) -> str:
    if summary is None:
        if not BBS_SUMMARY_ENABLED or not BBS_SUMMARY_URL:
            return ""
        try:
            summary = current_bbs_summary()
        except Exception:
            return ""
    if not isinstance(summary, dict):
        return ""
    janitor = summary.get("janitor")
    if not isinstance(janitor, dict):
        return ""
    recent = (
        janitor.get("recently_closed")
        if isinstance(janitor.get("recently_closed"), list)
        else []
    )
    items = [item for item in recent if isinstance(item, dict)][
        :BBS_TRANSITION_PROMPT_MAX_ITEMS
    ]
    if not items:
        return ""
    closed_count = sum(
        1
        for item in items
        if str(item.get("status") or "").strip().lower() in {"done", "closed"}
    )
    blocked_count = sum(
        1
        for item in items
        if str(item.get("status") or "").strip().lower() == "blocked"
    )
    canceled_count = sum(
        1
        for item in items
        if str(item.get("status") or "").strip().lower() == "canceled"
    )
    closure_parts = []
    if closed_count:
        closure_parts.append(f"{closed_count} closed")
    if blocked_count:
        closure_parts.append(f"{blocked_count} blocked")
    if canceled_count:
        closure_parts.append(f"{canceled_count} canceled")
    closure_summary = ", ".join(closure_parts) if closure_parts else "terminal updates"
    lines = [
        "BBS transition receipt:",
        f"- Loop closure summary: {closure_summary}; each item has a clickable trace.",
    ]
    for item in items:
        thread_id = str(item.get("thread_id") or "").strip()
        status = str(item.get("status_label") or item.get("status") or "").strip()
        loop_label = str(item.get("loop_label") or "").strip()
        title = summarize_text(
            str(item.get("title") or thread_id or "BBS thread"),
            BBS_TRANSITION_PROMPT_TITLE_CHARS,
        )
        owner = str(item.get("owner") or "").strip()
        activity = str(item.get("activity") or "").strip()
        ref = thread_id or title
        parts = [
            part
            for part in (
                loop_label,
                status,
                title,
                f"owner {owner}" if owner else "",
            )
            if part
        ]
        lines.append(f"- {ref}: {' · '.join(parts)}.")
        if activity:
            lines.append(f"  Result: {activity}.")
        lines.append(f"  Next: {_bbs_transition_next_action(item)}")
    lines.append(
        "- Trace: click any th_... / msg_... reference instead of reloading broad BBS history."
    )
    return "\n".join(lines)


def bbs_handoff_prompt_context(summary: dict[str, Any] | None = None) -> str:
    if summary is None:
        if not BBS_SUMMARY_ENABLED or not BBS_SUMMARY_URL:
            return ""
        try:
            summary = current_bbs_summary()
        except Exception:
            return ""
    if not isinstance(summary, dict):
        return ""
    handoff = summary.get("handoff")
    if not isinstance(handoff, dict):
        return ""
    state = str(handoff.get("state") or "").strip().lower()
    if state not in {"needs_ack", "working", "owner_attention", "review"}:
        return bbs_transition_prompt_context(summary)
    top_threads = (
        summary.get("top_threads")
        if isinstance(summary.get("top_threads"), list)
        else []
    )
    thread_id = str(handoff.get("thread_id") or "").strip()
    focus_thread: dict[str, Any] = {}
    for item in top_threads:
        if not isinstance(item, dict):
            continue
        if thread_id and str(item.get("thread_id") or "").strip() == thread_id:
            focus_thread = item
            break
    if not focus_thread:
        focus_thread = next(
            (item for item in top_threads if isinstance(item, dict)),
            {},
        )
    command_source = (
        handoff
        if any(
            str(handoff.get(key) or "").strip()
            for key in (
                "ack_command",
                "done_command",
                "blocked_command",
                "fork_command_hint",
            )
        )
        else focus_thread
    )
    summary_text = str(handoff.get("summary") or summary.get("summary") or "").strip()
    detail = str(handoff.get("detail") or "").strip()
    next_action = str(handoff.get("next_action") or "").strip()
    owner = str(handoff.get("owner") or focus_thread.get("owner") or "").strip()
    age_seconds = _coerce_int(
        handoff.get("age_seconds") or focus_thread.get("age_seconds")
    )
    focus_title = str(
        focus_thread.get("title") or handoff.get("title") or thread_id or "BBS handoff"
    ).strip()
    state_label = summary_text or state.replace("_", " ")
    reason = (
        detail
        or next_action
        or state_label
        or "The Switchboard BBS says this console has a handoff decision to close."
    )
    actor = str(BBS_SUMMARY_ACTOR or AGENT_SLUG or AGENT_NAME or "").strip()
    owner_line = "unknown"
    if actor and owner:
        if actor == owner:
            owner_line = f"this console owns it ({actor})"
        else:
            owner_line = f"owner is {owner}; this console is {actor}"
    elif owner:
        owner_line = f"owner is {owner}"
    elif actor:
        owner_line = f"this console is {actor}"

    safe_next = (
        next_action or "Pick exactly one lifecycle action: ACK, fork, DONE, or BLOCKED."
    )
    lines = [
        "BBS decision card:",
        f"- Situation: {reason}.",
        f"- Ownership: {owner_line}.",
        f"- Safe next step: {safe_next}",
        "- Do not: ACK just to clear noise; ACK only means the actor is taking ownership.",
        "",
        "BBS handoff alert:",
        "- From: Switchboard BBS.",
        f"- Why: {reason}.",
    ]
    if actor or owner:
        role_parts = []
        if actor:
            role_parts.append(f"this console actor {actor}")
        if owner:
            role_parts.append(f"owner TUI {owner}")
        if actor and owner and actor != owner:
            role_parts.append("observer/coordinator unless explicitly taking over")
        lines.append(f"- Who is involved: {' · '.join(role_parts)}.")
    focus_parts = []
    if thread_id:
        focus_parts.append(thread_id)
    if focus_title and focus_title != thread_id:
        focus_parts.append(focus_title)
    if owner:
        focus_parts.append(f"owner {owner}")
    if age_seconds:
        focus_parts.append(f"age {age_seconds}s")
    if focus_parts:
        lines.append(f"- Focus: {' · '.join(focus_parts)}.")
    if (
        str(focus_thread.get("handoff_contract_state") or "").strip()
        == "missing_context"
    ):
        lines.append(
            "- Handoff contract: missing body/evidence. Do not ACK this shell just "
            "to clear it; ask the creator to add context or mark BLOCKED with the "
            "missing-context reason."
        )
    action_choices = [
        "owner ACKs only if picking up",
        "coordinator TAKEOVER ACKs only if taking over",
        "fork/reassign a finite child",
        "mark DONE or BLOCKED with a reason",
    ]
    lines.append(f"- Choose one: {'; '.join(action_choices)}.")
    lines.append("Fine print:")
    if next_action and next_action != reason:
        lines.append(f"- Next owner/coordination action: {next_action}")
    lines.append(
        "- ACK semantics: ACK means the actor in the command is taking ownership "
        "of the work. Do not ACK from an observer/coordinator console just to "
        "clear the alert."
    )
    ack_label = str(command_source.get("ack_command_label") or "ACK").strip() or "ACK"
    command_labels = (
        ("ack_command", ack_label),
        ("fork_command_hint", "FORK"),
        ("done_command", "DONE"),
        ("blocked_command", "BLOCKED"),
    )
    for key, label in command_labels:
        command = str(command_source.get(key) or "").strip()
        if command:
            lines.append(f"- {label} helper: `{command}`")
            if key == "ack_command":
                ack_note = str(command_source.get("ack_command_note") or "").strip()
                if ack_note:
                    lines.append(f"- {label} note: {ack_note}")
    transition_context = bbs_transition_prompt_context(summary)
    if transition_context:
        lines.extend(["", transition_context])
    return "\n".join(lines)


def web_process_update_snapshot() -> dict[str, Any]:
    try:
        script_updated_at = int(WEB_SCRIPT_PATH.stat().st_mtime)
    except OSError:
        script_updated_at = 0
    restart_required = (
        script_updated_at > 0
        and script_updated_at > WEB_PROCESS_STARTED_AT + WEB_UPDATE_GRACE_SECONDS
    )
    return {
        "web_process_started_at": WEB_PROCESS_STARTED_AT,
        "web_script_updated_at": script_updated_at,
        "web_restart_required": restart_required,
        "web_restart_reason": (
            "Console web script changed after this process started."
            if restart_required
            else ""
        ),
    }


def web_process_refresh_event_from_meta(meta: dict[str, Any]) -> dict[str, Any]:
    return {
        "event_at": _coerce_int(meta.get("web_process_refresh_event_at")),
        "summary": str(meta.get("web_process_refresh_summary") or ""),
        "detail": str(meta.get("web_process_refresh_detail") or ""),
        "ui_version": str(meta.get("web_process_seen_ui_version") or ""),
        "process_started_at": _coerce_int(meta.get("web_process_seen_started_at")),
        "previous_ui_version": str(meta.get("web_process_previous_ui_version") or ""),
        "previous_process_started_at": _coerce_int(
            meta.get("web_process_previous_started_at")
        ),
        "changed": False,
    }


def record_web_process_seen(
    meta: dict[str, Any],
) -> tuple[dict[str, Any], dict[str, Any]]:
    global WEB_PROCESS_EVENT_RECORDED
    previous_version = str(meta.get("web_process_seen_ui_version") or "")
    previous_started_at = _coerce_int(meta.get("web_process_seen_started_at"))
    current_pid = os.getpid()
    current_started_at = WEB_PROCESS_STARTED_AT
    current_version = UI_VERSION
    changed = bool(previous_version or previous_started_at) and (
        previous_version != current_version or previous_started_at != current_started_at
    )
    current_already_recorded = (
        previous_version == current_version
        and previous_started_at == current_started_at
        and _coerce_int(meta.get("web_process_seen_pid")) == current_pid
    )
    with WEB_PROCESS_EVENT_LOCK:
        if WEB_PROCESS_EVENT_RECORDED or current_already_recorded:
            event = web_process_refresh_event_from_meta(meta)
            event["changed"] = changed
            return meta, event
        event_at = now_ts()
        summary = (
            f"UI wrapper refreshed to {current_version}."
            if changed
            else f"UI wrapper running {current_version}."
        )
        detail_parts = [
            f"pid={current_pid}",
            f"started_at={current_started_at}",
        ]
        if previous_version:
            detail_parts.append(f"previous_version={previous_version}")
        if previous_started_at:
            detail_parts.append(f"previous_started_at={previous_started_at}")
        detail = " · ".join(detail_parts)
        try:
            updated = update_status_meta(
                web_process_seen_at=event_at,
                web_process_seen_ui_version=current_version,
                web_process_seen_started_at=current_started_at,
                web_process_seen_pid=current_pid,
                web_process_previous_ui_version=previous_version,
                web_process_previous_started_at=previous_started_at,
                web_process_refresh_event_at=event_at,
                web_process_refresh_summary=summary,
                web_process_refresh_detail=detail,
            )
        except OSError:
            updated = dict(meta)
        if isinstance(updated, dict):
            updated = {**meta, **updated}
        else:
            updated = dict(meta)
        try:
            append_audit_event(
                event_type=(
                    "web.process_refreshed" if changed else "web.process_started"
                ),
                summary=summary,
                detail=detail,
                severity="info",
                actor_type="system",
                thread_id=read_text(THREAD_ID_PATH),
                payload={
                    "ui_version": current_version,
                    "process_started_at": current_started_at,
                    "pid": current_pid,
                    "previous_ui_version": previous_version,
                    "previous_process_started_at": previous_started_at,
                },
                event_at=event_at,
            )
        except OSError:
            pass
        WEB_PROCESS_EVENT_RECORDED = True
        event = web_process_refresh_event_from_meta(updated)
        event["changed"] = changed
        return updated, event


def _meter_generated_at(snapshot_at: int) -> str:
    try:
        return (
            datetime.utcfromtimestamp(int(snapshot_at or 0)).isoformat(
                timespec="seconds"
            )
            + "Z"
        )
    except (TypeError, ValueError, OSError):
        return datetime.utcfromtimestamp(now_ts()).isoformat(timespec="seconds") + "Z"


def _normalize_meter_tone(value: Any, default: str = "ok") -> str:
    clean = str(value or "").strip().lower()
    if clean in {"ok", "watch", "warn", "danger", "active", "alert"}:
        return clean
    return default


def normalize_kpi_meters(value: Any, *, limit: int = 4) -> list[dict[str, Any]]:
    if not isinstance(value, list):
        return []
    meters: list[dict[str, Any]] = []
    for raw in value:
        if not isinstance(raw, dict):
            continue
        label = str(raw.get("label") or "").strip()
        if not label:
            continue
        meter_id = str(raw.get("id") or label).strip()
        meters.append(
            {
                "id": meter_id,
                "label": label,
                "value": raw.get("value", ""),
                "unit": str(raw.get("unit") or "").strip(),
                "tone": _normalize_meter_tone(raw.get("tone")),
                "detail": str(raw.get("detail") or "").strip(),
                "source": str(raw.get("source") or "").strip(),
                "updated_at": raw.get("updated_at", ""),
                "stale_after_seconds": _coerce_int(raw.get("stale_after_seconds")),
                "href": str(raw.get("href") or "").strip(),
            }
        )
        if len(meters) >= limit:
            break
    return meters


def normalize_resource_meter(
    value: Any,
    *,
    snapshot_at: int,
    pending: bool,
    queue_depth: int,
    running_prompt: str,
) -> dict[str, Any]:
    source = value if isinstance(value, dict) else {}
    source_conversation = source.get("conversation")
    if not isinstance(source_conversation, dict):
        source_conversation = {}
    source_domain = source.get("domain")
    if not isinstance(source_domain, dict):
        source_domain = {}
    source_executor = source.get("executor")
    if not isinstance(source_executor, dict):
        source_executor = {}
    conversation = {
        "running": _coerce_int(source_conversation.get("running"))
        or (1 if pending and running_prompt else 0),
        "queued": _coerce_int(source_conversation.get("queued")) or queue_depth,
        "pending": bool(source_conversation.get("pending", pending)),
        "oldest_age_seconds": _coerce_int(
            source_conversation.get("oldest_age_seconds")
        ),
        "stale": _coerce_int(source_conversation.get("stale")),
    }
    if not source:
        summary = (
            f"Chat running / {queue_depth} queued"
            if pending
            else f"Chat idle / {queue_depth} queued"
            if queue_depth
            else "Chat idle"
        )
        tone = "watch" if pending else "warn" if queue_depth else "ok"
    else:
        summary = str(source.get("summary") or "").strip() or "Queues available"
        tone = _normalize_meter_tone(source.get("tone"))
    return {
        "version": str(source.get("version") or "norman.queue-resource-meter.v1"),
        "generated_at": str(source.get("generated_at") or "")
        or _meter_generated_at(snapshot_at),
        "read_only": True,
        "label": str(source.get("label") or "Queues").strip() or "Queues",
        "tone": tone,
        "summary": summary,
        "conversation": conversation,
        "domain": source_domain,
        "executor": source_executor,
        "kpi_meters": normalize_kpi_meters(source.get("kpi_meters")),
        "warnings": source.get("warnings")
        if isinstance(source.get("warnings"), list)
        else [],
        "sources": source.get("sources")
        if isinstance(source.get("sources"), list)
        else [],
    }


