def usage_accounting_tags() -> dict[str, str]:
    return {
        "accounting_version": "norman.tui-usage.v2",
        "billing_scope": usage_billing_scope(),
        "billing_unit": usage_billing_unit(),
        "billing_owner": usage_billing_owner(),
        "billing_project": usage_billing_project(),
        "agent_slug": AGENT_SLUG,
        "actor_slug": BBS_SUMMARY_ACTOR or AGENT_SLUG,
        "agent_name": AGENT_NAME,
        "agent_group": semantic_agent_group(AGENT_SLUG, AGENT_GROUP),
        "console_title": CONSOLE_TITLE,
        "host_name": HOST_NAME,
        "workdir": WORKDIR,
        "state_dir": str(STATE_DIR),
        "codex_home": CODEX_HOME,
    }


def usage_billing_scope() -> str:
    explicit = os.environ.get("NORMAN_CODEX_BILLING_SCOPE", "").strip()
    if explicit:
        return explicit
    group = semantic_agent_group(AGENT_SLUG, AGENT_GROUP)
    if group == "work":
        return "work-special"
    return HOST_NAME or "unknown"


def usage_billing_unit() -> str:
    explicit = os.environ.get("NORMAN_CODEX_BILLING_UNIT", "").strip()
    if explicit:
        return explicit
    scope = usage_billing_scope()
    actor = BBS_SUMMARY_ACTOR or AGENT_SLUG or "unknown"
    return f"{scope}:{actor}"


def usage_billing_owner() -> str:
    explicit = os.environ.get("NORMAN_CODEX_BILLING_OWNER", "").strip()
    if explicit:
        return explicit
    group = semantic_agent_group(AGENT_SLUG, AGENT_GROUP)
    return "openbrand" if group == "work" else "kristopher"


def usage_billing_project() -> str:
    explicit = os.environ.get("NORMAN_CODEX_BILLING_PROJECT", "").strip()
    if explicit:
        return explicit
    return WORKDIR or AGENT_SLUG or "unknown"


def usage_provider_tags(service_tier: Any) -> dict[str, str]:
    tier = normalize_service_tier(service_tier)
    profile = codex_profile_v2_for_service_tier(tier)
    return {
        "provider_label": service_tier_label(tier),
        "provider_surface": "aws-bedrock" if profile else "openai-direct",
        "profile_v2": profile,
        "aws_profile": codex_aws_profile_for_service_tier(tier) if profile else "",
        "aws_region": codex_aws_region_for_service_tier(tier) if profile else "",
    }


def local_llm_provider_tags() -> dict[str, str]:
    return {
        "provider_label": "Norllama",
        "provider_surface": "norllama",
        "profile_v2": "",
        "aws_profile": "",
        "aws_region": "",
    }


def usage_route_class(entry: dict[str, Any]) -> str:
    runtime = normalize_runtime(entry.get("runtime"))
    model = str(entry.get("model") or "").strip().lower()
    provider_surface = str(entry.get("provider_surface") or "").strip().lower()
    service_tier = normalize_service_tier(entry.get("service_tier"))
    if runtime == "codexspark" or "spark" in runtime or "spark" in model:
        return "spark"
    if runtime == "localllm" or provider_surface in {"local", "norllama", "ollama"}:
        return "local"
    if provider_surface == "aws-bedrock" or runtime in {
        "claude",
        "deepseek",
        "gptoss",
        "kimi",
        "qwen",
    }:
        return "bedrock"
    if provider_surface == "openai-direct" or runtime == "codex":
        return "cloud"
    if service_tier in {"default", "standard"}:
        return "bedrock"
    return "unknown"


def usage_route_label(entry: dict[str, Any]) -> str:
    execution = (
        str(entry.get("route_execution") or usage_route_execution(entry))
        .strip()
        .lower()
    )
    if execution == "local_spark":
        return "Local Spark"
    if execution == "spark_plus_verifier":
        return "Spark + verifier"
    if execution == "local_worker":
        return "Norllama"
    if execution == "cloud_bedrock":
        return "Bedrock"
    if execution == "cloud_openai":
        return "Cloud"
    return {
        "spark": "Spark",
        "local": "Local",
        "bedrock": "Bedrock",
        "cloud": "Cloud",
    }.get(
        str(entry.get("route_class") or usage_route_class(entry)).strip().lower(),
        "Route?",
    )


def usage_charge_ledger_kind(entry: dict[str, Any]) -> str:
    runtime = normalize_runtime(entry.get("runtime"))
    owner = str(entry.get("billing_owner") or usage_billing_owner()).strip().lower()
    provider_surface = str(entry.get("provider_surface") or "").strip().lower()
    group = (
        str(entry.get("agent_group") or semantic_agent_group(AGENT_SLUG, AGENT_GROUP))
        .strip()
        .lower()
    )
    if runtime == "codex" and owner == "kristopher" and group != "work":
        return "chatgpt_codex_credit_estimate"
    if runtime in {"claude", "kimi", "qwen"}:
        return "provider_invoice_estimate"
    if provider_surface == "aws-bedrock":
        return "provider_invoice_estimate"
    if provider_surface == "openai-direct":
        return "api_rate_card_estimate"
    return "local_token_estimate"


def usage_charge_display_unit(ledger_kind: str) -> str:
    if ledger_kind == "chatgpt_codex_credit_estimate":
        return "credits"
    if ledger_kind in {"api_rate_card_estimate", "provider_invoice_estimate"}:
        return "usd_equivalent"
    return "tokens"


def usage_route_charge_basis(entry: dict[str, Any]) -> str:
    ledger_kind = str(
        entry.get("charge_ledger_kind") or usage_charge_ledger_kind(entry)
    ).strip()
    if ledger_kind == "provider_invoice_estimate":
        return "provider_invoice"
    if ledger_kind == "api_rate_card_estimate":
        return "api_estimate"
    if ledger_kind == "chatgpt_codex_credit_estimate":
        return "codex_credits"
    return "local_token_estimate"


def usage_route_execution(entry: dict[str, Any]) -> str:
    explicit = str(entry.get("route_execution") or "").strip().lower()
    if explicit:
        return explicit
    runtime = normalize_runtime(entry.get("runtime"))
    model = str(entry.get("model") or "").strip().lower()
    route_class = str(entry.get("route_class") or usage_route_class(entry)).lower()
    local_worker_runtime = (
        str(entry.get("local_worker_runtime") or entry.get("worker_runtime") or "")
        .strip()
        .lower()
    )
    local_worker_model = (
        str(entry.get("local_worker_model") or entry.get("worker_model") or "")
        .strip()
        .lower()
    )
    verifier_runtime = str(entry.get("verifier_runtime") or "").strip().lower()
    verifier_model = str(entry.get("verifier_model") or "").strip().lower()
    spark_worker = (
        route_class == "spark"
        or runtime == "codexspark"
        or "spark" in runtime
        or "spark" in model
        or "spark" in local_worker_runtime
        or "spark" in local_worker_model
    )
    verifier_present = bool(verifier_runtime or verifier_model) or (
        spark_worker and route_class in {"bedrock", "cloud"}
    )
    if spark_worker and verifier_present:
        return "spark_plus_verifier"
    if spark_worker:
        return "local_spark"
    if route_class == "local":
        return "local_worker"
    if route_class == "bedrock":
        return "cloud_bedrock"
    if route_class == "cloud":
        return "cloud_openai"
    return "unknown"


def usage_route_verifier(entry: dict[str, Any]) -> str:
    explicit = str(entry.get("route_verifier") or "").strip().lower()
    if explicit:
        return explicit
    verifier_runtime = str(entry.get("verifier_runtime") or "").strip().lower()
    verifier_model = str(entry.get("verifier_model") or "").strip().lower()
    route_class = str(entry.get("route_class") or usage_route_class(entry)).lower()
    if verifier_runtime or verifier_model:
        verifier_text = f"{verifier_runtime} {verifier_model}".strip()
        if "bedrock" in verifier_text or route_class == "bedrock":
            return "bedrock_verifier"
        if "openai" in verifier_text or route_class == "cloud":
            return "cloud_verifier"
        return "external_verifier"
    if usage_route_execution(entry) == "spark_plus_verifier":
        return "bedrock_verifier" if route_class == "bedrock" else "cloud_verifier"
    return ""


def usage_charge_status(entry: dict[str, Any]) -> str:
    explicit = str(entry.get("charge_status") or "").strip().lower()
    if explicit:
        return explicit
    return "not_invoice_reconciled"


def normalize_usage_entry(value: Any) -> dict[str, Any]:
    payload = dict(default_usage_entry())
    provided_keys: set[str] = set()
    if isinstance(value, dict):
        provided_keys = set(value)
        payload.update(value)
    for key in (
        "accounting_version",
        "billing_scope",
        "billing_unit",
        "billing_owner",
        "billing_project",
        "agent_slug",
        "actor_slug",
        "agent_name",
        "agent_group",
        "console_title",
        "host_name",
        "workdir",
        "state_dir",
        "codex_home",
        "provider_label",
        "provider_surface",
        "profile_v2",
        "aws_profile",
        "aws_region",
        "local_worker_runtime",
        "local_worker_model",
        "verifier_runtime",
        "verifier_model",
        "route_class",
        "route_execution",
        "route_verifier",
        "route_label",
        "route_charge_basis",
        "preflight_accounting_schema",
        "offline_preflight_status",
        "local_preflight_status",
        "local_preflight_model",
        "local_preflight_endpoint",
        "local_preflight_candidate_lane",
        "local_preflight_candidate_policy",
        "local_preflight_failure_class",
        "local_preflight_warm_policy_source",
        "local_preflight_route_posture",
        "local_specialist_status",
        "local_specialist_failure_class",
        "local_specialist_warm_policy_source",
        "local_specialist_route_posture",
        "cloud_context_gate_status",
    ):
        payload[key] = str(payload.get(key) or "").strip()
    payload["started_at"] = _coerce_int(payload.get("started_at"))
    payload["finished_at"] = _coerce_int(payload.get("finished_at"))
    payload["thread_id"] = str(payload.get("thread_id") or "").strip()
    payload["speed"] = normalize_response_speed(payload.get("speed"))
    payload["detail"] = normalize_response_detail(payload.get("detail"))
    payload["service_tier"] = normalize_service_tier(payload.get("service_tier"))
    for key, tag_value in usage_provider_tags(payload["service_tier"]).items():
        if key not in provided_keys or not str(payload.get(key) or "").strip():
            payload[key] = tag_value
    for key in (
        "provider_label",
        "provider_surface",
        "profile_v2",
        "aws_profile",
        "aws_region",
    ):
        payload[key] = str(payload.get(key) or "").strip()
    resolved_service_tier = str(payload.get("resolved_service_tier") or "").strip()
    payload["resolved_service_tier"] = (
        normalize_service_tier(resolved_service_tier) if resolved_service_tier else ""
    )
    observed_service_tier = str(payload.get("observed_service_tier") or "").strip()
    payload["observed_service_tier"] = (
        normalize_service_tier(observed_service_tier) if observed_service_tier else ""
    )
    if not payload["observed_service_tier"] and payload["resolved_service_tier"]:
        payload["observed_service_tier"] = payload["resolved_service_tier"]
    payload["runtime"] = normalize_runtime(payload.get("runtime"))
    payload["model"] = normalize_runtime_model(payload["runtime"], payload.get("model"))
    payload["route_class"] = str(
        payload.get("route_class") or ""
    ).strip().lower() or usage_route_class(payload)
    payload["route_execution"] = str(
        payload.get("route_execution") or ""
    ).strip().lower() or usage_route_execution(payload)
    payload["route_verifier"] = str(
        payload.get("route_verifier") or ""
    ).strip().lower() or usage_route_verifier(payload)
    payload["route_label"] = str(
        payload.get("route_label") or ""
    ).strip() or usage_route_label(payload)
    payload["success"] = bool(payload.get("success"))
    payload["input_tokens"] = _coerce_int(payload.get("input_tokens"))
    input_details = payload.get("input_tokens_details")
    if not isinstance(input_details, dict):
        input_details = payload.get("prompt_tokens_details")
    if payload["cached_input_tokens"] <= 0 and isinstance(input_details, dict):
        payload["cached_input_tokens"] = _coerce_int(
            input_details.get("cached_tokens")
            or input_details.get("cached_input_tokens")
            or input_details.get("cache_read_input_tokens")
        )
    payload["cached_input_tokens"] = _coerce_int(payload.get("cached_input_tokens"))
    payload["output_tokens"] = _coerce_int(payload.get("output_tokens"))
    output_details = payload.get("output_tokens_details")
    if not isinstance(output_details, dict):
        output_details = payload.get("completion_tokens_details")
    if payload.get("reasoning_output_tokens") in (None, "", 0) and isinstance(
        output_details, dict
    ):
        payload["reasoning_output_tokens"] = _coerce_int(
            output_details.get("reasoning_tokens")
            or output_details.get("reasoning_output_tokens")
        )
    payload["reasoning_output_tokens"] = _coerce_int(
        payload.get("reasoning_output_tokens")
    )
    total_tokens = _coerce_int(payload.get("total_tokens"))
    if total_tokens <= 0:
        total_tokens = payload["input_tokens"] + max(
            payload["output_tokens"], payload["reasoning_output_tokens"]
        )
    payload["total_tokens"] = total_tokens
    for key in (
        "broker_tool_call_budget",
        "broker_tool_calls",
        "broker_tool_rounds",
        "broker_model_calls",
    ):
        payload[key] = _coerce_int(payload.get(key))
    payload["broker_tool_budget_exhausted"] = bool(
        payload.get("broker_tool_budget_exhausted")
    )
    if isinstance(payload.get("context_preflight_accounting"), dict):
        context_preflight_fields = usage_fields_from_context_preflight_accounting(
            payload.get("context_preflight_accounting")
        )
        for key, field_value in context_preflight_fields.items():
            if key == "context_preflight_accounting":
                continue
            if payload.get(key) in (None, "", 0, False, [], {}):
                payload[key] = field_value
    else:
        payload["context_preflight_accounting"] = {}
    for key in (
        "preflight_prompt_estimated_tokens",
        "attachment_saved_tokens",
        "memory_ref_count",
        "local_preflight_tokens",
        "local_specialist_stage_count",
        "local_specialist_executed_count",
        "local_specialist_ready_count",
        "local_specialist_tokens",
        "context_pack_saved_tokens",
        "cloud_tokens_avoided_floor",
        "cloud_tokens_avoided_estimate",
        "cloud_preflight_net_token_delta_estimate",
        "cloud_context_gate_threshold_tokens",
    ):
        payload[key] = _coerce_int(payload.get(key))
    payload["offline_preflight_used"] = bool(payload.get("offline_preflight_used"))
    payload["local_preflight_used"] = bool(payload.get("local_preflight_used"))
    payload["local_specialist_used"] = bool(payload.get("local_specialist_used"))
    payload["cloud_context_gate_active"] = bool(
        payload.get("cloud_context_gate_active")
    )
    if not isinstance(payload.get("cloud_context_gate_reasons"), list):
        payload["cloud_context_gate_reasons"] = []
    payload["cloud_context_gate_reasons"] = [
        str(reason).strip()
        for reason in payload.get("cloud_context_gate_reasons", [])
        if str(reason).strip()
    ]
    if not isinstance(payload.get("local_preflight_receipt"), dict):
        payload["local_preflight_receipt"] = {}
    if not isinstance(payload.get("local_specialist_receipt"), dict):
        payload["local_specialist_receipt"] = {}
    for key in (
        "raw_input_tokens",
        "raw_cached_input_tokens",
        "raw_output_tokens",
        "raw_reasoning_output_tokens",
        "raw_total_tokens",
        "cumulative_total_tokens",
    ):
        payload[key] = _coerce_int(payload.get(key))
    payload["usage_meter_mode"] = str(payload.get("usage_meter_mode") or "").strip()
    payload["provider_yield_kind"] = str(
        payload.get("provider_yield_kind") or ""
    ).strip()
    if not isinstance(payload.get("provider_yield_reasons"), list):
        payload["provider_yield_reasons"] = []
    payload["provider_yield_reasons"] = [
        str(reason).strip()
        for reason in payload.get("provider_yield_reasons", [])
        if str(reason).strip()
    ]
    payload["charge_ledger_kind"] = str(
        payload.get("charge_ledger_kind") or ""
    ).strip() or usage_charge_ledger_kind(payload)
    payload["charge_display_unit"] = str(
        payload.get("charge_display_unit") or ""
    ).strip() or usage_charge_display_unit(payload["charge_ledger_kind"])
    payload["route_charge_basis"] = str(
        payload.get("route_charge_basis") or ""
    ).strip() or usage_route_charge_basis(payload)
    payload["charge_status"] = usage_charge_status(payload)
    return payload


def _extract_observed_service_tier(event: dict[str, Any]) -> str:
    candidates: list[Any] = [
        event.get("observed_service_tier"),
        event.get("resolved_service_tier"),
        event.get("service_tier"),
    ]
    usage = event.get("usage")
    if isinstance(usage, dict):
        candidates.extend(
            [
                usage.get("observed_service_tier"),
                usage.get("resolved_service_tier"),
                usage.get("service_tier"),
            ]
        )
    response = event.get("response")
    if isinstance(response, dict):
        candidates.extend(
            [
                response.get("observed_service_tier"),
                response.get("resolved_service_tier"),
                response.get("service_tier"),
            ]
        )
    for candidate in candidates:
        clean = str(candidate or "").strip()
        if clean:
            return normalize_service_tier(clean)
    return ""


PROVIDER_REQUEST_ID_HEADER_RE = re.compile(
    r"(?i)\b(?:x-amz(?:n)?[-_ ]?request[-_ ]?id|x-amz(?:n)?[-_ ]?requestid|"
    r"x[-_ ]?request[-_ ]?id)\b[\"']?\s*[:=]\s*[\"']?"
    r"([A-Za-z0-9._:/+=-]{6,})"
)
PROVIDER_REQUEST_ID_GENERIC_RE = re.compile(
    r"(?i)\b(?:aws[-_ ]?request[-_ ]?id|request[-_ ]?id|requestid)\b"
    r"[\"']?\s*[:=]\s*[\"']?([A-Za-z0-9._:/+=-]{6,})"
)
PROVIDER_REQUEST_ID_RE = PROVIDER_REQUEST_ID_GENERIC_RE
PROVIDER_TRACE_ID_RE = re.compile(
    r"(?i)\b(?:x-amz(?:n)?[-_ ]?trace[-_ ]?id|trace[-_ ]?id)\b[\"']?"
    r"\s*[:=]\s*[\"']?([A-Za-z0-9._:/;+=-]{6,})"
)
PROVIDER_REQUEST_ID_HEADER_KEYS = {
    "xamznrequestid",
    "xamzrequestid",
    "xrequestid",
}
PROVIDER_REQUEST_ID_GENERIC_KEYS = {
    "awsrequestid",
    "requestid",
}
PROVIDER_TRACE_ID_KEYS = {
    "xamzntraceid",
    "xamztraceid",
    "xtraceid",
    "awstraceid",
    "traceid",
}
PROVIDER_ID_FIELD_NAME_RE = re.compile(
    r"(?i)(?:^|[._-])(?:requestid|request_id|request-id|traceid|trace_id|trace-id)"
    r"(?:$|[._-])"
)


def _unique_limited_values(values: list[str], *, limit: int = 12) -> list[str]:
    seen: set[str] = set()
    results: list[str] = []
    for value in values:
        clean = str(value or "").strip().strip("\"',")
        if not clean or clean in seen:
            continue
        seen.add(clean)
        results.append(clean)
        if len(results) >= limit:
            break
    return results


def _provider_payload_key_token(key: Any) -> str:
    return re.sub(r"[^a-z0-9]", "", str(key or "").strip().lower())


def _provider_simple_candidate_values(value: Any) -> list[str]:
    if isinstance(value, (str, int, float)):
        return [str(value)]
    if isinstance(value, (list, tuple)):
        return [
            str(item)
            for item in value
            if isinstance(item, (str, int, float)) and str(item).strip()
        ]
    return []


def _provider_id_value_looks_real(
    value: Any, *, generic: bool = False, trace: bool = False
) -> bool:
    clean = str(value or "").strip().strip("\"'`,;")
    if len(clean) < 6:
        return False
    if any(char.isspace() for char in clean):
        return False
    lowered = clean.lower()
    if lowered in {
        "optional",
        "none",
        "null",
        "string",
        "requestid",
        "request_id",
        "request-id",
        "traceid",
        "trace_id",
        "trace-id",
    }:
        return False
    if "request_id_var" in lowered or "requestid_var" in lowered:
        return False
    if PROVIDER_ID_FIELD_NAME_RE.search(lowered):
        return False
    if lowered.startswith(
        (
            "opts.",
            "self.",
            "this.",
            "payload.",
            "event.",
            "usage.",
            "ctx.",
            "context.",
            "meta.",
        )
    ):
        return False
    has_digit = any(char.isdigit() for char in clean)
    if lowered.startswith(("req", "amz")):
        return True
    if trace and lowered.startswith(("trace", "root=")):
        return True
    if re.fullmatch(
        r"[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}",
        lowered,
    ):
        return True
    if not generic:
        return has_digit or len(clean) >= 16
    return has_digit and len(clean) >= 12


def extract_provider_request_ids(text: str) -> list[str]:
    candidates = [
        value
        for value in PROVIDER_REQUEST_ID_HEADER_RE.findall(text or "")
        if _provider_id_value_looks_real(value)
    ]
    candidates.extend(
        value
        for value in PROVIDER_REQUEST_ID_GENERIC_RE.findall(text or "")
        if _provider_id_value_looks_real(value, generic=True)
    )
    return _unique_limited_values(candidates)


def extract_provider_trace_ids(text: str) -> list[str]:
    return _unique_limited_values(
        [
            value
            for value in PROVIDER_TRACE_ID_RE.findall(text or "")
            if _provider_id_value_looks_real(value, trace=True)
        ]
    )


def extract_provider_request_ids_from_payload(value: Any) -> list[str]:
    candidates: list[str] = []

    def walk(item: Any) -> None:
        if isinstance(item, dict):
            for key, child in item.items():
                token = _provider_payload_key_token(key)
                if token in PROVIDER_REQUEST_ID_HEADER_KEYS:
                    candidates.extend(
                        candidate
                        for candidate in _provider_simple_candidate_values(child)
                        if _provider_id_value_looks_real(candidate)
                    )
                elif token in PROVIDER_REQUEST_ID_GENERIC_KEYS:
                    candidates.extend(
                        candidate
                        for candidate in _provider_simple_candidate_values(child)
                        if _provider_id_value_looks_real(candidate, generic=True)
                    )
                if isinstance(child, (dict, list, tuple)):
                    walk(child)
        elif isinstance(item, (list, tuple)):
            for child in item:
                walk(child)

    walk(value)
    return _unique_limited_values(candidates)


def extract_provider_trace_ids_from_payload(value: Any) -> list[str]:
    candidates: list[str] = []

    def walk(item: Any) -> None:
        if isinstance(item, dict):
            for key, child in item.items():
                token = _provider_payload_key_token(key)
                if token in PROVIDER_TRACE_ID_KEYS:
                    candidates.extend(
                        candidate
                        for candidate in _provider_simple_candidate_values(child)
                        if _provider_id_value_looks_real(candidate, trace=True)
                    )
                if isinstance(child, (dict, list, tuple)):
                    walk(child)
        elif isinstance(item, (list, tuple)):
            for child in item:
                walk(child)

    walk(value)
    return _unique_limited_values(candidates)


PROVIDER_CAPACITY_ERROR_KINDS = {
    "bedrock_on_demand_capacity_exceeded",
    "provider_capacity_exceeded",
}


def provider_capacity_error_kind(error_text: Any, *, provider_surface: str = "") -> str:
    clean = str(error_text or "").strip()
    if not clean:
        return ""
    lowered = clean.lower()
    capacity_hit = (
        "exceeded on-demand capacity" in lowered
        or "exceeded on demand capacity" in lowered
        or ("on-demand capacity" in lowered and "try again later" in lowered)
        or ("on demand capacity" in lowered and "try again later" in lowered)
        or "capacity exceeded" in lowered
        or "capacity unavailable" in lowered
        or ("serviceunavailableexception" in lowered and "capacity" in lowered)
    )
    if not capacity_hit:
        return ""
    surface = str(provider_surface or "").strip().lower()
    return (
        "bedrock_on_demand_capacity_exceeded"
        if surface == "aws-bedrock"
        else "provider_capacity_exceeded"
    )


def provider_capacity_no_retry_message(
    error_text: Any,
    *,
    provider_error_kind: str = "",
    service_tier: Any = "",
    model: Any = "",
) -> str:
    kind = str(provider_error_kind or "").strip()
    subject = (
        "Bedrock on-demand capacity"
        if kind == "bedrock_on_demand_capacity_exceeded"
        else "Provider capacity"
    )
    lane_label = service_tier_label(normalize_service_tier(service_tier))
    model_label = str(model or "").strip()
    parts = [
        f"{subject} was unavailable before the provider returned any tokens.",
        (
            "The failed turn had already used tools or files, so the TUI "
            "preserved the current context instead of replaying side effects."
        ),
        (
            "Retry or Proceed later, or split the next prompt into a smaller "
            "Bedrock continuation."
        ),
    ]
    if lane_label:
        parts.append(f"Lane was {lane_label}.")
    if model_label:
        parts.append(f"Model was {model_label}.")
    original = summarize_text(str(error_text or ""), 360)
    if original:
        parts.append(f"Original provider error: {original}")
    return " ".join(parts)


def visible_provider_error_message(
    error_text: Any,
    usage: dict[str, Any] | None,
    *,
    service_tier: Any = "",
    model: Any = "",
) -> str:
    clean = str(error_text or "").strip()
    if not clean:
        return ""
    normalized_usage = normalize_usage_entry(usage or {})
    provider_surface = (
        str(normalized_usage.get("provider_surface") or "").strip().lower()
    )
    if provider_surface != "aws-bedrock":
        return clean
    provider_kind = str(normalized_usage.get("provider_error_kind") or "").strip()
    if not provider_kind:
        provider_kind = provider_error_kind(clean, provider_surface=provider_surface)
    if not provider_kind.startswith("bedrock_") and not bool(
        normalized_usage.get("zero_token_provider_failure")
    ):
        return clean
    label = "Bedrock provider failure"
    if provider_kind == "bedrock_on_demand_capacity_exceeded":
        label = "Bedrock on-demand capacity failure"
    elif provider_kind == "bedrock_stream_disconnected":
        label = "Bedrock stream failure"
    elif provider_kind == "bedrock_engine_not_found":
        label = "Bedrock engine lookup failure"
    elif provider_kind == "bedrock_provider_server_error":
        label = "Bedrock provider server failure"
    elif provider_kind == "bedrock_zero_token_no_final":
        label = "Bedrock zero-token completion failure"
    route_bits = []
    lane_label = service_tier_label(normalize_service_tier(service_tier))
    if lane_label:
        route_bits.append(f"lane={lane_label}")
    model_label = str(model or "").strip()
    if model_label:
        route_bits.append(f"model={model_label}")
    route_text = f" Route: {', '.join(route_bits)}." if route_bits else ""
    return (
        f"{label} ({provider_kind or 'unknown'}) before any usable tokens."
        f"{route_text} Original provider error: {summarize_text(clean, 500)}"
    )


BENIGN_CODEX_PROVIDER_WARNING_PATTERNS = (
    re.compile(
        r"\bWARNING:\s*failed to clean up stale arg0 temp dirs:\s*"
        r"Permission denied \(os error 13\)\s*",
        re.IGNORECASE,
    ),
)


def strip_benign_codex_provider_warnings(error_text: str) -> str:
    clean = str(error_text or "")
    for pattern in BENIGN_CODEX_PROVIDER_WARNING_PATTERNS:
        clean = pattern.sub("", clean)
    return clean.strip()


def provider_error_kind(error_text: str, *, provider_surface: str = "") -> str:
    clean = strip_benign_codex_provider_warnings(error_text)
    if not clean:
        return ""
    lowered = clean.lower()
    surface = str(provider_surface or "").strip().lower()
    if "model is not supported when using codex with a chatgpt account" in lowered or (
        "openai.gpt-" in lowered and "chatgpt account" in lowered
    ):
        return "codex_model_route_mismatch"
    capacity_kind = provider_capacity_error_kind(clean, provider_surface=surface)
    if capacity_kind:
        return capacity_kind
    if "stream disconnected before completion" in lowered:
        return (
            "bedrock_stream_disconnected"
            if surface == "aws-bedrock"
            else "stream_disconnected"
        )
    if codex_engine_not_found(clean):
        return (
            "bedrock_engine_not_found"
            if surface == "aws-bedrock"
            else "codex_engine_not_found"
        )
    if "server had an error while processing your request" in lowered:
        return (
            "bedrock_provider_server_error"
            if surface == "aws-bedrock"
            else "provider_server_error"
        )
    if "rate limit" in lowered or "rate_limit" in lowered or "throttl" in lowered:
        return "provider_rate_limited"
    if "refresh_token_reused" in lowered or "auth" in lowered:
        return "codex_auth_error"
    if "permission denied" in lowered:
        return "permission_denied"
    if "failed to record rollout items" in lowered and "not found" in lowered:
        return "codex_rollout_state_stale"
    return "codex_provider_error" if surface else "codex_error"


def provider_diagnostic_excerpt(
    *,
    proc: subprocess.CompletedProcess[str],
    event_types: list[str],
    messages: list[str],
    provider_error_text: str,
    total_tokens: int,
    has_turn_completed: bool,
    turn_failed_count: int,
) -> str:
    parts: list[str] = []
    returncode = _coerce_int(proc.returncode)
    if returncode:
        parts.append(f"codex_returncode={returncode}")
    if event_types:
        parts.append(f"codex_event_types={','.join(event_types)}")
    if not has_turn_completed:
        parts.append("missing_turn_completed=true")
    if total_tokens <= 0:
        parts.append("total_tokens=0")
    if turn_failed_count:
        parts.append(f"turn_failed_count={turn_failed_count}")
    clean_messages = [summarize_text(message, 300) for message in messages if message]
    if clean_messages:
        parts.append(f"messages={' | '.join(clean_messages[:3])}")
    stderr_excerpt = summarize_text(
        strip_benign_codex_provider_warnings(proc.stderr or ""), 600
    )
    if stderr_excerpt:
        parts.append(f"stderr={stderr_excerpt}")
    elif provider_error_text:
        parts.append(f"provider_error={summarize_text(provider_error_text, 600)}")
    return summarize_text(" | ".join(part for part in parts if part), 1200)


def codex_provider_diagnostics(
    *,
    proc: subprocess.CompletedProcess[str],
    events: list[dict[str, Any]],
    messages: list[str],
    error_text: str,
    usage: dict[str, Any],
    timed_out: bool,
    service_tier: str,
) -> dict[str, Any]:
    normalized_usage = normalize_usage_entry(
        {**(usage or {}), "service_tier": service_tier}
    )
    event_text = "\n".join(json.dumps(event, default=str) for event in events)
    diagnostic_text = "\n".join(
        part
        for part in [
            proc.stdout or "",
            proc.stderr or "",
            "\n".join(messages),
            event_text,
            error_text,
        ]
        if part
    )
    event_types = _unique_limited_values(
        [str(event.get("type") or "") for event in events], limit=20
    )
    request_ids = _unique_limited_values(
        extract_provider_request_ids(diagnostic_text)
        + extract_provider_request_ids_from_payload(events)
    )
    trace_ids = _unique_limited_values(
        extract_provider_trace_ids(diagnostic_text)
        + extract_provider_trace_ids_from_payload(events)
    )
    provider_error_text = strip_benign_codex_provider_warnings(error_text)
    provider_surface = (
        str(normalized_usage.get("provider_surface") or "").strip().lower()
    )
    total_tokens = _coerce_int(normalized_usage.get("total_tokens"))
    turn_failed_count = sum(1 for event in events if event.get("type") == "turn.failed")
    has_turn_completed = any(event.get("type") == "turn.completed" for event in events)
    error_kind = provider_error_kind(
        provider_error_text,
        provider_surface=provider_surface,
    )
    if (
        not error_kind
        and provider_surface == "aws-bedrock"
        and total_tokens == 0
        and not timed_out
        and not has_turn_completed
        and bool(events or _coerce_int(proc.returncode))
    ):
        error_kind = "bedrock_zero_token_no_final"
        provider_error_text = (
            "Bedrock turn ended without a final completion or provider error text."
        )
    zero_token_provider_failure = bool(
        error_kind
        and provider_surface == "aws-bedrock"
        and total_tokens == 0
        and not timed_out
    )
    diagnostic_excerpt = ""
    if provider_surface == "aws-bedrock" and (
        error_kind or total_tokens == 0 or request_ids or trace_ids
    ):
        diagnostic_excerpt = provider_diagnostic_excerpt(
            proc=proc,
            event_types=event_types,
            messages=messages,
            provider_error_text=provider_error_text,
            total_tokens=total_tokens,
            has_turn_completed=has_turn_completed,
            turn_failed_count=turn_failed_count,
        )
    return {
        "provider_error_kind": error_kind,
        "provider_error_text": (
            summarize_text(provider_error_text or error_text, 800) if error_kind else ""
        ),
        "provider_diagnostic_excerpt": diagnostic_excerpt,
        "provider_request_ids": request_ids,
        "provider_trace_ids": trace_ids,
        "codex_returncode": _coerce_int(proc.returncode),
        "codex_event_types": event_types,
        "codex_turn_failed_count": turn_failed_count,
        "codex_stdout_json_events": len(events),
        "zero_token_provider_failure": zero_token_provider_failure,
    }


def codex_yield_diagnostics(
    *,
    response: str,
    error_text: str,
    usage: dict[str, Any],
    success: bool,
    promised_followup: bool,
    continuation_incomplete: bool,
    started_at: int,
    finished_at: int,
) -> dict[str, Any]:
    normalized_usage = normalize_usage_entry(usage)
    total_tokens = _coerce_int(normalized_usage.get("total_tokens"))
    input_tokens = _coerce_int(normalized_usage.get("input_tokens"))
    output_tokens = _coerce_int(normalized_usage.get("output_tokens"))
    reasoning_tokens = _coerce_int(normalized_usage.get("reasoning_output_tokens"))
    response_chars = len(str(response or ""))
    duration_seconds = max(0, _coerce_int(finished_at) - _coerce_int(started_at))
    provider_error = str(normalized_usage.get("provider_error_kind") or "").strip()
    reasons: list[str] = []
    kind = ""
    if normalized_usage.get("zero_token_provider_failure") or (
        provider_error and total_tokens == 0
    ):
        kind = "zero_transport"
        reasons.append(provider_error or "zero-token provider failure")
    elif promised_followup or continuation_incomplete:
        kind = "short_stop"
        reasons.append("final response promises future work")
        if duration_seconds <= 300:
            reasons.append(f"fast return: {duration_seconds}s")
        if reasoning_tokens == 0:
            reasons.append("zero reasoning tokens")
    elif (
        success
        and total_tokens >= 20_000
        and output_tokens <= 1_000
        and duration_seconds <= 300
    ):
        kind = "low_yield"
        reasons.extend(
            [
                f"low output tokens: {output_tokens}",
                f"fast return: {duration_seconds}s",
            ]
        )
        if reasoning_tokens == 0:
            reasons.append("zero reasoning tokens")
    elif (
        success
        and total_tokens >= 20_000
        and input_tokens >= 100_000
        and response_chars <= 2_500
        and duration_seconds <= 300
    ):
        kind = "low_yield"
        reasons.extend(
            [
                f"high input tokens: {input_tokens}",
                f"short visible response chars: {response_chars}",
                f"visible yield chars per 1k input tokens: {round(response_chars / input_tokens * 1000, 2) if input_tokens else 0}",
                f"fast return: {duration_seconds}s",
            ]
        )
    elif not success and error_text:
        kind = "failed_nonzero"
        reasons.append(provider_error or "nonzero failure")
    return {
        "provider_yield_kind": kind,
        "provider_yield_reasons": reasons,
        "provider_yield_duration_seconds": duration_seconds,
        "provider_yield_response_preview": summarize_text(response, 240)
        if kind
        else "",
    }


def _usage_raw_counter(entry: dict[str, Any], key: str) -> int:
    raw_key = f"raw_{key}"
    raw_value = _coerce_int(entry.get(raw_key))
    if raw_value > 0:
        return raw_value
    return _coerce_int(entry.get(key))


def _usage_scope_key(entry: dict[str, Any]) -> tuple[str, str, str, str]:
    return (
        str(entry.get("thread_id") or "").strip(),
        str(entry.get("runtime") or "").strip(),
        str(entry.get("model") or "").strip(),
        str(entry.get("provider_surface") or "").strip(),
    )


def _usage_entry_with_effective_delta(
    entry: dict[str, Any],
    previous_entry: dict[str, Any] | None = None,
) -> dict[str, Any]:
    current = normalize_usage_entry(entry)
    if current.get("usage_meter_mode") in {"cumulative_delta", "cumulative_baseline"}:
        return current

    raw_counters = {
        "input_tokens": _usage_raw_counter(current, "input_tokens"),
        "cached_input_tokens": _usage_raw_counter(current, "cached_input_tokens"),
        "output_tokens": _usage_raw_counter(current, "output_tokens"),
        "reasoning_output_tokens": _usage_raw_counter(
            current, "reasoning_output_tokens"
        ),
        "total_tokens": _usage_raw_counter(current, "total_tokens"),
    }
    for key, value in raw_counters.items():
        current[f"raw_{key}"] = value
    current["cumulative_total_tokens"] = raw_counters["total_tokens"]

    if raw_counters["total_tokens"] < USAGE_CUMULATIVE_DETECT_MIN_TOKENS:
        current["usage_meter_mode"] = current.get("usage_meter_mode") or "per_turn"
        return current

    if not previous_entry and (
        raw_counters["total_tokens"] >= USAGE_CUMULATIVE_BASELINE_MIN_TOKENS
    ):
        # Codex/Bedrock resumed threads can report cumulative counters. If the
        # retained history starts mid-thread, treat the first huge point as a
        # baseline so summaries do not multiply-count the same token history.
        current.update(
            {
                "input_tokens": 0,
                "cached_input_tokens": 0,
                "output_tokens": 0,
                "reasoning_output_tokens": 0,
                "total_tokens": 0,
                "usage_meter_mode": "cumulative_baseline",
            }
        )
        return current
    if not previous_entry:
        current["usage_meter_mode"] = current.get("usage_meter_mode") or "per_turn"
        return current

    previous = normalize_usage_entry(previous_entry)
    previous_raw = {
        "input_tokens": _usage_raw_counter(previous, "input_tokens"),
        "cached_input_tokens": _usage_raw_counter(previous, "cached_input_tokens"),
        "output_tokens": _usage_raw_counter(previous, "output_tokens"),
        "reasoning_output_tokens": _usage_raw_counter(
            previous, "reasoning_output_tokens"
        ),
        "total_tokens": _usage_raw_counter(previous, "total_tokens"),
    }
    counter_did_not_advance = (
        raw_counters["total_tokens"] <= previous_raw["total_tokens"]
    )
    counter_component_reset = any(
        raw_counters[key] < previous_raw[key] for key in raw_counters
    )
    if counter_did_not_advance or counter_component_reset:
        if raw_counters["total_tokens"] >= USAGE_CUMULATIVE_BASELINE_MIN_TOKENS:
            # A repeated or reset cumulative counter is not fresh billable usage.
            # Keep the raw counter for diagnostics, but zero the effective turn.
            current.update(
                {
                    "input_tokens": 0,
                    "cached_input_tokens": 0,
                    "output_tokens": 0,
                    "reasoning_output_tokens": 0,
                    "total_tokens": 0,
                    "usage_meter_mode": "cumulative_baseline",
                }
            )
            return current
        current["usage_meter_mode"] = current.get("usage_meter_mode") or "per_turn"
        return current

    deltas = {
        key: max(0, raw_counters[key] - previous_raw[key]) for key in raw_counters
    }
    current.update(
        {
            "input_tokens": deltas["input_tokens"],
            "cached_input_tokens": deltas["cached_input_tokens"],
            "output_tokens": deltas["output_tokens"],
            "reasoning_output_tokens": deltas["reasoning_output_tokens"],
            "total_tokens": deltas["total_tokens"]
            or deltas["input_tokens"] + deltas["output_tokens"],
            "usage_meter_mode": "cumulative_delta",
        }
    )
    return current


def usage_entries_with_effective_deltas(
    entries: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    effective: list[dict[str, Any]] = []
    previous_by_scope: dict[tuple[str, str, str, str], dict[str, Any]] = {}
    for raw_entry in entries:
        entry = normalize_usage_entry(raw_entry)
        scope = _usage_scope_key(entry)
        previous = previous_by_scope.get(scope) if scope[0] else None
        effective_entry = _usage_entry_with_effective_delta(entry, previous)
        effective.append(effective_entry)
        if scope[0] and effective_entry.get("usage_meter_mode") in {
            "cumulative_baseline",
            "cumulative_delta",
        }:
            previous_by_scope[scope] = effective_entry
    return effective


def default_usage_summary() -> dict[str, int]:
    return {
        "turns": 0,
        "successful_turns": 0,
        "failed_turns": 0,
        "input_tokens": 0,
        "cached_input_tokens": 0,
        "output_tokens": 0,
        "reasoning_output_tokens": 0,
        "total_tokens": 0,
        "preflight_prompt_estimated_tokens": 0,
        "attachment_saved_tokens": 0,
        "local_preflight_tokens": 0,
        "local_specialist_tokens": 0,
        "local_specialist_turns": 0,
        "context_pack_saved_tokens": 0,
        "cloud_tokens_avoided_floor": 0,
        "cloud_tokens_avoided_estimate": 0,
        "cloud_preflight_net_token_delta_estimate": 0,
        "cloud_context_gate_active_turns": 0,
        "cloud_context_gate_needs_reduction_turns": 0,
        "last_turn_at": 0,
    }


def summarize_usage_entries(
    entries: list[dict[str, Any]], *, since_ts: int = 0
) -> dict[str, int]:
    summary = dict(default_usage_summary())
    for raw_entry in entries:
        entry = normalize_usage_entry(raw_entry)
        finished_at = int(entry.get("finished_at") or 0)
        if since_ts and finished_at and finished_at < since_ts:
            continue
        summary["turns"] += 1
        if entry["success"]:
            summary["successful_turns"] += 1
        else:
            summary["failed_turns"] += 1
        summary["input_tokens"] += entry["input_tokens"]
        summary["cached_input_tokens"] += entry["cached_input_tokens"]
        summary["output_tokens"] += entry["output_tokens"]
        summary["reasoning_output_tokens"] += entry["reasoning_output_tokens"]
        summary["total_tokens"] += entry["total_tokens"]
        summary["preflight_prompt_estimated_tokens"] += entry[
            "preflight_prompt_estimated_tokens"
        ]
        summary["attachment_saved_tokens"] += entry["attachment_saved_tokens"]
        summary["local_preflight_tokens"] += entry["local_preflight_tokens"]
        summary["local_specialist_tokens"] += entry["local_specialist_tokens"]
        if entry.get("local_specialist_used"):
            summary["local_specialist_turns"] += 1
        summary["context_pack_saved_tokens"] += entry["context_pack_saved_tokens"]
        summary["cloud_tokens_avoided_floor"] += entry["cloud_tokens_avoided_floor"]
        summary["cloud_tokens_avoided_estimate"] += entry[
            "cloud_tokens_avoided_estimate"
        ]
        summary["cloud_preflight_net_token_delta_estimate"] += entry[
            "cloud_preflight_net_token_delta_estimate"
        ]
        if entry["cloud_context_gate_active"]:
            summary["cloud_context_gate_active_turns"] += 1
        if entry["cloud_context_gate_status"] == "needs-local-reduction":
            summary["cloud_context_gate_needs_reduction_turns"] += 1
        summary["last_turn_at"] = max(summary["last_turn_at"], finished_at)
    return summary


def usage_sparkline_values(
    entries: list[dict[str, Any]], *, limit: int = USAGE_SPARKLINE_ITEMS
) -> list[int]:
    clean_limit = max(1, int(limit or USAGE_SPARKLINE_ITEMS))
    values: list[int] = []
    for raw_entry in entries[-clean_limit:]:
        entry = normalize_usage_entry(raw_entry)
        values.append(max(0, _coerce_int(entry.get("total_tokens"))))
    return values


def summarize_usage_by_key(
    entries: list[dict[str, Any]], key: str, *, since_ts: int = 0
) -> dict[str, dict[str, int]]:
    grouped: dict[str, dict[str, int]] = {}
    for raw_entry in entries:
        entry = normalize_usage_entry(raw_entry)
        finished_at = int(entry.get("finished_at") or 0)
        if since_ts and finished_at and finished_at < since_ts:
            continue
        value = str(entry.get(key) or "").strip() or "unknown"
        bucket = grouped.setdefault(value, dict(default_usage_summary()))
        bucket["turns"] += 1
        if entry["success"]:
            bucket["successful_turns"] += 1
        else:
            bucket["failed_turns"] += 1
        bucket["input_tokens"] += entry["input_tokens"]
        bucket["cached_input_tokens"] += entry["cached_input_tokens"]
        bucket["output_tokens"] += entry["output_tokens"]
        bucket["reasoning_output_tokens"] += entry["reasoning_output_tokens"]
        bucket["total_tokens"] += entry["total_tokens"]
        bucket["preflight_prompt_estimated_tokens"] += entry[
            "preflight_prompt_estimated_tokens"
        ]
        bucket["attachment_saved_tokens"] += entry["attachment_saved_tokens"]
        bucket["local_preflight_tokens"] += entry["local_preflight_tokens"]
        bucket["local_specialist_tokens"] += entry["local_specialist_tokens"]
        if entry.get("local_specialist_used"):
            bucket["local_specialist_turns"] += 1
        bucket["context_pack_saved_tokens"] += entry["context_pack_saved_tokens"]
        bucket["cloud_tokens_avoided_floor"] += entry["cloud_tokens_avoided_floor"]
        bucket["cloud_tokens_avoided_estimate"] += entry[
            "cloud_tokens_avoided_estimate"
        ]
        bucket["cloud_preflight_net_token_delta_estimate"] += entry[
            "cloud_preflight_net_token_delta_estimate"
        ]
        if entry["cloud_context_gate_active"]:
            bucket["cloud_context_gate_active_turns"] += 1
        if entry["cloud_context_gate_status"] == "needs-local-reduction":
            bucket["cloud_context_gate_needs_reduction_turns"] += 1
        bucket["last_turn_at"] = max(bucket["last_turn_at"], finished_at)
    return grouped


def default_route_utilization_summary() -> dict[str, Any]:
    return {
        "turns": 0,
        "successful_turns": 0,
        "failed_turns": 0,
        "local_turns": 0,
        "spark_turns": 0,
        "norllama_turns": 0,
        "cloud_turns": 0,
        "bedrock_turns": 0,
        "openai_turns": 0,
        "hybrid_turns": 0,
        "local_assisted_turns": 0,
        "local_preflight_turns": 0,
        "local_specialist_turns": 0,
        "offline_preflight_turns": 0,
        "cloud_context_gate_turns": 0,
        "cloud_context_gate_needs_reduction_turns": 0,
        "total_tokens": 0,
        "local_tokens": 0,
        "cloud_tokens": 0,
        "local_preflight_tokens": 0,
        "local_specialist_tokens": 0,
        "cloud_tokens_avoided_floor": 0,
        "cloud_tokens_avoided_estimate": 0,
        "cloud_preflight_net_token_delta_estimate": 0,
        "local_turn_rate": 0.0,
        "local_assist_rate": 0.0,
        "cloud_token_avoidance_rate": 0.0,
        "cloud_token_reduction_rate": 0.0,
        "last_turn_at": 0,
        "by_route": {},
        "by_provider": {},
    }


def route_utilization_flags(entry: dict[str, Any]) -> dict[str, bool]:
    route_class = str(entry.get("route_class") or usage_route_class(entry)).lower()
    execution = str(
        entry.get("route_execution") or usage_route_execution(entry)
    ).lower()
    runtime = normalize_runtime(entry.get("runtime"))
    provider = str(entry.get("provider_surface") or "").strip().lower()
    model = str(entry.get("model") or "").strip().lower()
    is_spark = (
        route_class == "spark"
        or runtime == "codexspark"
        or "spark" in runtime
        or "spark" in model
        or "spark" in execution
    )
    is_norllama = (
        runtime == "localllm"
        or provider in {"norllama", "ollama", "local"}
        or "norllama" in execution
        or "local_worker" in execution
    )
    is_local = route_class in {"local", "spark"} or is_spark or is_norllama
    is_bedrock = provider == "aws-bedrock" or route_class == "bedrock"
    is_openai = provider == "openai-direct" or (
        route_class == "cloud" and not is_bedrock
    )
    is_cloud = route_class in {"bedrock", "cloud"} or is_bedrock or is_openai
    is_hybrid = bool(
        is_local
        and is_cloud
        or "verifier" in execution
        or str(entry.get("route_verifier") or "").strip()
        or str(entry.get("verifier_runtime") or "").strip()
        or str(entry.get("verifier_model") or "").strip()
    )
    local_preflight = (
        bool(entry.get("local_preflight_used"))
        or _coerce_int(entry.get("local_preflight_tokens")) > 0
    )
    local_specialist = (
        bool(entry.get("local_specialist_used"))
        or _coerce_int(entry.get("local_specialist_tokens")) > 0
    )
    offline_preflight = bool(entry.get("offline_preflight_used"))
    avoided_tokens = _coerce_int(entry.get("cloud_tokens_avoided_estimate"))
    local_assisted = bool(
        is_local
        or local_preflight
        or local_specialist
        or offline_preflight
        or avoided_tokens > 0
    )
    return {
        "local": is_local,
        "spark": is_spark,
        "norllama": is_norllama,
        "cloud": is_cloud,
        "bedrock": is_bedrock,
        "openai": is_openai,
        "hybrid": is_hybrid,
        "local_preflight": local_preflight,
        "local_specialist": local_specialist,
        "offline_preflight": offline_preflight,
        "local_assisted": local_assisted,
    }


def summarize_route_utilization(
    entries: list[dict[str, Any]], *, since_ts: int = 0
) -> dict[str, Any]:
    summary = default_route_utilization_summary()
    by_route: dict[str, int] = {}
    by_provider: dict[str, int] = {}
    for raw_entry in entries:
        entry = normalize_usage_entry(raw_entry)
        finished_at = _coerce_int(entry.get("finished_at"))
        if since_ts and finished_at and finished_at < since_ts:
            continue
        flags = route_utilization_flags(entry)
        route_class = str(entry.get("route_class") or usage_route_class(entry)).lower()
        provider = str(entry.get("provider_surface") or "").strip().lower() or "unknown"
        total_tokens = _coerce_int(entry.get("total_tokens"))
        local_preflight_tokens = _coerce_int(entry.get("local_preflight_tokens"))
        local_specialist_tokens = _coerce_int(entry.get("local_specialist_tokens"))
        summary["turns"] += 1
        if entry.get("success"):
            summary["successful_turns"] += 1
        else:
            summary["failed_turns"] += 1
        if flags["local"]:
            summary["local_turns"] += 1
        if flags["spark"]:
            summary["spark_turns"] += 1
        if flags["norllama"]:
            summary["norllama_turns"] += 1
        if flags["cloud"]:
            summary["cloud_turns"] += 1
        if flags["bedrock"]:
            summary["bedrock_turns"] += 1
        if flags["openai"]:
            summary["openai_turns"] += 1
        if flags["hybrid"]:
            summary["hybrid_turns"] += 1
        if flags["local_assisted"]:
            summary["local_assisted_turns"] += 1
        if flags["local_preflight"]:
            summary["local_preflight_turns"] += 1
        if flags["local_specialist"]:
            summary["local_specialist_turns"] += 1
        if flags["offline_preflight"]:
            summary["offline_preflight_turns"] += 1
        if entry.get("cloud_context_gate_active"):
            summary["cloud_context_gate_turns"] += 1
        if str(entry.get("cloud_context_gate_status") or "") == "needs-local-reduction":
            summary["cloud_context_gate_needs_reduction_turns"] += 1
        summary["total_tokens"] += total_tokens
        summary["local_preflight_tokens"] += local_preflight_tokens
        summary["local_specialist_tokens"] += local_specialist_tokens
        if flags["local"] and not flags["cloud"]:
            summary["local_tokens"] += total_tokens
        if flags["cloud"]:
            summary["cloud_tokens"] += total_tokens
        summary["local_tokens"] += local_preflight_tokens + local_specialist_tokens
        summary["cloud_tokens_avoided_floor"] += _coerce_int(
            entry.get("cloud_tokens_avoided_floor")
        )
        summary["cloud_tokens_avoided_estimate"] += _coerce_int(
            entry.get("cloud_tokens_avoided_estimate")
        )
        summary["cloud_preflight_net_token_delta_estimate"] += _coerce_int(
            entry.get("cloud_preflight_net_token_delta_estimate")
        )
        summary["last_turn_at"] = max(summary["last_turn_at"], finished_at)
        by_route[route_class or "unknown"] = (
            by_route.get(route_class or "unknown", 0) + 1
        )
        by_provider[provider] = by_provider.get(provider, 0) + 1
    turns = max(0, _coerce_int(summary.get("turns")))
    if turns > 0:
        summary["local_turn_rate"] = round(summary["local_turns"] / turns, 4)
        summary["local_assist_rate"] = round(summary["local_assisted_turns"] / turns, 4)
    cloud_tokens = max(0, _coerce_int(summary.get("cloud_tokens")))
    avoided = max(0, _coerce_int(summary.get("cloud_tokens_avoided_estimate")))
    denominator = cloud_tokens + avoided
    if denominator > 0:
        summary["cloud_token_avoidance_rate"] = round(avoided / denominator, 4)
        summary["cloud_token_reduction_rate"] = summary["cloud_token_avoidance_rate"]
    summary["by_route"] = dict(sorted(by_route.items()))
    summary["by_provider"] = dict(sorted(by_provider.items()))
    return summary


def route_utilization_snapshot(
    entries: list[dict[str, Any]],
    *,
    current_thread_entries: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    recent_since = max(0, now_ts() - USAGE_WINDOW_SECONDS)
    thread_entries = current_thread_entries or []
    return {
        "schema": "norman.tui.route-utilization.v1",
        "window_seconds": USAGE_WINDOW_SECONDS,
        "totals": summarize_route_utilization(entries),
        "last_24h": summarize_route_utilization(entries, since_ts=recent_since),
        "current_thread": summarize_route_utilization(thread_entries)
        if thread_entries
        else default_route_utilization_summary(),
        "live_tool_activity": {},
    }


def route_utilization_with_live_activity(
    utilization: dict[str, Any],
    tool_activity: dict[str, Any] | None,
    route_outcomes: dict[str, Any] | None = None,
) -> dict[str, Any]:
    payload = dict(utilization) if isinstance(utilization, dict) else {}
    payload.setdefault("schema", "norman.tui.route-utilization.v1")
    activity = tool_activity if isinstance(tool_activity, dict) else {}
    outcomes = route_outcomes if isinstance(route_outcomes, dict) else {}
    live_tool_activity = {
        "schema": str(
            activity.get("schema") or "norman.norllama.tool-activity.v1"
        ).strip(),
        "status": str(activity.get("status") or "quiet").strip(),
        "tool_call_count": _coerce_int(activity.get("tool_call_count")),
        "source_count": _coerce_int(activity.get("source_count")),
        "capability_counts": activity.get("capability_counts")
        if isinstance(activity.get("capability_counts"), dict)
        else {},
        "latest_tool_call": activity.get("latest_tool_call")
        if isinstance(activity.get("latest_tool_call"), dict)
        else {},
        "route_outcome_count": _coerce_int(outcomes.get("count")),
        "route_outcome_ok": _coerce_int(outcomes.get("ok")),
        "route_outcome_fail": _coerce_int(outcomes.get("fail")),
    }
    payload["live_tool_activity"] = live_tool_activity
    return payload


def _usage_cost_rates_from_env(prefix: str, *, source: str) -> dict[str, Any]:
    input_rate = _coerce_float(os.environ.get(f"{prefix}_INPUT_USD_PER_1M", ""))
    cached_input_rate = _coerce_float(
        os.environ.get(f"{prefix}_CACHED_INPUT_USD_PER_1M", "")
    )
    output_rate = _coerce_float(os.environ.get(f"{prefix}_OUTPUT_USD_PER_1M", ""))
    configured = any(rate > 0 for rate in (input_rate, cached_input_rate, output_rate))
    return {
        "configured": configured,
        "approximate": False,
        "source": source if configured else "not_configured",
        "input_usd_per_1m": input_rate,
        "cached_input_usd_per_1m": cached_input_rate,
        "output_usd_per_1m": output_rate,
        "long_context_input_threshold": 0,
        "long_context_input_multiplier": 1.0,
        "long_context_output_multiplier": 1.0,
    }


def _usage_cost_rates() -> dict[str, Any]:
    return _usage_cost_rates_from_env("NORMAN_CODEX_EST", source="env:global")


def _usage_cost_rates_for_model_tier(
    model: Any = "", service_tier: Any = ""
) -> dict[str, Any]:
    tier = normalize_service_tier(service_tier or DEFAULT_SERVICE_TIER)
    env_suffixes = [tier.upper().replace("-", "_")]
    if tier == "default":
        env_suffixes.append("STANDARD")
    for suffix in env_suffixes:
        env_rates = _usage_cost_rates_from_env(
            f"NORMAN_CODEX_EST_{suffix}", source=f"env:{tier}"
        )
        if env_rates["configured"]:
            env_rates["service_tier"] = tier
            return env_rates
    global_rates = _usage_cost_rates()
    if global_rates["configured"]:
        global_rates["service_tier"] = tier
        return global_rates
    rates = _public_usage_cost_rates_for_model(model, service_tier=tier)
    rates["service_tier"] = tier
    return rates


def _effective_usage_service_tier(entry: dict[str, Any]) -> str:
    observed = str(entry.get("observed_service_tier") or "").strip()
    resolved = str(entry.get("resolved_service_tier") or "").strip()
    requested = str(entry.get("service_tier") or "").strip()
    return normalize_service_tier(observed or resolved or requested)


def _billable_output_tokens(summary: dict[str, Any]) -> int:
    output_tokens = max(0, _coerce_int(summary.get("output_tokens")))
    reasoning_tokens = max(0, _coerce_int(summary.get("reasoning_output_tokens")))
    return output_tokens if output_tokens > 0 else reasoning_tokens


def _estimate_usage_cost_with_rates(
    summary: dict[str, Any], rates: dict[str, Any]
) -> dict[str, Any]:
    input_tokens = max(0, _coerce_int(summary.get("input_tokens")))
    cached_tokens = max(0, _coerce_int(summary.get("cached_input_tokens")))
    output_tokens = _billable_output_tokens(summary)
    uncached_input_tokens = max(0, input_tokens - cached_tokens)
    usd = 0.0
    if rates["configured"]:
        input_multiplier = 1.0
        output_multiplier = 1.0
        threshold = _coerce_int(rates.get("long_context_input_threshold"))
        long_context = threshold > 0 and input_tokens > threshold
        if long_context:
            input_multiplier = max(
                1.0, _coerce_float(rates.get("long_context_input_multiplier"))
            )
            output_multiplier = max(
                1.0, _coerce_float(rates.get("long_context_output_multiplier"))
            )
        usd += (
            (uncached_input_tokens / 1_000_000)
            * rates["input_usd_per_1m"]
            * input_multiplier
        )
        usd += (
            (cached_tokens / 1_000_000)
            * rates["cached_input_usd_per_1m"]
            * input_multiplier
        )
        usd += (
            (output_tokens / 1_000_000) * rates["output_usd_per_1m"] * output_multiplier
        )
    else:
        long_context = False
    return {
        "configured": bool(rates["configured"]),
        "approximate": bool(rates.get("approximate")),
        "usd": round(usd, 6) if rates["configured"] else 0.0,
        "rate_source": str(rates["source"]),
        "long_context": long_context,
        "rates": rates,
    }


def _codex_credit_rates_for_model(model: Any) -> dict[str, Any]:
    clean = normalize_codex_model_name(
        model or configured_chat_model(), fallback=MODEL
    ).lower()
    if clean.startswith(("gpt-5.4", "openai.gpt-5.4")):
        return {
            "configured": True,
            "source": "OpenAI Codex GPT-5.4 credit rate card",
            "input_credits_per_1m": 62.5,
            "cached_input_credits_per_1m": 6.25,
            "output_credits_per_1m": 375.0,
        }
    if clean.startswith(("gpt-5.5", "openai.gpt-5.5")):
        return {
            "configured": True,
            "source": "OpenAI Codex GPT-5.5 credit rate card",
            "input_credits_per_1m": 125.0,
            "cached_input_credits_per_1m": 12.5,
            "output_credits_per_1m": 750.0,
        }
    return {
        "configured": False,
        "source": "",
        "input_credits_per_1m": 0.0,
        "cached_input_credits_per_1m": 0.0,
        "output_credits_per_1m": 0.0,
    }


def _estimate_usage_codex_credits(
    summary: dict[str, Any], *, model: Any = ""
) -> dict[str, Any]:
    rates = _codex_credit_rates_for_model(model)
    input_tokens = max(0, _coerce_int(summary.get("input_tokens")))
    cached_tokens = max(0, _coerce_int(summary.get("cached_input_tokens")))
    output_tokens = _billable_output_tokens(summary)
    uncached_input_tokens = max(0, input_tokens - cached_tokens)
    credits = 0.0
    if rates["configured"]:
        credits += (uncached_input_tokens / 1_000_000) * rates["input_credits_per_1m"]
        credits += (cached_tokens / 1_000_000) * rates["cached_input_credits_per_1m"]
        credits += (output_tokens / 1_000_000) * rates["output_credits_per_1m"]
    return {
        "configured": bool(rates["configured"]),
        "credits": round(credits, 6) if rates["configured"] else 0.0,
        "rate_source": str(rates["source"]),
        "rates": rates,
    }


def estimate_usage_cost(
    summary: dict[str, Any], *, model: Any = "", service_tier: Any = ""
) -> dict[str, Any]:
    rates = _usage_cost_rates_for_model_tier(model, service_tier)
    return _estimate_usage_cost_with_rates(summary, rates)


TURN_PLAN_PROMPT_MARKERS = (
    "Governance drift preflight:",
    "BBS handoff notice",
    "Context preflight:",
    "When you respond in this console",
    "Staged material for this prompt:",
)


def default_turn_plan_estimate() -> dict[str, Any]:
    return {
        "schema": "norman.tui.turn-plan-estimate.v1",
        "stage": "idle",
        "created_at": 0,
        "finished_at": 0,
        "understood_task": "",
        "plan_summary": "",
        "plan_steps": [],
        "skill_labels": [],
        "estimated_skill_count": 0,
        "estimated_tool_calls_min": 0,
        "estimated_tool_calls_max": 0,
        "estimated_input_tokens": 0,
        "estimated_output_tokens": 0,
        "estimated_total_tokens": 0,
        "observed_total_tokens": 0,
        "estimate_delta_tokens": 0,
        "estimated_cost_usd": 0.0,
        "cost_configured": False,
        "cost_rate_source": "",
        "estimate_confidence": "none",
        "runtime": "",
        "model": "",
        "service_tier": "",
        "job_budget": "",
        "optimization_mode": "",
        "speed": "",
        "detail": 0,
        "timeout_seconds": 0,
        "attachment_count": 0,
        "success": False,
    }


def normalize_turn_plan_estimate(value: Any) -> dict[str, Any]:
    payload = dict(default_turn_plan_estimate())
    if isinstance(value, dict):
        payload.update(value)
    payload["stage"] = str(payload.get("stage") or "idle").strip().lower() or "idle"
    if payload["stage"] not in {"idle", "planned", "final"}:
        payload["stage"] = "planned"
    for key in (
        "created_at",
        "finished_at",
        "estimated_skill_count",
        "estimated_tool_calls_min",
        "estimated_tool_calls_max",
        "estimated_input_tokens",
        "estimated_output_tokens",
        "estimated_total_tokens",
        "observed_total_tokens",
        "estimate_delta_tokens",
        "timeout_seconds",
        "attachment_count",
        "detail",
    ):
        payload[key] = _coerce_int(payload.get(key))
    payload["estimated_cost_usd"] = round(
        max(0.0, _coerce_float(payload.get("estimated_cost_usd"))), 6
    )
    payload["cost_configured"] = bool(payload.get("cost_configured"))
    payload["success"] = bool(payload.get("success"))
    for key in (
        "understood_task",
        "plan_summary",
        "cost_rate_source",
        "estimate_confidence",
        "runtime",
        "model",
        "service_tier",
        "job_budget",
        "optimization_mode",
        "speed",
    ):
        payload[key] = summarize_text(str(payload.get(key) or "").strip(), 360)
    for key in ("plan_steps", "skill_labels"):
        raw_items = payload.get(key)
        if not isinstance(raw_items, list):
            payload[key] = []
            continue
        items: list[str] = []
        for raw_item in raw_items[:8]:
            item = summarize_text(str(raw_item or "").strip(), 140)
            if item and item not in items:
                items.append(item)
        payload[key] = items
    if not payload["estimated_skill_count"]:
        payload["estimated_skill_count"] = len(payload["skill_labels"])
    if not payload["estimated_total_tokens"]:
        payload["estimated_total_tokens"] = (
            payload["estimated_input_tokens"] + payload["estimated_output_tokens"]
        )
    return payload


def prompt_core_request(prompt: str) -> str:
    text = str(prompt or "").strip()
    for marker in TURN_PLAN_PROMPT_MARKERS:
        index = text.find(marker)
        if index > 0:
            text = text[:index].strip()
    text = re.sub(r"\s+", " ", text)
    return text


def prompt_without_request_preface(prompt: str) -> str:
    text = prompt_core_request(prompt)
    text = re.sub(
        r"^(please\s+)?(can|could|would)\s+you\s+",
        "",
        text,
        flags=re.IGNORECASE,
    )
    text = re.sub(r"^i\s+(want|need|would like)\s+(you\s+)?to\s+", "", text, flags=re.I)
    return text.strip(" .")


def planner_understood_task(prompt: str, attachments: list[dict[str, Any]]) -> str:
    clean = prompt_without_request_preface(prompt)
    lower = clean.lower()
    if not clean and attachments:
        return "Handle the attached material."
    if any(token in lower for token in ("benchmark", "matrix", "kpi")):
        prefix = "Benchmark and measure"
    elif any(token in lower for token in ("implement", "add ", "wire ", "build ")):
        prefix = "Implement"
    elif any(token in lower for token in ("test", "verify", "proof", "check")):
        prefix = "Verify"
    elif any(token in lower for token in ("explain", "why", "what is", "feedback")):
        prefix = "Explain"
    else:
        prefix = "Handle"
    return summarize_text(f"{prefix}: {clean}", 220)


def console_runtime_execution_objective(
    prompt: str, attachments: list[dict[str, Any]]
) -> str:
    clean = prompt_core_request(prompt).strip()
    if clean:
        return clean
    if attachments:
        return "Handle the attached material."
    return "Handle the operator request."


def turn_plan_skill_labels(prompt: str, attachments: list[dict[str, Any]]) -> list[str]:
    lower = prompt_core_request(prompt).lower()
    labels = ["context triage"]
    if attachments:
        labels.append("attachment review")
    if any(
        token in lower
        for token in (
            "code",
            "implement",
            "patch",
            "wire",
            "build",
            "add ",
            "create",
            "change",
            "edit",
        )
    ):
        labels.append("code edit")
    if any(
        token in lower for token in ("test", "verify", "benchmark", "kpi", "matrix")
    ):
        labels.append("verification")
    if any(
        token in lower for token in ("cost", "token", "budget", "estimate", "pricing")
    ):
        labels.append("cost accounting")
    if any(token in lower for token in ("deploy", "restart", "prod", "production")):
        labels.append("approval boundary check")
    if any(token in lower for token in ("jira", "helpdesk", "ticket", "runbook")):
        labels.append("runbook routing")
    if len(labels) == 1:
        labels.append("answer synthesis")
    return labels[:7]


def turn_plan_steps_for_prompt(
    prompt: str, attachments: list[dict[str, Any]]
) -> list[str]:
    labels = turn_plan_skill_labels(prompt, attachments)
    steps = ["Read the targeted context and active state."]
    if "attachment review" in labels:
        steps.append("Inspect attached material only where it affects the task.")
    if "code edit" in labels:
        steps.append("Patch the smallest relevant code path.")
    if "runbook routing" in labels:
        steps.append("Match the request to the eligible runbook or handoff path.")
    if "verification" in labels:
        steps.append("Run focused checks and capture evidence.")
    if "cost accounting" in labels:
        steps.append("Estimate planned spend and compare it with observed usage.")
    if "approval boundary check" in labels:
        steps.append("Stop before any high-impact external action.")
    steps.append("Return the result with concrete evidence.")
    return steps[:7]


def estimate_turn_output_tokens(detail: int, job_budget: str, prompt: str) -> int:
    detail_tokens = {1: 700, 2: 1200, 3: 2200, 4: 3600, 5: 5600}
    output_tokens = detail_tokens.get(normalize_response_detail(detail), 2200)
    lower = prompt_core_request(prompt).lower()
    if any(token in lower for token in ("benchmark", "matrix", "test", "kpi")):
        output_tokens += 1400
    if any(
        token in lower
        for token in (
            "implement",
            "patch",
            "build",
            "wire",
            "add ",
            "create",
            "change",
            "edit",
        )
    ):
        output_tokens += 900
    target_seconds = job_budget_timeout_seconds(normalize_job_budget(job_budget))
    if target_seconds >= 2 * 60 * 60:
        output_tokens += 1600
    elif target_seconds >= 60 * 60:
        output_tokens += 800
    return output_tokens


def estimate_turn_tool_call_range(
    prompt: str, attachments: list[dict[str, Any]], skill_count: int
) -> tuple[int, int]:
    lower = prompt_core_request(prompt).lower()
    minimum = 1 if prompt or attachments else 0
    maximum = max(minimum, skill_count + 1)
    if any(
        token in lower
        for token in (
            "implement",
            "patch",
            "code",
            "build",
            "wire",
            "add ",
            "create",
            "change",
            "edit",
        )
    ):
        minimum += 2
        maximum += 5
    if any(
        token in lower for token in ("test", "verify", "benchmark", "matrix", "kpi")
    ):
        minimum += 2
        maximum += 5
    if attachments:
        minimum += 1
        maximum += max(1, min(len(attachments), 4))
    if any(token in lower for token in ("deploy", "restart", "aws", "bedrock")):
        maximum += 3
    return max(0, minimum), max(minimum, maximum)


def build_turn_plan_estimate(
    *,
    prompt: str,
    attachments: list[dict[str, Any]],
    runtime: str,
    model: str,
    service_tier: str,
    job_budget: str,
    optimization_mode: str,
    speed: str,
    detail: int,
    timeout_seconds: int,
    drift_assessment: dict[str, Any] | None = None,
    created_at: int = 0,
) -> dict[str, Any]:
    normalized_runtime = normalize_runtime(runtime)
    normalized_model = normalize_runtime_model(normalized_runtime, model)
    normalized_tier = normalize_service_tier(service_tier)
    normalized_budget = normalize_job_budget(job_budget)
    normalized_detail = normalize_response_detail(detail)
    normalized_attachments = normalize_attachments(attachments)
    skill_labels = turn_plan_skill_labels(prompt, normalized_attachments)
    plan_steps = turn_plan_steps_for_prompt(prompt, normalized_attachments)
    input_tokens = _estimated_text_tokens(prompt) + _estimated_attachment_tokens(
        normalized_attachments
    )
    output_tokens = estimate_turn_output_tokens(
        normalized_detail, normalized_budget, prompt
    )
    cost = estimate_usage_cost(
        {
            "input_tokens": input_tokens,
            "cached_input_tokens": 0,
            "output_tokens": output_tokens,
        },
        model=normalized_model,
        service_tier=normalized_tier,
    )
    tool_min, tool_max = estimate_turn_tool_call_range(
        prompt, normalized_attachments, len(skill_labels)
    )
    confidence = "medium"
    if drift_assessment and str(drift_assessment.get("tone") or "") in {
        "warn",
        "alert",
    }:
        confidence = "low"
    elif input_tokens > 80_000 or tool_max > 10:
        confidence = "rough"
    return normalize_turn_plan_estimate(
        {
            "stage": "planned",
            "created_at": created_at or now_ts(),
            "understood_task": planner_understood_task(prompt, normalized_attachments),
            "plan_summary": " ".join(step.rstrip(".") + "." for step in plan_steps[:3]),
            "plan_steps": plan_steps,
            "skill_labels": skill_labels,
            "estimated_skill_count": len(skill_labels),
            "estimated_tool_calls_min": tool_min,
            "estimated_tool_calls_max": tool_max,
            "estimated_input_tokens": input_tokens,
            "estimated_output_tokens": output_tokens,
            "estimated_total_tokens": input_tokens + output_tokens,
            "estimated_cost_usd": cost.get("usd", 0.0),
            "cost_configured": bool(cost.get("configured")),
            "cost_rate_source": str(cost.get("rate_source") or ""),
            "estimate_confidence": confidence,
            "runtime": normalized_runtime,
            "model": normalized_model,
            "service_tier": normalized_tier,
            "job_budget": normalized_budget,
            "optimization_mode": normalize_optimization_mode(optimization_mode),
            "speed": normalize_response_speed(speed),
            "detail": normalized_detail,
            "timeout_seconds": normalize_job_timeout_seconds(
                timeout_seconds, normalized_budget
            ),
            "attachment_count": len(normalized_attachments),
        }
    )


def finalize_turn_plan_estimate(
    value: Any, *, usage: dict[str, Any], finished_at: int, success: bool
) -> dict[str, Any]:
    payload = normalize_turn_plan_estimate(value)
    usage_entry = normalize_usage_entry(usage)
    observed_total = _coerce_int(usage_entry.get("total_tokens"))
    estimated_total = _coerce_int(payload.get("estimated_total_tokens"))
    payload.update(
        {
            "stage": "final",
            "finished_at": finished_at or now_ts(),
            "observed_total_tokens": observed_total,
            "estimate_delta_tokens": observed_total - estimated_total
            if observed_total
            else 0,
            "success": bool(success),
        }
    )
    return normalize_turn_plan_estimate(payload)


def _usage_rate_card_key(model: Any, service_tier: Any) -> str:
    clean_model = str(model or configured_chat_model() or MODEL or "unknown").strip()
    tier = normalize_service_tier(service_tier)
    return f"{clean_model}::{tier}"


def usage_rate_cards(entries: list[dict[str, Any]]) -> dict[str, dict[str, Any]]:
    cards: dict[str, dict[str, Any]] = {}
    for raw_entry in entries:
        entry = normalize_usage_entry(raw_entry)
        tier = _effective_usage_service_tier(entry)
        model = entry.get("model") or MODEL
        key = _usage_rate_card_key(model, tier)
        cards[key] = _usage_cost_rates_for_model_tier(model, tier)
    return cards


def estimate_usage_entries_cost(
    entries: list[dict[str, Any]], *, since_ts: int = 0
) -> dict[str, Any]:
    total_usd = 0.0
    total_credits = 0.0
    configured_entries = 0
    credit_configured_entries = 0
    approximate = False
    long_context = False
    by_rate_source: dict[str, int] = {}
    by_credit_rate_source: dict[str, int] = {}
    by_meter_mode: dict[str, int] = {}
    by_charge_ledger_kind: dict[str, int] = {}
    by_charge_display_unit: dict[str, int] = {}
    cards: dict[str, dict[str, Any]] = {}
    counted_entries = 0
    excluded_cumulative_baselines = 0
    zero_effective_token_entries = 0
    for raw_entry in entries:
        entry = normalize_usage_entry(raw_entry)
        finished_at = int(entry.get("finished_at") or 0)
        if since_ts and finished_at and finished_at < since_ts:
            continue
        counted_entries += 1
        meter_mode = (
            str(entry.get("usage_meter_mode") or "unknown").strip() or "unknown"
        )
        by_meter_mode[meter_mode] = by_meter_mode.get(meter_mode, 0) + 1
        if meter_mode == "cumulative_baseline":
            excluded_cumulative_baselines += 1
        if _coerce_int(entry.get("total_tokens")) <= 0:
            zero_effective_token_entries += 1
        tier = _effective_usage_service_tier(entry)
        model = entry.get("model") or MODEL
        ledger_kind = str(
            entry.get("charge_ledger_kind") or ""
        ).strip() or usage_charge_ledger_kind(entry)
        display_unit = str(
            entry.get("charge_display_unit") or ""
        ).strip() or usage_charge_display_unit(ledger_kind)
        by_charge_ledger_kind[ledger_kind] = (
            by_charge_ledger_kind.get(ledger_kind, 0) + 1
        )
        by_charge_display_unit[display_unit] = (
            by_charge_display_unit.get(display_unit, 0) + 1
        )
        rates = _usage_cost_rates_for_model_tier(model, tier)
        cards[_usage_rate_card_key(model, tier)] = rates
        source = str(rates.get("source") or "not_configured")
        by_rate_source[source] = by_rate_source.get(source, 0) + 1
        estimate = _estimate_usage_cost_with_rates(entry, rates)
        approximate = approximate or bool(estimate.get("approximate"))
        long_context = long_context or bool(estimate.get("long_context"))
        if estimate["configured"]:
            configured_entries += 1
            total_usd += float(estimate["usd"])
        credit_estimate = _estimate_usage_codex_credits(entry, model=model)
        credit_source = str(credit_estimate.get("rate_source") or "not_configured")
        by_credit_rate_source[credit_source] = (
            by_credit_rate_source.get(credit_source, 0) + 1
        )
        if credit_estimate["configured"]:
            credit_configured_entries += 1
            total_credits += float(credit_estimate["credits"])
    configured = counted_entries > 0 and configured_entries == counted_entries
    credit_configured = (
        counted_entries > 0 and credit_configured_entries == counted_entries
    )
    confidence = "unpriced"
    if configured:
        confidence = "approximate_rate_card" if approximate else "configured_local_rate"
    elif configured_entries:
        confidence = "partial_rate_card"
    return {
        "configured": configured,
        "credits_configured": credit_configured,
        "approximate": approximate,
        "confidence": confidence,
        "invoice_reconciled": False,
        "charge_status": "not_invoice_reconciled",
        "ledger_kind": (
            "mixed"
            if len(by_charge_ledger_kind) > 1
            else next(iter(by_charge_ledger_kind), "unknown")
        ),
        "display_unit": (
            "mixed"
            if len(by_charge_display_unit) > 1
            else next(iter(by_charge_display_unit), "tokens")
        ),
        "usd": round(total_usd, 6) if configured_entries else 0.0,
        "credits": round(total_credits, 6) if credit_configured_entries else 0.0,
        "long_context": long_context,
        "rate_source": (
            "mixed"
            if len(by_rate_source) > 1
            else next(iter(by_rate_source), "not_configured")
        ),
        "rates": next(iter(cards.values()), _usage_cost_rates()),
        "rate_cards": cards,
        "entries": counted_entries,
        "configured_entries": configured_entries,
        "credit_configured_entries": credit_configured_entries,
        "by_rate_source": by_rate_source,
        "by_credit_rate_source": by_credit_rate_source,
        "by_meter_mode": by_meter_mode,
        "by_charge_ledger_kind": by_charge_ledger_kind,
        "by_charge_display_unit": by_charge_display_unit,
        "excluded_cumulative_baseline_entries": excluded_cumulative_baselines,
        "zero_effective_token_entries": zero_effective_token_entries,
        "note": (
            "Local estimate from effective per-turn or cumulative-delta tokens; "
            "not a credit-card charge and not reconciled to a provider invoice."
        ),
    }


def billing_tag_health(tags: dict[str, str]) -> dict[str, Any]:
    required = (
        "billing_scope",
        "billing_unit",
        "billing_owner",
        "billing_project",
        "agent_slug",
        "host_name",
    )
    missing = [
        key
        for key in required
        if not str(tags.get(key) or "").strip()
        or str(tags.get(key) or "").strip().lower() == "unknown"
    ]
    warnings: list[str] = []
    scope = str(tags.get("billing_scope") or "").strip()
    unit = str(tags.get("billing_unit") or "").strip()
    owner = str(tags.get("billing_owner") or "").strip()
    group = str(tags.get("agent_group") or "").strip().lower()
    if scope and unit and not unit.startswith(f"{scope}:"):
        warnings.append("billing_unit does not start with billing_scope")
    if group == "work" and owner != "openbrand":
        warnings.append("work lane billing_owner is not openbrand")
    if DEFAULT_SERVICE_TIER == "default" and CODEX_STANDARD_PROFILE_V2:
        if not CODEX_STANDARD_AWS_PROFILE:
            warnings.append("Bedrock default is missing AWS profile")
        if not CODEX_STANDARD_AWS_REGION:
            warnings.append("Bedrock default is missing AWS region")
    state = "ok"
    if missing:
        state = "missing"
    elif warnings:
        state = "warn"
    return {
        "state": state,
        "missing": missing,
        "warnings": warnings,
        "tagged": not missing,
    }


def cost_explorer_hints(tags: dict[str, str]) -> dict[str, Any]:
    surface = "aws-bedrock" if CODEX_STANDARD_PROFILE_V2 else "openai-direct"
    return {
        "surface": surface,
        "default_service_tier": DEFAULT_SERVICE_TIER,
        "provider_label": service_tier_label(DEFAULT_SERVICE_TIER),
        "profile_v2": CODEX_STANDARD_PROFILE_V2,
        "aws_profile": CODEX_STANDARD_AWS_PROFILE,
        "aws_region": CODEX_STANDARD_AWS_REGION,
        "billing_scope": tags.get("billing_scope", ""),
        "billing_unit": tags.get("billing_unit", ""),
        "billing_owner": tags.get("billing_owner", ""),
        "billing_project": tags.get("billing_project", ""),
        "suggested_group_by": [
            "billing_owner",
            "billing_scope",
            "billing_unit",
            "billing_project",
            "profile_v2",
            "service_tier",
        ],
        "note": (
            "Cost Explorer attribution requires the AWS/Bedrock side to preserve "
            "profile, principal, inference-profile, or cost-allocation tags. The TUI "
            "ledger keeps matching local tags for reconciliation."
        ),
    }


def usage_billing_report(entries: list[dict[str, Any]]) -> dict[str, Any]:
    tags = usage_accounting_tags()
    recent_since = max(0, now_ts() - USAGE_WINDOW_SECONDS)
    effective_entries = usage_entries_with_effective_deltas(entries)
    return {
        "schema": "norman.tui.billing.v1",
        "tags": tags,
        "tag_health": billing_tag_health(tags),
        "cost_explorer": cost_explorer_hints(tags),
        "sparkline": usage_sparkline_values(effective_entries),
        "routes": summarize_usage_by_key(effective_entries, "route_class"),
        "providers": summarize_usage_by_key(effective_entries, "provider_surface"),
        "service_tiers": summarize_usage_by_key(effective_entries, "service_tier"),
        "models": summarize_usage_by_key(effective_entries, "model"),
        "rate_cards": usage_rate_cards(effective_entries),
        "totals_estimate": estimate_usage_entries_cost(effective_entries),
        "last_24h_estimate": estimate_usage_entries_cost(
            effective_entries, since_ts=recent_since
        ),
    }


def load_usage_history(limit: int = MAX_USAGE_ITEMS) -> list[dict[str, Any]]:
    ensure_state_dir()
    entries: list[dict[str, Any]] = []
    try:
        lines = USAGE_PATH.read_text(encoding="utf-8").splitlines()
    except FileNotFoundError:
        return entries
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        try:
            payload = json.loads(stripped)
        except json.JSONDecodeError:
            continue
        entries.append(normalize_usage_entry(payload))
    if limit and len(entries) > limit:
        return entries[-limit:]
    return entries


def append_usage_ledger_entry(entry: dict[str, Any]) -> None:
    ensure_state_dir()
    serialized = json.dumps(normalize_usage_entry(entry), sort_keys=True)
    with USAGE_LEDGER_PATH.open("a", encoding="utf-8") as handle:
        handle.write(serialized + "\n")
    if MAX_USAGE_LEDGER_ITEMS <= 0:
        return
    try:
        lines = [
            line
            for line in USAGE_LEDGER_PATH.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    except OSError:
        return
    trimmed = lines[-MAX_USAGE_LEDGER_ITEMS:]
    if len(trimmed) != len(lines):
        USAGE_LEDGER_PATH.write_text("\n".join(trimmed) + "\n", encoding="utf-8")


def append_usage_entry(
    *,
    started_at: int,
    finished_at: int,
    thread_id: str,
    speed: str,
    detail: int,
    service_tier: str = "",
    success: bool,
    runtime: str = "",
    model: str = "",
    usage: dict[str, Any] | None = None,
) -> None:
    normalized_runtime = normalize_runtime(runtime)
    normalized_model = normalize_runtime_model(normalized_runtime, model)
    normalized_service_tier = normalize_service_tier(service_tier)
    provider_tags = (
        local_llm_provider_tags()
        if normalized_runtime == "localllm"
        else usage_provider_tags(normalized_service_tier)
    )
    usage_entry = normalize_usage_entry(
        {
            **(usage or {}),
            **provider_tags,
            "started_at": started_at,
            "finished_at": finished_at,
            "thread_id": thread_id,
            "speed": speed,
            "detail": detail,
            "service_tier": normalized_service_tier,
            "success": success,
            "runtime": normalized_runtime,
            "model": normalized_model,
        }
    )
    append_usage_ledger_entry(usage_entry)
    mirror_usage_entry_to_state_db(usage_entry)
    entries = load_usage_history(limit=0)
    entries.append(usage_entry)
    trimmed = entries[-MAX_USAGE_ITEMS:]
    ensure_state_dir()
    payload = "\n".join(json.dumps(item, sort_keys=True) for item in trimmed)
    if payload:
        payload += "\n"
    USAGE_PATH.write_text(payload, encoding="utf-8")


