def route_receipt_prompt_id(prompt: Any) -> str:
    clean = prompt_core_request(str(prompt or ""))
    return hashlib.sha256(clean.encode("utf-8", "replace")).hexdigest()[:16]


def route_receipt_digest(value: Any, *, length: int = 16) -> str:
    clean = json.dumps(value, sort_keys=True, default=str)
    return hashlib.sha256(clean.encode("utf-8", "replace")).hexdigest()[:length]


def route_receipt_text_has_any(text: Any, tokens: tuple[str, ...]) -> bool:
    lower = f" {str(text or '').lower()} "
    return any(token in lower for token in tokens)


def route_receipt_requires_operator_approval(prompt: Any) -> bool:
    if prompt_is_literal_response_request(prompt):
        return False
    if prompt_is_route_status_diagnostic(prompt):
        return False
    return route_receipt_text_has_any(
        prompt_core_request(str(prompt or "")), ROUTE_RECEIPT_APPROVAL_TOKENS
    )


def route_receipt_requested_action(prompt: Any) -> str:
    clean = prompt_core_request(str(prompt or ""))
    lower = clean.lower()
    if prompt_is_literal_response_request(clean):
        return "status"
    if prompt_is_route_status_diagnostic(clean):
        return "status"
    if any(token in lower for token in ("status", "check on", "wedged", "crashing")):
        return "status"
    if any(
        token in lower
        for token in ("what's next", "whats next", "what next", "proceed", "continue")
    ):
        return "proceed_or_next"
    if "wahts next" in lower:
        return "proceed_or_next"
    if any(token in lower for token in ("undo", "go back", "rollback", "revert")):
        return "undo_or_back"
    if route_receipt_requires_operator_approval(clean):
        return "approval_boundary"
    if any(
        token in lower
        for token in ("benchmark", "hybrid", "optimizer", "metric", "test")
    ):
        return "benchmark_or_optimizer"
    return "operator_prompt"


def route_receipt_skill_id(requested_action: str) -> str:
    return {
        "status": "common-status",
        "proceed_or_next": "common-proceed-next",
        "undo_or_back": "common-undo-back",
        "approval_boundary": "governance-approval-boundary",
        "benchmark_or_optimizer": "hybrid-benchmark-optimizer",
    }.get(requested_action, "general-operator-prompt")


def route_receipt_model_tier(model: Any, service_tier: Any) -> str:
    clean_model = str(model or "").strip().lower()
    tier = normalize_service_tier(service_tier)
    bedrock_surface = tier in {"default", "standard"}
    if "5.5" in clean_model:
        return "bedrock_5_5_xhigh_final" if bedrock_surface else "frontier_5_5_final"
    if "5.4" in clean_model:
        return "bedrock_5_4_verifier" if bedrock_surface else "frontier_5_4_verifier"
    if any(token in clean_model for token in ("mini", "small", "nano")):
        return "small_worker"
    if "medium" in clean_model:
        return "medium_worker"
    return "unknown"


def route_receipt_allowed_role(selected_model_tier: str) -> str:
    if "5_5" in selected_model_tier:
        return "final_authority"
    if "5_4" in selected_model_tier:
        return "verifier"
    if selected_model_tier in {"small_worker", "medium_worker"}:
        return "worker_draft"
    return "unknown"


def route_receipt_fallback_used(
    *,
    empty_reply_attempt: int = 0,
    zero_token_provider_attempt: int = 0,
    rate_limit_attempt: int = 0,
) -> str:
    labels: list[str] = []
    if empty_reply_attempt:
        labels.append("empty_reply_retry")
    if zero_token_provider_attempt:
        labels.append("zero_token_provider_retry")
    if rate_limit_attempt:
        labels.append("rate_limit_retry")
    return ",".join(labels)


def route_receipt_cost_usd(
    usage_entry: dict[str, Any], *, model: Any, service_tier: Any
) -> float:
    cost = estimate_usage_entries_cost(
        [
            normalize_usage_entry(
                {
                    **usage_entry,
                    "model": normalize_runtime_model("codex", model),
                    "service_tier": normalize_service_tier(service_tier),
                    "observed_service_tier": normalize_service_tier(service_tier),
                    "resolved_service_tier": normalize_service_tier(service_tier),
                }
            )
        ]
    )
    return round(max(0.0, _coerce_float(cost.get("usd"))), 6)


def build_route_receipt(
    *,
    prompt: str,
    visible_response: str = "",
    error_text: str = "",
    started_at: int,
    finished_at: int,
    thread_id: str,
    speed: str,
    detail: int,
    service_tier: str,
    job_budget: str,
    optimization_mode: str,
    success: bool,
    runtime: str,
    model: str,
    usage: dict[str, Any] | None = None,
    outcome: str = "",
    empty_reply_attempt: int = 0,
    zero_token_provider_attempt: int = 0,
    rate_limit_attempt: int = 0,
    timed_out: bool = False,
    turn_plan: dict[str, Any] | None = None,
    turn_envelope: dict[str, Any] | None = None,
    requested_model: str = "",
    requested_service_tier: str = "",
) -> dict[str, Any]:
    normalized_runtime = normalize_runtime(runtime)
    normalized_model = normalize_runtime_model(normalized_runtime, model)
    normalized_requested_model = normalize_runtime_model(
        normalized_runtime, requested_model or normalized_model
    )
    normalized_service_tier = normalize_service_tier(service_tier)
    normalized_requested_tier = normalize_service_tier(
        requested_service_tier or normalized_service_tier
    )
    normalized_optimization_mode = normalize_optimization_mode(optimization_mode)
    usage_entry = normalize_usage_entry(
        {
            **(usage or {}),
            "started_at": started_at,
            "finished_at": finished_at,
            "thread_id": thread_id,
            "speed": normalize_response_speed(speed),
            "detail": normalize_response_detail(detail),
            "service_tier": normalized_service_tier,
            "success": bool(success),
            "runtime": normalized_runtime,
            "model": normalized_model,
        }
    )
    prompt_id = route_receipt_prompt_id(prompt)
    requested_action = route_receipt_requested_action(prompt)
    selected_model_tier = route_receipt_model_tier(
        normalized_model, normalized_service_tier
    )
    allowed_role = route_receipt_allowed_role(selected_model_tier)
    operator_approval_required = route_receipt_requires_operator_approval(prompt)
    mutation_risk = turn_control_mutation_risk(prompt, visible_response, error_text)
    operator_intent_class = turn_control_operator_intent_class(prompt)
    authority_class = turn_control_authority_class(
        prompt,
        selected_model_tier=selected_model_tier,
        mutation_risk=mutation_risk,
        requested_action=requested_action,
    )
    final_authority_required = (
        allowed_role == "final_authority"
        or operator_approval_required
        or authority_class == "final_authority"
    )
    live_write_attempted = route_receipt_text_has_any(
        f"{prompt}\n{visible_response}\n{error_text}", ROUTE_RECEIPT_LIVE_WRITE_MARKERS
    )
    boundary_violation = bool(
        live_write_attempted
        and (operator_approval_required or final_authority_required)
    )
    manual_override = normalized_optimization_mode == "raw" or (
        os.environ.get("NORMAN_CODEX_ROUTE_RECEIPT_MANUAL_OVERRIDE", "0")
        .strip()
        .lower()
        in {"1", "true", "yes", "on"}
    )
    fallback_used = route_receipt_fallback_used(
        empty_reply_attempt=empty_reply_attempt,
        zero_token_provider_attempt=zero_token_provider_attempt,
        rate_limit_attempt=rate_limit_attempt,
    )
    retry_count = sum(
        1
        for value in (
            empty_reply_attempt,
            zero_token_provider_attempt,
            rate_limit_attempt,
        )
        if _coerce_int(value) > 0
    )
    estimated_cost_usd = route_receipt_cost_usd(
        usage_entry, model=normalized_model, service_tier=normalized_service_tier
    )
    baseline_all_5_5_cost_usd = route_receipt_cost_usd(
        usage_entry, model="openai.gpt-5.5", service_tier="default"
    )
    if boundary_violation:
        validator_gate = "boundary_violation"
    elif operator_approval_required:
        validator_gate = "hold_operator_approval"
    elif final_authority_required:
        validator_gate = "hold_final_authority"
    elif success:
        validator_gate = "pass"
    else:
        validator_gate = "fail"
    escalation_trigger = ""
    if boundary_violation:
        escalation_trigger = "boundary_violation"
    elif operator_approval_required:
        escalation_trigger = "operator_approval_required"
    elif final_authority_required:
        escalation_trigger = "final_authority_required"
    elif not success:
        escalation_trigger = "validator_failed"
    receipt_id_hash = hashlib.sha256(
        "\0".join(
            [
                ROUTE_RECEIPT_OWNER_TUI,
                str(started_at),
                str(finished_at),
                str(thread_id or ""),
                prompt_id,
                normalized_model,
                normalized_service_tier,
            ]
        ).encode("utf-8", "replace")
    ).hexdigest()[:16]
    routing_score = 0.0
    if not boundary_violation and not operator_approval_required:
        routing_score = 0.5 if final_authority_required else 1.0
    evidence_refs = [
        f"thread:{str(thread_id or '')[:16]}",
        f"history:{HISTORY_PATH}",
        f"usage:{USAGE_LEDGER_PATH}",
    ]
    if turn_plan:
        evidence_refs.append("turn_plan:final")
    if turn_envelope:
        evidence_refs.append("turn_envelope:classified")
    provider_tags = usage_provider_tags(normalized_service_tier)
    requested_provider_tags = usage_provider_tags(normalized_requested_tier)
    observed_service_tier = (
        str(usage_entry.get("observed_service_tier") or "").strip()
        or str(usage_entry.get("resolved_service_tier") or "").strip()
        or normalized_service_tier
    )
    route_source = (
        "service_tier_profile" if provider_tags.get("profile_v2") else "direct"
    )
    context_digest = route_receipt_digest(
        {
            "thread_id": thread_id,
            "turn_plan": turn_plan or {},
            "turn_envelope": turn_envelope or {},
        }
    )
    return {
        "receipt_id": f"{ROUTE_RECEIPT_OWNER_TUI}-{finished_at}-{receipt_id_hash}",
        "receipt_source": "live_tui_shadow_route",
        "previous_receipt_hash": "",
        "receipt_hash": "",
        "synthetic": False,
        "created_at": finished_at or now_ts(),
        "owner_tui": ROUTE_RECEIPT_OWNER_TUI,
        "prompt_id": prompt_id,
        "prompt_digest": route_receipt_digest(prompt_core_request(prompt)),
        "benchmark_skill_id": route_receipt_skill_id(requested_action),
        "requested_action": requested_action,
        "operator_intent_class": operator_intent_class,
        "authority_class": authority_class,
        "mutation_risk": mutation_risk,
        "selected_model_tier": selected_model_tier,
        "selected_model": normalized_model,
        "requested_model": normalized_requested_model,
        "effective_model": normalized_model,
        "requested_provider": requested_provider_tags.get("provider_surface", ""),
        "effective_provider": provider_tags.get("provider_surface", ""),
        "provider_profile": provider_tags.get("profile_v2", ""),
        "requested_service_tier": normalized_requested_tier,
        "effective_service_tier": normalized_service_tier,
        "observed_service_tier": observed_service_tier,
        "reasoning_effort": response_reasoning_effort(speed),
        "route_source": route_source,
        "route_execution": str(usage_entry.get("route_execution") or ""),
        "route_verifier": str(usage_entry.get("route_verifier") or ""),
        "fallback_reason": fallback_used,
        "routing_score": routing_score,
        "routing_bands": {
            "runtime": normalized_runtime,
            "model": normalized_model,
            "service_tier": normalized_service_tier,
            "requested_model": normalized_requested_model,
            "requested_service_tier": normalized_requested_tier,
            "speed": normalize_response_speed(speed),
            "detail": normalize_response_detail(detail),
            "job_budget": normalize_job_budget(job_budget),
            "optimization_mode": normalized_optimization_mode,
            "operator_intent_class": operator_intent_class,
            "authority_class": authority_class,
            "mutation_risk": mutation_risk,
            "route_execution": str(usage_entry.get("route_execution") or ""),
            "route_verifier": str(usage_entry.get("route_verifier") or ""),
        },
        "allowed_role": allowed_role,
        "validator_gate": validator_gate,
        "escalation_trigger": escalation_trigger,
        "fallback_used": fallback_used,
        "estimated_cost_usd": estimated_cost_usd,
        "baseline_all_5_5_cost_usd": baseline_all_5_5_cost_usd,
        "input_tokens": _coerce_int(usage_entry.get("input_tokens")),
        "cached_input_tokens": _coerce_int(usage_entry.get("cached_input_tokens")),
        "output_tokens": _coerce_int(usage_entry.get("output_tokens")),
        "reasoning_tokens": _coerce_int(usage_entry.get("reasoning_output_tokens")),
        "tool_call_count": _coerce_int(usage_entry.get("broker_tool_calls")),
        "retry_count": retry_count,
        "timeout_count": 1 if timed_out else 0,
        "validator_passed": bool(success and not boundary_violation),
        "manual_override": manual_override,
        "boundary_violation": boundary_violation,
        "latency_ms": max(
            0, (_coerce_int(finished_at) - _coerce_int(started_at)) * 1000
        ),
        "operator_approval_required": operator_approval_required,
        "final_authority_required": final_authority_required,
        "live_write_attempted": live_write_attempted,
        "outcome": str(outcome or ("accepted" if success else "failed")),
        "context_digest": context_digest,
        "allowed_files_digest": "",
        "diff_digest": "",
        "test_command": "",
        "test_exit_code": None,
        "test_output_ref": "",
        "route_policy_version": ROUTE_RECEIPT_POLICY_VERSION,
        "approval_id": os.environ.get("NORMAN_CODEX_ROUTE_APPROVAL_ID", "").strip(),
        "evidence_refs": evidence_refs,
    }


def route_receipt_canonical_payload(entry: dict[str, Any]) -> str:
    payload = dict(entry)
    payload.pop("receipt_hash", None)
    return json.dumps(payload, sort_keys=True, separators=(",", ":"), default=str)


def route_receipt_compute_hash(entry: dict[str, Any]) -> str:
    previous = str(entry.get("previous_receipt_hash") or "").strip()
    payload = route_receipt_canonical_payload(entry)
    return hashlib.sha256(f"{previous}\n{payload}".encode("utf-8")).hexdigest()


def route_receipt_last_hash(path: Path = ROUTE_RECEIPT_PATH) -> str:
    try:
        lines = [
            line
            for line in path.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    except OSError:
        return ""
    for raw in reversed(lines):
        try:
            item = json.loads(raw)
        except json.JSONDecodeError:
            continue
        if not isinstance(item, dict):
            continue
        receipt_hash = str(item.get("receipt_hash") or "").strip()
        if receipt_hash:
            return receipt_hash
    return ""


def prepare_route_receipt_for_append(
    entry: dict[str, Any], path: Path = ROUTE_RECEIPT_PATH
) -> dict[str, Any]:
    entry["previous_receipt_hash"] = route_receipt_last_hash(path)
    entry["receipt_hash"] = route_receipt_compute_hash(entry)
    return entry


def route_receipt_chain_issues(receipts: list[dict[str, Any]]) -> list[str]:
    issues: list[str] = []
    previous_hash: str | None = None
    for index, receipt in enumerate(receipts, 1):
        if not isinstance(receipt, dict):
            issues.append(f"receipt {index} is not a JSON object")
            continue
        saved_hash = str(receipt.get("receipt_hash") or "").strip()
        previous_receipt_hash = str(receipt.get("previous_receipt_hash") or "").strip()
        if not saved_hash:
            issues.append(f"receipt {index} is missing receipt_hash")
        else:
            expected_hash = route_receipt_compute_hash(receipt)
            if saved_hash != expected_hash:
                issues.append(f"receipt {index} receipt_hash does not match payload")
        if previous_hash is not None and previous_receipt_hash != previous_hash:
            issues.append(
                f"receipt {index} previous_receipt_hash does not link to receipt {index - 1}"
            )
        previous_hash = saved_hash
    return issues


def route_receipt_chain_status(path: Path = ROUTE_RECEIPT_PATH) -> dict[str, Any]:
    receipts: list[dict[str, Any]] = []
    load_errors: list[str] = []
    try:
        lines = [
            line
            for line in path.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    except OSError as exc:
        return {
            "status": "missing",
            "path": str(path),
            "receipt_count": 0,
            "latest_hash": "",
            "issue_count": 1,
            "issues": [str(exc)],
        }
    for line_no, raw in enumerate(lines, 1):
        try:
            item = json.loads(raw)
        except json.JSONDecodeError as exc:
            load_errors.append(f"{path}:{line_no}: malformed JSON: {exc.msg}")
            continue
        if not isinstance(item, dict):
            load_errors.append(f"{path}:{line_no}: route receipt is not a JSON object")
            continue
        receipts.append(item)
    issues = load_errors + route_receipt_chain_issues(receipts)
    latest_hash = (
        str(receipts[-1].get("receipt_hash") or "").strip() if receipts else ""
    )
    if receipts and not issues:
        status = "pass"
    elif not receipts and not issues:
        status = "empty"
    else:
        status = "fail"
    return {
        "status": status,
        "path": str(path),
        "receipt_count": len(receipts),
        "latest_hash": latest_hash,
        "issue_count": len(issues),
        "issues": issues,
    }


def route_receipt_status_snapshot() -> dict[str, Any]:
    if not ROUTE_RECEIPTS_ENABLED:
        return {
            "status": "disabled",
            "path": str(ROUTE_RECEIPT_PATH),
            "receipt_count": 0,
            "latest_hash": "",
            "issue_count": 0,
            "issues": [],
        }
    snapshot = route_receipt_chain_status(ROUTE_RECEIPT_PATH)
    if ROUTE_RECEIPT_LAST_WRITE_ERROR:
        snapshot["last_write_error"] = ROUTE_RECEIPT_LAST_WRITE_ERROR
        if snapshot.get("status") == "missing":
            snapshot["status"] = "degraded"
    return snapshot


def append_route_receipt_entry(entry: dict[str, Any]) -> None:
    prepare_route_receipt_for_append(entry, ROUTE_RECEIPT_PATH)
    missing = [field for field in ROUTE_RECEIPT_REQUIRED_FIELDS if field not in entry]
    if missing:
        raise ValueError(f"route receipt missing required fields: {', '.join(missing)}")
    ROUTE_RECEIPT_PATH.parent.mkdir(parents=True, exist_ok=True)
    serialized = json.dumps(entry, sort_keys=True)
    with ROUTE_RECEIPT_PATH.open("a", encoding="utf-8") as handle:
        handle.write(serialized + "\n")
    try:
        os.chmod(ROUTE_RECEIPT_PATH, 0o640)
    except OSError:
        pass
    if MAX_ROUTE_RECEIPT_ITEMS <= 0:
        return
    try:
        lines = [
            line
            for line in ROUTE_RECEIPT_PATH.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    except OSError:
        return
    trimmed = lines[-MAX_ROUTE_RECEIPT_ITEMS:]
    if len(trimmed) != len(lines):
        ROUTE_RECEIPT_PATH.write_text("\n".join(trimmed) + "\n", encoding="utf-8")


def append_route_receipt(**kwargs: Any) -> dict[str, Any] | None:
    global ROUTE_RECEIPT_LAST_WRITE_ERROR
    if not ROUTE_RECEIPTS_ENABLED:
        return None
    receipt = build_route_receipt(**kwargs)
    try:
        append_route_receipt_entry(receipt)
    except OSError as exc:
        ROUTE_RECEIPT_LAST_WRITE_ERROR = str(exc)
        receipt["mirror_status"] = "write_failed"
        receipt["mirror_error"] = ROUTE_RECEIPT_LAST_WRITE_ERROR
        return receipt
    ROUTE_RECEIPT_LAST_WRITE_ERROR = ""
    return receipt


def usage_snapshot(
    entries: list[dict[str, Any]] | None = None, *, thread_id: str = ""
) -> dict[str, Any]:
    items = load_usage_history() if entries is None else entries
    normalized_items = usage_entries_with_effective_deltas(
        [normalize_usage_entry(item) for item in items]
    )
    clean_thread_id = str(thread_id or "").strip()
    current_thread_items = (
        [
            item
            for item in normalized_items
            if str(item.get("thread_id") or "").strip() == clean_thread_id
        ]
        if clean_thread_id
        else []
    )
    return {
        "tracked": bool(normalized_items),
        "window_seconds": USAGE_WINDOW_SECONDS,
        "totals": summarize_usage_entries(normalized_items),
        "last_24h": summarize_usage_entries(
            normalized_items, since_ts=max(0, now_ts() - USAGE_WINDOW_SECONDS)
        ),
        "current_thread": summarize_usage_entries(current_thread_items)
        if clean_thread_id
        else dict(default_usage_summary()),
        "last_turn": normalize_usage_entry(normalized_items[-1])
        if normalized_items
        else default_usage_entry(),
        "recent": list(normalized_items[-USAGE_RECENT_ITEMS:]),
        "route_utilization": route_utilization_snapshot(
            normalized_items, current_thread_entries=current_thread_items
        ),
        "billing": usage_billing_report(normalized_items),
    }


def usage_api_payload(
    *,
    thread_id: str = "",
    include_recent: bool = False,
    include_billing: bool = False,
    include_live: bool = False,
) -> dict[str, Any]:
    usage = usage_snapshot(thread_id=str(thread_id or "").strip())
    if not include_recent:
        usage.pop("recent", None)
    if not include_billing:
        usage.pop("billing", None)
    if include_live:
        configured_chat_runtime = configured_runtime()
        configured_chat_model = configured_runtime_model(configured_chat_runtime)
        health = local_llm_health_snapshot(
            configured_chat_model
            if normalize_runtime(configured_chat_runtime) == "localllm"
            else LOCAL_LLM_ROUTE_DEFAULT_MODEL
        )
        usage["route_utilization"] = route_utilization_with_live_activity(
            usage.get("route_utilization")
            if isinstance(usage.get("route_utilization"), dict)
            else {},
            health.get("tool_activity") if isinstance(health, dict) else {},
            local_llm_route_outcome_summary(),
        )
    return {
        "schema": "norman.tui.usage-api.v1",
        "ok": True,
        "ui_version": UI_VERSION,
        "agent_name": AGENT_NAME,
        "host_name": HOST_NAME,
        "session_name": SESSION,
        "generated_at": now_ts(),
        "usage": usage,
    }


BEDROCK_HEALTH_FAILURE_KINDS = {
    "bedrock_engine_not_found",
    "bedrock_on_demand_capacity_exceeded",
    "bedrock_stream_disconnected",
    "bedrock_provider_server_error",
    "bedrock_zero_token_no_final",
}
BEDROCK_HEALTH_LEDGER_CACHE_LOCK = threading.Lock()
BEDROCK_HEALTH_LEDGER_CACHE: dict[str, Any] = {
    "path": "",
    "mtime_ns": 0,
    "size": -1,
    "limit": 0,
    "entries": [],
}


def _load_usage_ledger_tail(
    limit: int = BEDROCK_HEALTH_LEDGER_SCAN_ITEMS,
) -> list[dict[str, Any]]:
    if limit <= 0:
        return []
    try:
        stat = USAGE_LEDGER_PATH.stat()
    except OSError:
        return []
    cache_key = {
        "path": str(USAGE_LEDGER_PATH),
        "mtime_ns": getattr(stat, "st_mtime_ns", int(stat.st_mtime * 1_000_000_000)),
        "size": stat.st_size,
        "limit": limit,
    }
    with BEDROCK_HEALTH_LEDGER_CACHE_LOCK:
        if all(
            BEDROCK_HEALTH_LEDGER_CACHE.get(key) == value
            for key, value in cache_key.items()
        ):
            return list(BEDROCK_HEALTH_LEDGER_CACHE.get("entries") or [])
    try:
        lines = [
            line
            for line in USAGE_LEDGER_PATH.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
    except OSError:
        return []
    entries: list[dict[str, Any]] = []
    for line in lines[-limit:]:
        try:
            payload = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(payload, dict):
            entries.append(normalize_usage_entry(payload))
    with BEDROCK_HEALTH_LEDGER_CACHE_LOCK:
        BEDROCK_HEALTH_LEDGER_CACHE.update(cache_key)
        BEDROCK_HEALTH_LEDGER_CACHE["entries"] = list(entries)
    return entries


def _usage_entry_is_bedrock_health_failure(entry: dict[str, Any]) -> bool:
    normalized = normalize_usage_entry(entry)
    surface = str(normalized.get("provider_surface") or "").strip().lower()
    if surface != "aws-bedrock":
        return False
    if bool(normalized.get("success")):
        return False
    kind = str(normalized.get("provider_error_kind") or "").strip()
    if kind in BEDROCK_HEALTH_FAILURE_KINDS:
        return True
    return (
        bool(normalized.get("zero_token_provider_failure"))
        and _coerce_int(normalized.get("total_tokens")) == 0
    )


def _bedrock_health_audit_failure_entry(event: dict[str, Any]) -> dict[str, Any]:
    normalized = normalize_audit_event(event)
    event_type = str(normalized.get("event_type") or "").strip().lower()
    if event_type not in {
        "chat.zero-token-provider-retry",
        "chat.zero-token-provider-recovery-handoff",
        "chat.zero-token-provider-no-retry",
    }:
        return {}
    payload = normalized.get("payload")
    if not isinstance(payload, dict):
        return {}
    kind = str(payload.get("provider_error_kind") or "").strip()
    if kind not in BEDROCK_HEALTH_FAILURE_KINDS:
        return {}
    failed_tier = normalize_service_tier(
        payload.get("previous_service_tier") or payload.get("service_tier")
    )
    if not codex_profile_v2_for_service_tier(failed_tier):
        return {}
    event_at = _coerce_int(normalized.get("event_at")) or now_ts()
    return normalize_usage_entry(
        {
            **usage_provider_tags(failed_tier),
            "started_at": event_at,
            "finished_at": event_at,
            "thread_id": normalized.get("thread_id") or "",
            "speed": "",
            "detail": 0,
            "service_tier": failed_tier,
            "success": False,
            "runtime": payload.get("runtime") or "codex",
            "model": payload.get("model") or MODEL,
            "provider_error_kind": kind,
            "provider_error_text": payload.get("provider_error_text") or "",
            "provider_request_ids": payload.get("provider_request_ids") or [],
            "provider_trace_ids": payload.get("provider_trace_ids") or [],
            "total_tokens": 0,
            "zero_token_provider_failure": True,
        }
    )


def _bedrock_health_audit_failure_entries() -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for event in load_audit_events(limit=BEDROCK_HEALTH_AUDIT_SCAN_ITEMS):
        entry = _bedrock_health_audit_failure_entry(event)
        if entry:
            entries.append(entry)
    return entries


def _dedupe_bedrock_health_failures(
    entries: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[Any, ...]] = set()
    for item in entries:
        key = (
            _coerce_int(item.get("finished_at")) or _coerce_int(item.get("started_at")),
            str(item.get("service_tier") or ""),
            str(item.get("provider_error_kind") or ""),
            str(item.get("thread_id") or ""),
            summarize_text(str(item.get("provider_error_text") or ""), 160),
        )
        if key in seen:
            continue
        seen.add(key)
        deduped.append(item)
    return deduped


def _bedrock_health_smoke_snapshot(snapshot_at: int) -> dict[str, Any]:
    payload = read_json(BEDROCK_HEALTH_SMOKE_PATH, {})
    if not payload:
        return {}
    checked_at = _coerce_int(
        payload.get("checked_at")
        or payload.get("observed_at")
        or payload.get("updated_at")
        or payload.get("finished_at")
    )
    status = str(payload.get("status") or payload.get("state") or "").strip().lower()
    models = payload.get("models") if isinstance(payload.get("models"), dict) else {}
    model_values = [item for item in models.values() if isinstance(item, dict)]
    if not status and model_values:
        any_failed = any(item.get("ok") is False for item in model_values)
        any_ok = any(item.get("ok") is True for item in model_values)
        status = "failing" if any_failed else "ok" if any_ok else ""
    if status in {"pass", "passed", "healthy", "green"}:
        status = "ok"
    elif status in {"fail", "failed", "red", "error"}:
        status = "failing"
    elif status not in {"ok", "degraded", "failing", "unknown"}:
        status = "unknown"
    stale = (
        checked_at <= 0 or checked_at < snapshot_at - BEDROCK_HEALTH_SMOKE_STALE_SECONDS
    )
    return {
        "source": str(payload.get("source") or "smoke-cache").strip() or "smoke-cache",
        "status": status,
        "checked_at": checked_at,
        "stale": stale,
        "summary": str(payload.get("summary") or payload.get("message") or "").strip(),
        "detail": str(payload.get("detail") or payload.get("error") or "").strip(),
        "models": models,
        "path": str(BEDROCK_HEALTH_SMOKE_PATH),
    }


def bedrock_health_snapshot(
    *,
    snapshot_at: int | None = None,
    ledger_entries: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    observed_at = _coerce_int(snapshot_at) or now_ts()
    entries = (
        [normalize_usage_entry(item) for item in ledger_entries]
        if ledger_entries is not None
        else _load_usage_ledger_tail()
    )
    if ledger_entries is None:
        entries.extend(_bedrock_health_audit_failure_entries())
    since_ts = max(0, observed_at - BEDROCK_HEALTH_FAILURE_WINDOW_SECONDS)
    failures = _dedupe_bedrock_health_failures(
        [
            item
            for item in entries
            if _usage_entry_is_bedrock_health_failure(item)
            and (
                _coerce_int(item.get("finished_at"))
                or _coerce_int(item.get("started_at"))
            )
            >= since_ts
        ]
    )
    failures.sort(
        key=lambda item: _coerce_int(item.get("finished_at"))
        or _coerce_int(item.get("started_at"))
    )
    latest = failures[-1] if failures else {}
    latest_at = _coerce_int(latest.get("finished_at")) or _coerce_int(
        latest.get("started_at")
    )
    kinds: dict[str, int] = {}
    request_ids: list[str] = []
    trace_ids: list[str] = []
    zero_token_failures = 0
    for item in failures:
        kind = str(
            item.get("provider_error_kind") or "bedrock_provider_failure"
        ).strip()
        kinds[kind] = kinds.get(kind, 0) + 1
        if (
            bool(item.get("zero_token_provider_failure"))
            or _coerce_int(item.get("total_tokens")) == 0
        ):
            zero_token_failures += 1
        request_ids.extend(str(value) for value in item.get("provider_request_ids", []))
        trace_ids.extend(str(value) for value in item.get("provider_trace_ids", []))
    smoke = _bedrock_health_smoke_snapshot(observed_at)
    configured = bool(CODEX_STANDARD_PROFILE_V2)
    if failures:
        fresh_failures = [
            item
            for item in failures
            if (
                _coerce_int(item.get("finished_at"))
                or _coerce_int(item.get("started_at"))
            )
            >= observed_at - BEDROCK_HEALTH_FRESH_FAILURE_SECONDS
        ]
        state = "failing" if fresh_failures or len(failures) >= 2 else "degraded"
        tone = "alert" if state == "failing" else "warn"
        label = "Bedrock failing" if state == "failing" else "Bedrock unstable"
        kind_bits = ", ".join(
            f"{kind}:{count}" for kind, count in sorted(kinds.items())
        )
        latest_label = (
            f"latest {format_duration_label(max(0, observed_at - latest_at))} ago"
            if latest_at
            else "latest time unknown"
        )
        summary = (
            f"{len(failures)} Bedrock provider failure"
            f"{'' if len(failures) == 1 else 's'} in the last "
            f"{format_duration_label(BEDROCK_HEALTH_FAILURE_WINDOW_SECONDS)}."
        )
        detail = " · ".join(
            part
            for part in [
                latest_label,
                f"kinds {kind_bits}" if kind_bits else "",
                f"zero-token {zero_token_failures}" if zero_token_failures else "",
                "AWS request IDs captured"
                if request_ids
                else "no AWS request IDs captured",
            ]
            if part
        )
        hidden = False
    elif smoke:
        smoke_status = str(smoke.get("status") or "unknown")
        stale = bool(smoke.get("stale"))
        if stale:
            state = "stale"
            tone = "warn"
            label = "Bedrock check stale"
        elif smoke_status == "ok":
            state = "ok"
            tone = "ok"
            label = "Bedrock OK"
        elif smoke_status == "degraded":
            state = "degraded"
            tone = "warn"
            label = "Bedrock degraded"
        elif smoke_status == "failing":
            state = "failing"
            tone = "alert"
            label = "Bedrock failing"
        else:
            state = "unknown"
            tone = "idle"
            label = "Bedrock unknown"
        summary = str(smoke.get("summary") or "")
        if not summary:
            checked_at = _coerce_int(smoke.get("checked_at"))
            summary = (
                f"Last smoke check {format_duration_label(max(0, observed_at - checked_at))} ago."
                if checked_at
                else "Smoke-check cache exists but has no timestamp."
            )
        detail = str(smoke.get("detail") or "")
        hidden = False
    elif configured:
        state = "unknown"
        tone = "idle"
        label = "Bedrock not checked"
        summary = "No recent Bedrock failures or smoke-check cache found."
        detail = (
            "The badge appears automatically when local Bedrock failures are logged."
        )
        hidden = True
    else:
        state = "not_configured"
        tone = "idle"
        label = "Bedrock off"
        summary = "No Bedrock profile is configured for this console."
        detail = ""
        hidden = True
    return {
        "schema": "norman.tui.bedrock-health.v1",
        "state": state,
        "tone": tone,
        "label": label,
        "summary": summary,
        "detail": detail,
        "hidden": hidden,
        "observed_at": observed_at,
        "configured": configured,
        "profile_v2": CODEX_STANDARD_PROFILE_V2,
        "aws_profile": CODEX_STANDARD_AWS_PROFILE,
        "aws_region": CODEX_STANDARD_AWS_REGION,
        "failure_window_seconds": BEDROCK_HEALTH_FAILURE_WINDOW_SECONDS,
        "failure_count": len(failures),
        "zero_token_failure_count": zero_token_failures,
        "latest_failure_at": latest_at,
        "failure_kinds": kinds,
        "provider_request_ids": _unique_limited_values(request_ids),
        "provider_trace_ids": _unique_limited_values(trace_ids),
        "smoke": smoke,
    }


def default_kpi_snapshot() -> dict[str, Any]:
    return {
        "schema": "norman.tui.kpis.v1",
        "host_name": HOST_NAME,
        "agent_name": AGENT_NAME,
        "session_name": SESSION,
        "observed_at": 0,
        "state": "unknown",
        "activity_state": "unknown",
        "health_state": "unknown",
        "diagnosis": "No KPI snapshot has been collected yet.",
        "prompt_visible": False,
        "waiting_visible": False,
        "stale_seconds": 0,
        "last_output_changed_at": 0,
        "last_pane_hash": "",
        "state_entered_at": 0,
        "signals": [],
        "sentinel": {
            "schema": "norman.tui.sentinel.v1",
            "mode": SENTINEL_MODE,
            "state": "unknown",
            "tone": "ok",
            "severity": "quiet_log",
            "expected_action": "none",
            "summary": "Sentinel has not observed this TUI yet.",
            "reason_codes": [],
            "report_targets": ["tui"],
            "actions_enabled": False,
            "llm_enabled": False,
            "sms_enabled": False,
            "observe_only": True,
            "observed_at": 0,
        },
        "metrics": {
            "turns": 0,
            "successful_turns": 0,
            "failed_turns": 0,
            "avg_turn_seconds": 0,
            "last_turn_at": 0,
            "pending_seconds": 0,
            "queue_depth": 0,
            "wedge_count": 0,
            "blocked_count": 0,
            "degraded_count": 0,
            "state_changes": 0,
            "route_local_turns_24h": 0,
            "route_cloud_turns_24h": 0,
            "route_local_assisted_turns_24h": 0,
            "route_local_turn_rate_24h": 0.0,
            "route_local_assist_rate_24h": 0.0,
            "route_cloud_tokens_24h": 0,
            "route_cloud_tokens_avoided_24h": 0,
            "route_cloud_token_avoidance_rate_24h": 0.0,
            "route_live_tool_calls": 0,
        },
    }


def load_kpi_snapshot() -> dict[str, Any]:
    ensure_state_dir()
    return read_json(KPI_PATH, default_kpi_snapshot())


def _pane_hash(value: Any) -> str:
    return hashlib.sha256(str(value or "").encode("utf-8", "replace")).hexdigest()


def _pane_prompt_visible(value: Any) -> bool:
    text = str(value or "")
    if not text:
        return False
    prompt_markers = (
        "\n› ",
        "\n> ",
        "OpenAI Codex (v",
        "Tip: Use /status",
        "% left ·",
        "Use /skills to list available skills",
    )
    return any(marker in text for marker in prompt_markers) or text.lstrip().startswith(
        ("› ", "> ")
    )


def _pane_waiting_visible(value: Any) -> bool:
    text = str(value or "").lower()
    if not text:
        return False
    waiting_markers = (
        "press enter to continue",
        "do you trust the contents of this directory",
        "complete device-code sign-in",
        "choose sign-in",
        "continue sign-in",
        "waiting for operator input",
    )
    return any(marker in text for marker in waiting_markers)


def _contains_usage_limit_error(value: Any) -> bool:
    text = str(value or "").lower()
    if not text:
        return False
    return (
        "you've hit your usage limit" in text
        or "you hit your usage limit" in text
        or ("usage limit" in text and "try again at" in text)
        or ("usage limit" in text and "send a request to your admin" in text)
    )


def _latest_history_entry(snapshot: dict[str, Any]) -> dict[str, Any]:
    history = snapshot.get("history")
    if not isinstance(history, list):
        return {}
    latest: dict[str, Any] = {}
    latest_key: tuple[int, int] = (-1, -1)
    for index, entry in enumerate(history):
        if not isinstance(entry, dict):
            continue
        timestamp = max(
            _coerce_int(entry.get("finished_at")),
            _coerce_int(entry.get("started_at")),
        )
        key = (timestamp, index)
        if key >= latest_key:
            latest = entry
            latest_key = key
    return latest


def _current_usage_limit_error_text(snapshot: dict[str, Any], pane: str) -> str:
    last_error = str(snapshot.get("last_error") or "")
    if _contains_usage_limit_error(last_error):
        return last_error

    rate_limit_error = str(snapshot.get("rate_limit_error") or "")
    if _contains_usage_limit_error(rate_limit_error):
        return rate_limit_error

    state = str(snapshot.get("state") or "").strip().lower()
    if state in {"blocked", "error"} and _contains_usage_limit_error(pane):
        return pane

    latest_history = _latest_history_entry(snapshot)
    latest_error = str(latest_history.get("error") or "")
    if _contains_usage_limit_error(latest_error):
        return latest_error
    return ""


def _usage_limit_signal_is_current(snapshot: dict[str, Any], pane: str) -> bool:
    return bool(_current_usage_limit_error_text(snapshot, pane))


def usage_limit_reset_hint(value: Any, now_epoch: float | None = None) -> str:
    text = str(value or "")
    if not text:
        return ""
    match = re.search(
        r"\btry\s+again\s+at\s+([0-9]{1,2}:[0-9]{2})\s*([AaPp])\.?[Mm]\.?\b",
        text,
    )
    if not match:
        return ""
    observed_at = datetime.fromtimestamp(
        time.time() if now_epoch is None else now_epoch
    )
    time_label = f"{match.group(1)} {match.group(2).upper()}M"
    date_label = f"{observed_at:%B} {observed_at.day}, {observed_at:%Y}"
    return f"{date_label} at {time_label} (timezone not provided by provider)"


def stored_codex_auth_mode() -> str:
    try:
        payload = json.loads(CODEX_AUTH_PATH.read_text(encoding="utf-8"))
    except (FileNotFoundError, OSError, json.JSONDecodeError):
        return ""
    if not isinstance(payload, dict):
        return ""
    return str(payload.get("auth_mode") or "").strip().lower()


def usage_limit_billing_action(
    value: Any, auth_mode: str = "", now_epoch: float | None = None
) -> dict[str, str]:
    if not _contains_usage_limit_error(value):
        return {}
    clean_auth_mode = str(auth_mode or "").strip().lower()
    reset_hint = usage_limit_reset_hint(value, now_epoch=now_epoch)
    if clean_auth_mode == "chatgpt":
        summary = (
            "This bot hit a plan account usage limit. API credits may still "
            "be available; wait for reset or switch it to an available "
            "Bedrock/API-backed lane."
        )
        if reset_hint:
            summary = f"{summary} Reset hint: {reset_hint}."
        action = {
            "code": "codex_usage_limit",
            "label": "Usage cap",
            "summary": summary,
            "billing_url": OPENAI_BILLING_URL,
            "limits_url": OPENAI_LIMITS_URL,
        }
        if reset_hint:
            action["reset_hint"] = reset_hint
        return action
    summary = (
        "This bot hit an OpenAI usage limit. Check project/model limits, "
        "billing, or switch it to an available provider lane."
    )
    if reset_hint:
        summary = f"{summary} Reset hint: {reset_hint}."
    action = {
        "code": "openai_usage_limit",
        "label": "Usage limit",
        "summary": summary,
        "billing_url": OPENAI_BILLING_URL,
        "limits_url": OPENAI_LIMITS_URL,
    }
    if reset_hint:
        action["reset_hint"] = reset_hint
    return action


def bedrock_default_recovery_service_tier() -> str:
    if DEFAULT_SERVICE_TIER not in {"auto", "default"}:
        return ""
    if not CODEX_STANDARD_PROFILE_V2 or "default" not in SERVICE_TIER_OPTIONS:
        return ""
    target = "default"
    return target if codex_profile_v2_for_service_tier(target) else ""


def direct_service_tier_usage_limit_recovery(
    service_tier: Any,
    *,
    route_lock: bool = False,
    runtime: Any = "codex",
    entries: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    requested_tier = normalize_service_tier(service_tier)
    target_tier = bedrock_default_recovery_service_tier()
    if (
        route_lock
        or normalize_runtime(runtime) != "codex"
        or requested_tier not in DIRECT_SERVICE_TIERS
        or not target_tier
    ):
        return {}
    items = (
        load_usage_history(limit=DIRECT_TIER_USAGE_LIMIT_RECOVERY_LOOKBACK)
        if entries is None
        else entries
    )
    matches: list[dict[str, Any]] = []
    for item in items:
        usage = normalize_usage_entry(item)
        if normalize_service_tier(usage.get("service_tier")) != requested_tier:
            continue
        if str(usage.get("provider_surface") or "").strip().lower() != "openai-direct":
            continue
        if not _contains_usage_limit_error(usage.get("provider_error_text")):
            continue
        matches.append(usage)
    if not matches:
        return {}
    latest = matches[-1]
    return {
        "requested_service_tier": requested_tier,
        "service_tier": target_tier,
        "reason": "recent_direct_usage_limit",
        "recent_usage_limit_count": len(matches),
        "latest_usage_limit_at": _coerce_int(latest.get("finished_at"))
        or _coerce_int(latest.get("started_at")),
        "target_profile_v2": codex_profile_v2_for_service_tier(target_tier),
        "target_aws_profile": codex_aws_profile_for_service_tier(target_tier),
        "target_aws_region": codex_aws_region_for_service_tier(target_tier),
    }


def append_direct_service_tier_recovery_event(
    recovery: dict[str, Any],
    *,
    prompt: str = "",
    actor_ip: str = "",
    route_lock: bool = False,
    runtime: str = "",
    model: str = "",
) -> None:
    requested_tier = normalize_service_tier(recovery.get("requested_service_tier"))
    recovered_tier = normalize_service_tier(recovery.get("service_tier"))
    append_audit_event(
        event_type="chat.direct-tier-recovered-to-default",
        summary="Recovered a direct OpenAI tier request back to Bedrock default.",
        detail=(
            f"{service_tier_label(requested_tier)} recently hit a usage limit; "
            f"routing this turn through {service_tier_label(recovered_tier)} first."
        ),
        severity="warn",
        actor_type="system",
        actor_ip=actor_ip,
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            **recovery,
            "prompt_preview": summarize_text(prompt, 240),
            "route_lock": route_lock,
            "runtime": normalize_runtime(runtime),
            "model": normalize_runtime_model(normalize_runtime(runtime), model),
        },
    )


def _snapshot_runtime_active(snapshot: dict[str, Any]) -> bool:
    return (
        bool(snapshot.get("pending"))
        or bool(snapshot.get("model_process_alive"))
        or bool(snapshot.get("web_worker_alive"))
        or _coerce_int(snapshot.get("active_child_pid")) > 0
    )


def _kpi_signal(
    code: str, severity: str, summary: str, detail: str = ""
) -> dict[str, Any]:
    return {
        "code": code,
        "severity": severity,
        "summary": summary,
        "detail": detail,
    }


def detect_kpi_signals(
    snapshot: dict[str, Any],
    pane: str,
    prompt_visible: bool,
    waiting_visible: bool,
    stale_seconds: int,
) -> list[dict[str, Any]]:
    signals: list[dict[str, Any]] = []
    auth = snapshot.get("auth") if isinstance(snapshot.get("auth"), dict) else {}
    if bool(auth.get("required")):
        signals.append(
            _kpi_signal(
                "auth_required",
                "blocked",
                str(auth.get("summary") or "The TUI needs a fresh sign-in."),
            )
        )
    if _usage_limit_signal_is_current(snapshot, pane):
        signals.append(
            _kpi_signal(
                "usage_limit",
                "blocked",
                "The model provider is reporting a usage limit.",
            )
        )
    lower_pane = pane.lower()
    if (
        "disabled `js_repl`" in lower_pane
        or "node runtime too old" in lower_pane
        or ("node runtime" in lower_pane and "incompatible" in lower_pane)
    ):
        signals.append(
            _kpi_signal(
                "js_repl_node_too_old",
                "degraded",
                "The JavaScript REPL tool is disabled because Node is too old or incompatible.",
            )
        )
    if (
        "model resume mismatch" in lower_pane
        or (
            "resume" in lower_pane
            and "model" in lower_pane
            and "mismatch" in lower_pane
        )
        or (
            "requested model" in lower_pane
            and "session" in lower_pane
            and "model" in lower_pane
        )
    ):
        signals.append(
            _kpi_signal(
                "model_resume_mismatch",
                "degraded",
                "The visible session mentions a model/resume mismatch.",
            )
        )
    for service in snapshot.get("services") or []:
        if not isinstance(service, dict):
            continue
        state = str(service.get("state") or "").strip().lower()
        if state in {"failed", "inactive", "dead"}:
            signals.append(
                _kpi_signal(
                    "service_not_active",
                    "degraded",
                    f"{service.get('name') or 'service'} is {state}.",
                )
            )
    if (
        _snapshot_runtime_active(snapshot)
        and stale_seconds >= RUNNING_NO_OUTPUT_SECONDS
        and not waiting_visible
    ):
        signals.append(
            _kpi_signal(
                "running_no_output",
                "degraded",
                f"The {WORKER_SESSION_LABEL} is still running, but pane output has not changed recently.",
                f"No pane change for {stale_seconds}s.",
            )
        )
    if (
        not _snapshot_runtime_active(snapshot)
        and stale_seconds >= KPI_WEDGE_SECONDS
        and not prompt_visible
        and not waiting_visible
    ):
        signals.append(
            _kpi_signal(
                "no_prompt_stale",
                "wedged",
                "The pane has not changed and no ready prompt is visible.",
            )
        )
    deduped: list[dict[str, Any]] = []
    seen: set[str] = set()
    for item in signals:
        code = str(item.get("code") or "")
        if code in seen:
            continue
        seen.add(code)
        deduped.append(item)
    return deduped


def _sentinel_visible_bbs_priority_count(
    snapshot: dict[str, Any], priority: str
) -> int | None:
    bbs = snapshot.get("bbs") if isinstance(snapshot.get("bbs"), dict) else {}
    top_threads = (
        bbs.get("top_threads") if isinstance(bbs.get("top_threads"), list) else None
    )
    if top_threads is None:
        return None
    clean_priority = str(priority or "").strip().lower()
    count = 0
    for item in top_threads:
        if not isinstance(item, dict) or _bbs_thread_is_terminal(item):
            continue
        if str(item.get("priority") or "").strip().lower() == clean_priority:
            count += 1
    return count


def _sentinel_bbs_count(snapshot: dict[str, Any], key: str) -> int:
    bbs = snapshot.get("bbs") if isinstance(snapshot.get("bbs"), dict) else {}
    counts = bbs.get("counts") if isinstance(bbs.get("counts"), dict) else {}
    handoff = bbs.get("handoff") if isinstance(bbs.get("handoff"), dict) else {}
    janitor = bbs.get("janitor") if isinstance(bbs.get("janitor"), dict) else {}
    if key in {"urgent", "high"}:
        actionable_key = f"actionable_{key}"
        if actionable_key in counts:
            return max(0, _coerce_int(counts.get(actionable_key)))
        visible_count = _sentinel_visible_bbs_priority_count(snapshot, key)
        if visible_count is not None:
            return visible_count
    if (
        key in {"needs_ack", "owner_attention"}
        and str(handoff.get("state") or "").strip().lower() == "clear"
    ):
        return 0
    for source in (counts, handoff, janitor):
        if key in source:
            return max(0, _coerce_int(source.get(key)))
    return 0


def _sentinel_oldest_queue_age(snapshot: dict[str, Any], observed_at: int) -> int:
    queued = snapshot.get("queued_prompts")
    if not isinstance(queued, list):
        return 0
    ages: list[int] = []
    for item in queued:
        if not isinstance(item, dict):
            continue
        queued_at = _coerce_int(item.get("queued_at"))
        if queued_at > 0:
            ages.append(max(0, observed_at - queued_at))
    return max(ages) if ages else 0


def _sentinel_base(observed_at: int) -> dict[str, Any]:
    actions_enabled = bool(SENTINEL_ACTIONS_ENABLED and SENTINEL_MODE != "observe_only")
    llm_enabled = bool(
        SENTINEL_LLM_ENABLED
        and SENTINEL_MAX_LLM_TOKENS_PER_DAY > 0
        and SENTINEL_MODE != "off"
    )
    sms_enabled = bool(SENTINEL_SMS_ENABLED and actions_enabled)
    return {
        "schema": "norman.tui.sentinel.v1",
        "mode": SENTINEL_MODE,
        "observed_at": observed_at,
        "next_check_seconds": max(5, KPI_INTERVAL_SECONDS),
        "actions_enabled": actions_enabled,
        "llm_enabled": llm_enabled,
        "sms_enabled": sms_enabled,
        "observe_only": not actions_enabled,
        "spend_guardrail": {
            "llm_default": "disabled" if not llm_enabled else "enabled",
            "max_llm_tokens_per_day": SENTINEL_MAX_LLM_TOKENS_PER_DAY,
            "estimated_llm_tokens_this_tick": 0,
            "estimated_llm_cost_usd_this_tick": 0,
        },
    }


def build_sentinel_state(
    snapshot: dict[str, Any], kpis: dict[str, Any] | None = None
) -> dict[str, Any]:
    observed_at = now_ts()
    base = _sentinel_base(observed_at)
    if SENTINEL_MODE == "off":
        return {
            **base,
            "state": "disabled",
            "tone": "ok",
            "severity": "quiet_log",
            "expected_action": "none",
            "summary": "Sentinel is disabled.",
            "reason_codes": ["sentinel_disabled"],
            "report_targets": ["tui"],
            "evidence": {},
        }

    kpis = kpis if isinstance(kpis, dict) else {}
    signals = [item for item in kpis.get("signals") or [] if isinstance(item, dict)]
    signal_codes = {str(item.get("code") or "") for item in signals}
    kpi_state = str(kpis.get("state") or "").strip().lower()
    auth = snapshot.get("auth") if isinstance(snapshot.get("auth"), dict) else {}
    pending = bool(snapshot.get("pending"))
    queue_depth = _coerce_int(snapshot.get("queue_depth"))
    pending_seconds = max(0, observed_at - _coerce_int(snapshot.get("last_started_at")))
    time_target = (
        snapshot.get("time_target")
        if isinstance(snapshot.get("time_target"), dict)
        else {}
    )
    time_phase = str(time_target.get("phase") or "").strip().lower()
    active_runtime = _snapshot_runtime_active(snapshot)
    worker_alive = bool(snapshot.get("web_worker_alive"))
    process_alive = (
        bool(snapshot.get("model_process_alive"))
        or _coerce_int(snapshot.get("active_child_pid")) > 0
    )
    oldest_queue_age = _sentinel_oldest_queue_age(snapshot, observed_at)
    human_ask_count = _coerce_int(snapshot.get("human_intervention_ask_now_count"))
    human_count = _coerce_int(snapshot.get("human_intervention_count"))
    urgent_bbs = (
        _sentinel_bbs_count(snapshot, "urgent")
        + _sentinel_bbs_count(snapshot, "high")
        + _sentinel_bbs_count(snapshot, "owner_attention")
    )
    waiting_bbs = (
        _sentinel_bbs_count(snapshot, "needs_ack")
        + _sentinel_bbs_count(snapshot, "waiting_pickup")
        + _sentinel_bbs_count(snapshot, "owner_offline")
        + _sentinel_bbs_count(snapshot, "owner_stale")
        + _sentinel_bbs_count(snapshot, "stale")
    )

    state = "healthy_idle"
    tone = "ok"
    severity = "quiet_log"
    expected_action = "none"
    summary = "Idle and no local action is needed."
    reason_codes: list[str] = []
    report_targets = ["tui"]

    def choose(
        *,
        next_state: str,
        next_tone: str,
        next_severity: str,
        action: str,
        text: str,
        reasons: list[str],
        targets: list[str] | None = None,
    ) -> None:
        nonlocal \
            state, \
            tone, \
            severity, \
            expected_action, \
            summary, \
            reason_codes, \
            report_targets
        state = next_state
        tone = next_tone
        severity = next_severity
        expected_action = action
        summary = text
        reason_codes = reasons
        report_targets = targets or ["tui"]

    if human_ask_count > 0:
        choose(
            next_state="waiting_operator",
            next_tone="alert",
            next_severity="ask_now",
            action="operator",
            text=f"{human_ask_count} open operator intervention(s) need attention.",
            reasons=["open_intervention"],
            targets=["tui", "norman"],
        )
    elif bool(auth.get("required")):
        choose(
            next_state="waiting_operator",
            next_tone="alert",
            next_severity="ask_now",
            action="operator",
            text=str(auth.get("summary") or "Sign-in or verification is required."),
            reasons=["auth_required"],
            targets=["tui", "norman"],
        )
    elif "usage_limit" in signal_codes:
        choose(
            next_state="waiting_operator",
            next_tone="alert",
            next_severity="ask_now",
            action="operator",
            text="Provider usage limit is blocking this TUI.",
            reasons=["usage_limit"],
            targets=["tui", "norman"],
        )
    elif (
        pending
        and pending_seconds >= SENTINEL_PENDING_NO_WORKER_SECONDS
        and not worker_alive
        and not process_alive
    ):
        choose(
            next_state="wedged",
            next_tone="alert",
            next_severity="ask_now",
            action="operator",
            text="Prompt is marked pending, but no worker/model process is alive.",
            reasons=["pending_without_worker"],
            targets=["tui", "norman"],
        )
    elif kpi_state in {"blocked", "wedged"}:
        choose(
            next_state=kpi_state,
            next_tone="alert",
            next_severity="ask_now",
            action="operator",
            text=str(kpis.get("diagnosis") or "KPI state is blocked or wedged."),
            reasons=[f"kpi_{kpi_state}"],
            targets=["tui", "norman"],
        )
    elif urgent_bbs > 0:
        choose(
            next_state="waiting_peer",
            next_tone="alert",
            next_severity="ask_now",
            action="peer_or_operator",
            text=(
                f"{urgent_bbs} actionable BBS item(s) need owner pickup, "
                "reassignment, or close-loop."
            ),
            reasons=["bbs_urgent"],
            targets=["tui", "bbs", "norman"],
        )
    elif "running_no_output" in signal_codes or time_phase in {
        "over_target",
        "guardrail",
        "hard_guardrail",
    }:
        choose(
            next_state="stuck_running"
            if "running_no_output" in signal_codes
            else "over_budget",
            next_tone="warn",
            next_severity="batch_review",
            action="review",
            text="Running work needs review: output is stale or the time target is over.",
            reasons=[
                reason
                for reason in [
                    "running_no_output" if "running_no_output" in signal_codes else "",
                    f"time_{time_phase}" if time_phase else "",
                ]
                if reason
            ],
            targets=["tui", "norman"],
        )
    elif waiting_bbs > 0:
        choose(
            next_state="waiting_peer",
            next_tone="warn",
            next_severity="batch_review",
            action="peer",
            text=f"{waiting_bbs} BBS item(s) are waiting for ack, pickup, or cleanup.",
            reasons=["bbs_waiting"],
            targets=["tui", "bbs"],
        )
    elif (
        queue_depth > 0
        and not pending
        and oldest_queue_age >= SENTINEL_STALE_QUEUE_SECONDS
    ):
        choose(
            next_state="stale_queue",
            next_tone="warn",
            next_severity="batch_review",
            action="review",
            text=f"{queue_depth} queued prompt(s) are idle; oldest has waited {oldest_queue_age}s.",
            reasons=["stale_queue"],
            targets=["tui", "norman"],
        )
    elif bool(snapshot.get("web_restart_required")) and not pending:
        choose(
            next_state="restart_staged",
            next_tone="warn",
            next_severity="batch_review",
            action="review",
            text="A TUI web refresh is staged and can be applied when safe.",
            reasons=["web_restart_staged"],
            targets=["tui", "norman"],
        )
    elif active_runtime:
        choose(
            next_state="healthy_running",
            next_tone="active",
            next_severity="quiet_log",
            action="none",
            text="Running state looks plausible and within observe-only guardrails.",
            reasons=["runtime_active"],
            targets=["tui"],
        )
    elif queue_depth > 0:
        choose(
            next_state="queue_waiting",
            next_tone="ok",
            next_severity="quiet_log",
            action="none",
            text=f"{queue_depth} queued prompt(s) are waiting inside the grace window.",
            reasons=["queue_within_grace"],
            targets=["tui"],
        )
    elif human_count > 0:
        choose(
            next_state="batch_review",
            next_tone="warn",
            next_severity="batch_review",
            action="review",
            text=f"{human_count} non-urgent intervention(s) are open.",
            reasons=["open_batch_intervention"],
            targets=["tui", "norman"],
        )

    return {
        **base,
        "state": state,
        "tone": tone,
        "severity": severity,
        "expected_action": expected_action,
        "summary": summary,
        "reason_codes": reason_codes,
        "report_targets": report_targets,
        "evidence": {
            "kpi_state": kpi_state,
            "signal_codes": sorted(signal_codes),
            "queue_depth": queue_depth,
            "oldest_queue_age_seconds": oldest_queue_age,
            "pending_seconds": pending_seconds if pending else 0,
            "time_phase": time_phase,
            "bbs_urgent_count": urgent_bbs,
            "bbs_waiting_count": waiting_bbs,
            "human_intervention_count": human_count,
            "human_intervention_ask_now_count": human_ask_count,
        },
    }


def maybe_raise_sentinel_intervention(
    sentinel: dict[str, Any],
) -> dict[str, Any] | None:
    if SENTINEL_MODE == "off" or not isinstance(sentinel, dict):
        return None
    if str(sentinel.get("severity") or "") != "ask_now":
        return None
    reason_codes = [
        str(item)
        for item in sentinel.get("reason_codes", [])
        if str(item or "").strip()
    ]
    if "open_intervention" in reason_codes:
        return None
    state = str(sentinel.get("state") or "sentinel_attention").strip()
    fingerprint = ":".join(
        [
            "sentinel",
            str(AGENT_NAME or SESSION),
            state,
            ",".join(sorted(reason_codes)),
        ]
    )
    return upsert_human_intervention(
        {
            "kind": f"sentinel_{state}",
            "severity": "ask_now",
            "fingerprint": fingerprint,
            "question": (
                f"Sentinel is asking this {AGENT_NAME} console for review: "
                f"{sentinel.get('summary')}"
            ),
            "detail": (
                "Observe-only sentinel detected a high-confidence blocker. "
                "No autonomous action was taken."
            ),
            "options": [
                "Review source and owner",
                "Defer and keep visible",
                "Mark not actionable",
            ],
            "evidence": sentinel,
            "source_actor": AGENT_NAME,
            "thread_id": read_text(THREAD_ID_PATH),
        }
    )


def _usage_duration_metrics(entries: list[dict[str, Any]]) -> dict[str, int]:
    durations: list[int] = []
    for entry in entries:
        started = _coerce_int(entry.get("started_at"))
        finished = _coerce_int(entry.get("finished_at"))
        if started > 0 and finished >= started:
            durations.append(finished - started)
    return {
        "avg_turn_seconds": int(sum(durations) / len(durations)) if durations else 0
    }


def build_kpi_snapshot(
    snapshot: dict[str, Any], previous: dict[str, Any] | None = None
) -> dict[str, Any]:
    previous = previous if isinstance(previous, dict) else {}
    now = now_ts()
    pane = str(snapshot.get("pane") or "")
    pane_hash = _pane_hash(pane)
    previous_hash = str(previous.get("last_pane_hash") or "")
    if previous_hash and previous_hash == pane_hash:
        last_output_changed_at = (
            _coerce_int(previous.get("last_output_changed_at")) or now
        )
    else:
        last_output_changed_at = now
    stale_seconds = max(0, now - last_output_changed_at)
    prompt_is_visible = _pane_prompt_visible(pane)
    waiting_is_visible = _pane_waiting_visible(pane)
    pending = bool(snapshot.get("pending"))
    signals = detect_kpi_signals(
        snapshot,
        pane,
        prompt_is_visible,
        waiting_is_visible,
        stale_seconds,
    )
    severities = {str(signal.get("severity") or "") for signal in signals}
    if "blocked" in severities:
        state, activity_state, health_state = "blocked", "waiting", "blocked"
    elif "wedged" in severities:
        state, activity_state, health_state = "wedged", "stalled", "wedged"
    elif "degraded" in severities:
        state = "degraded"
        activity_state = (
            "working" if pending else "idle" if prompt_is_visible else "unknown"
        )
        health_state = "degraded"
    elif (
        pending
        or bool(snapshot.get("model_process_alive"))
        or bool(snapshot.get("web_worker_alive"))
    ):
        state, activity_state, health_state = "working", "working", "ok"
    elif waiting_is_visible:
        state, activity_state, health_state = "waiting", "waiting", "ok"
    elif prompt_is_visible:
        state, activity_state, health_state = "idle", "idle", "ok"
    elif stale_seconds >= KPI_WEDGE_SECONDS:
        state, activity_state, health_state = "wedged", "stalled", "wedged"
    else:
        state, activity_state, health_state = "working", "working", "unknown"
    previous_state = str(previous.get("state") or "")
    previous_metrics = (
        previous.get("metrics") if isinstance(previous.get("metrics"), dict) else {}
    )
    state_entered_at = _coerce_int(previous.get("state_entered_at")) or now
    state_changes = _coerce_int(previous_metrics.get("state_changes"))
    if previous_state and previous_state != state:
        state_entered_at = now
        state_changes += 1
    elif not previous_state:
        state_entered_at = now
    usage = snapshot.get("usage") if isinstance(snapshot.get("usage"), dict) else {}
    totals = usage.get("totals") if isinstance(usage.get("totals"), dict) else {}
    route_utilization = (
        usage.get("route_utilization")
        if isinstance(usage.get("route_utilization"), dict)
        else {}
    )
    route_24h = (
        route_utilization.get("last_24h")
        if isinstance(route_utilization.get("last_24h"), dict)
        else {}
    )
    live_route_tools = (
        route_utilization.get("live_tool_activity")
        if isinstance(route_utilization.get("live_tool_activity"), dict)
        else {}
    )
    duration_metrics = _usage_duration_metrics(load_usage_history(limit=0))
    metrics = {
        "turns": _coerce_int(totals.get("turns")),
        "successful_turns": _coerce_int(totals.get("successful_turns")),
        "failed_turns": _coerce_int(totals.get("failed_turns")),
        "avg_turn_seconds": duration_metrics["avg_turn_seconds"],
        "last_turn_at": _coerce_int(totals.get("last_turn_at")),
        "pending_seconds": max(0, now - _coerce_int(snapshot.get("last_started_at")))
        if pending
        else 0,
        "queue_depth": _coerce_int(snapshot.get("queue_depth")),
        "wedge_count": _coerce_int(previous_metrics.get("wedge_count"))
        + int(previous_state != "wedged" and state == "wedged"),
        "blocked_count": _coerce_int(previous_metrics.get("blocked_count"))
        + int(previous_state != "blocked" and state == "blocked"),
        "degraded_count": _coerce_int(previous_metrics.get("degraded_count"))
        + int(previous_state != "degraded" and state == "degraded"),
        "state_changes": state_changes,
        "route_local_turns_24h": _coerce_int(route_24h.get("local_turns")),
        "route_cloud_turns_24h": _coerce_int(route_24h.get("cloud_turns")),
        "route_local_assisted_turns_24h": _coerce_int(
            route_24h.get("local_assisted_turns")
        ),
        "route_local_turn_rate_24h": _coerce_float(route_24h.get("local_turn_rate")),
        "route_local_assist_rate_24h": _coerce_float(
            route_24h.get("local_assist_rate")
        ),
        "route_cloud_tokens_24h": _coerce_int(route_24h.get("cloud_tokens")),
        "route_cloud_tokens_avoided_24h": _coerce_int(
            route_24h.get("cloud_tokens_avoided_estimate")
        ),
        "route_cloud_token_avoidance_rate_24h": _coerce_float(
            route_24h.get("cloud_token_avoidance_rate")
        ),
        "route_live_tool_calls": _coerce_int(live_route_tools.get("tool_call_count")),
    }
    diagnosis = {
        "blocked": signals[0]["summary"] if signals else "The TUI is blocked.",
        "wedged": "The TUI has no prompt and has not produced output recently.",
        "degraded": signals[0]["summary"] if signals else "The TUI is degraded.",
        "working": "The TUI is actively working.",
        "idle": "The TUI is idle and ready.",
        "waiting": "The TUI is waiting for operator input.",
        "dead": "The TUI session is unavailable.",
    }.get(state, "The TUI state is not yet classified.")
    payload = {
        "schema": "norman.tui.kpis.v1",
        "host_name": HOST_NAME,
        "agent_name": AGENT_NAME,
        "session_name": SESSION,
        "observed_at": now,
        "state": state,
        "activity_state": activity_state,
        "health_state": health_state,
        "diagnosis": diagnosis,
        "prompt_visible": prompt_is_visible,
        "waiting_visible": waiting_is_visible,
        "stale_seconds": stale_seconds,
        "last_output_changed_at": last_output_changed_at,
        "last_pane_hash": pane_hash,
        "state_entered_at": state_entered_at,
        "signals": signals,
        "metrics": metrics,
    }
    payload["sentinel"] = build_sentinel_state(snapshot, payload)
    return payload


def update_kpi_snapshot(snapshot: dict[str, Any]) -> dict[str, Any]:
    with KPI_LOCK:
        payload = build_kpi_snapshot(snapshot, load_kpi_snapshot())
        write_json(KPI_PATH, payload)
        return payload


def runtime_time_target_snapshot(
    meta: dict[str, Any], *, pending: bool, snapshot_at: int
) -> dict[str, Any]:
    if pending:
        budget = normalize_job_budget(meta.get("running_job_budget"))
        timeout_seconds = normalize_job_timeout_seconds(
            meta.get("running_timeout_seconds"), budget
        )
        started_at = _coerce_int(meta.get("last_started_at"))
    else:
        budget = normalize_job_budget(
            meta.get("last_job_budget")
            or meta.get("running_job_budget")
            or DEFAULT_JOB_BUDGET
        )
        timeout_seconds = normalize_job_timeout_seconds(
            meta.get("last_timeout_seconds") or meta.get("running_timeout_seconds"),
            budget,
        )
        started_at = 0
    plan = time_target_plan(
        budget,
        timeout_seconds,
        started_at=started_at,
        now=snapshot_at,
        pending=pending,
    )
    if bool(meta.get("deadline_warning_active")) and not pending:
        plan["hidden"] = False
        plan["phase"] = "checkpoint"
        plan["phase_label"] = "Checkpoint"
        plan["value"] = "Last warning"
        plan["meta"] = summarize_text(meta.get("deadline_warning_message"), 80)
        plan["next_action"] = "Review the last warning before starting more work."
    return plan


def current_kpis() -> dict[str, Any]:
    snapshot = current_snapshot()
    kpis = snapshot.get("kpis")
    return kpis if isinstance(kpis, dict) else load_kpi_snapshot()


def kpi_collector_loop() -> None:
    while True:
        try:
            current_snapshot()
        except Exception:
            pass
        time.sleep(max(5, KPI_INTERVAL_SECONDS))


def start_kpi_collector() -> None:
    global KPI_COLLECTOR_STARTED
    if KPI_COLLECTOR_STARTED or KPI_INTERVAL_SECONDS <= 0:
        return
    KPI_COLLECTOR_STARTED = True
    threading.Thread(
        target=kpi_collector_loop, name="tui-kpi-collector", daemon=True
    ).start()


def load_status_meta() -> dict[str, Any]:
    ensure_state_dir()
    return read_json(STATUS_PATH, default_status_meta())


def load_resource_meter_file() -> dict[str, Any]:
    try:
        payload = json.loads(RESOURCE_METER_PATH.read_text(encoding="utf-8"))
    except (FileNotFoundError, OSError, json.JSONDecodeError):
        return {}
    return payload if isinstance(payload, dict) else {}


def normalize_queue(value: Any) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    if not isinstance(value, list):
        return items
    for entry in value:
        if isinstance(entry, str):
            prompt = entry.strip()
            queued_at = 0
            speed = DEFAULT_RESPONSE_SPEED
            detail = DEFAULT_RESPONSE_DETAIL
            service_tier = DEFAULT_SERVICE_TIER
            job_budget = DEFAULT_JOB_BUDGET
            optimization_mode = DEFAULT_OPTIMIZATION_MODE
            runtime = DEFAULT_RUNTIME
            model = normalize_runtime_model(runtime)
            timeout_seconds = job_budget_timeout_seconds(job_budget)
            item_id = ""
            checkpoint_policy = queue_checkpoint_policy()
            interlace_mode = queue_interlace_mode()
        elif isinstance(entry, dict):
            prompt = str(entry.get("prompt") or "").strip()
            try:
                queued_at = int(entry.get("queued_at") or 0)
            except (TypeError, ValueError):
                queued_at = 0
            item_id = str(entry.get("id") or "").strip()
            speed = normalize_response_speed(entry.get("speed"))
            detail = normalize_response_detail(entry.get("detail"))
            service_tier = normalize_service_tier(entry.get("service_tier"))
            job_budget = normalize_job_budget(entry.get("job_budget"))
            optimization_mode = normalize_optimization_mode(
                entry.get("optimization_mode")
            )
            runtime = normalize_runtime(entry.get("runtime"))
            model = normalize_runtime_model(runtime, entry.get("model"))
            timeout_seconds = normalize_job_timeout_seconds(
                entry.get("timeout_seconds"), job_budget
            )
            attachments = normalize_attachments(entry.get("attachments"))
            relay_callback = normalize_relay_callback(entry.get("relay_callback"))
            source = normalize_queue_source(entry.get("source"), relay_callback, prompt)
            cost_route = (
                dict(entry.get("cost_route"))
                if isinstance(entry.get("cost_route"), dict)
                else {}
            )
            checkpoint_policy = (
                str(entry.get("checkpoint_policy") or queue_checkpoint_policy()).strip()
                or queue_checkpoint_policy()
            )
            interlace_mode = normalize_queue_interlace_mode(
                entry.get("interlace_mode")
                or queue_interlace_mode_for_checkpoint_policy(checkpoint_policy)
            )
            checkpoint_policy = queue_checkpoint_policy_for_interlace(interlace_mode)
            recovered = bool(entry.get("recovered"))
        else:
            continue
        if not isinstance(entry, dict):
            attachments = []
            relay_callback = {}
            source = normalize_queue_source("", relay_callback, prompt)
            cost_route = {}
            recovered = False
            item_id = ""
            checkpoint_policy = queue_checkpoint_policy()
            interlace_mode = queue_interlace_mode()
        if prompt:
            item_id = queue_item_id(prompt, queued_at, source, item_id)
            item = {
                "id": item_id,
                "prompt": prompt,
                "queued_at": queued_at,
                "speed": speed,
                "detail": detail,
                "service_tier": service_tier,
                "job_budget": job_budget,
                "optimization_mode": optimization_mode,
                "runtime": runtime,
                "model": model,
                "timeout_seconds": timeout_seconds,
                "attachments": attachments,
                "source": source,
                "cost_route": cost_route,
                "interlace_mode": interlace_mode,
                "checkpoint_policy": checkpoint_policy,
                "recovered": recovered,
            }
            if relay_callback:
                item["relay_callback"] = relay_callback
            items.append(item)
    return items


def queue_item_is_recovered(item: dict[str, Any]) -> bool:
    return (
        bool(item.get("recovered"))
        or str(item.get("source") or "").strip().lower() == "recovered"
    )


def default_restart_handoff() -> dict[str, Any]:
    return {
        "schema": "norman.tui.restart-handoff.v1",
        "id": "",
        "created_at": 0,
        "scope": "",
        "reason": "",
        "summary": "No restart handoff has been recorded.",
        "detail": "",
        "context_preserved": False,
        "can_resume_thread": False,
        "thread_id": "",
        "thread_scope": "",
        "history_count": 0,
        "queue_depth": 0,
        "pending": False,
        "state": "idle",
        "status_message": "",
        "running_prompt_preview": "",
        "last_prompt_preview": "",
        "last_response_preview": "",
        "last_error_preview": "",
        "last_started_at": 0,
        "last_finished_at": 0,
    }


def normalize_restart_handoff(value: Any) -> dict[str, Any]:
    payload = default_restart_handoff()
    if isinstance(value, dict):
        payload.update(value)
    payload["id"] = str(payload.get("id") or "").strip()
    payload["created_at"] = _coerce_int(payload.get("created_at"))
    payload["scope"] = str(payload.get("scope") or "").strip()
    payload["reason"] = str(payload.get("reason") or "").strip()
    payload["summary"] = str(payload.get("summary") or "").strip() or payload["summary"]
    payload["detail"] = str(payload.get("detail") or "").strip()
    payload["context_preserved"] = bool(payload.get("context_preserved"))
    payload["can_resume_thread"] = bool(payload.get("can_resume_thread"))
    payload["thread_id"] = str(payload.get("thread_id") or "").strip()
    payload["thread_scope"] = str(payload.get("thread_scope") or "").strip()
    payload["history_count"] = _coerce_int(payload.get("history_count"))
    payload["queue_depth"] = _coerce_int(payload.get("queue_depth"))
    payload["pending"] = bool(payload.get("pending"))
    payload["state"] = str(payload.get("state") or "idle").strip() or "idle"
    payload["status_message"] = str(payload.get("status_message") or "").strip()
    for key in (
        "running_prompt_preview",
        "last_prompt_preview",
        "last_response_preview",
        "last_error_preview",
    ):
        payload[key] = summarize_text(str(payload.get(key) or ""), 160)
    payload["last_started_at"] = _coerce_int(payload.get("last_started_at"))
    payload["last_finished_at"] = _coerce_int(payload.get("last_finished_at"))
    return payload


def load_restart_handoff() -> dict[str, Any]:
    return normalize_restart_handoff(read_json(RESTART_HANDOFF_PATH, {}))


def restart_context_handoff(
    *,
    scope: str,
    reason: str = "",
    meta: dict[str, Any] | None = None,
    history: list[dict[str, Any]] | None = None,
    queued_prompts: list[dict[str, Any]] | None = None,
    created_at: int | None = None,
) -> dict[str, Any]:
    source_meta = meta if isinstance(meta, dict) else load_status_meta()
    history_entries = (
        history if history is not None else load_history(limit=MAX_HISTORY_ITEMS)
    )
    queue = (
        normalize_queue(queued_prompts)
        if queued_prompts is not None
        else normalize_queue(source_meta.get("queued_prompts"))
    )
    observed_at = now_ts() if created_at is None else int(created_at)
    thread_id = read_text(THREAD_ID_PATH)
    thread_scope = read_text(THREAD_SCOPE_PATH)
    last_prompt = read_text(LAST_PROMPT_PATH)
    last_response = read_text(LAST_RESPONSE_PATH)
    last_error = read_text(LAST_ERROR_PATH)
    history_count = len(history_entries)
    queue_depth = len(queue)
    pending = bool(source_meta.get("pending"))
    state = str(source_meta.get("state") or "idle").strip() or "idle"
    status_message = str(source_meta.get("status_message") or "").strip()
    preserved_parts: list[str] = []
    if thread_id:
        preserved_parts.append(f"thread {thread_id[:8]}")
    if history_count:
        preserved_parts.append(
            f"{history_count} history item{'s' if history_count != 1 else ''}"
        )
    if queue_depth:
        preserved_parts.append(
            f"{queue_depth} queued prompt{'s' if queue_depth != 1 else ''}"
        )
    if last_prompt.strip():
        preserved_parts.append("last prompt")
    if last_response.strip() and last_response.strip() != "[no response yet]":
        preserved_parts.append("last response")
    context_preserved = bool(preserved_parts)
    summary = (
        "Context handoff ready: " + ", ".join(preserved_parts) + "."
        if context_preserved
        else "No prior context found to preserve."
    )
    if pending:
        summary += " Active work should be guarded, not cut off."
    clean_scope = str(scope or "").strip().lower()
    clean_reason = str(reason or "").strip()
    handoff_id = hashlib.sha256(
        "\0".join(
            [
                clean_scope,
                str(observed_at),
                thread_id,
                str(_coerce_int(source_meta.get("last_started_at"))),
                str(_coerce_int(source_meta.get("last_finished_at"))),
            ]
        ).encode("utf-8", errors="replace")
    ).hexdigest()[:16]
    return normalize_restart_handoff(
        {
            "id": handoff_id,
            "created_at": observed_at,
            "scope": clean_scope,
            "reason": clean_reason,
            "summary": summary,
            "detail": " · ".join(
                part
                for part in (
                    clean_reason,
                    status_message,
                    f"state={state}",
                    f"queue={queue_depth}",
                    "resume-thread" if thread_id else "",
                )
                if part
            ),
            "context_preserved": context_preserved,
            "can_resume_thread": bool(thread_id),
            "thread_id": thread_id,
            "thread_scope": thread_scope,
            "history_count": history_count,
            "queue_depth": queue_depth,
            "pending": pending,
            "state": state,
            "status_message": status_message,
            "running_prompt_preview": summarize_text(
                str(source_meta.get("running_prompt") or ""), 160
            ),
            "last_prompt_preview": summarize_text(last_prompt, 160),
            "last_response_preview": summarize_text(last_response, 160),
            "last_error_preview": summarize_text(last_error, 160),
            "last_started_at": _coerce_int(source_meta.get("last_started_at")),
            "last_finished_at": _coerce_int(source_meta.get("last_finished_at")),
        }
    )


def write_restart_handoff(scope: str, reason: str = "") -> dict[str, Any]:
    handoff = restart_context_handoff(scope=scope, reason=reason)
    write_json(RESTART_HANDOFF_PATH, handoff)
    update_status_meta(
        restart_handoff_id=handoff["id"],
        restart_handoff_at=handoff["created_at"],
        restart_handoff_scope=handoff["scope"],
        restart_handoff_summary=handoff["summary"],
        restart_handoff_detail=handoff["detail"],
    )
    append_audit_event(
        event_type="restart.handoff",
        summary=handoff["summary"],
        detail=handoff["detail"],
        severity="warn" if handoff["pending"] else "info",
        actor_type="system",
        thread_id=handoff["thread_id"],
        payload=handoff,
        event_at=handoff["created_at"],
    )
    return handoff


def prompt_completed_after(
    prompt: str, queued_at: int, history: list[dict[str, Any]]
) -> bool:
    clean = str(prompt or "").strip()
    if not clean:
        return False
    for entry in history:
        if str(entry.get("prompt") or "").strip() != clean:
            continue
        finished_at = _coerce_int(entry.get("finished_at") or entry.get("started_at"))
        if queued_at > 0 and finished_at > 0 and finished_at < queued_at:
            continue
        if (
            str(entry.get("response") or "").strip()
            or str(entry.get("error") or "").strip()
        ):
            return True
    return False


def prompt_text_matches(left: Any, right: Any) -> bool:
    return (
        str(left or "").replace("\r\n", "\n").strip()
        == str(right or "").replace("\r\n", "\n").strip()
    )


def prompt_attachment_signature(attachments: Any) -> tuple[tuple[str, ...], ...]:
    signature: list[tuple[str, ...]] = []
    for item in normalize_attachments(attachments):
        signature.append(
            (
                str(item.get("token") or ""),
                str(item.get("kind") or ""),
                str(item.get("name") or ""),
                str(item.get("path") or ""),
                str(item.get("content_type") or ""),
                str(item.get("size") or 0),
            )
        )
    return tuple(signature)


def prompt_submission_matches(
    existing_prompt: Any,
    existing_attachments: Any,
    incoming_prompt: Any,
    incoming_attachments: Any,
) -> bool:
    if not prompt_text_matches(existing_prompt, incoming_prompt):
        return False
    existing_signature = prompt_attachment_signature(existing_attachments)
    incoming_signature = prompt_attachment_signature(incoming_attachments)
    return existing_signature == incoming_signature or not incoming_signature


def prompt_already_running_or_queued(
    meta: dict[str, Any],
    *,
    prompt: str,
    attachments: list[dict[str, Any]],
    source: str = "operator",
) -> tuple[str, int]:
    if prompt_submission_matches(
        meta.get("running_prompt"),
        meta.get("running_attachments"),
        prompt,
        attachments,
    ):
        return "running", 0
    for index, item in enumerate(normalize_queue(meta.get("queued_prompts")), start=1):
        item_source = normalize_queue_source(
            item.get("source"),
            normalize_relay_callback(item.get("relay_callback")),
            str(item.get("prompt") or ""),
        )
        if item_source != source:
            continue
        if prompt_submission_matches(
            item.get("prompt"),
            item.get("attachments"),
            prompt,
            attachments,
        ):
            return "queued", index
    return "", 0


def prune_stale_recovered_queue_items(
    meta: dict[str, Any],
    *,
    history: list[dict[str, Any]] | None = None,
    now: int | None = None,
) -> tuple[dict[str, Any], int]:
    queue = normalize_queue(meta.get("queued_prompts"))
    if not queue:
        if (
            meta.get("queued_prompts")
            or meta.get("stale_queue")
            or meta.get("recovered_after_restart")
        ):
            meta["queued_prompts"] = []
            meta["stale_queue"] = False
            meta["recovered_after_restart"] = False
        return meta, 0
    pending = bool(meta.get("pending"))
    observed_at = now_ts() if now is None else int(now)
    completed_history = (
        history if history is not None else load_history(limit=MAX_HISTORY_ITEMS)
    )
    kept: list[dict[str, Any]] = []
    removed = 0
    for item in queue:
        recovered = queue_item_is_recovered(item)
        queued_at = _coerce_int(item.get("queued_at"))
        age = max(0, observed_at - queued_at) if queued_at > 0 else 0
        completed = prompt_completed_after(
            str(item.get("prompt") or ""), queued_at, completed_history
        )
        should_prune = (
            recovered
            and not pending
            and (age >= RECOVERED_QUEUE_TTL_SECONDS or completed)
        )
        if should_prune:
            removed += 1
            continue
        kept.append(item)
    if removed:
        meta["queued_prompts"] = kept
        meta["last_action"] = "queue-prune-recovered"
        meta["last_action_at"] = observed_at
        meta["last_action_detail"] = (
            f"Pruned {removed} stale recovered queued prompt"
            f"{'s' if removed != 1 else ''}."
        )
        meta["status_message"] = meta["last_action_detail"]
    recovered_remaining = any(queue_item_is_recovered(item) for item in kept)
    meta["stale_queue"] = recovered_remaining
    meta["recovered_after_restart"] = recovered_remaining
    if (
        not pending
        and not recovered_remaining
        and str(meta.get("state") or "").strip().lower() == "recovered"
    ):
        meta["state"] = "ok"
        meta["status_message"] = "Queued work is waiting." if kept else "Ready."
        meta["running_prompt"] = ""
        meta["running_attachments"] = []
    return meta, removed


def normalize_queue_source(
    value: Any, relay_callback: dict[str, Any] | None = None, prompt: str = ""
) -> str:
    clean = str(value or "").strip().lower()
    if clean in {"operator", "relay", "passive", "system", "recovered"}:
        return clean
    text = str(prompt or "").lower()
    if relay_callback:
        return "relay"
    if "passive fleet context" in text or "party line" in text or "bbs" in text:
        return "passive"
    return "operator"


def normalize_relay_callback(value: Any) -> dict[str, Any]:
    if not isinstance(value, dict):
        return {}
    aliases = {
        "relay_source_channel_id": "source_channel_id",
        "relay_source_message_id": "source_message_id",
        "relay_target_connector_name": "target_connector_name",
        "relay_target_connector_id": "target_connector_id",
    }
    normalized_input = dict(value)
    for old_key, new_key in aliases.items():
        if old_key in normalized_input and new_key not in normalized_input:
            normalized_input[new_key] = normalized_input.get(old_key)
    allowed = {
        "relay_id",
        "callback_url",
        "source_channel_id",
        "source_message_id",
        "target_connector_id",
        "target_connector_name",
    }
    return {
        key: normalized_input.get(key)
        for key in allowed
        if str(normalized_input.get(key) or "").strip()
        or isinstance(normalized_input.get(key), int)
    }


def queue_item_id(prompt: str, queued_at: int, source: str, existing: Any = "") -> str:
    clean_existing = str(existing or "").strip()
    if clean_existing:
        return clean_existing
    raw = f"{queued_at}\0{source}\0{prompt}".encode("utf-8", errors="replace")
    return hashlib.sha256(raw).hexdigest()[:16]


def queue_checkpoint_policy() -> str:
    return QUEUE_CHECKPOINT_POLICY


def queue_interlace_mode() -> str:
    return QUEUE_INTERLACE_MODE


def queue_checkpoint_policy_for_interlace(mode: str) -> str:
    return (
        "interrupt"
        if normalize_queue_interlace_mode(mode) == "interrupt"
        else "observe"
    )


def queue_interlace_mode_for_checkpoint_policy(policy: str) -> str:
    clean = str(policy or "").strip().lower()
    if clean == "interrupt":
        return "interrupt"
    if clean == "observe":
        return "queue"
    return normalize_queue_interlace_mode(clean)


def queued_operator_prompt_waiting(meta: dict[str, Any] | None = None) -> bool:
    source_meta = meta if isinstance(meta, dict) else load_status_meta()
    for item in normalize_queue(source_meta.get("queued_prompts")):
        if queue_item_is_recovered(item):
            continue
        if str(item.get("source") or "").strip().lower() == "operator":
            return True
    return False


def queued_operator_interlace_mode(meta: dict[str, Any] | None = None) -> str:
    source_meta = meta if isinstance(meta, dict) else load_status_meta()
    for item in normalize_queue(source_meta.get("queued_prompts")):
        if queue_item_is_recovered(item):
            continue
        if str(item.get("source") or "").strip().lower() != "operator":
            continue
        return normalize_queue_interlace_mode(
            item.get("interlace_mode")
            or queue_interlace_mode_for_checkpoint_policy(
                str(item.get("checkpoint_policy") or "")
            )
        )
    return normalize_queue_interlace_mode(source_meta.get("queue_interlace_mode"))


def first_queued_operator_prompt(
    queue: list[dict[str, Any]],
) -> dict[str, Any] | None:
    for item in queue:
        if queue_item_is_recovered(item):
            continue
        if str(item.get("source") or "").strip().lower() == "operator":
            return item
    return None


def queue_operator_plan_detail(
    queue: list[dict[str, Any]],
    *,
    interlace_mode: str,
    checkpoint_label: str = "",
    checkpoint_kind: str = "",
) -> str:
    normalized_mode = normalize_queue_interlace_mode(interlace_mode)
    item = first_queued_operator_prompt(queue)
    prompt_preview = summarize_text(str((item or {}).get("prompt") or "").strip(), 96)
    target = f"'{prompt_preview}'" if prompt_preview else "the queued prompt"
    label = summarize_text(str(checkpoint_label or "").strip(), 80)
    after_label = f" after {label}" if label else ""
    next_checkpoint = (
        f" after {label}"
        if label and checkpoint_kind
        else " at the next supported safe checkpoint"
    )
    if normalized_mode == "interrupt":
        if checkpoint_kind == "tool-finished":
            return (
                f"Interrupt acknowledged: safe checkpoint{after_label}; queued "
                f"operator prompt will run next with a handoff note. Plan: pause "
                f"the current reply, preserve the interrupted work, run {target} "
                "next, and tell the operator what was deferred. No action needed "
                "unless you want to cancel or reorder the queue."
            )
        return (
            "Interrupt acknowledged: operator prompt queued; waiting for a safe "
            f"checkpoint{next_checkpoint}. Plan: at the next tool boundary, pause "
            f"the current reply, preserve its context, and run {target} with a "
            "clear handoff note. No action needed yet."
        )
    if checkpoint_kind == "tool-finished":
        return (
            f"Queue mode acknowledged: safe checkpoint{after_label}; current reply "
            f"keeps running. Plan: keep {target} parked until the active reply "
            "finishes, then run queued work in order."
        )
    return (
        "Queue mode acknowledged: operator prompt queued behind the active reply. "
        f"Plan: keep {target} parked until the current turn finishes, then run "
        "queued work in order."
    )


def build_interrupt_handoff_execution_prompt(
    operator_prompt: str,
    *,
    interrupted_prompt: str = "",
    checkpoint_event: str = "",
    checkpoint_tool: str = "",
    checkpoint_detail: str = "",
) -> str:
    clean_prompt = str(operator_prompt or "").strip()
    interrupted_preview = summarize_text(str(interrupted_prompt or "").strip(), 260)
    event_preview = summarize_text(str(checkpoint_event or "").strip(), 80)
    tool_preview = summarize_text(str(checkpoint_tool or "").strip(), 120)
    detail_preview = summarize_text(str(checkpoint_detail or "").strip(), 220)
    checkpoint_parts = [
        f"event={event_preview}" if event_preview else "",
        f"tool={tool_preview}" if tool_preview else "",
    ]
    checkpoint_line = ", ".join(part for part in checkpoint_parts if part)
    lines = [
        "Safe-checkpoint interrupt handoff:",
        "- The operator intentionally interrupted the previous reply at a supported tool boundary.",
        "- Start with one short orientation sentence that says the handoff is active and whether older work is deferred or preserved.",
        "- Then answer the operator's new prompt directly. Do not restart unrelated setup unless the new prompt requires it.",
        "- If the previous task still matters, name the deferred work and the next resume point briefly.",
    ]
    if interrupted_preview:
        lines.append(f"- Interrupted prompt snapshot: {interrupted_preview}")
    if checkpoint_line:
        lines.append(f"- Checkpoint: {checkpoint_line}")
    if detail_preview:
        lines.append(f"- Operator-facing queue note: {detail_preview}")
    lines.extend(["", "Operator prompt:", clean_prompt])
    return "\n".join(lines).strip()


def active_interrupt_handoff_execution_prompt(prompt: str) -> str:
    clean_prompt = str(prompt or "").strip()
    if not clean_prompt:
        return ""
    meta = load_status_meta()
    if str(meta.get("queue_handoff_state") or "").strip().lower() != "running":
        return ""
    handoff_prompt = str(meta.get("queue_handoff_prompt") or "").strip()
    if handoff_prompt and handoff_prompt != clean_prompt:
        return ""
    return build_interrupt_handoff_execution_prompt(
        clean_prompt,
        interrupted_prompt=str(meta.get("queue_handoff_interrupted_prompt") or ""),
        checkpoint_event=str(meta.get("queue_handoff_checkpoint_event") or ""),
        checkpoint_tool=str(meta.get("queue_handoff_checkpoint_tool") or ""),
        checkpoint_detail=str(meta.get("queue_handoff_detail") or ""),
    )


def active_interrupt_handoff_matches_prompt(prompt: str) -> bool:
    clean_prompt = str(prompt or "").strip()
    if not clean_prompt:
        return False
    meta = load_status_meta()
    return (
        str(meta.get("queue_handoff_state") or "").strip().lower() == "running"
        and str(meta.get("queue_handoff_prompt") or "").strip() == clean_prompt
    )


def codex_event_type(event: dict[str, Any]) -> str:
    return str(event.get("type") or event.get("event") or "").strip().lower()


def codex_event_tool_label(event: dict[str, Any]) -> str:
    candidates = [
        event.get("tool"),
        event.get("tool_name"),
        event.get("name"),
        event.get("command"),
    ]
    item = event.get("item")
    if isinstance(item, dict):
        candidates.extend(
            [
                item.get("tool"),
                item.get("tool_name"),
                item.get("name"),
                item.get("command"),
            ]
        )
    for candidate in candidates:
        clean = summarize_text(str(candidate or "").strip(), 80)
        if clean:
            return clean
    event_type = codex_event_type(event)
    return event_type or "tool"


def codex_event_checkpoint_kind(event: dict[str, Any]) -> str:
    event_type = codex_event_type(event)
    if not event_type:
        return ""
    searchable = event_type
    item = event.get("item")
    if isinstance(item, dict):
        searchable += " " + str(item.get("type") or "").strip().lower()
    toolish = any(
        token in searchable
        for token in (
            "tool",
            "exec",
            "command",
            "shell",
            "apply_patch",
            "function",
            "mcp",
        )
    )
    if not toolish:
        return ""
    if any(
        token in searchable
        for token in (
            "completed",
            "complete",
            "finished",
            "succeeded",
            "failed",
            "result",
            "end",
            "exited",
        )
    ):
        return "tool-finished"
    if any(
        token in searchable
        for token in ("started", "start", "begin", "running", "call")
    ):
        return "tool-started"
    return "tool-observed"


LIVE_TURN_PATH_RE = re.compile(
    r"(?<![A-Za-z0-9_./:-])"
    r"(?P<path>(?:/[\w.@:+-][\w.@:+\-/ ]{1,180})|"
    r"(?:(?:[\w.@:+-]+/){1,8}[\w.@:+-]+))"
)


def default_live_turn() -> dict[str, Any]:
    return {
        "schema": "norman.tui.live-turn.v1",
        "state": "idle",
        "started_at": 0,
        "updated_at": 0,
        "finished_at": 0,
        "elapsed_seconds": 0,
        "runtime": "",
        "model": "",
        "service_tier": "",
        "job_budget": "",
        "event_count": 0,
        "tool_event_count": 0,
        "tool_started_count": 0,
        "tool_finished_count": 0,
        "decision_count": 0,
        "file_interaction_count": 0,
        "estimated_input_tokens": 0,
        "estimated_output_tokens": 0,
        "estimated_total_tokens": 0,
        "observed_input_tokens": 0,
        "observed_cached_input_tokens": 0,
        "observed_output_tokens": 0,
        "observed_reasoning_output_tokens": 0,
        "observed_total_tokens": 0,
        "token_source": "estimate",
        "last_event_type": "",
        "last_tool": "",
        "last_tool_status": "",
        "last_decision": "",
        "last_file": "",
        "tools": [],
        "files": [],
        "decisions": [],
    }


def _live_turn_limited_strings(value: Any, *, limit: int) -> list[str]:
    if not isinstance(value, list):
        return []
    seen: set[str] = set()
    items: list[str] = []
    for raw in value:
        clean = summarize_text(str(raw or "").strip(), 120)
        if not clean or clean in seen:
            continue
        seen.add(clean)
        items.append(clean)
    return items[-limit:]


def normalize_live_turn(value: Any) -> dict[str, Any]:
    payload = dict(default_live_turn())
    if isinstance(value, dict):
        payload.update(value)
    payload["state"] = str(payload.get("state") or "idle").strip().lower() or "idle"
    if payload["state"] not in {
        "idle",
        "running",
        "done",
        "error",
        "cancelled",
        "interrupted",
        "needs_continue",
        "blocked",
        "stale",
    }:
        payload["state"] = "running"
    for key in (
        "started_at",
        "updated_at",
        "finished_at",
        "elapsed_seconds",
        "event_count",
        "tool_event_count",
        "tool_started_count",
        "tool_finished_count",
        "decision_count",
        "file_interaction_count",
        "estimated_input_tokens",
        "estimated_output_tokens",
        "estimated_total_tokens",
        "observed_input_tokens",
        "observed_cached_input_tokens",
        "observed_output_tokens",
        "observed_reasoning_output_tokens",
        "observed_total_tokens",
    ):
        payload[key] = _coerce_int(payload.get(key))
    for key in (
        "runtime",
        "model",
        "service_tier",
        "job_budget",
        "token_source",
        "last_event_type",
        "last_tool",
        "last_tool_status",
        "last_decision",
        "last_file",
    ):
        payload[key] = summarize_text(str(payload.get(key) or "").strip(), 180)
    payload["tools"] = _live_turn_limited_strings(payload.get("tools"), limit=8)
    payload["files"] = _live_turn_limited_strings(payload.get("files"), limit=12)
    payload["decisions"] = _live_turn_limited_strings(payload.get("decisions"), limit=8)
    if not payload["estimated_total_tokens"]:
        payload["estimated_total_tokens"] = (
            payload["estimated_input_tokens"] + payload["estimated_output_tokens"]
        )
    return payload


def initial_live_turn(
    *,
    prompt: str,
    attachments: list[dict[str, Any]],
    started_at: int,
    runtime: str,
    model: str,
    service_tier: str,
    job_budget: str,
) -> dict[str, Any]:
    input_tokens = _estimated_text_tokens(prompt) + _estimated_attachment_tokens(
        attachments
    )
    now = now_ts()
    payload = normalize_live_turn(
        {
            "state": "running",
            "started_at": started_at or now,
            "updated_at": now,
            "runtime": runtime,
            "model": model,
            "service_tier": service_tier,
            "job_budget": job_budget,
            "estimated_input_tokens": input_tokens,
            "estimated_total_tokens": input_tokens,
            "token_source": "estimate",
        }
    )
    return payload


def live_turn_snapshot(
    value: Any, *, pending: bool, observed_at: int
) -> dict[str, Any]:
    live = normalize_live_turn(value)
    started_at = _coerce_int(live.get("started_at"))
    finished_at = _coerce_int(live.get("finished_at"))
    if started_at:
        end_at = observed_at if pending or not finished_at else finished_at
        live["elapsed_seconds"] = max(0, end_at - started_at)
    if not pending and live["state"] == "running":
        live["state"] = "stale"
    return live


def _live_turn_event_text_fragments(value: Any, *, depth: int = 0) -> list[str]:
    if depth > 4:
        return []
    if isinstance(value, str):
        return [value]
    if isinstance(value, (int, float, bool)) or value is None:
        return []
    if isinstance(value, list):
        parts: list[str] = []
        for item in value[:20]:
            parts.extend(_live_turn_event_text_fragments(item, depth=depth + 1))
        return parts
    if isinstance(value, dict):
        parts = []
        for key, item in list(value.items())[:40]:
            if str(key).lower() in {"id", "thread_id", "session_id"}:
                continue
            parts.extend(_live_turn_event_text_fragments(item, depth=depth + 1))
        return parts
    return []


def live_turn_event_files(event: dict[str, Any]) -> list[str]:
    files: list[str] = []
    seen: set[str] = set()
    for fragment in _live_turn_event_text_fragments(event):
        for match in LIVE_TURN_PATH_RE.finditer(fragment):
            path = match.group("path").strip(".,;:'\")]}>\n\r\t ")
            if not path or path in seen:
                continue
            lowered = path.lower()
            if lowered.startswith(("http://", "https://")):
                continue
            if len(path) < 3 or path.count("/") <= 0:
                continue
            seen.add(path)
            files.append(path)
    return files[:12]


def codex_event_decision_label(event: dict[str, Any]) -> str:
    event_type = codex_event_type(event)
    item = event.get("item")
    item_type = (
        str(item.get("type") or "").strip().lower() if isinstance(item, dict) else ""
    )
    role = (
        str(item.get("role") or event.get("role") or "").strip().lower()
        if isinstance(item, dict)
        else str(event.get("role") or "").strip().lower()
    )
    searchable = " ".join(part for part in (event_type, item_type, role) if part)
    if not searchable:
        return ""
    if "delta" in searchable:
        return ""
    labels = (
        ("plan", "plan"),
        ("reasoning", "reasoning"),
        ("decision", "decision"),
        ("approval", "approval"),
        ("assistant", "assistant message"),
        ("message", "message"),
    )
    for token, label in labels:
        if token in searchable:
            return label
    return ""


def live_turn_event_usage(event: dict[str, Any]) -> dict[str, Any]:
    usage = event.get("usage")
    if isinstance(usage, dict):
        return normalize_usage_entry(usage)
    item = event.get("item")
    if isinstance(item, dict) and isinstance(item.get("usage"), dict):
        return normalize_usage_entry(item["usage"])
    return {}


def _append_limited_unique(
    values: list[str], additions: list[str], *, limit: int
) -> list[str]:
    merged: list[str] = []
    for item in [*values, *additions]:
        clean = summarize_text(str(item or "").strip(), 120)
        if clean and clean not in merged:
            merged.append(clean)
    return merged[-limit:]


def live_turn_with_event(
    live_turn: Any,
    event: dict[str, Any],
    *,
    kind: str = "",
    observed_at: int = 0,
) -> dict[str, Any]:
    live = normalize_live_turn(live_turn)
    now = observed_at or now_ts()
    event_type = codex_event_type(event)
    label = codex_event_tool_label(event) if kind else ""
    decision = codex_event_decision_label(event)
    files = live_turn_event_files(event)
    usage = live_turn_event_usage(event)
    live["state"] = "running"
    live["updated_at"] = now
    live["last_event_type"] = event_type
    live["event_count"] += 1
    if kind:
        live["tool_event_count"] += 1
        live["last_tool"] = label
        live["last_tool_status"] = kind
        live["tools"] = _append_limited_unique(
            live["tools"], [label] if label else [], limit=8
        )
        if kind == "tool-started":
            live["tool_started_count"] += 1
        elif kind == "tool-finished":
            live["tool_finished_count"] += 1
    if decision:
        live["decision_count"] += 1
        live["last_decision"] = decision
        live["decisions"] = _append_limited_unique(
            live["decisions"], [decision], limit=8
        )
    if files:
        live["files"] = _append_limited_unique(live["files"], files, limit=12)
        live["file_interaction_count"] = len(live["files"])
        live["last_file"] = live["files"][-1]
    output_fragment_tokens = _estimated_text_tokens(
        " ".join(
            fragment
            for fragment in _live_turn_event_text_fragments(event)
            if len(fragment) <= 2000
        )[:4000]
    )
    live["estimated_output_tokens"] = max(
        live["estimated_output_tokens"],
        min(live["estimated_output_tokens"] + output_fragment_tokens, 2_000_000),
    )
    if usage:
        live["observed_input_tokens"] = _coerce_int(usage.get("input_tokens"))
        live["observed_cached_input_tokens"] = _coerce_int(
            usage.get("cached_input_tokens")
        )
        live["observed_output_tokens"] = _coerce_int(usage.get("output_tokens"))
        live["observed_reasoning_output_tokens"] = _coerce_int(
            usage.get("reasoning_output_tokens")
        )
        live["observed_total_tokens"] = _coerce_int(usage.get("total_tokens"))
        if live["observed_total_tokens"] > 0:
            live["token_source"] = "observed"
    live["estimated_total_tokens"] = max(
        live["estimated_total_tokens"],
        live["estimated_input_tokens"] + live["estimated_output_tokens"],
        live["observed_total_tokens"],
    )
    started_at = _coerce_int(live.get("started_at"))
    if started_at:
        live["elapsed_seconds"] = max(0, now - started_at)
    return normalize_live_turn(live)


def record_live_turn_event(event: dict[str, Any], *, kind: str = "") -> None:
    if not isinstance(event, dict):
        return
    important = bool(
        kind
        or codex_event_decision_label(event)
        or live_turn_event_files(event)
        or live_turn_event_usage(event)
    )
    with STATUS_LOCK:
        meta = load_status_meta()
        live = normalize_live_turn(meta.get("live_turn"))
        if (
            not important
            and _coerce_int(live.get("updated_at"))
            and now_ts() - _coerce_int(live.get("updated_at")) < 2
        ):
            return
        meta["live_turn"] = live_turn_with_event(
            live, event, kind=kind, observed_at=now_ts()
        )
        save_status_meta(meta)


def update_live_turn_prompt_estimate(
    *,
    tuned_prompt: str,
    attachments: list[dict[str, Any]],
    runtime: str,
    model: str,
    service_tier: str,
    job_budget: str,
) -> None:
    input_tokens = _estimated_text_tokens(tuned_prompt)
    if not input_tokens:
        input_tokens = _estimated_attachment_tokens(attachments)
    with STATUS_LOCK:
        meta = load_status_meta()
        live = normalize_live_turn(meta.get("live_turn"))
        live.update(
            {
                "state": "running",
                "updated_at": now_ts(),
                "runtime": runtime,
                "model": model,
                "service_tier": service_tier,
                "job_budget": job_budget,
                "estimated_input_tokens": input_tokens,
                "estimated_total_tokens": input_tokens
                + _coerce_int(live.get("estimated_output_tokens")),
                "token_source": "estimate",
            }
        )
        meta["live_turn"] = normalize_live_turn(live)
        save_status_meta(meta)


def finalize_live_turn(
    *,
    usage: dict[str, Any],
    visible_response: str,
    error_text: str,
    state: str,
    finished_at: int,
) -> dict[str, Any]:
    usage_entry = normalize_usage_entry(usage)
    with STATUS_LOCK:
        meta = load_status_meta()
        live = normalize_live_turn(meta.get("live_turn"))
        output_tokens = max(
            _coerce_int(live.get("estimated_output_tokens")),
            _estimated_text_tokens(visible_response or error_text),
        )
        live.update(
            {
                "state": state,
                "updated_at": finished_at or now_ts(),
                "finished_at": finished_at or now_ts(),
                "estimated_output_tokens": output_tokens,
                "observed_input_tokens": _coerce_int(usage_entry.get("input_tokens")),
                "observed_cached_input_tokens": _coerce_int(
                    usage_entry.get("cached_input_tokens")
                ),
                "observed_output_tokens": _coerce_int(usage_entry.get("output_tokens")),
                "observed_reasoning_output_tokens": _coerce_int(
                    usage_entry.get("reasoning_output_tokens")
                ),
                "observed_total_tokens": _coerce_int(usage_entry.get("total_tokens")),
            }
        )
        if live["observed_total_tokens"] > 0:
            live["token_source"] = "observed"
        live["estimated_total_tokens"] = max(
            live["estimated_input_tokens"] + live["estimated_output_tokens"],
            live["observed_total_tokens"],
        )
        started_at = _coerce_int(live.get("started_at"))
        if started_at:
            live["elapsed_seconds"] = max(0, live["finished_at"] - started_at)
        meta["live_turn"] = normalize_live_turn(live)
        save_status_meta(meta)
        return meta["live_turn"]


def record_queue_checkpoint(
    *,
    event: dict[str, Any],
    kind: str,
    queued_operator_waiting: bool | None = None,
) -> bool:
    if kind not in {"tool-started", "tool-finished", "tool-observed"}:
        return False
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        if not queue:
            meta["queue_checkpoint_state"] = "idle"
            meta["queue_checkpoint_event"] = ""
            meta["queue_checkpoint_detail"] = ""
            meta["queue_interlace_mode"] = queue_interlace_mode()
            meta["queue_checkpoint_policy"] = queue_checkpoint_policy()
            meta["queue_handoff_state"] = "idle"
            meta["queue_handoff_detail"] = ""
            meta["queue_handoff_prompt"] = ""
            meta["queue_handoff_interrupted_prompt"] = ""
            meta["queue_handoff_checkpoint_event"] = ""
            meta["queue_handoff_checkpoint_tool"] = ""
            meta["queue_handoff_started_at"] = 0
            save_status_meta(meta)
            return False
        operator_waiting = (
            queued_operator_prompt_waiting(meta)
            if queued_operator_waiting is None
            else bool(queued_operator_waiting)
        )
        interlace_mode = (
            queued_operator_interlace_mode(meta)
            if operator_waiting
            else normalize_queue_interlace_mode(meta.get("queue_interlace_mode"))
        )
        policy = queue_checkpoint_policy_for_interlace(interlace_mode)
        event_type = codex_event_type(event)
        label = codex_event_tool_label(event)
        checkpoint_count = _coerce_int(meta.get("queue_checkpoint_count")) + 1
        can_interrupt = bool(
            operator_waiting and policy == "interrupt" and kind == "tool-finished"
        )
        if can_interrupt:
            state = "interrupting"
            detail = queue_operator_plan_detail(
                queue,
                interlace_mode=interlace_mode,
                checkpoint_label=label,
                checkpoint_kind=kind,
            )
        elif operator_waiting and kind == "tool-finished":
            state = "ready"
            detail = queue_operator_plan_detail(
                queue,
                interlace_mode=interlace_mode,
                checkpoint_label=label,
                checkpoint_kind=kind,
            )
        elif operator_waiting:
            state = "waiting"
            detail = queue_operator_plan_detail(
                queue,
                interlace_mode=interlace_mode,
                checkpoint_label=label,
                checkpoint_kind=kind,
            )
        else:
            state = "waiting-nonoperator"
            detail = "Queued non-operator work waits for the current turn."
        meta.update(
            {
                "queue_interlace_mode": interlace_mode,
                "queue_checkpoint_policy": policy,
                "queue_checkpoint_state": state,
                "queue_checkpoint_event": event_type or kind,
                "queue_checkpoint_detail": detail,
                "queue_checkpoint_count": checkpoint_count,
                "queue_checkpoint_last_at": now_ts(),
                "queue_handoff_state": "checkpoint-ready" if can_interrupt else "idle",
                "queue_handoff_detail": detail if can_interrupt else "",
                "queue_handoff_prompt": str(
                    (first_queued_operator_prompt(queue) or {}).get("prompt") or ""
                ).strip()
                if can_interrupt
                else "",
                "queue_handoff_interrupted_prompt": str(
                    meta.get("running_prompt") or read_text(LAST_PROMPT_PATH)
                ).strip()
                if can_interrupt
                else "",
                "queue_handoff_checkpoint_event": (event_type or kind)
                if can_interrupt
                else "",
                "queue_handoff_checkpoint_tool": label if can_interrupt else "",
                "queue_handoff_started_at": 0,
                "status_message": detail,
            }
        )
        save_status_meta(meta)
    if kind == "tool-finished" and operator_waiting:
        append_audit_event(
            event_type="queue.checkpoint",
            summary="Queued operator prompt reached a tool checkpoint.",
            detail=detail,
            severity="info",
            actor_type="system",
            payload={
                "policy": policy,
                "interlace_mode": interlace_mode,
                "checkpoint_state": state,
                "event_type": event_type,
                "tool": label,
                "will_interrupt": can_interrupt,
            },
        )
    return can_interrupt


def prompt_is_deadline_continuation(prompt: str) -> bool:
    return AUTO_CONTINUE_DEADLINE_MARKER in (prompt or "")


def deadline_checkpoint_policy_allows(meta: dict[str, Any]) -> bool:
    policy = str(
        meta.get("deadline_checkpoint_policy") or DEADLINE_CHECKPOINT_POLICY
    ).strip()
    if policy == "off":
        return False
    warning_kind = str(meta.get("deadline_warning_kind") or "")
    remaining = _coerce_int(meta.get("deadline_warning_remaining_seconds"))
    if policy in {"auto", "final"}:
        return remaining > 0 and remaining <= 5 * 60
    return "target" in warning_kind or (remaining > 0 and remaining <= 5 * 60)


def build_deadline_checkpoint_detail(
    *,
    event: dict[str, Any],
    kind: str,
    prompt: str,
    meta: dict[str, Any],
) -> str:
    label = codex_event_tool_label(event)
    warning = str(meta.get("deadline_warning_message") or "").strip()
    remaining = _coerce_int(meta.get("deadline_warning_remaining_seconds"))
    remaining_label = prompt_duration_label(remaining) if remaining else "unknown time"
    prompt_preview = summarize_text(prompt, 120)
    tool_part = f" after {label}" if label else ""
    warning_part = f" Warning: {warning}" if warning else ""
    return (
        f"Deadline checkpoint{tool_part}: pausing '{prompt_preview}' with "
        f"{remaining_label} before the hard guardrail.{warning_part}"
    )


def record_deadline_checkpoint(
    *,
    event: dict[str, Any],
    kind: str,
    prompt: str,
) -> bool:
    if kind != "tool-finished":
        return False
    if prompt_is_deadline_continuation(prompt):
        return False
    with STATUS_LOCK:
        meta = load_status_meta()
        if not bool(meta.get("deadline_warning_active")):
            return False
        if not deadline_checkpoint_policy_allows(meta):
            return False
        detail = build_deadline_checkpoint_detail(
            event=event,
            kind=kind,
            prompt=prompt,
            meta=meta,
        )
        event_type = codex_event_type(event)
        tool_label = codex_event_tool_label(event)
        meta.update(
            {
                "deadline_checkpoint_policy": str(
                    meta.get("deadline_checkpoint_policy") or DEADLINE_CHECKPOINT_POLICY
                ),
                "deadline_checkpoint_state": "interrupting",
                "deadline_checkpoint_detail": detail,
                "deadline_checkpoint_event": event_type or kind,
                "deadline_checkpoint_tool": tool_label,
                "deadline_checkpoint_started_at": now_ts(),
                "status_message": detail,
            }
        )
        save_status_meta(meta)
    append_audit_event(
        event_type="chat.deadline-checkpoint",
        summary="Deadline checkpoint paused a web prompt at a tool boundary.",
        detail=detail,
        severity="warn",
        actor_type="system",
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "event_type": event_type,
            "tool": tool_label,
            "checkpoint_kind": kind,
            "policy": str(meta.get("deadline_checkpoint_policy") or ""),
            "warning_kind": str(meta.get("deadline_warning_kind") or ""),
            "remaining_seconds": _coerce_int(
                meta.get("deadline_warning_remaining_seconds")
            ),
            "target_seconds": _coerce_int(meta.get("deadline_warning_target_seconds")),
            "guardrail_seconds": _coerce_int(
                meta.get("deadline_warning_guardrail_seconds")
            ),
            "prompt_preview": summarize_text(prompt, 240),
        },
    )
    return True


