def update_status_meta(**updates: Any) -> dict[str, Any]:
    with STATUS_LOCK:
        meta = load_status_meta()
        meta.update(updates)
        return save_status_meta(meta)


def prompt_thread_alive() -> bool:
    return ACTIVE_PROMPT_THREAD is not None and ACTIVE_PROMPT_THREAD.is_alive()


def codex_exec_child_alive() -> bool:
    parent_pid = str(os.getpid())
    state_dir_marker = str(STATE_DIR)
    proc_root = Path("/proc")
    if not proc_root.exists():
        return False
    for proc_dir in proc_root.iterdir():
        if not proc_dir.name.isdigit():
            continue
        try:
            stat_fields = (proc_dir / "stat").read_text().split()
            if len(stat_fields) < 4 or stat_fields[3] != parent_pid:
                continue
            cmdline = (proc_dir / "cmdline").read_bytes().replace(b"\0", b" ")
        except (FileNotFoundError, ProcessLookupError, PermissionError, OSError):
            continue
        command = cmdline.decode("utf-8", errors="replace")
        if "codex exec" in command and state_dir_marker in command:
            return True
    return False


def pid_alive(pid: int) -> bool:
    if pid <= 0:
        return False
    try:
        os.kill(pid, 0)
    except ProcessLookupError:
        return False
    except PermissionError:
        return True
    except OSError:
        return False
    return True


def codex_runtime_pid_alive(pid: int) -> bool:
    if not pid_alive(pid):
        return False
    proc_dir = Path("/proc") / str(pid)
    try:
        cmdline = (proc_dir / "cmdline").read_bytes().replace(b"\0", b" ")
    except (FileNotFoundError, ProcessLookupError, OSError):
        return False
    except PermissionError:
        return True
    command = cmdline.decode("utf-8", errors="replace")
    return "codex exec" in command and str(STATE_DIR) in command


def active_codex_process_alive() -> bool:
    with ACTIVE_CODEX_LOCK:
        proc = ACTIVE_CODEX_PROC
    if proc is not None and proc.poll() is None:
        return True
    meta = load_status_meta()
    return codex_runtime_pid_alive(_coerce_int(meta.get("active_child_pid")))


def prompt_runtime_alive() -> bool:
    return (
        prompt_thread_alive()
        or active_codex_process_alive()
        or codex_exec_child_alive()
    )


def working_response_text(prompt: str) -> str:
    return f"Working on: {summarize_text(prompt, 180)}. New messages will be queued."


def set_active_codex_process(proc: subprocess.Popen[str] | None) -> None:
    global ACTIVE_CODEX_PROC
    with ACTIVE_CODEX_LOCK:
        ACTIVE_CODEX_PROC = proc
    if proc is None:
        update_status_meta(
            active_child_pid=0,
            active_child_pgid=0,
            active_child_started_at=0,
        )
        return
    try:
        pgid = os.getpgid(proc.pid)
    except OSError:
        pgid = proc.pid
    update_status_meta(
        active_child_pid=int(proc.pid),
        active_child_pgid=int(pgid),
        active_child_started_at=now_ts(),
        cancel_requested_at=0,
        status_message="Model process running.",
    )


def terminate_process_group(pid: int, pgid: int) -> bool:
    target_pgid = pgid or pid
    if target_pgid <= 0:
        return False
    try:
        os.killpg(target_pgid, signal.SIGTERM)
    except ProcessLookupError:
        return True
    except OSError:
        try:
            os.kill(pid, signal.SIGTERM)
        except ProcessLookupError:
            return True
        except OSError:
            return False
    for _ in range(12):
        if not pid_alive(pid):
            return True
        time.sleep(0.1)
    try:
        os.killpg(target_pgid, signal.SIGKILL)
    except ProcessLookupError:
        return True
    except OSError:
        try:
            os.kill(pid, signal.SIGKILL)
        except ProcessLookupError:
            return True
        except OSError:
            return False
    return not pid_alive(pid)


def launch_prompt_worker(
    prompt: str,
    started_at: int,
    speed: str,
    detail: int,
    job_budget: str,
    timeout_seconds: int,
    attachments: list[dict[str, Any]],
    runtime: str,
    model: str,
    relay_callback: dict[str, Any] | None = None,
    service_tier: str = "",
    optimization_mode: str = "",
) -> None:
    global ACTIVE_PROMPT_THREAD
    thread = threading.Thread(
        target=_prompt_worker,
        args=(
            prompt,
            started_at,
            normalize_response_speed(speed),
            normalize_response_detail(detail),
            normalize_job_budget(job_budget),
            normalize_job_timeout_seconds(timeout_seconds, job_budget),
            normalize_attachments(attachments),
            normalize_runtime(runtime),
            normalize_runtime_model(runtime, model),
            normalize_relay_callback(relay_callback),
            normalize_service_tier(service_tier),
            normalize_optimization_mode(optimization_mode),
        ),
        daemon=True,
    )
    ACTIVE_PROMPT_THREAD = thread
    thread.start()


def queue_prompt(
    prompt: str,
    speed: str,
    detail: int,
    job_budget: str,
    attachments: list[dict[str, Any]],
    runtime: str,
    model: str,
    relay_callback: dict[str, Any] | None = None,
    service_tier: str = "",
    interlace_mode: str = "",
    optimization_mode: str = "",
    cost_route: dict[str, Any] | None = None,
) -> dict[str, Any]:
    duplicate_queue_position = 0
    duplicate_queue_state = ""
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        normalized_relay = normalize_relay_callback(relay_callback)
        source = normalize_queue_source("", normalized_relay, prompt)
        position = len(queue) + 1
        normalized_attachments = normalize_attachments(attachments)
        normalized_service_tier = normalize_service_tier(service_tier)
        normalized_budget = normalize_job_budget(job_budget)
        normalized_optimization_mode = normalize_optimization_mode(optimization_mode)
        normalized_runtime = normalize_runtime(runtime)
        normalized_model = normalize_runtime_model(normalized_runtime, model)
        normalized_cost_route = dict(cost_route or {})
        normalized_interlace_mode = normalize_queue_interlace_mode(interlace_mode)
        duplicate_queue_state, duplicate_queue_position = (
            prompt_already_running_or_queued(
                meta,
                prompt=prompt,
                attachments=normalized_attachments,
                source=source,
            )
            if source == "operator"
            else ("", 0)
        )
        if duplicate_queue_state:
            if duplicate_queue_state == "running":
                detail_text = (
                    "Prompt is already running; duplicate submit was not queued."
                )
            else:
                detail_text = (
                    "Prompt is already queued"
                    f" at position {duplicate_queue_position}; duplicate submit was ignored."
                )
            meta["last_action"] = "dedupe-prompt"
            meta["last_action_at"] = now_ts()
            meta["last_action_detail"] = detail_text
            meta["status_message"] = detail_text
            save_status_meta(meta)
        else:
            checkpoint_policy = queue_checkpoint_policy_for_interlace(
                normalized_interlace_mode
            )
            timeout_seconds = job_budget_timeout_seconds(normalized_budget)
            attachment_phrase = attachment_count_phrase(normalized_attachments)
            attachment_suffix = (
                f" with {attachment_phrase}" if attachment_phrase else ""
            )
            queued_at = now_ts()
            item = {
                "id": queue_item_id(prompt, queued_at, source),
                "prompt": prompt,
                "queued_at": queued_at,
                "speed": normalize_response_speed(speed),
                "detail": normalize_response_detail(detail),
                "service_tier": normalized_service_tier,
                "job_budget": normalized_budget,
                "optimization_mode": normalized_optimization_mode,
                "runtime": normalized_runtime,
                "model": normalized_model,
                "timeout_seconds": timeout_seconds,
                "attachments": normalized_attachments,
                "source": source,
                "cost_route": normalized_cost_route,
                "interlace_mode": normalized_interlace_mode,
                "checkpoint_policy": checkpoint_policy,
            }
            if normalized_relay:
                item["relay_callback"] = normalized_relay
            queue.append(item)
            meta["selected_runtime"] = normalized_runtime
            meta["selected_model"] = normalized_model
            meta["queued_prompts"] = queue
            meta["queue_interlace_mode"] = normalized_interlace_mode
            meta["queue_checkpoint_policy"] = checkpoint_policy
            meta["queue_checkpoint_state"] = (
                "waiting" if source == "operator" else "waiting-nonoperator"
            )
            operator_queue_ack = queue_operator_plan_detail(
                queue,
                interlace_mode=normalized_interlace_mode,
            )
            meta["queue_checkpoint_detail"] = (
                operator_queue_ack
                if source == "operator"
                else "Queued non-operator work waits for the current turn."
            )
            meta["last_action"] = "queue-prompt"
            meta["last_action_at"] = now_ts()
            if source == "operator":
                queue_mode = (
                    "in interrupt mode after the next safe checkpoint, with acknowledgement"
                    if normalized_interlace_mode == "interrupt"
                    else "in queue mode after the current reply finishes"
                )
            else:
                queue_mode = "after the current web reply"
            ack_prefix = f"{operator_queue_ack} " if source == "operator" else ""
            meta["last_action_detail"] = (
                f"{ack_prefix}Queued prompt{attachment_suffix} at position {position}. "
                f"It will run {queue_mode}."
            )
            meta["status_message"] = (
                f"{ack_prefix}Queued prompt{attachment_suffix} at position {position}. "
                f"Current web reply is still running; queued {queue_mode}."
            )
            save_status_meta(meta)
    if duplicate_queue_state:
        append_audit_event(
            event_type="chat.deduped",
            summary="Ignored a duplicate operator prompt from the web TUI.",
            detail=(
                "Already running."
                if duplicate_queue_state == "running"
                else f"Already queued at position {duplicate_queue_position}."
            ),
            severity="info",
            actor_type="operator",
            thread_id=read_text(THREAD_ID_PATH),
            payload={
                "prompt_preview": summarize_text(prompt, 240),
                "duplicate_state": duplicate_queue_state,
                "queue_position": duplicate_queue_position,
                "source": source,
            },
        )
        snapshot = current_snapshot()
        snapshot["deduplicated_prompt"] = True
        return snapshot
    append_audit_event(
        event_type="chat.queued",
        summary="Queued a follow-up prompt in the web TUI.",
        detail=summarize_text(prompt, 180),
        severity="info",
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "prompt_preview": summarize_text(prompt, 240),
            "speed": normalize_response_speed(speed),
            "detail": normalize_response_detail(detail),
            "service_tier": normalized_service_tier,
            "job_budget": normalized_budget,
            "optimization_mode": normalized_optimization_mode,
            "runtime": normalized_runtime,
            "model": normalized_model,
            "timeout_seconds": timeout_seconds,
            "attachment_count": len(attachments),
            "attachment_summary": attachment_phrase,
            "queue_position": position,
            "source": source,
            "interlace_mode": normalized_interlace_mode,
            "checkpoint_policy": checkpoint_policy,
        },
    )
    return current_snapshot()


WAITING_RESPONSE_SENTINELS = {
    "",
    "[waiting for reply]",
    "[no response yet]",
    "[no response returned]",
}


def completed_response_available(response_text: str, error_text: str = "") -> bool:
    response = str(response_text or "").strip()
    if str(error_text or "").strip():
        return False
    return response.lower() not in WAITING_RESPONSE_SENTINELS


def recover_stale_prompt_state() -> None:
    if prompt_runtime_alive():
        with STATUS_LOCK:
            meta = load_status_meta()
            last_prompt = read_text(LAST_PROMPT_PATH).strip()
            last_response = read_text(LAST_RESPONSE_PATH).strip()
            if (
                not meta.get("pending")
                and last_prompt
                and last_response == "[waiting for reply]"
            ):
                meta.update(
                    {
                        "pending": True,
                        "state": "running",
                        "status_message": f"{AGENT_NAME} is working.",
                        "running_prompt": last_prompt,
                        "running_attachments": normalize_attachments(
                            meta.get("running_attachments")
                        ),
                        "last_started_at": int(meta.get("last_started_at") or now_ts()),
                    }
                )
                save_status_meta(meta)
        return
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        running_prompt = str(meta.get("running_prompt") or "").strip()
        last_response = read_text(LAST_RESPONSE_PATH).strip()
        last_error = read_text(LAST_ERROR_PATH).strip()
        observed_at = now_ts()
        recovered_queue = any(queue_item_is_recovered(item) for item in queue)
        if meta.get("pending") and running_prompt:
            if completed_response_available(last_response, last_error):
                write_text(LAST_PROMPT_PATH, running_prompt)
                meta.update(
                    {
                        "pending": False,
                        "state": "ok",
                        "status_message": "Web prompt completed.",
                        "running_prompt": "",
                        "running_attachments": [],
                        "queued_prompts": queue,
                        "recovered_after_restart": recovered_queue,
                        "stale_queue": recovered_queue,
                        "active_child_pid": 0,
                        "active_child_pgid": 0,
                        "active_child_started_at": 0,
                        "last_finished_at": observed_at,
                    }
                )
                save_status_meta(meta)
                return
            abandoned_message = "Web prompt was abandoned after restart; no running model process was found."
            write_text(LAST_PROMPT_PATH, running_prompt)
            write_last_response(abandoned_message)
            write_text(LAST_ERROR_PATH, abandoned_message)
            meta.update(
                {
                    "pending": False,
                    "state": "error",
                    "status_message": abandoned_message,
                    "running_prompt": "",
                    "running_attachments": [],
                    "queued_prompts": queue,
                    "recovered_after_restart": recovered_queue,
                    "stale_queue": recovered_queue,
                    "active_child_pid": 0,
                    "active_child_pgid": 0,
                    "active_child_started_at": 0,
                    "last_finished_at": observed_at,
                }
            )
            save_status_meta(meta)
            return
        if not meta.get("pending") and not queue:
            if (
                meta.get("queued_prompts")
                or meta.get("recovered_after_restart")
                or meta.get("stale_queue")
                or str(meta.get("state") or "").strip().lower() == "recovered"
            ):
                meta.update(
                    {
                        "pending": False,
                        "state": "ok",
                        "status_message": "Ready.",
                        "running_prompt": "",
                        "running_attachments": [],
                        "queued_prompts": [],
                        "recovered_after_restart": False,
                        "stale_queue": False,
                        "active_child_pid": 0,
                        "active_child_pgid": 0,
                        "active_child_started_at": 0,
                    }
                )
                save_status_meta(meta)
            return
        if not recovered_queue:
            if (
                meta.get("pending")
                or meta.get("recovered_after_restart")
                or meta.get("stale_queue")
                or str(meta.get("state") or "").strip().lower() == "recovered"
            ):
                meta.update(
                    {
                        "pending": False,
                        "state": "ok",
                        "status_message": "Queued work is waiting.",
                        "running_prompt": "",
                        "running_attachments": [],
                        "queued_prompts": queue,
                        "recovered_after_restart": False,
                        "stale_queue": False,
                        "active_child_pid": 0,
                        "active_child_pgid": 0,
                        "active_child_started_at": 0,
                    }
                )
                save_status_meta(meta)
            return
        meta.update(
            {
                "pending": False,
                "state": "recovered",
                "status_message": "Recovered queued work after restart. Review the queue before resuming.",
                "running_prompt": "",
                "running_attachments": [],
                "queued_prompts": queue,
                "recovered_after_restart": True,
                "stale_queue": True,
                "active_child_pid": 0,
                "active_child_pgid": 0,
                "active_child_started_at": 0,
            }
        )
        meta, _ = prune_stale_recovered_queue_items(meta)
        save_status_meta(meta)


def start_next_queued_prompt() -> (
    tuple[
        str,
        int,
        str,
        int,
        str,
        str,
        int,
        list[dict[str, Any]],
        str,
        str,
        dict[str, Any],
        str,
    ]
    | None
):
    with STATUS_LOCK:
        meta = load_status_meta()
        meta, _ = prune_stale_recovered_queue_items(meta)
        queue = normalize_queue(meta.get("queued_prompts"))
        if not queue:
            meta["queued_prompts"] = []
            meta["queue_checkpoint_state"] = "idle"
            meta["queue_checkpoint_event"] = ""
            meta["queue_checkpoint_detail"] = ""
            meta["queue_handoff_state"] = "idle"
            meta["queue_handoff_detail"] = ""
            meta["queue_handoff_prompt"] = ""
            meta["queue_handoff_interrupted_prompt"] = ""
            meta["queue_handoff_checkpoint_event"] = ""
            meta["queue_handoff_checkpoint_tool"] = ""
            meta["queue_handoff_started_at"] = 0
            save_status_meta(meta)
            return None
        run_index = next(
            (
                index
                for index, candidate in enumerate(queue)
                if not queue_item_is_recovered(candidate)
            ),
            -1,
        )
        if run_index < 0:
            meta["queued_prompts"] = queue
            has_recovered = any(queue_item_is_recovered(item) for item in queue)
            meta["state"] = "recovered" if has_recovered else "ok"
            meta["status_message"] = (
                "Recovered queued work after restart. Review the queue before resuming."
                if has_recovered
                else "Queued work is waiting."
            )
            meta["stale_queue"] = has_recovered
            meta["recovered_after_restart"] = meta["stale_queue"]
            save_status_meta(meta)
            return None
        guard = host_pressure_guard_snapshot()
        if host_pressure_guard_blocks_new_work(guard):
            detail = host_pressure_guard_message(guard)
            meta["state"] = "pressure-blocked"
            meta["status_message"] = detail
            meta["queue_checkpoint_state"] = "pressure-blocked"
            meta["queue_checkpoint_detail"] = f"{detail} Queued work remains waiting."
            meta["last_action"] = "pressure-guard-block"
            meta["last_action_at"] = now_ts()
            meta["last_action_detail"] = detail
            save_status_meta(meta)
            return None
        item = queue.pop(run_index)
        started_at = now_ts()
        prompt = item["prompt"]
        speed = normalize_response_speed(item.get("speed"))
        detail = normalize_response_detail(item.get("detail"))
        service_tier = normalize_service_tier(item.get("service_tier"))
        job_budget = normalize_job_budget(item.get("job_budget"))
        optimization_mode = normalize_optimization_mode(item.get("optimization_mode"))
        runtime = normalize_runtime(item.get("runtime"))
        model = normalize_runtime_model(runtime, item.get("model"))
        timeout_seconds = normalize_job_timeout_seconds(
            item.get("timeout_seconds"), job_budget
        )
        attachments = normalize_attachments(item.get("attachments"))
        relay_callback = normalize_relay_callback(item.get("relay_callback"))
        cost_route = (
            dict(item.get("cost_route"))
            if isinstance(item.get("cost_route"), dict)
            else {}
        )
        item_interlace_mode = normalize_queue_interlace_mode(item.get("interlace_mode"))
        handoff_ready = (
            item_interlace_mode == "interrupt"
            and str(meta.get("queue_handoff_state") or "").strip().lower()
            in {"checkpoint-ready", "interrupting"}
            and str(meta.get("queue_handoff_prompt") or "").strip() == prompt
        )
        handoff_detail = str(meta.get("queue_handoff_detail") or "").strip()
        handoff_interrupted_prompt = str(
            meta.get("queue_handoff_interrupted_prompt") or ""
        ).strip()
        handoff_checkpoint_event = str(
            meta.get("queue_handoff_checkpoint_event") or ""
        ).strip()
        handoff_checkpoint_tool = str(
            meta.get("queue_handoff_checkpoint_tool") or ""
        ).strip()
        handoff_status = (
            "Interrupt handoff is running. The previous reply was paused at a "
            "safe checkpoint; the queued prompt is now active."
            if handoff_ready
            else f"{AGENT_NAME} is working."
        )
        write_text(LAST_PROMPT_PATH, prompt)
        write_last_response(working_response_text(prompt))
        write_text(LAST_ERROR_PATH, "")
        meta.update(
            {
                "pending": True,
                "state": "running",
                "status_message": handoff_status,
                "running_prompt": prompt,
                "running_attachments": attachments,
                "running_speed": speed,
                "running_detail": detail,
                "running_service_tier": service_tier,
                "running_job_budget": job_budget,
                "running_optimization_mode": optimization_mode,
                "running_runtime": runtime,
                "running_model": model,
                "running_timeout_seconds": timeout_seconds,
                "running_cost_route": cost_route,
                "last_started_at": started_at,
                "queued_prompts": queue,
                "queue_checkpoint_state": "idle" if not queue else "waiting",
                "queue_checkpoint_event": "",
                "queue_checkpoint_detail": "",
                "queue_handoff_state": "running" if handoff_ready else "idle",
                "queue_handoff_detail": handoff_detail if handoff_ready else "",
                "queue_handoff_prompt": prompt if handoff_ready else "",
                "queue_handoff_interrupted_prompt": handoff_interrupted_prompt
                if handoff_ready
                else "",
                "queue_handoff_checkpoint_event": handoff_checkpoint_event
                if handoff_ready
                else "",
                "queue_handoff_checkpoint_tool": handoff_checkpoint_tool
                if handoff_ready
                else "",
                "queue_handoff_started_at": started_at if handoff_ready else 0,
                "recovered_after_restart": False,
                "stale_queue": False,
                "cancel_requested_at": 0,
            }
        )
        save_status_meta(meta)
    if handoff_ready:
        append_audit_event(
            event_type="queue.handoff-started",
            summary="Interrupt handoff started after a safe checkpoint.",
            detail=handoff_status,
            severity="info",
            actor_type="system",
            payload={
                "prompt_preview": summarize_text(prompt, 240),
                "interrupted_prompt_preview": summarize_text(
                    handoff_interrupted_prompt, 240
                ),
                "checkpoint_event": handoff_checkpoint_event,
                "checkpoint_tool": handoff_checkpoint_tool,
                "optimization_mode": optimization_mode,
            },
            event_at=started_at,
        )
    return (
        prompt,
        started_at,
        speed,
        detail,
        service_tier,
        job_budget,
        timeout_seconds,
        attachments,
        runtime,
        model,
        relay_callback,
        optimization_mode,
    )


def record_action(action: str, detail: str) -> None:
    update_status_meta(
        last_action=action,
        last_action_at=now_ts(),
        last_action_detail=detail,
        status_message=detail,
    )
    severity = (
        "error"
        if "error" in action
        else "warn"
        if action in {"tmux-interrupt", "tmux-restart"}
        else "info"
    )
    append_audit_event(
        event_type=action,
        summary=detail,
        detail=detail,
        severity=severity,
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={"action": action},
    )


def session_exists() -> bool:
    proc = run(tmux_cmd("has-session", "-t", SESSION))
    return proc.returncode == 0


def ensure_session() -> bool:
    if session_exists():
        return True
    proc = run(["systemctl", "start", CODEX_SERVICE])
    if proc.returncode != 0:
        return False
    for _ in range(20):
        if session_exists():
            return True
        time.sleep(0.5)
    return False


def capture_pane() -> str:
    if not session_exists():
        return "[session unavailable]"
    proc = run(
        tmux_cmd(
            "capture-pane",
            "-p",
            "-t",
            f"{SESSION}:0.0",
            "-S",
            f"-{MAX_PANE_LINES}",
        )
    )
    text = proc.stdout or proc.stderr
    return truncate_block(text) or "[pane empty]"


def send_text(text: str) -> None:
    if not ensure_session():
        raise RuntimeError(f"{WORKER_SESSION_LABEL.capitalize()} could not be started.")
    buffer_name = f"{SESSION}-web-{int(time.time() * 1000)}"
    try:
        run(
            tmux_cmd("load-buffer", "-b", buffer_name, "-"), input_text=text, check=True
        )
        run(
            tmux_cmd("paste-buffer", "-d", "-b", buffer_name, "-t", f"{SESSION}:0.0"),
            check=True,
        )
        run(tmux_cmd("send-keys", "-t", f"{SESSION}:0.0", "Enter"), check=True)
    finally:
        run(tmux_cmd("delete-buffer", "-b", buffer_name))
    record_action("tmux-send", f"Sent raw text to tmux: {summarize_text(text, 140)}")


def send_keys(*keys: str) -> None:
    if not ensure_session():
        raise RuntimeError(f"{WORKER_SESSION_LABEL.capitalize()} could not be started.")
    run(tmux_cmd("send-keys", "-t", f"{SESSION}:0.0", *keys), check=True)


def _run_post_auth_self_check(*, timeout: float = 10.0) -> tuple[bool, str]:
    if not ensure_session():
        return (
            False,
            f"Sign-in delivered, but the {WORKER_SESSION_LABEL} is unavailable.",
        )

    deadline = time.time() + max(timeout, 1.0)
    advanced_steps: list[str] = []
    latest = capture_pane()

    while time.time() < deadline:
        latest = capture_pane()
        if _contains_signed_in_banner(latest):
            send_keys("Enter")
            advanced_steps.append("accepted the signed-in banner")
            time.sleep(0.35)
            continue
        if _contains_trust_directory_prompt(latest):
            send_keys("1", "Enter")
            advanced_steps.append("trusted the working directory")
            time.sleep(0.35)
            continue
        if _contains_active_update_interstitial(latest):
            send_keys("Enter")
            advanced_steps.append("cleared the update interstitial")
            time.sleep(0.35)
            continue
        auth_state = _auth_state_from_console(latest, read_text(LAST_ERROR_PATH))
        if auth_state.get("required"):
            time.sleep(0.35)
            continue
        if _contains_codex_ready_prompt(latest):
            detail = f"{AGENT_NAME} is ready. Self-check passed."
            if advanced_steps:
                detail = f"{detail} Auto-finished: {', '.join(advanced_steps)}."
            return True, detail
        time.sleep(0.35)

    detail = "Sign-in delivered, but readiness is still settling."
    if advanced_steps:
        detail = f"{detail} Auto-finished: {', '.join(advanced_steps)}."
    return False, detail


def send_interrupt() -> None:
    if ensure_session():
        run(tmux_cmd("send-keys", "-t", f"{SESSION}:0.0", "C-c"), check=True)
    record_action("tmux-interrupt", "Sent Ctrl+C to the interactive tmux session.")


def clear_queued_prompts(reason: str = "Cleared queued web prompts.") -> dict[str, Any]:
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        cleared = len(queue)
        meta["queued_prompts"] = []
        meta["stale_queue"] = False
        if not meta.get("pending"):
            meta["state"] = "ok"
            meta["recovered_after_restart"] = False
            meta["running_prompt"] = ""
            meta["running_attachments"] = []
        meta["last_action"] = "queue-clear"
        meta["last_action_at"] = now_ts()
        meta["last_action_detail"] = reason
        meta["status_message"] = reason
        save_status_meta(meta)
    append_audit_event(
        event_type="queue.cleared",
        summary=reason,
        detail=f"Cleared {cleared} queued prompt{'s' if cleared != 1 else ''}.",
        severity="warn",
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={"cleared": cleared},
    )
    return current_snapshot()


def delete_queued_prompt(item_id: str = "", index: int | None = None) -> dict[str, Any]:
    clean_id = str(item_id or "").strip()
    removed: dict[str, Any] | None = None
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        remove_index = -1
        if clean_id:
            for candidate_index, item in enumerate(queue):
                if str(item.get("id") or "") == clean_id:
                    remove_index = candidate_index
                    break
        elif index is not None and 0 <= index < len(queue):
            remove_index = index
        if remove_index >= 0:
            removed = queue.pop(remove_index)
            meta["queued_prompts"] = queue
            if not queue:
                meta["stale_queue"] = False
                meta["recovered_after_restart"] = False
                if not meta.get("pending"):
                    meta["state"] = "ok"
                    meta["status_message"] = "Ready."
                    meta["running_prompt"] = ""
                    meta["running_attachments"] = []
            meta["last_action_detail"] = (
                f"Removed queued prompt: {summarize_text(removed.get('prompt') or '', 120)}"
            )
        else:
            meta["last_action_detail"] = "Queued prompt was not found."
        meta["last_action"] = "queue-delete"
        meta["last_action_at"] = now_ts()
        if removed is not None:
            meta["status_message"] = meta["last_action_detail"]
        save_status_meta(meta)
    append_audit_event(
        event_type="queue.deleted",
        summary="Removed queued prompt." if removed else "Queued prompt not found.",
        detail=summarize_text((removed or {}).get("prompt") or clean_id, 220),
        severity="warn" if removed else "info",
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "id": clean_id,
            "index": index,
            "removed": bool(removed),
            "prompt_preview": summarize_text((removed or {}).get("prompt") or "", 240),
        },
    )
    return current_snapshot()


def promote_latest_operator_prompt() -> dict[str, Any]:
    item: dict[str, Any] | None = None
    return_snapshot = False
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        if len(queue) < 2:
            meta["last_action"] = "queue-promote"
            meta["last_action_at"] = now_ts()
            meta["last_action_detail"] = (
                "Queue promotion skipped; fewer than two queued prompts."
            )
            save_status_meta(meta)
            return_snapshot = True
        else:
            selected_index = -1
            for index in range(len(queue) - 1, -1, -1):
                if queue[index].get("source") == "operator":
                    selected_index = index
                    break
            if selected_index <= 0:
                meta["last_action"] = "queue-promote"
                meta["last_action_at"] = now_ts()
                meta["last_action_detail"] = "Latest operator prompt is already next."
                save_status_meta(meta)
                item = None
                return_snapshot = True
            else:
                item = queue.pop(selected_index)
                queue.insert(0, item)
                meta["queued_prompts"] = queue
                meta["last_action"] = "queue-promote"
                meta["last_action_at"] = now_ts()
                meta["last_action_detail"] = (
                    "Promoted the latest operator prompt to the front of the queue."
                )
                meta["status_message"] = (
                    "Latest operator prompt will run next after the current web reply."
                )
                save_status_meta(meta)
    if return_snapshot:
        return current_snapshot()
    append_audit_event(
        event_type="queue.promoted",
        summary="Promoted latest operator prompt.",
        detail=summarize_text((item or {}).get("prompt") or "", 220),
        severity="warn",
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "prompt_preview": summarize_text((item or {}).get("prompt") or "", 240)
        },
    )
    return current_snapshot()


def upgrade_queued_prompt_to_interrupt(
    item_id: str = "", index: int | None = None
) -> dict[str, Any]:
    clean_id = str(item_id or "").strip()
    item: dict[str, Any] | None = None
    selected_index = -1
    reason = "Queued prompt was not found."
    with STATUS_LOCK:
        meta = load_status_meta()
        queue = normalize_queue(meta.get("queued_prompts"))
        if clean_id:
            for candidate_index, candidate in enumerate(queue):
                if str(candidate.get("id") or "") == clean_id:
                    selected_index = candidate_index
                    break
        elif index is not None and 0 <= index < len(queue):
            selected_index = index
        else:
            for candidate_index in range(len(queue) - 1, -1, -1):
                candidate = queue[candidate_index]
                if str(candidate.get("source") or "").strip().lower() == "operator":
                    selected_index = candidate_index
                    break
        if selected_index >= 0:
            candidate = queue[selected_index]
            if queue_item_is_recovered(candidate):
                reason = "Recovered queue items must be reviewed before interruption."
            elif str(candidate.get("source") or "").strip().lower() != "operator":
                reason = "Only operator queued prompts can be upgraded to interruption."
            else:
                item = queue.pop(selected_index)
                item["interlace_mode"] = "interrupt"
                item["checkpoint_policy"] = "interrupt"
                queue.insert(0, item)
                detail = queue_operator_plan_detail(queue, interlace_mode="interrupt")
                meta.update(
                    {
                        "queued_prompts": queue,
                        "queue_interlace_mode": "interrupt",
                        "queue_checkpoint_policy": "interrupt",
                        "queue_checkpoint_state": "waiting"
                        if meta.get("pending")
                        else "ready",
                        "queue_checkpoint_detail": detail,
                        "queue_handoff_state": "idle",
                        "queue_handoff_detail": "",
                        "queue_handoff_prompt": "",
                        "queue_handoff_interrupted_prompt": "",
                        "queue_handoff_checkpoint_event": "",
                        "queue_handoff_checkpoint_tool": "",
                        "queue_handoff_started_at": 0,
                        "last_action": "queue-upgrade-interrupt",
                        "last_action_at": now_ts(),
                        "last_action_detail": (
                            "Upgraded queued operator prompt to safe-checkpoint interruption."
                        ),
                        "status_message": detail,
                    }
                )
        if item is None:
            meta["last_action"] = "queue-upgrade-interrupt"
            meta["last_action_at"] = now_ts()
            meta["last_action_detail"] = reason
            meta["status_message"] = reason
        save_status_meta(meta)
    append_audit_event(
        event_type="queue.interrupt-upgraded",
        summary=(
            "Upgraded queued prompt to interruption."
            if item
            else "Queued prompt interruption upgrade skipped."
        ),
        detail=summarize_text((item or {}).get("prompt") or reason, 220),
        severity="warn" if item else "info",
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "id": clean_id,
            "index": index,
            "upgraded": bool(item),
            "prompt_preview": summarize_text((item or {}).get("prompt") or "", 240),
        },
    )
    return current_snapshot()


def cancel_active_web_prompt(clear_queue: bool = False) -> dict[str, Any]:
    meta = update_status_meta(
        state="cancelling",
        status_message="Cancelling current web reply.",
        cancel_requested_at=now_ts(),
        last_action="web-cancel",
        last_action_at=now_ts(),
        last_action_detail="Cancelling current web reply.",
    )
    pid = _coerce_int(meta.get("active_child_pid"))
    pgid = _coerce_int(meta.get("active_child_pgid"))
    killed = terminate_process_group(pid, pgid) if pid else False
    if not pid or not killed:
        with ACTIVE_CODEX_LOCK:
            proc = ACTIVE_CODEX_PROC
        if proc is not None and proc.poll() is None:
            try:
                pgid = os.getpgid(proc.pid)
            except OSError:
                pgid = proc.pid
            killed = terminate_process_group(proc.pid, pgid)
            pid = proc.pid
    if clear_queue:
        with STATUS_LOCK:
            meta = load_status_meta()
            meta["queued_prompts"] = []
            meta["stale_queue"] = False
            save_status_meta(meta)
    if not killed and not prompt_runtime_alive():
        write_last_response(CANCELLED_WEB_REPLY_MESSAGE)
        write_text(LAST_ERROR_PATH, CANCELLED_WEB_REPLY_MESSAGE)
        update_status_meta(
            pending=False,
            state="cancelled",
            status_message="Web prompt cancelled.",
            running_prompt="",
            running_attachments=[],
            active_child_pid=0,
            active_child_pgid=0,
            active_child_started_at=0,
            cancel_requested_at=0,
        )
    append_audit_event(
        event_type="chat.cancel-requested",
        summary="Cancel requested for current web reply.",
        detail=(
            "Terminated active codex exec process."
            if killed
            else "No active codex exec process was found."
        ),
        severity="warn",
        actor_type="operator",
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "pid": pid,
            "pgid": pgid,
            "killed": killed,
            "cleared_queue": clear_queue,
        },
    )
    return current_snapshot()


def restart_session() -> None:
    handoff = write_restart_handoff(
        "tmux",
        f"Operator requested restart of {AGENT_NAME} tmux {WORKER_SESSION_LABEL}.",
    )
    run(tmux_cmd("kill-session", "-t", SESSION))
    run(["systemctl", "restart", CODEX_SERVICE])
    ensure_session()
    record_action(
        "tmux-restart",
        (
            f"Restarted the interactive {AGENT_NAME} tmux {WORKER_SESSION_LABEL}. "
            f"{handoff['summary']}"
        ),
    )


def defer_web_only_restart_until_idle(
    *,
    actor_ip: str = "",
    readiness: dict[str, Any] | None = None,
    delay_seconds: float = 0.45,
) -> dict[str, Any]:
    global WEB_RESTART_DEFERRED_AT

    current = readiness if isinstance(readiness, dict) else restart_readiness_snapshot()
    now = now_ts()
    with WEB_RESTART_LOCK:
        if WEB_RESTART_DEFERRED_AT and now - WEB_RESTART_DEFERRED_AT < 30:
            current.update(
                {
                    "web_restart_deferred": True,
                    "web_restart_service": WEB_SERVICE,
                }
            )
            return {
                "ok": True,
                "deferred": True,
                "already_deferred": True,
                "service": WEB_SERVICE,
                "snapshot": current,
            }
        WEB_RESTART_DEFERRED_AT = now

    handoff = write_restart_handoff(
        "web",
        f"Operator requested deferred web-only restart of {AGENT_NAME} TUI.",
    )
    update_status_meta(
        last_action="web-restart-deferred",
        last_action_at=now,
        last_action_detail=(
            f"Web-only restart queued for {WEB_SERVICE}; waiting for idle."
        ),
        status_message="Web-only restart queued until idle.",
    )
    append_audit_event(
        event_type="web.restart.deferred",
        summary="Web-only TUI restart deferred until idle.",
        detail=(
            f"Queued guarded restart of {WEB_SERVICE}; it will run after the "
            "active prompt and queue clear."
        ),
        severity="warn",
        actor_type="operator",
        actor_ip=actor_ip,
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "service": WEB_SERVICE,
            "codex_service": CODEX_SERVICE,
            "handoff_id": handoff.get("id"),
            "handoff_summary": handoff.get("summary"),
        },
    )

    def _wait_for_idle_restart() -> None:
        global WEB_RESTART_DEFERRED_AT

        deadline = time.monotonic() + WEB_RESTART_DEFERRED_MAX_WAIT_SECONDS
        while time.monotonic() < deadline:
            time.sleep(WEB_RESTART_DEFERRED_POLL_SECONDS)
            probe = restart_readiness_snapshot()
            if not bool(probe.get("web_restart_required")):
                with WEB_RESTART_LOCK:
                    WEB_RESTART_DEFERRED_AT = 0
                append_audit_event(
                    event_type="web.restart.deferred.cleared",
                    summary="Deferred web restart cleared.",
                    detail="No staged web restart was required when the idle check ran.",
                    severity="info",
                    actor_type="system",
                    thread_id=read_text(THREAD_ID_PATH),
                    payload={"service": WEB_SERVICE},
                )
                return
            if not bool(probe.get("busy")):
                with WEB_RESTART_LOCK:
                    WEB_RESTART_DEFERRED_AT = 0
                schedule_web_only_restart(
                    actor_ip=actor_ip,
                    delay_seconds=delay_seconds,
                )
                return

        with WEB_RESTART_LOCK:
            WEB_RESTART_DEFERRED_AT = 0
        append_audit_event(
            event_type="web.restart.deferred.expired",
            summary="Deferred web restart expired while waiting for idle.",
            detail=(
                f"{WEB_SERVICE} stayed busy for "
                f"{WEB_RESTART_DEFERRED_MAX_WAIT_SECONDS}s."
            ),
            severity="warn",
            actor_type="system",
            thread_id=read_text(THREAD_ID_PATH),
            payload={"service": WEB_SERVICE},
        )

    threading.Thread(
        target=_wait_for_idle_restart,
        name=f"{SESSION}-web-only-restart-deferred",
        daemon=True,
    ).start()

    current.update(
        {
            "web_restart_deferred": True,
            "web_restart_service": WEB_SERVICE,
            "restart_handoff": handoff,
            "context_handoff": handoff,
        }
    )
    return {
        "ok": True,
        "deferred": True,
        "already_deferred": False,
        "service": WEB_SERVICE,
        "handoff": handoff,
        "snapshot": current,
    }


def schedule_web_only_restart(
    *,
    actor_ip: str = "",
    delay_seconds: float = 0.45,
) -> dict[str, Any]:
    global WEB_RESTART_SCHEDULED_AT

    readiness = restart_readiness_snapshot()
    if WEB_SERVICE.strip() == CODEX_SERVICE.strip():
        return {
            "ok": False,
            "error": (
                "web-only restart is not available because the web service name "
                f"matches the {WORKER_SESSION_LABEL} service"
            ),
            "snapshot": readiness,
        }
    if not bool(readiness.get("web_restart_required")):
        return {
            "ok": False,
            "error": "no staged web restart is currently required",
            "snapshot": readiness,
        }
    if bool(readiness.get("busy")):
        return defer_web_only_restart_until_idle(
            actor_ip=actor_ip,
            readiness=readiness,
            delay_seconds=delay_seconds,
        )

    now = now_ts()
    with WEB_RESTART_LOCK:
        if WEB_RESTART_SCHEDULED_AT and now - WEB_RESTART_SCHEDULED_AT < 30:
            return {
                "ok": True,
                "already_scheduled": True,
                "service": WEB_SERVICE,
                "snapshot": readiness,
            }
        WEB_RESTART_SCHEDULED_AT = now

    handoff = write_restart_handoff(
        "web", f"Operator requested web-only restart of {AGENT_NAME} TUI."
    )
    update_status_meta(
        last_action="web-restart",
        last_action_at=now,
        last_action_detail=f"Web-only restart scheduled for {WEB_SERVICE}.",
        status_message="Web-only restart scheduled.",
    )
    append_audit_event(
        event_type="web.restart.requested",
        summary="Web-only TUI restart requested.",
        detail=f"Scheduled guarded restart of {WEB_SERVICE}; {WORKER_SESSION_LABEL} service was not restarted.",
        severity="warn",
        actor_type="operator",
        actor_ip=actor_ip,
        thread_id=read_text(THREAD_ID_PATH),
        payload={
            "service": WEB_SERVICE,
            "codex_service": CODEX_SERVICE,
            "handoff_id": handoff.get("id"),
            "handoff_summary": handoff.get("summary"),
        },
    )

    def _restart_web_service() -> None:
        time.sleep(max(0.05, float(delay_seconds)))
        proc = run(["systemctl", "restart", WEB_SERVICE])
        if proc.returncode != 0:
            detail = (proc.stderr or proc.stdout or "").strip()
            update_status_meta(
                last_action="web-restart-failed",
                last_action_at=now_ts(),
                last_action_detail=f"Web-only restart failed for {WEB_SERVICE}.",
                status_message="Web-only restart failed.",
            )
            append_audit_event(
                event_type="web.restart.failed",
                summary="Web-only TUI restart failed.",
                detail=detail
                or f"systemctl restart {WEB_SERVICE} returned {proc.returncode}.",
                severity="alert",
                actor_type="system",
                thread_id=read_text(THREAD_ID_PATH),
                payload={
                    "service": WEB_SERVICE,
                    "returncode": proc.returncode,
                    "stderr": proc.stderr,
                    "stdout": proc.stdout,
                },
            )

    threading.Thread(
        target=_restart_web_service,
        name=f"{SESSION}-web-only-restart",
        daemon=True,
    ).start()

    readiness.update(
        {
            "web_restart_scheduled": True,
            "web_restart_service": WEB_SERVICE,
            "restart_handoff": handoff,
            "context_handoff": handoff,
        }
    )
    return {
        "ok": True,
        "already_scheduled": False,
        "service": WEB_SERVICE,
        "handoff": handoff,
        "snapshot": readiness,
    }


def service_status(units: list[str]) -> list[tuple[str, str]]:
    results: list[tuple[str, str]] = []
    seen: set[str] = set()
    for unit in units:
        clean = unit.strip()
        if not clean or clean in seen:
            continue
        seen.add(clean)
        proc = run(["systemctl", "is-active", clean])
        value = (proc.stdout or proc.stderr).strip() or "unknown"
        results.append((clean, value))
    return results


def housebot_log_tail() -> str:
    proc = run(
        [
            "journalctl",
            "-u",
            AGENT_SERVICE_NAME,
            "-n",
            str(MAX_LOG_LINES),
            "--no-pager",
            "-o",
            "cat",
        ]
    )
    text = proc.stdout or proc.stderr
    return truncate_block(text) or "[no housebot journal output]"


def attachment_prompt_context(
    attachments: list[dict[str, Any]],
    *,
    savings_out: list[dict[str, Any]] | None = None,
) -> str:
    if not attachments:
        return ""
    lines = [
        "",
        "Staged material for this prompt:",
        "Treat these as supporting context. Do not default to summarizing staged material unless the operator asks for that explicitly.",
    ]
    for entry in normalize_attachments(attachments):
        token = entry["token"]
        path = entry["path"]
        summary = entry.get("summary") or build_attachment_summary(
            token=token,
            name=entry["name"],
            content_type=entry["content_type"],
            size=entry["size"],
            kind=entry["kind"],
            source=str(entry.get("source") or ""),
            line_count=int(entry.get("line_count") or 0),
            char_count=int(entry.get("char_count") or 0),
            url=str(entry.get("url") or ""),
        )
        lines.append(f"- {summary} · path: {path}")
        if entry["kind"] == "text":
            body = read_text(Path(path))
            if body:
                rendered_body, render_meta = attachment_text_prompt_body(body)
                if savings_out is not None:
                    savings_out.append(
                        {
                            **render_meta,
                            "token": token,
                            "name": entry["name"],
                            "path": path,
                        }
                    )
                content_label = (
                    "inline content"
                    if render_meta.get("mode") == "inline"
                    else "path-backed preview content"
                )
                lines.append(f"  [{token}] {content_label}:")
                for line in rendered_body.splitlines():
                    lines.append(f"    {line}")
            else:
                lines.append(
                    f"  [{token}] text content could not be read; inspect {path} directly."
                )
        else:
            lines.append(
                f"  [{token}] is available as a local file at {path}. Inspect it directly if useful."
            )
    return "\n".join(lines)


def build_prompt_with_attachments(
    prompt: str,
    detail: int,
    attachments: list[dict[str, Any]],
    job_budget: Any = "",
    timeout_seconds: Any = None,
    runtime: str = "",
    model: str = "",
    speed: Any = "",
    service_tier: Any = "",
    optimization_mode: Any = "",
) -> str:
    combined = prompt.strip()
    attachment_savings: list[dict[str, Any]] = []
    attachment_context = attachment_prompt_context(
        attachments, savings_out=attachment_savings
    )
    if attachment_context:
        combined = f"{combined}\n{attachment_context}".strip()
    drift_context = drift_assessment_prompt_context(
        assess_tui_drift(
            prompt,
            attachments=attachments,
            job_budget=job_budget,
            timeout_seconds=timeout_seconds,
            runtime=runtime or configured_runtime(),
            model=model or configured_chat_model(),
        )
    )
    if drift_context:
        combined = f"{combined}\n{drift_context}".strip()
    bbs_context = bbs_handoff_prompt_context()
    if bbs_context:
        combined = f"{combined}\n{bbs_context}".strip()
    preflight_context = context_preflight_prompt_context(
        combined,
        attachments=attachments,
        attachment_savings=attachment_savings,
        runtime=runtime or configured_runtime(),
        model=model or configured_chat_model(),
    )
    if preflight_context:
        combined = f"{combined}\n{preflight_context}".strip()
    return build_tuned_prompt(
        combined,
        detail,
        job_budget,
        timeout_seconds,
        speed,
        service_tier,
        optimization_mode,
    )


NO_LAST_AGENT_MESSAGE_RE = re.compile(
    r"^Warning: no last agent message; wrote empty content to .+$"
)
WEB_PROMPT_TIMED_OUT_PREFIX = "Web prompt timed out after "
RATE_LIMIT_ERROR_RE = re.compile(
    r"\b(?:429|too many requests|rate[-_\s]?limit(?:ed|s)?|"
    r"rate_limit(?:ed|_exceeded)?|throttl(?:e|ed|ing)|"
    r"ThrottlingException|TooManyRequestsException|"
    r"exceeded\s+on[-_\s]?demand\s+capacity|"
    r"on[-_\s]?demand\s+capacity|"
    r"capacity\s+(?:exceeded|unavailable))\b",
    re.IGNORECASE,
)
RETRY_AFTER_RE = re.compile(
    r"(?:retry[-_\s]?after|try again in|retry in)\D{0,24}(\d+(?:\.\d+)?)",
    re.IGNORECASE,
)


def web_prompt_timed_out_message(
    timeout_seconds: int, *, job_budget: Any = "", service_tier: Any = ""
) -> str:
    normalized_budget = normalize_job_budget(job_budget)
    target_seconds = job_budget_timeout_seconds(normalized_budget)
    timeout_label = prompt_duration_label(timeout_seconds)
    target_label = prompt_duration_label(target_seconds)
    tier_label = service_tier_label(normalize_service_tier(service_tier))
    parts = [
        f"{WEB_PROMPT_TIMED_OUT_PREFIX}{timeout_seconds} seconds and was terminated.",
        f"Target was {target_label}; hard guardrail was {timeout_label}.",
        f"Lane was {tier_label}.",
        "This protects cost, but it means the worker did not finish the requested slice.",
        "Use Proceed/Verify to resume with the saved context, or choose a longer budget/less constrained lane for slow provider work.",
    ]
    return " ".join(part for part in parts if part)


def is_rate_limit_error(text: Any) -> bool:
    return bool(RATE_LIMIT_ERROR_RE.search(str(text or "")))


def rate_limit_retry_after_seconds(text: Any) -> int:
    match = RETRY_AFTER_RE.search(str(text or ""))
    if not match:
        return 0
    try:
        return max(0, int(float(match.group(1))))
    except (TypeError, ValueError):
        return 0


def rate_limit_backoff_seconds(error_text: Any, attempt: int) -> int:
    explicit_retry = rate_limit_retry_after_seconds(error_text)
    if explicit_retry > 0:
        return int(min(WEB_PROMPT_RATE_LIMIT_MAX_BACKOFF_SECONDS, explicit_retry))
    exponent = max(0, int(attempt or 1) - 1)
    base = WEB_PROMPT_RATE_LIMIT_BASE_SECONDS * (2**exponent)
    # Classic exponential backoff with jitter. Keep jitter deterministic enough for
    # UI expectations while preventing fleet-wide retry stampedes.
    jitter = 0.75 + (secrets.randbelow(501) / 1000)
    return int(
        max(
            1,
            min(WEB_PROMPT_RATE_LIMIT_MAX_BACKOFF_SECONDS, round(base * jitter)),
        )
    )


def rate_limit_status_message(error_text: Any, attempt: int, delay_seconds: int) -> str:
    return (
        "Provider rate limit hit. "
        f"Backing off {format_duration_label(delay_seconds)} before retry "
        f"{max(1, int(attempt or 1)) + 1}/{WEB_PROMPT_RATE_LIMIT_MAX_ATTEMPTS}. "
        "No action needed unless you want to cancel or switch lane/model."
    )


def rate_limit_exhausted_message(error_text: Any, attempts: int) -> str:
    return (
        "Provider rate limit persisted after "
        f"{max(1, int(attempts or 1))} attempts. "
        "I stopped retrying so the TUI does not wedge. Try again later, switch "
        "lane/model, or cancel/reorder queued work."
    )


def strip_codex_empty_last_message_warning(text: str) -> str:
    lines = []
    for line in str(text or "").splitlines():
        if _is_codex_transient_stderr_noise(line):
            continue
        lines.append(line)
    return "\n".join(lines).strip()


def process_output_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="replace")
    return str(value)


def communicate_with_prompt_timeout(
    popen: subprocess.Popen[str],
    timeout_seconds: int | None = None,
    stdout_line_callback: Callable[[str], None] | None = None,
    deadline_warning_callback: Callable[[dict[str, Any]], None] | None = None,
    deadline_warning_checkpoints: list[dict[str, Any]] | None = None,
) -> tuple[str, str, bool]:
    timeout = max(
        0,
        normalize_job_timeout_seconds(timeout_seconds, DEFAULT_JOB_BUDGET)
        if timeout_seconds is not None
        else WEB_PROMPT_TIMEOUT_SECONDS,
    )
    stdout_stream = getattr(popen, "stdout", None)
    stderr_stream = getattr(popen, "stderr", None)
    can_stream = (
        stdout_line_callback is not None
        and stdout_stream is not None
        and stderr_stream is not None
        and hasattr(stdout_stream, "fileno")
        and hasattr(stderr_stream, "fileno")
    )
    if can_stream:
        stdout_parts: list[str] = []
        stderr_parts: list[str] = []
        started_monotonic = time.monotonic()
        deadline = started_monotonic + timeout if timeout > 0 else 0.0
        timed_out = False
        warning_checkpoints = list(deadline_warning_checkpoints or [])
        fired_warning_indexes: set[int] = set()
        selector = selectors.DefaultSelector()

        def emit_due_deadline_warnings() -> None:
            if not deadline_warning_callback or timeout <= 0 or not warning_checkpoints:
                return
            elapsed = max(0, int(time.monotonic() - started_monotonic))
            remaining = max(0, int(deadline - time.monotonic())) if deadline else 0
            for index, checkpoint in enumerate(warning_checkpoints):
                if index in fired_warning_indexes:
                    continue
                checkpoint_elapsed = _coerce_int(checkpoint.get("elapsed_seconds"))
                if checkpoint_elapsed <= 0 or elapsed < checkpoint_elapsed:
                    continue
                fired_warning_indexes.add(index)
                payload = dict(checkpoint)
                payload["elapsed_seconds"] = elapsed
                payload["remaining_seconds"] = (
                    _coerce_int(payload.get("remaining_seconds")) or remaining
                )
                try:
                    deadline_warning_callback(payload)
                except Exception:
                    continue

        try:
            selector.register(stdout_stream, selectors.EVENT_READ, "stdout")
            selector.register(stderr_stream, selectors.EVENT_READ, "stderr")
            while selector.get_map():
                emit_due_deadline_warnings()
                if timeout > 0 and time.monotonic() >= deadline:
                    timed_out = True
                    try:
                        pgid = os.getpgid(popen.pid)
                    except OSError:
                        pgid = popen.pid
                    terminate_process_group(popen.pid, pgid)
                    break
                if popen.poll() is not None and not selector.get_map():
                    break
                wait = 0.1
                if timeout > 0:
                    wait = max(0.01, min(wait, deadline - time.monotonic()))
                events = selector.select(wait)
                if not events and popen.poll() is not None:
                    # Drain any final buffered lines before exiting.
                    events = [(key, 0) for key in list(selector.get_map().values())]
                for key, _mask in events:
                    stream = key.fileobj
                    try:
                        line = stream.readline()
                    except Exception:
                        line = ""
                    if line == "":
                        try:
                            selector.unregister(stream)
                        except Exception:
                            pass
                        continue
                    text = process_output_text(line)
                    if key.data == "stdout":
                        stdout_parts.append(text)
                        stdout_line_callback(text)
                    else:
                        stderr_parts.append(text)
                if popen.poll() is not None and not events:
                    break
            emit_due_deadline_warnings()
            try:
                tail_stdout, tail_stderr = popen.communicate(timeout=0.2)
                if tail_stdout:
                    stdout_parts.append(process_output_text(tail_stdout))
                if tail_stderr:
                    stderr_parts.append(process_output_text(tail_stderr))
            except (subprocess.TimeoutExpired, TypeError):
                if timed_out:
                    try:
                        pgid = os.getpgid(popen.pid)
                    except OSError:
                        pgid = popen.pid
                    terminate_process_group(popen.pid, pgid)
            return (
                "".join(stdout_parts).strip(),
                "".join(stderr_parts).strip(),
                timed_out,
            )
        except Exception:
            try:
                selector.close()
            except Exception:
                pass
        finally:
            try:
                selector.close()
            except Exception:
                pass

    if timeout <= 0:
        stdout_text, stderr_text = popen.communicate()
        return process_output_text(stdout_text), process_output_text(stderr_text), False
    try:
        stdout_text, stderr_text = popen.communicate(timeout=timeout)
        return process_output_text(stdout_text), process_output_text(stderr_text), False
    except TypeError:
        # Older test doubles do not accept the timeout kwarg.
        stdout_text, stderr_text = popen.communicate()
        return process_output_text(stdout_text), process_output_text(stderr_text), False
    except subprocess.TimeoutExpired as exc:
        stdout_parts = [process_output_text(exc.stdout)]
        stderr_parts = [process_output_text(exc.stderr)]
        try:
            pgid = os.getpgid(popen.pid)
        except OSError:
            pgid = popen.pid
        terminate_process_group(popen.pid, pgid)
        try:
            tail_stdout, tail_stderr = popen.communicate(
                timeout=max(0.1, WEB_PROMPT_TIMEOUT_GRACE_SECONDS)
            )
            stdout_parts.append(process_output_text(tail_stdout))
            stderr_parts.append(process_output_text(tail_stderr))
        except (subprocess.TimeoutExpired, TypeError):
            terminate_process_group(popen.pid, pgid)
        return (
            "\n".join(part for part in stdout_parts if part).strip(),
            "\n".join(part for part in stderr_parts if part).strip(),
            True,
        )


def notify_relay_callback(
    relay_callback: dict[str, Any],
    *,
    success: bool | None,
    summary: str,
    thread_id: str,
    started_at: int,
    finished_at: int,
    status: str = "",
    timeout_seconds: float = 8.0,
) -> bool:
    callback = normalize_relay_callback(relay_callback)
    callback_url = str(callback.get("callback_url") or "").strip()
    if not callback_url:
        return False
    status_text = str(status or "").strip().lower().replace("-", "_").replace(" ", "_")
    if status_text == "completed":
        status_text = "closed"
    if status_text not in {
        "accepted",
        "queued",
        "picked_up",
        "running",
        "closed",
        "failed",
        "stale",
    }:
        if success is True:
            status_text = "closed"
        elif success is False:
            status_text = "failed"
        else:
            status_text = "accepted"
    payload = {
        "relay_id": callback.get("relay_id"),
        "source_channel_id": callback.get("source_channel_id"),
        "source_message_id": callback.get("source_message_id"),
        "status": status_text,
        "success": success,
        "summary": summarize_text(summary, 1000),
        "thread_id": str(thread_id or ""),
        "target_connector_id": callback.get("target_connector_id"),
        "target_connector_name": callback.get("target_connector_name"),
        "target": AGENT_NAME,
        "started_at": int(started_at or 0),
        "finished_at": int(finished_at or 0),
    }
    request = urllib_request.Request(
        callback_url,
        data=json.dumps(payload).encode("utf-8"),
        headers={"Content-Type": "application/json"},
        method="POST",
    )
    try:
        with urllib_request.urlopen(request, timeout=timeout_seconds) as response:
            response.read()
        return True
    except Exception:
        return False


def format_duration_label(seconds: int) -> str:
    total = max(0, int(seconds or 0))
    hours, remainder = divmod(total, 60 * 60)
    minutes, seconds = divmod(remainder, 60)
    parts = []
    if hours:
        parts.append(f"{hours}h")
    if minutes or hours:
        parts.append(f"{minutes}m")
    if not hours:
        parts.append(f"{seconds}s")
    return " ".join(parts) or "0s"


def long_job_status_label(
    *, success: bool, cancelled: bool, timed_out: bool
) -> tuple[str, str]:
    if cancelled:
        return "cancelled", "cancelled"
    if timed_out:
        return "timed_out", "timed out"
    if success:
        return "completed", "completed"
    return "failed", "failed"


def build_long_job_completion_payload(
    *,
    prompt: str,
    visible_response: str,
    error_text: str,
    thread_id: str,
    started_at: int,
    finished_at: int,
    speed: str,
    detail: int,
    job_budget: str,
    timeout_seconds: int,
    usage: dict[str, Any] | None,
    success: bool,
    cancelled: bool,
    timed_out: bool,
    runtime: str = "",
    model: str = "",
    service_tier: str = "",
    optimization_mode: str = "",
) -> dict[str, Any]:
    duration_seconds = max(0, int(finished_at or 0) - int(started_at or 0))
    status, status_label = long_job_status_label(
        success=success, cancelled=cancelled, timed_out=timed_out
    )
    duration_label = format_duration_label(duration_seconds)
    normalized_runtime = normalize_runtime(runtime)
    normalized_model = normalize_runtime_model(normalized_runtime, model)
    normalized_service_tier = normalize_service_tier(service_tier)
    normalized_optimization_mode = normalize_optimization_mode(optimization_mode)
    text = (
        f"{AGENT_NAME} finished after {duration_label}: {status_label}. "
        "Open the TUI for details."
    )
    payload: dict[str, Any] = {
        "type": "codex.long_job.completed",
        "text": text,
        "body": text,
        "agent": AGENT_NAME,
        "agent_group": AGENT_GROUP,
        "agent_slug": AGENT_SERVICE_NAME or SESSION,
        "host": HOST_NAME,
        "session": SESSION,
        "console_title": CONSOLE_TITLE,
        "status": status,
        "success": bool(success),
        "cancelled": bool(cancelled),
        "timed_out": bool(timed_out),
        "duration_seconds": duration_seconds,
        "duration_label": duration_label,
        "threshold_seconds": int(LONG_JOB_NOTIFY_THRESHOLD_SECONDS),
        "started_at": int(started_at or 0),
        "finished_at": int(finished_at or 0),
        "thread_id": str(thread_id or ""),
        "speed": normalize_response_speed(speed),
        "detail": normalize_response_detail(detail),
        "service_tier": normalized_service_tier,
        "service_tier_label": service_tier_label(normalized_service_tier),
        "job_budget": normalize_job_budget(job_budget),
        "optimization_mode": normalized_optimization_mode,
        "optimization_mode_label": optimization_mode_label(
            normalized_optimization_mode
        ),
        "runtime": normalized_runtime,
        "model": normalized_model,
        "timeout_seconds": normalize_job_timeout_seconds(
            timeout_seconds, normalize_job_budget(job_budget)
        ),
        "usage": normalize_usage_entry(
            {
                **(usage or {}),
                "runtime": normalized_runtime,
                "model": normalized_model,
                "service_tier": normalized_service_tier,
            }
        ),
    }
    if LONG_JOB_NOTIFY_INCLUDE_CONTENT:
        payload["prompt_preview"] = summarize_text(prompt, 240)
        payload["result_preview"] = summarize_text(
            visible_response or error_text or "[no response returned]", 320
        )
    return payload


def _post_long_job_notification(payload: dict[str, Any]) -> tuple[bool, str]:
    if not LONG_JOB_NOTIFY_URL:
        return False, "url-unconfigured"
    headers = {"Content-Type": "application/json"}
    if LONG_JOB_NOTIFY_TOKEN:
        headers["Authorization"] = f"Bearer {LONG_JOB_NOTIFY_TOKEN}"
    request = urllib_request.Request(
        LONG_JOB_NOTIFY_URL,
        data=json.dumps(payload).encode("utf-8"),
        headers=headers,
        method="POST",
    )
    try:
        with urllib_request.urlopen(
            request, timeout=LONG_JOB_NOTIFY_TIMEOUT_SECONDS
        ) as response:
            response.read()
        return True, "url"
    except Exception as exc:
        return False, f"url:{type(exc).__name__}"


def _run_long_job_notification_command(payload: dict[str, Any]) -> tuple[bool, str]:
    if not LONG_JOB_NOTIFY_COMMAND:
        return False, "command-unconfigured"
    try:
        args = shlex.split(LONG_JOB_NOTIFY_COMMAND)
    except ValueError:
        return False, "command-invalid"
    if not args:
        return False, "command-unconfigured"
    try:
        completed = subprocess.run(
            args,
            input=json.dumps(payload),
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=LONG_JOB_NOTIFY_TIMEOUT_SECONDS,
            check=False,
        )
    except subprocess.TimeoutExpired:
        return False, "command:TimeoutExpired"
    except OSError as exc:
        return False, f"command:{type(exc).__name__}"
    if completed.returncode != 0:
        return False, f"command:exit-{completed.returncode}"
    return True, "command"


def deliver_long_job_completion_notification(
    payload: dict[str, Any], *, use_url: bool = True, use_command: bool = True
) -> tuple[bool, str]:
    outcomes: list[tuple[bool, str]] = []
    if use_url and LONG_JOB_NOTIFY_URL:
        outcomes.append(_post_long_job_notification(payload))
    if use_command and LONG_JOB_NOTIFY_COMMAND:
        outcomes.append(_run_long_job_notification_command(payload))
    if not outcomes:
        return False, "unconfigured"
    if any(ok for ok, _detail in outcomes):
        return True, ",".join(detail for _ok, detail in outcomes)
    return False, ",".join(detail for _ok, detail in outcomes)


def maybe_notify_long_job_completion(
    *,
    prompt: str,
    visible_response: str,
    error_text: str,
    thread_id: str,
    started_at: int,
    finished_at: int,
    speed: str,
    detail: int,
    job_budget: str,
    timeout_seconds: int,
    usage: dict[str, Any] | None,
    success: bool,
    cancelled: bool,
    timed_out: bool,
    runtime: str = "",
    model: str = "",
    service_tier: str = "",
    optimization_mode: str = "",
) -> bool:
    duration_seconds = max(0, int(finished_at or 0) - int(started_at or 0))
    threshold_seconds = int(LONG_JOB_NOTIFY_THRESHOLD_SECONDS)
    if threshold_seconds > 0 and duration_seconds < threshold_seconds:
        return False
    if not LONG_JOB_NOTIFY_URL and not LONG_JOB_NOTIFY_COMMAND:
        return False
    payload = build_long_job_completion_payload(
        prompt=prompt,
        visible_response=visible_response,
        error_text=error_text,
        thread_id=thread_id,
        started_at=started_at,
        finished_at=finished_at,
        speed=speed,
        detail=detail,
        service_tier=service_tier,
        optimization_mode=optimization_mode,
        job_budget=job_budget,
        timeout_seconds=timeout_seconds,
        runtime=runtime,
        model=model,
        usage=usage,
        success=success,
        cancelled=cancelled,
        timed_out=timed_out,
    )
    sent, detail_text = deliver_long_job_completion_notification(payload)
    append_audit_event(
        event_type="notification.long-job.sent"
        if sent
        else "notification.long-job.failed",
        summary="Long-running job completion notification sent."
        if sent
        else "Long-running job completion notification failed.",
        detail=detail_text,
        severity="info" if sent else "warn",
        actor_type="system",
        thread_id=thread_id,
        payload={
            "duration_seconds": duration_seconds,
            "threshold_seconds": threshold_seconds,
            "status": payload.get("status"),
            "success": bool(success),
            "runtime": payload.get("runtime"),
            "model": payload.get("model"),
            "delivery": detail_text,
        },
        event_at=finished_at,
    )
    return sent


def _compact_token_label(value: Any) -> str:
    amount = max(0, _coerce_int(value))
    if amount >= 1_000_000:
        return f"{amount / 1_000_000:.1f}M".rstrip("0").rstrip(".")
    if amount >= 1000:
        return f"{amount / 1000:.1f}k".rstrip("0").rstrip(".")
    return str(amount)


def _thread_usage_token_ceiling(thread_id: str) -> int:
    clean_thread_id = str(thread_id or "").strip()
    if not clean_thread_id:
        return 0
    candidates: list[int] = []
    for entry in load_usage_history(limit=0):
        if str(entry.get("thread_id") or "").strip() != clean_thread_id:
            continue
        candidates.extend(
            [
                _coerce_int(entry.get("total_tokens")),
                _coerce_int(entry.get("input_tokens")),
                _coerce_int(entry.get("cached_input_tokens"))
                + _coerce_int(entry.get("input_tokens")),
            ]
        )
    usage = usage_snapshot(thread_id=clean_thread_id)
    current_thread = (
        usage.get("current_thread")
        if isinstance(usage.get("current_thread"), dict)
        else {}
    )
    candidates.extend(
        [
            _coerce_int(current_thread.get("total_tokens")),
            _coerce_int(current_thread.get("input_tokens")),
        ]
    )
    return max(candidates or [0])


def bedrock_context_pack_plan(
    *,
    service_tier: Any,
    model: Any,
    session_id: str,
    thread_scope: str = "",
) -> dict[str, Any]:
    normalized_service_tier = normalize_service_tier(service_tier)
    requested_model = normalize_runtime_model("codex", model)
    normalized_model = codex_model_for_service_tier(
        normalized_service_tier, requested_model
    )
    if not requested_model:
        requested_model = normalized_model
    profile_v2 = codex_profile_v2_for_service_tier(normalized_service_tier)
    clean_session_id = str(session_id or "").strip()
    if not BEDROCK_CONTEXT_PACK_ENABLED or not profile_v2 or not clean_session_id:
        return {"should_pack": False, "reason": "not-applicable"}

    history = load_history(limit=MAX_HISTORY_ITEMS)
    usage = usage_snapshot(thread_id=clean_session_id)
    meta = load_status_meta()
    snapshot = {
        "history": history,
        "usage": usage,
        "thread_id": clean_session_id,
        "thread_scope": thread_scope,
        "state": str(meta.get("state") or ""),
        "status_message": str(meta.get("status_message") or ""),
        "pending": bool(meta.get("pending")),
        "queue_depth": len(normalize_queue(meta.get("queued_prompts"))),
        "selected_runtime": "codex",
        "selected_model": normalized_model,
        "chat_runtime": "codex",
        "chat_model": normalized_model,
        "last_model": normalized_model,
        "last_service_tier": normalized_service_tier,
        "accounting": usage_accounting_tags(),
        "bbs": {},
        "logs": "",
        "pane": "",
    }
    preview = context_pack_preview(snapshot)
    current = preview.get("current") if isinstance(preview.get("current"), dict) else {}
    packed = preview.get("packed") if isinstance(preview.get("packed"), dict) else {}
    savings = preview.get("savings") if isinstance(preview.get("savings"), dict) else {}
    current_tokens = _coerce_int(current.get("tokens"))
    packed_tokens = _coerce_int(packed.get("tokens"))
    saved_tokens = _coerce_int(savings.get("tokens"))
    saved_pct = _coerce_float(savings.get("pct"))
    thread_tokens = _thread_usage_token_ceiling(clean_session_id)
    thread_heavy_enough = thread_tokens >= BEDROCK_CONTEXT_PACK_MIN_THREAD_TOKENS
    current_heavy_enough = current_tokens >= BEDROCK_CONTEXT_PACK_MIN_THREAD_TOKENS
    visible_context_worthwhile = (
        saved_tokens >= BEDROCK_CONTEXT_PACK_MIN_SAVED_TOKENS
        and saved_pct >= BEDROCK_CONTEXT_PACK_MIN_SAVED_PCT
    )
    should_pack = bool(
        thread_heavy_enough or (current_heavy_enough and visible_context_worthwhile)
    )
    if should_pack:
        reason = (
            "heavy-bedrock-thread" if thread_heavy_enough else "heavy-visible-context"
        )
    else:
        reason = "below-threshold"
    return {
        "should_pack": should_pack,
        "reason": reason,
        "session_id": clean_session_id,
        "thread_scope": str(thread_scope or ""),
        "profile_v2": profile_v2,
        "model": normalized_model,
        "service_tier": normalized_service_tier,
        "history": history,
        "usage": usage,
        "preview": preview,
        "thread_tokens": thread_tokens,
        "current_tokens": current_tokens,
        "packed_tokens": packed_tokens,
        "saved_tokens": saved_tokens,
        "saved_pct": saved_pct,
        "thread_heavy_enough": thread_heavy_enough,
        "current_heavy_enough": current_heavy_enough,
        "visible_context_worthwhile": visible_context_worthwhile,
    }


def bedrock_context_pack_prompt_context(plan: dict[str, Any]) -> str:
    if not plan or not plan.get("should_pack"):
        return ""
    history = [item for item in plan.get("history") or [] if isinstance(item, dict)]
    recent = history[-CONTEXT_PACK_RECENT_TURNS:]
    older_count = max(0, len(history) - len(recent))
    session_id = str(plan.get("session_id") or "")
    thread_scope = str(plan.get("thread_scope") or "")
    lines = [
        "",
        "Bedrock compact-context handoff:",
        "- This turn starts a fresh Bedrock thread because the previous Bedrock thread is high-context and low-yield risk.",
        f"- Previous thread: {session_id or 'unknown'}"
        + (f" · scope: {thread_scope}" if thread_scope else ""),
        (
            "- Trigger: previous-thread usage ceiling "
            f"{_compact_token_label(plan.get('thread_tokens'))} tokens; "
            f"context estimate {_compact_token_label(plan.get('current_tokens'))} -> "
            f"{_compact_token_label(plan.get('packed_tokens'))}; "
            f"saved {_compact_token_label(plan.get('saved_tokens'))} "
            f"({plan.get('saved_pct', 0):.1f}%)."
        ),
        "- Treat this as a pointer packet. If an older detail matters, inspect local history/status files or repo artifacts before relying on memory.",
    ]
    if recent:
        lines.append("- Recent durable turns:")
        for item in recent:
            started = str(item.get("started_label") or "").strip()
            prompt_preview = summarize_text(str(item.get("prompt") or ""), 140)
            response_preview = summarize_text(str(item.get("response") or ""), 180)
            error_preview = summarize_text(str(item.get("error") or ""), 120)
            head = "  - "
            if started:
                head += f"{started} · "
            head += f"prompt: {prompt_preview or '[no prompt recorded]'}"
            lines.append(head)
            if response_preview:
                lines.append(f"    response: {response_preview}")
            if error_preview:
                lines.append(f"    error: {error_preview}")
    if older_count:
        lines.append(
            f"- Older turn bodies omitted: {older_count}. Retrieve them from {HISTORY_PATH} or the state DB only if needed."
        )
    lines.append(
        "- Continue the operator's current request now; do not summarize this handoff unless it affects the answer."
    )
    return "\n".join(lines)


def _execute_codex_prompt(
    prompt: str,
    speed: str,
    detail: int,
    attachments: list[dict[str, Any]],
    timeout_seconds: int | None = None,
    model: str = "",
    service_tier: str = "",
    job_budget: str = "",
    optimization_mode: str = "",
) -> tuple[str, str, str, dict[str, Any]]:
    output_path = STATE_DIR / "last_message.txt"
    if output_path.exists():
        output_path.unlink()

    normalized_speed = normalize_response_speed(speed)
    normalized_detail = normalize_response_detail(detail)
    normalized_service_tier = normalize_service_tier(service_tier)
    execution_service_tier = service_tier_execution_tier(normalized_service_tier)
    normalized_optimization_mode = normalize_optimization_mode(optimization_mode)
    normalized_budget = normalize_job_budget(job_budget)
    normalized_timeout = normalize_job_timeout_seconds(timeout_seconds, job_budget)
    target_timeout = job_budget_timeout_seconds(normalized_budget)
    warning_checkpoints = deadline_warning_checkpoints(
        target_timeout, normalized_timeout
    )
    normalized_model = codex_model_for_service_tier(normalized_service_tier, model)
    thread_scope = codex_thread_scope_key(normalized_service_tier, model)
    stored_thread_scope = read_text(THREAD_SCOPE_PATH)
    session_id = read_text(THREAD_ID_PATH)
    if session_id and stored_thread_scope and stored_thread_scope != thread_scope:
        session_id = ""
    if (
        session_id
        and not stored_thread_scope
        and codex_profile_v2_for_service_tier(normalized_service_tier)
    ):
        session_id = ""
    context_pack_plan = (
        bedrock_context_pack_plan(
            service_tier=normalized_service_tier,
            model=normalized_model,
            session_id=session_id,
            thread_scope=stored_thread_scope,
        )
        if normalized_optimization_mode != "raw"
        else {"should_pack": False, "mode": "raw"}
    )
    cmd = [
        CODEX_BIN,
        "exec",
        "--json",
        "--dangerously-bypass-approvals-and-sandbox",
        *codex_profile_v2_config_args(normalized_service_tier),
        "-m",
        normalized_model,
        "-c",
        f'model_reasoning_effort="{response_reasoning_effort(normalized_speed)}"',
        *service_tier_config_args(normalized_service_tier),
        "-C",
        WORKDIR,
        "-o",
        str(output_path),
    ]
    execution_prompt = active_interrupt_handoff_execution_prompt(prompt) or prompt
    if context_pack_plan.get("should_pack"):
        compact_context = bedrock_context_pack_prompt_context(context_pack_plan)
        if compact_context:
            old_session_id = session_id
            execution_prompt = f"{execution_prompt}\n{compact_context}".strip()
            session_id = ""
            write_text(THREAD_ID_PATH, "")
            write_text(THREAD_SCOPE_PATH, "")
            append_audit_event(
                event_type="chat.bedrock-context-packed",
                summary="Starting a fresh Bedrock thread with compact context handoff.",
                detail=(
                    f"Previous thread {old_session_id} exceeded context pack threshold; "
                    "resume was skipped to reduce low-yield Bedrock turns."
                ),
                severity="warn",
                actor_type="system",
                thread_id=old_session_id,
                payload={
                    "previous_thread_id": old_session_id,
                    "previous_thread_scope": stored_thread_scope,
                    "service_tier": normalized_service_tier,
                    "execution_service_tier": execution_service_tier,
                    "optimization_mode": normalized_optimization_mode,
                    "model": normalized_model,
                    "profile_v2": context_pack_plan.get("profile_v2"),
                    "thread_tokens": context_pack_plan.get("thread_tokens"),
                    "current_tokens": context_pack_plan.get("current_tokens"),
                    "packed_tokens": context_pack_plan.get("packed_tokens"),
                    "saved_tokens": context_pack_plan.get("saved_tokens"),
                    "saved_pct": context_pack_plan.get("saved_pct"),
                },
            )
    tuned_prompt = build_prompt_with_attachments(
        execution_prompt,
        normalized_detail,
        attachments,
        normalized_budget,
        normalized_timeout,
        "codex",
        normalized_model,
        normalized_speed,
        normalized_service_tier,
        normalized_optimization_mode,
    )
    preflight_usage_fields = usage_fields_from_context_preflight_accounting(
        add_context_pack_to_preflight_accounting(
            take_latest_context_preflight_accounting("codex", normalized_model),
            context_pack_plan,
        )
    )
    update_live_turn_prompt_estimate(
        tuned_prompt=tuned_prompt,
        attachments=attachments,
        runtime="codex",
        model=normalized_model,
        service_tier=normalized_service_tier,
        job_budget=normalized_budget,
    )
    if session_id:
        cmd.extend(["resume", session_id, tuned_prompt])
    else:
        cmd.append(tuned_prompt)

    env = dict(os.environ)
    env["CODEX_HOME"] = CODEX_HOME
    apply_codex_provider_environment(env, normalized_service_tier)
    checkpoint_interrupted = False
    deadline_checkpoint_interrupted = False
    popen = subprocess.Popen(
        cmd,
        text=True,
        stdin=subprocess.DEVNULL,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        env=env,
        start_new_session=True,
    )
    set_active_codex_process(popen)

    def _observe_stdout_line(line: str) -> None:
        nonlocal checkpoint_interrupted, deadline_checkpoint_interrupted
        stripped = str(line or "").strip()
        if not stripped.startswith("{"):
            return
        try:
            event = json.loads(stripped)
        except json.JSONDecodeError:
            return
        if not isinstance(event, dict):
            return
        kind = codex_event_checkpoint_kind(event)
        record_live_turn_event(event, kind=kind)
        if not kind:
            return
        should_interrupt = record_queue_checkpoint(event=event, kind=kind)
        if should_interrupt and not (
            checkpoint_interrupted or deadline_checkpoint_interrupted
        ):
            checkpoint_interrupted = True
            try:
                pgid = os.getpgid(popen.pid)
            except OSError:
                pgid = popen.pid
            terminate_process_group(popen.pid, pgid)
            return
        should_deadline_interrupt = record_deadline_checkpoint(
            event=event, kind=kind, prompt=prompt
        )
        if should_deadline_interrupt and not (
            checkpoint_interrupted or deadline_checkpoint_interrupted
        ):
            deadline_checkpoint_interrupted = True
            try:
                pgid = os.getpgid(popen.pid)
            except OSError:
                pgid = popen.pid
            terminate_process_group(popen.pid, pgid)

    def _observe_deadline_warning(warning: dict[str, Any]) -> None:
        message = deadline_warning_status_message(warning, agent_name=AGENT_NAME)
        warning_at = now_ts()
        meta = update_status_meta(
            deadline_warning_active=True,
            deadline_warning_kind=str(warning.get("kind") or ""),
            deadline_warning_message=message,
            deadline_warning_at=warning_at,
            deadline_warning_count=_coerce_int(
                load_status_meta().get("deadline_warning_count")
            )
            + 1,
            deadline_warning_elapsed_seconds=_coerce_int(
                warning.get("elapsed_seconds")
            ),
            deadline_warning_remaining_seconds=_coerce_int(
                warning.get("remaining_seconds")
            ),
            deadline_warning_target_seconds=target_timeout,
            deadline_warning_guardrail_seconds=normalized_timeout,
            status_message=message,
        )
        append_audit_event(
            event_type="chat.deadline-warning",
            summary="Web prompt deadline warning.",
            detail=message,
            severity="warn",
            actor_type="system",
            thread_id=read_text(THREAD_ID_PATH) or session_id,
            payload={
                "kind": str(warning.get("kind") or ""),
                "elapsed_seconds": _coerce_int(warning.get("elapsed_seconds")),
                "remaining_seconds": _coerce_int(warning.get("remaining_seconds")),
                "target_seconds": target_timeout,
                "guardrail_seconds": normalized_timeout,
                "warning_count": _coerce_int(meta.get("deadline_warning_count")),
                "runtime": "codex",
                "model": normalized_model,
                "service_tier": normalized_service_tier,
                "job_budget": normalized_budget,
            },
        )

    try:
        stdout_text, stderr_text, timed_out = communicate_with_prompt_timeout(
            popen,
            normalized_timeout,
            stdout_line_callback=_observe_stdout_line,
            deadline_warning_callback=_observe_deadline_warning,
            deadline_warning_checkpoints=warning_checkpoints,
        )
    finally:
        set_active_codex_process(None)
    proc = subprocess.CompletedProcess(
        cmd,
        popen.returncode,
        stdout_text,
        stderr_text,
    )

    new_session_id = session_id
    messages: list[str] = []
    codex_events: list[dict[str, Any]] = []
    usage = normalize_usage_entry({"service_tier": normalized_service_tier})
    for line in (proc.stdout or "").splitlines():
        stripped = line.strip()
        if not stripped.startswith("{"):
            continue
        try:
            event = json.loads(stripped)
        except json.JSONDecodeError:
            continue
        if not isinstance(event, dict):
            continue
        codex_events.append(event)
        if event.get("type") == "thread.started":
            candidate = str(event.get("thread_id") or "").strip()
            if candidate:
                new_session_id = candidate
        elif event.get("type") == "turn.completed":
            observed_service_tier = _extract_observed_service_tier(event)
            usage_payload = {
                **(event.get("usage") or {}),
                "service_tier": normalized_service_tier,
            }
            if observed_service_tier:
                usage_payload["observed_service_tier"] = observed_service_tier
                usage_payload["resolved_service_tier"] = observed_service_tier
            usage = normalize_usage_entry(usage_payload)
        elif event.get("type") == "turn.failed":
            err = event.get("error") or {}
            msg = str(err.get("message") or "").strip()
            if msg:
                messages.append(msg)

    raw_stderr_text = strip_codex_empty_last_message_warning(proc.stderr)
    raw_error_text = "\n".join(
        part for part in [raw_stderr_text, "\n".join(messages).strip()] if part
    ).strip()
    raw_error_text = strip_codex_empty_last_message_warning(raw_error_text)
    usage = normalize_usage_entry(
        {
            **usage,
            **preflight_usage_fields,
            **codex_provider_diagnostics(
                proc=proc,
                events=codex_events,
                messages=messages,
                error_text=raw_error_text,
                usage=usage,
                timed_out=timed_out,
                service_tier=normalized_service_tier,
            ),
        }
    )

    if timed_out:
        return (
            "",
            web_prompt_timed_out_message(
                normalized_timeout,
                job_budget=normalized_budget,
                service_tier=normalized_service_tier,
            ),
            new_session_id,
            usage,
        )

    if checkpoint_interrupted:
        return "", CHECKPOINT_INTERRUPTED_WEB_REPLY_MESSAGE, new_session_id, usage

    if deadline_checkpoint_interrupted:
        return (
            "",
            DEADLINE_CHECKPOINT_INTERRUPTED_WEB_REPLY_MESSAGE,
            new_session_id,
            usage,
        )

    cancelled = (
        proc.returncode is not None
        and proc.returncode < 0
        and _coerce_int(load_status_meta().get("cancel_requested_at")) > 0
    )
    if cancelled:
        return "", CANCELLED_WEB_REPLY_MESSAGE, new_session_id, usage

    stderr_rollout_ids = codex_rollout_thread_not_found_ids(proc.stderr)
    message_rollout_ids = codex_rollout_thread_not_found_ids("\n".join(messages))
    if session_id and session_id in (stderr_rollout_ids | message_rollout_ids):
        write_text(THREAD_ID_PATH, "")
        write_text(THREAD_SCOPE_PATH, "")
        new_session_id = ""
        messages = [
            message
            for message in messages
            if not CODEX_ROLLOUT_THREAD_NOT_FOUND_RE.search(message)
        ]
        resume_reset_note = "Worker resume state was stale and has been reset."
        append_audit_event(
            event_type="chat.resume-reset",
            summary=resume_reset_note,
            detail=resume_reset_note,
            severity="warn",
            actor_type="system",
            thread_id=session_id,
            payload={"thread_id": session_id},
        )

    engine_not_found_text = "\n".join(
        part
        for part in [
            raw_error_text,
            "\n".join(messages),
            proc.stdout,
            proc.stderr,
        ]
        if part
    )
    engine_not_found_thread_id = str(session_id or new_session_id or "").strip()
    if (
        engine_not_found_thread_id
        and codex_profile_v2_for_service_tier(normalized_service_tier)
        and codex_engine_not_found(engine_not_found_text)
    ):
        engine_not_found_new_thread_started = bool(
            new_session_id and new_session_id != session_id
        )
        write_text(THREAD_ID_PATH, "")
        write_text(THREAD_SCOPE_PATH, "")
        new_session_id = ""
        reset_note = "Bedrock engine was not found; stored thread was reset."
        append_audit_event(
            event_type="chat.resume-reset",
            summary=reset_note,
            detail=reset_note,
            severity="warn",
            actor_type="system",
            thread_id=engine_not_found_thread_id,
            payload={
                "thread_id": engine_not_found_thread_id,
                "thread_scope": stored_thread_scope,
                "new_thread_started": engine_not_found_new_thread_started,
                "model": normalized_model,
                "service_tier": normalized_service_tier,
                "provider_error_kind": "bedrock_engine_not_found",
            },
        )

    stream_failure_error_kind = str(usage.get("provider_error_kind") or "").strip()
    stream_failure_thread_id = str(session_id or new_session_id or "").strip()
    if (
        stream_failure_thread_id
        and codex_profile_v2_for_service_tier(normalized_service_tier)
        and usage.get("zero_token_provider_failure")
        and stream_failure_error_kind
        in {"bedrock_stream_disconnected", "bedrock_on_demand_capacity_exceeded"}
    ):
        write_text(THREAD_ID_PATH, "")
        write_text(THREAD_SCOPE_PATH, "")
        new_session_id = ""
        reset_note = "Bedrock stream failed with zero tokens; stored thread was reset."
        append_audit_event(
            event_type="chat.resume-reset",
            summary=reset_note,
            detail=reset_note,
            severity="warn",
            actor_type="system",
            thread_id=stream_failure_thread_id,
            payload={
                "thread_id": stream_failure_thread_id,
                "thread_scope": stored_thread_scope,
                "model": normalized_model,
                "service_tier": normalized_service_tier,
                "provider_error_kind": stream_failure_error_kind,
                "provider_request_ids": usage.get("provider_request_ids"),
                "provider_trace_ids": usage.get("provider_trace_ids"),
            },
        )

    if new_session_id:
        write_text(THREAD_ID_PATH, new_session_id)
        write_text(THREAD_SCOPE_PATH, thread_scope)

    response = read_text(output_path)
    stderr_text = raw_stderr_text
    error_text = "\n".join(
        part for part in [stderr_text, "\n".join(messages).strip()] if part
    ).strip()
    error_text = strip_codex_empty_last_message_warning(error_text)
    if error_text != raw_error_text:
        usage = normalize_usage_entry(
            {
                **usage,
                **preflight_usage_fields,
                **codex_provider_diagnostics(
                    proc=proc,
                    events=codex_events,
                    messages=messages,
                    error_text=error_text,
                    usage=usage,
                    timed_out=timed_out,
                    service_tier=normalized_service_tier,
                ),
            }
        )
    return response, error_text, new_session_id, usage


BEDROCK_CONVERSE_HELPER_CODE = r"""
import json
import os
import sys

import boto3

payload = json.loads(sys.stdin.read())
region = payload.get("region") or os.environ.get("AWS_REGION") or "us-east-2"
client = boto3.client("bedrock-runtime", region_name=region)
kwargs = {
    "modelId": payload["model_id"],
    "messages": payload["messages"],
    "inferenceConfig": payload["inference_config"],
}
if payload.get("tool_config"):
    kwargs["toolConfig"] = payload["tool_config"]
response = client.converse(**kwargs)
print(json.dumps(response, default=str))
"""

BEDROCK_CONVERSE_READONLY_DENY_RE = re.compile(
    r"(?i)(?:^|[;&|]\s*)"
    r"(rm|rmdir|mv|cp|install|touch|mkdir|chmod|chown|chgrp|sudo|su|ssh|scp|rsync|"
    r"curl|wget|aws|npm|pnpm|yarn|make|systemctl\s+(?:start|stop|restart|reload|"
    r"enable|disable)|service\s+\S+\s+(?:start|stop|restart|reload)|"
    r"git\s+(?:reset|clean|checkout|switch|restore|commit|push|pull|merge|rebase|"
    r"apply|am|cherry-pick)|python(?:3)?|node|perl|ruby|php|sqlite3)\b"
)
BEDROCK_CONVERSE_READONLY_PREFIXES = (
    "pwd",
    "ls",
    "find",
    "rg",
    "grep",
    "sed -n",
    "cat",
    "head",
    "tail",
    "wc",
    "stat",
    "date",
    "test ",
    "command -v",
    "which",
    "git status",
    "git diff",
    "git log",
    "git show",
    "systemctl status",
    "journalctl ",
)
BEDROCK_CONVERSE_AWS_READONLY_OPERATIONS = {
    "autoscaling": {
        "describe-auto-scaling-groups",
        "describe-launch-configurations",
        "describe-scaling-activities",
    },
    "cloudwatch": {
        "describe-alarms",
        "get-metric-data",
        "get-metric-statistics",
    },
    "configure": {"list"},
    "ec2": {
        "describe-images",
        "describe-instances",
        "describe-instance-status",
        "describe-launch-template-versions",
        "describe-regions",
        "describe-security-groups",
        "describe-subnets",
        "describe-tags",
        "describe-vpcs",
    },
    "sqs": {"get-queue-attributes", "get-queue-url", "list-queues"},
    "ssm": {
        "describe-instance-information",
        "describe-sessions",
        "get-connection-status",
    },
    "sts": {"get-caller-identity"},
}
BEDROCK_CONVERSE_AWS_READONLY_GLOBAL_OPTIONS = {
    "--no-cli-pager": 0,
    "--output": 1,
    "--query": 1,
    "--region": 1,
}
BEDROCK_CONVERSE_AWS_READONLY_DENIED_OPTIONS = {
    "--cli-input-json",
    "--cli-input-yaml",
    "--debug",
    "--endpoint-url",
    "--generate-cli-skeleton",
    "--no-sign-request",
    "--profile",
}


def bedrock_converse_provider_tags() -> dict[str, str]:
    return {
        "provider_label": "Bedrock Converse",
        "provider_surface": "aws-bedrock",
        "profile_v2": "",
        "aws_profile": BEDROCK_CONVERSE_AWS_PROFILE,
        "aws_region": BEDROCK_CONVERSE_AWS_REGION,
    }


def bedrock_converse_shell_command_allowed(command: Any) -> tuple[bool, str]:
    clean = re.sub(r"\s+", " ", str(command or "")).strip()
    if not clean:
        return False, "empty command"
    if len(clean) > 2000:
        return False, "command too long"
    lowered = clean.lower()
    if any(token in clean for token in ("`", "$(", ">", "<")):
        return False, "shell expansion or redirection is not allowed"
    if BEDROCK_CONVERSE_READONLY_DENY_RE.search(clean):
        return False, "command is outside the read-only tool policy"
    if any(
        lowered == prefix.rstrip() or lowered.startswith(prefix)
        for prefix in BEDROCK_CONVERSE_READONLY_PREFIXES
    ):
        return True, ""
    return False, "command is not in the read-only allowlist"


def run_bedrock_converse_shell_readonly(command: Any) -> dict[str, Any]:
    clean = re.sub(r"\s+", " ", str(command or "")).strip()
    allowed, reason = bedrock_converse_shell_command_allowed(clean)
    if not allowed:
        return {
            "ok": False,
            "command": clean,
            "returncode": 126,
            "stdout": "",
            "stderr": reason,
        }
    try:
        completed = subprocess.run(
            clean,
            shell=True,
            cwd=WORKDIR,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=BEDROCK_CONVERSE_TOOL_TIMEOUT_SECONDS,
        )
    except subprocess.TimeoutExpired:
        return {
            "ok": False,
            "command": clean,
            "returncode": 124,
            "stdout": "",
            "stderr": (
                f"read-only command timed out after "
                f"{BEDROCK_CONVERSE_TOOL_TIMEOUT_SECONDS}s"
            ),
        }
    except OSError as exc:
        return {
            "ok": False,
            "command": clean,
            "returncode": 1,
            "stdout": "",
            "stderr": str(exc),
        }
    return {
        "ok": completed.returncode == 0,
        "command": clean,
        "returncode": completed.returncode,
        "stdout": summarize_text(completed.stdout, 6000),
        "stderr": summarize_text(completed.stderr, 2000),
    }


def bedrock_converse_aws_readonly_command_allowed(
    command: Any,
) -> tuple[bool, list[str], str]:
    if not BEDROCK_CONVERSE_AWS_READONLY_ENABLED:
        return False, [], "brokered aws_readonly is disabled"
    clean = re.sub(r"\s+", " ", str(command or "")).strip()
    if not clean:
        return False, [], "empty command"
    if len(clean) > 2000:
        return False, [], "command too long"
    if any(token in clean for token in ("`", "$(", ">", "<", ";", "|", "&&")):
        return False, [], "shell control syntax is not allowed"
    try:
        argv = shlex.split(clean)
    except ValueError as exc:
        return False, [], f"invalid shell-like syntax: {exc}"
    if not argv or argv[0] != "aws":
        return False, argv, "command must start with aws"
    if len(argv) == 2 and argv[1] == "--version":
        return True, argv, ""
    if any(arg in BEDROCK_CONVERSE_AWS_READONLY_DENIED_OPTIONS for arg in argv[1:]):
        return False, argv, "aws option is outside the read-only broker policy"
    index = 1
    while index < len(argv) and argv[index].startswith("--"):
        option = argv[index]
        if option not in BEDROCK_CONVERSE_AWS_READONLY_GLOBAL_OPTIONS:
            return False, argv, "unsupported aws global option"
        index += 1 + BEDROCK_CONVERSE_AWS_READONLY_GLOBAL_OPTIONS[option]
    if len(argv) <= index + 1:
        return False, argv, "aws service and operation are required"
    service = argv[index]
    operation = argv[index + 1]
    allowed = BEDROCK_CONVERSE_AWS_READONLY_OPERATIONS.get(service, set())
    if operation not in allowed:
        return False, argv, "aws operation is outside the read-only broker policy"
    return True, argv, ""


def run_bedrock_converse_aws_readonly(command: Any) -> dict[str, Any]:
    allowed, argv, reason = bedrock_converse_aws_readonly_command_allowed(command)
    clean = re.sub(r"\s+", " ", str(command or "")).strip()
    if not allowed:
        return {
            "ok": False,
            "command": clean,
            "returncode": 126,
            "stdout": "",
            "stderr": reason,
        }
    env = os.environ.copy()
    if BEDROCK_CONVERSE_AWS_PROFILE:
        env["AWS_PROFILE"] = BEDROCK_CONVERSE_AWS_PROFILE
    if BEDROCK_CONVERSE_AWS_REGION:
        env["AWS_REGION"] = BEDROCK_CONVERSE_AWS_REGION
        env["AWS_DEFAULT_REGION"] = BEDROCK_CONVERSE_AWS_REGION
    try:
        completed = subprocess.run(
            argv,
            cwd=str(WORKDIR),
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=BEDROCK_CONVERSE_TOOL_TIMEOUT_SECONDS,
            env=env,
        )
    except subprocess.TimeoutExpired:
        return {
            "ok": False,
            "command": clean,
            "returncode": 124,
            "stdout": "",
            "stderr": (
                f"aws command timed out after {BEDROCK_CONVERSE_TOOL_TIMEOUT_SECONDS}s"
            ),
        }
    except OSError as exc:
        return {
            "ok": False,
            "command": clean,
            "returncode": 1,
            "stdout": "",
            "stderr": str(exc),
        }
    return {
        "ok": completed.returncode == 0,
        "command": clean,
        "argv": argv,
        "returncode": completed.returncode,
        "stdout": summarize_text(completed.stdout, 8000),
        "stderr": summarize_text(completed.stderr, 3000),
    }


def bedrock_converse_write_path_allowed(path: Any) -> tuple[bool, Path | None, str]:
    if not BEDROCK_CONVERSE_FILE_WRITE_ENABLED:
        return False, None, "limited file writes are disabled"
    if not BEDROCK_CONVERSE_WRITE_PATH_PREFIXES:
        return False, None, "no limited write path prefixes are configured"
    raw = str(path or "").strip()
    if not raw:
        return False, None, "empty path"
    if "\x00" in raw:
        return False, None, "path contains NUL"
    base = Path(WORKDIR).resolve()
    candidate_path = Path(raw)
    candidate = (
        candidate_path.resolve()
        if candidate_path.is_absolute()
        else (base / candidate_path).resolve()
    )
    try:
        rel = candidate.relative_to(base).as_posix()
    except ValueError:
        return False, None, "path is outside the TUI workdir"
    if rel.startswith(".git/") or rel == ".git":
        return False, None, "writes to .git are not allowed"
    for prefix in BEDROCK_CONVERSE_WRITE_PATH_PREFIXES:
        clean_prefix = prefix.rstrip("/")
        if rel == clean_prefix or rel.startswith(f"{clean_prefix}/"):
            return True, candidate, ""
    return False, None, "path is outside the limited write allowlist"


def run_bedrock_converse_file_write_limited(
    path: Any, content: Any, mode: Any = "overwrite"
) -> dict[str, Any]:
    allowed, candidate, reason = bedrock_converse_write_path_allowed(path)
    raw_path = str(path or "").strip()
    if not allowed or candidate is None:
        return {
            "ok": False,
            "path": raw_path,
            "returncode": 126,
            "stdout": "",
            "stderr": reason,
        }
    clean_mode = str(mode or "overwrite").strip().lower()
    if clean_mode not in {"overwrite", "create"}:
        return {
            "ok": False,
            "path": raw_path,
            "returncode": 126,
            "stdout": "",
            "stderr": "mode must be overwrite or create",
        }
    data = str(content if content is not None else "")
    encoded = data.encode("utf-8")
    if len(encoded) > BEDROCK_CONVERSE_WRITE_MAX_BYTES:
        return {
            "ok": False,
            "path": raw_path,
            "returncode": 126,
            "stdout": "",
            "stderr": (
                "content exceeds limited write max bytes "
                f"({BEDROCK_CONVERSE_WRITE_MAX_BYTES})"
            ),
        }
    if clean_mode == "create" and candidate.exists():
        return {
            "ok": False,
            "path": raw_path,
            "returncode": 1,
            "stdout": "",
            "stderr": "file already exists",
        }
    try:
        candidate.parent.mkdir(parents=True, exist_ok=True)
        backup = ""
        if candidate.exists():
            backup_path = candidate.with_name(
                f"{candidate.name}.bedrock-converse-bak-{now_ts()}"
            )
            shutil.copy2(candidate, backup_path)
            backup = str(backup_path)
        candidate.write_text(data, encoding="utf-8")
    except OSError as exc:
        return {
            "ok": False,
            "path": raw_path,
            "returncode": 1,
            "stdout": "",
            "stderr": str(exc),
        }
    return {
        "ok": True,
        "path": raw_path,
        "resolved_path": str(candidate),
        "backup_path": backup,
        "returncode": 0,
        "stdout": f"wrote {len(encoded)} bytes",
        "stderr": "",
    }


def bedrock_converse_ssh_target_allowed(target: Any) -> tuple[bool, str, str]:
    clean = str(target or "").strip()
    if not BEDROCK_CONVERSE_SSH_ENABLED:
        return False, clean, "limited ssh is disabled"
    if not clean:
        return False, clean, "empty ssh target"
    if clean not in BEDROCK_CONVERSE_SSH_TARGETS:
        return False, clean, "ssh target is outside the allowlist"
    return True, clean, ""


def run_bedrock_converse_ssh_limited(target: Any, command: Any) -> dict[str, Any]:
    target_allowed, clean_target, target_reason = bedrock_converse_ssh_target_allowed(
        target
    )
    clean_command = re.sub(r"\s+", " ", str(command or "")).strip()
    if not target_allowed:
        return {
            "ok": False,
            "target": clean_target,
            "command": clean_command,
            "returncode": 126,
            "stdout": "",
            "stderr": target_reason,
        }
    command_allowed, command_reason = bedrock_converse_shell_command_allowed(
        clean_command
    )
    if not command_allowed:
        return {
            "ok": False,
            "target": clean_target,
            "command": clean_command,
            "returncode": 126,
            "stdout": "",
            "stderr": command_reason,
        }
    try:
        completed = subprocess.run(
            [
                "ssh",
                "-o",
                "BatchMode=yes",
                "-o",
                f"ConnectTimeout={BEDROCK_CONVERSE_SSH_CONNECT_TIMEOUT_SECONDS}",
                clean_target,
                clean_command,
            ],
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=BEDROCK_CONVERSE_TOOL_TIMEOUT_SECONDS,
        )
    except subprocess.TimeoutExpired:
        return {
            "ok": False,
            "target": clean_target,
            "command": clean_command,
            "returncode": 124,
            "stdout": "",
            "stderr": (
                f"ssh command timed out after {BEDROCK_CONVERSE_TOOL_TIMEOUT_SECONDS}s"
            ),
        }
    except OSError as exc:
        return {
            "ok": False,
            "target": clean_target,
            "command": clean_command,
            "returncode": 1,
            "stdout": "",
            "stderr": str(exc),
        }
    return {
        "ok": completed.returncode == 0,
        "target": clean_target,
        "command": clean_command,
        "returncode": completed.returncode,
        "stdout": summarize_text(completed.stdout, 6000),
        "stderr": summarize_text(completed.stderr, 2000),
    }


def call_bedrock_converse(
    *,
    model_id: str,
    messages: list[dict[str, Any]],
    tool_config: dict[str, Any] | None,
    inference_config: dict[str, Any],
) -> dict[str, Any]:
    payload = {
        "model_id": model_id,
        "messages": messages,
        "tool_config": tool_config,
        "inference_config": inference_config,
        "region": BEDROCK_CONVERSE_AWS_REGION,
    }
    if BEDROCK_CONVERSE_PYTHON:
        env = dict(os.environ)
        if BEDROCK_CONVERSE_AWS_PROFILE:
            env["AWS_PROFILE"] = BEDROCK_CONVERSE_AWS_PROFILE
        if BEDROCK_CONVERSE_AWS_REGION:
            env["AWS_REGION"] = BEDROCK_CONVERSE_AWS_REGION
            env["AWS_DEFAULT_REGION"] = BEDROCK_CONVERSE_AWS_REGION
        completed = subprocess.run(
            [BEDROCK_CONVERSE_PYTHON, "-c", BEDROCK_CONVERSE_HELPER_CODE],
            input=json.dumps(payload),
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=env,
            timeout=BEDROCK_CONVERSE_CALL_TIMEOUT_SECONDS,
        )
        if completed.returncode != 0:
            raise RuntimeError(
                summarize_text(
                    completed.stderr
                    or completed.stdout
                    or f"helper exited {completed.returncode}",
                    1000,
                )
            )
        return json.loads(completed.stdout)

    if BEDROCK_CONVERSE_AWS_PROFILE:
        os.environ.setdefault("AWS_PROFILE", BEDROCK_CONVERSE_AWS_PROFILE)
    if BEDROCK_CONVERSE_AWS_REGION:
        os.environ.setdefault("AWS_REGION", BEDROCK_CONVERSE_AWS_REGION)
        os.environ.setdefault("AWS_DEFAULT_REGION", BEDROCK_CONVERSE_AWS_REGION)
    try:
        import boto3  # type: ignore[import-not-found]
    except ImportError as exc:
        raise RuntimeError("boto3 is required for Bedrock Converse") from exc
    client = boto3.client("bedrock-runtime", region_name=BEDROCK_CONVERSE_AWS_REGION)
    kwargs: dict[str, Any] = {
        "modelId": model_id,
        "messages": messages,
        "inferenceConfig": inference_config,
    }
    if tool_config:
        kwargs["toolConfig"] = tool_config
    return client.converse(**kwargs)


def bedrock_converse_tool_specs() -> list[dict[str, Any]]:
    tools: list[dict[str, Any]] = [
        {
            "toolSpec": {
                "name": "shell_readonly",
                "description": (
                    "Run one approved read-only shell command in the TUI "
                    "working directory."
                ),
                "inputSchema": {
                    "json": {
                        "type": "object",
                        "properties": {"command": {"type": "string"}},
                        "required": ["command"],
                        "additionalProperties": False,
                    }
                },
            }
        }
    ]
    if BEDROCK_CONVERSE_AWS_READONLY_ENABLED:
        tools.append(
            {
                "toolSpec": {
                    "name": "aws_readonly",
                    "description": (
                        "Run one explicitly approved read-only AWS CLI status "
                        "command using the configured AWS profile and region. "
                        "Use for identity/config checks and selected describe, "
                        "list, and get-status operations only."
                    ),
                    "inputSchema": {
                        "json": {
                            "type": "object",
                            "properties": {"command": {"type": "string"}},
                            "required": ["command"],
                            "additionalProperties": False,
                        }
                    },
                }
            }
        )
    if BEDROCK_CONVERSE_FILE_WRITE_ENABLED:
        tools.append(
            {
                "toolSpec": {
                    "name": "file_write_limited",
                    "description": (
                        "Write a UTF-8 text file under explicitly allowed "
                        "TUI workdir path prefixes. Existing files are backed up."
                    ),
                    "inputSchema": {
                        "json": {
                            "type": "object",
                            "properties": {
                                "path": {"type": "string"},
                                "content": {"type": "string"},
                                "mode": {
                                    "type": "string",
                                    "enum": ["overwrite", "create"],
                                },
                            },
                            "required": ["path", "content"],
                            "additionalProperties": False,
                        }
                    },
                }
            }
        )
    if BEDROCK_CONVERSE_SSH_ENABLED and BEDROCK_CONVERSE_SSH_TARGETS:
        tools.append(
            {
                "toolSpec": {
                    "name": "ssh_limited",
                    "description": (
                        "Run one approved read-only shell command on an "
                        "explicitly allowed SSH target."
                    ),
                    "inputSchema": {
                        "json": {
                            "type": "object",
                            "properties": {
                                "target": {"type": "string"},
                                "command": {"type": "string"},
                            },
                            "required": ["target", "command"],
                            "additionalProperties": False,
                        }
                    },
                }
            }
        )
    return tools


def build_bedrock_converse_tool_budget_checkpoint(
    *,
    tool_budget: int,
    tool_calls: int,
    tool_rounds: int,
    model_calls: int,
    requested_tools: list[str],
    last_response: str,
) -> str:
    requested = ", ".join(_unique_limited_values(requested_tools, limit=8))
    partial = summarize_text(last_response, 900)
    lines = [
        "BLOCKED — brokered tool budget reached before the model produced a final answer.",
        "",
        f"tool_budget: {tool_budget}",
        f"tool_calls_completed: {tool_calls}",
        f"tool_rounds_completed: {tool_rounds}",
        f"model_calls_completed: {model_calls}",
    ]
    if requested:
        lines.append(f"next_requested_tool: {requested}")
    if partial:
        lines.extend(["", "partial_response:", partial])
    lines.extend(
        [
            "",
            "next_action: Continue with a narrower follow-up prompt using the evidence already gathered, or choose a longer job budget for this TUI so the broker can safely allow more tool calls.",
            "resume_prompt: Continue from the brokered tool-budget checkpoint. First summarize the evidence already gathered, then run only the next highest-value brokered tool calls needed to finish, and return DONE or BLOCKED.",
        ]
    )
    return "\n".join(lines)


def _execute_bedrock_converse_prompt(
    prompt: str,
    speed: str,
    detail: int,
    attachments: list[dict[str, Any]],
    timeout_seconds: int | None = None,
    model: str = "",
    service_tier: str = "",
    job_budget: str = "",
    optimization_mode: str = "",
) -> tuple[str, str, str, dict[str, Any]]:
    started_at = now_ts()
    normalized_speed = normalize_response_speed(speed)
    normalized_detail = normalize_response_detail(detail)
    normalized_budget = normalize_job_budget(job_budget)
    normalized_timeout = normalize_job_timeout_seconds(timeout_seconds, job_budget)
    normalized_model = normalize_runtime_model("claude", model)
    thread_id = read_text(THREAD_ID_PATH) or f"bedrock-converse-{started_at}"
    tuned_prompt = build_prompt_with_attachments(
        prompt,
        normalized_detail,
        attachments,
        normalized_budget,
        normalized_timeout,
        "claude",
        normalized_model,
        normalized_speed,
        "default",
        optimization_mode,
    )
    preflight_usage_fields = usage_fields_from_context_preflight_accounting(
        take_latest_context_preflight_accounting("claude", normalized_model)
    )
    tool_budget = bedrock_converse_tool_call_budget(
        normalized_budget, normalized_timeout
    )
    execution_prompt = (
        f"{tuned_prompt}\n\n"
        "Bedrock Converse emergency runtime:\n"
        f"- Available brokered tools: "
        f"{', '.join(tool['toolSpec']['name'] for tool in bedrock_converse_tool_specs())}.\n"
        f"- Brokered tool-call budget for this turn: {tool_budget}. "
        "When you are close to that budget, stop opening new branches and "
        "return DONE or BLOCKED with a concise checkpoint.\n"
        "- Operate like a Codex execution agent, not a chat-only assistant: "
        "inspect, act within the brokered policy, verify, then report.\n"
        "- For repo, runtime, log, artifact, or deployment-readiness questions, "
        "use at least one brokered tool before the final answer unless the "
        "operator explicitly asks for explanation only.\n"
        "- Use shell_readonly for inspection before final answers when command "
        "evidence is needed. Commands already run in the TUI workdir; do not "
        "prefix commands with cd. Prefer simple one-command-at-a-time forms "
        "without shell redirection or command substitution.\n"
        "- If a brokered command is denied by policy, adapt once to an allowed "
        "read-only shape and report the denied form only as evidence.\n"
        "- Use aws_readonly for AWS identity, configuration, and explicitly "
        "allowed status reads. Do not request credential material, SSO role "
        "credentials, start-session, mutation, deploy, or secret/value reads.\n"
        "- Use file_write_limited only for bounded text edits under configured "
        "allowed path prefixes; do not write secrets, credentials, or unrelated "
        "files. After a write, verify with shell_readonly before finalizing.\n"
        "- Use ssh_limited only for configured targets and read-only inspection. "
        "Deploys, restarts, remote writes, secret access, and destructive actions "
        "remain human-gated; return BLOCKED at those approval points.\n"
        "- Final answers must be concrete, must not end with progress text, and "
        "when the prompt requests DONE/BLOCKED, the first visible token of the "
        "final answer must be DONE or BLOCKED."
    )
    messages: list[dict[str, Any]] = [
        {"role": "user", "content": [{"text": execution_prompt}]}
    ]
    tool_config = {"tools": bedrock_converse_tool_specs()}
    inference_config = {"maxTokens": BEDROCK_CONVERSE_MAX_OUTPUT_TOKENS}
    response_text = ""
    error_text = ""
    usage = normalize_usage_entry(
        {
            **bedrock_converse_provider_tags(),
            **preflight_usage_fields,
            "runtime": "claude",
            "model": normalized_model,
            "service_tier": service_tier,
            "started_at": started_at,
            "thread_id": thread_id,
        }
    )
    total_input = 0
    total_output = 0
    total_tokens = 0
    tool_calls = 0
    tool_rounds = 0
    model_calls = 0
    tool_budget_exhausted = False
    try:
        for _ in range(max(1, tool_budget + 1)):
            model_calls += 1
            response = call_bedrock_converse(
                model_id=normalized_model,
                messages=messages,
                tool_config=tool_config,
                inference_config=inference_config,
            )
            response_usage = response.get("usage") if isinstance(response, dict) else {}
            if isinstance(response_usage, dict):
                total_input += _coerce_int(response_usage.get("inputTokens"))
                total_output += _coerce_int(response_usage.get("outputTokens"))
                total_tokens += _coerce_int(response_usage.get("totalTokens"))
            message = (
                response.get("output", {}).get("message", {})
                if isinstance(response, dict)
                else {}
            )
            content = message.get("content") if isinstance(message, dict) else []
            if not isinstance(content, list):
                content = []
            messages.append({"role": "assistant", "content": content})
            text_parts = [
                str(part.get("text") or "")
                for part in content
                if isinstance(part, dict) and "text" in part
            ]
            if text_parts:
                response_text = "".join(text_parts).strip()
            tool_uses = [
                part.get("toolUse")
                for part in content
                if isinstance(part, dict) and isinstance(part.get("toolUse"), dict)
            ]
            if not tool_uses:
                break
            if tool_calls + len(tool_uses) > tool_budget:
                tool_budget_exhausted = True
                response_text = build_bedrock_converse_tool_budget_checkpoint(
                    tool_budget=tool_budget,
                    tool_calls=tool_calls,
                    tool_rounds=tool_rounds,
                    model_calls=model_calls,
                    requested_tools=[
                        str(tool_use.get("name") or "")
                        for tool_use in tool_uses
                        if isinstance(tool_use, dict)
                    ],
                    last_response=response_text,
                )
                break
            tool_results: list[dict[str, Any]] = []
            for tool_use in tool_uses:
                name = str(tool_use.get("name") or "")
                tool_use_id = str(tool_use.get("toolUseId") or "")
                tool_input = tool_use.get("input")
                if not tool_use_id:
                    result = {
                        "ok": False,
                        "error": f"unsupported tool: {name or '[missing]'}",
                    }
                elif name == "shell_readonly":
                    command = (
                        tool_input.get("command")
                        if isinstance(tool_input, dict)
                        else ""
                    )
                    result = run_bedrock_converse_shell_readonly(command)
                elif name == "aws_readonly":
                    command = (
                        tool_input.get("command")
                        if isinstance(tool_input, dict)
                        else ""
                    )
                    result = run_bedrock_converse_aws_readonly(command)
                elif name == "file_write_limited":
                    if isinstance(tool_input, dict):
                        result = run_bedrock_converse_file_write_limited(
                            tool_input.get("path"),
                            tool_input.get("content"),
                            tool_input.get("mode", "overwrite"),
                        )
                    else:
                        result = {
                            "ok": False,
                            "error": "file_write_limited input must be an object",
                        }
                elif name == "ssh_limited":
                    if isinstance(tool_input, dict):
                        result = run_bedrock_converse_ssh_limited(
                            tool_input.get("target"), tool_input.get("command")
                        )
                    else:
                        result = {
                            "ok": False,
                            "error": "ssh_limited input must be an object",
                        }
                else:
                    result = {
                        "ok": False,
                        "error": f"unsupported tool: {name or '[missing]'}",
                    }
                tool_results.append(
                    {
                        "toolResult": {
                            "toolUseId": tool_use_id,
                            "content": [{"json": result}],
                        }
                    }
                )
                tool_calls += 1
            tool_rounds += 1
            messages.append({"role": "user", "content": tool_results})
        else:
            tool_budget_exhausted = True
            response_text = build_bedrock_converse_tool_budget_checkpoint(
                tool_budget=tool_budget,
                tool_calls=tool_calls,
                tool_rounds=tool_rounds,
                model_calls=model_calls,
                requested_tools=[],
                last_response=response_text,
            )
    except Exception as exc:
        error_text = summarize_text(str(exc), 1000)
    finished_at = now_ts()
    usage = normalize_usage_entry(
        {
            **bedrock_converse_provider_tags(),
            "runtime": "claude",
            "model": normalized_model,
            "service_tier": service_tier,
            "started_at": started_at,
            "finished_at": finished_at,
            "thread_id": thread_id,
            "speed": normalized_speed,
            "detail": normalized_detail,
            "success": bool(response_text and not error_text),
            "input_tokens": total_input,
            "output_tokens": total_output,
            "total_tokens": total_tokens,
            "broker_tool_call_budget": tool_budget,
            "broker_tool_calls": tool_calls,
            "broker_tool_rounds": tool_rounds,
            "broker_model_calls": model_calls,
            "broker_tool_budget_exhausted": tool_budget_exhausted,
            "provider_yield_kind": "broker_tool_budget_checkpoint"
            if tool_budget_exhausted
            else "",
            "provider_yield_reasons": [f"broker tool budget reached: {tool_budget}"]
            if tool_budget_exhausted
            else [],
        }
    )
    return response_text, error_text, thread_id, usage


