    snapshot["human_intervention_ask_now_count"] = len(ask_now_interventions)
    snapshot["human_intervention_focus"] = (
        ask_now_interventions[0]
        if ask_now_interventions
        else human_interventions[0]
        if human_interventions
        else None
    )
    snapshot["context_pack_preview"] = context_pack_preview(snapshot)
