    snapshot["kpis"] = update_kpi_snapshot(snapshot)
    sentinel = (
        snapshot["kpis"].get("sentinel")
        if isinstance(snapshot.get("kpis"), dict)
        and isinstance(snapshot["kpis"].get("sentinel"), dict)
        else build_sentinel_state(snapshot, snapshot.get("kpis"))
    )
    snapshot["sentinel"] = sentinel
    if maybe_raise_sentinel_intervention(sentinel):
        human_interventions = load_human_interventions()
        ask_now_interventions = [
            item for item in human_interventions if item.get("severity") == "ask_now"
        ]
        snapshot["human_interventions"] = human_interventions
